// zlinter-disable declaration_naming field_naming field_ordering function_naming max_positional_args no_empty_block no_undefined no_swallow_error require_doc_comment
const lowered_machine = @import("lowered_machine");
const lowering_api = @import("lowering_api");
const plan_types = @import("internal_program_plan");
const program_evidence = @import("program/evidence.zig");
const std = @import("std");

fn hasDeclSafe(comptime T: type, comptime name: []const u8) bool {
    return switch (@typeInfo(T)) {
        .@"struct", .@"union", .@"enum", .@"opaque" => @hasDecl(T, name),
        else => false,
    };
}

fn dummyPointer(comptime PtrType: type) PtrType {
    const pointer = @typeInfo(PtrType).pointer;
    const Child = std.meta.Child(PtrType);
    if (pointer.size == .slice) {
        const many = @as([*]Child, @ptrFromInt(std.mem.alignForward(usize, 1, @alignOf(Child))));
        const slice = if (comptime pointer.sentinel()) |sentinel| many[0..1 :sentinel] else many[0..1];
        if (pointer.is_const) return @as(PtrType, slice);
        return @as(PtrType, @constCast(slice));
    }
    return @as(PtrType, @ptrFromInt(std.mem.alignForward(usize, 1, @alignOf(Child))));
}

fn dummyValue(comptime T: type) T {
    return switch (@typeInfo(T)) {
        .pointer => dummyPointer(T),
        .optional => |optional| dummyValue(optional.child),
        .void => {},
        .@"struct" => |info| blk: {
            var value: T = undefined;
            inline for (info.fields) |field| {
                @field(value, field.name) = dummyValue(field.type);
            }
            break :blk value;
        },
        else => dummyPointer(*T).*,
    };
}

fn ProgramPlanForBody(comptime Body: type) lowering_api.ProgramPlan {
    if (!hasDeclSafe(Body, "compiled_plan")) {
        @compileError("ability.program bodies must declare pub const compiled_plan: ability.ir.ProgramPlan");
    }
    const plan = Body.compiled_plan;
    if (@TypeOf(plan) != lowering_api.ProgramPlan) {
        @compileError("Body.compiled_plan must have type ability.ir.ProgramPlan");
    }
    comptime {
        @setEvalBranchQuota(100_000);
        const nested_with_targets = BodyNestedWithTargets(Body).values;
        plan.validateWithNestedTargets(nested_with_targets) catch |err| {
            @compileError("Body.compiled_plan failed ProgramPlan.validate: " ++ @errorName(err));
        };
        validateBodyValueSchemaTypes(plan, Body, nested_with_targets);
        const schema_types = BodyValueSchemaTypes(Body).values;
        lowering_api.validateTypedExecutablePlanSupportWithNestedTargets(plan, schema_types, nested_with_targets) catch |err| {
            @compileError("Body.compiled_plan is not supported by ability.program: " ++ @errorName(err) ++ "\n" ++
                lowering_api.executableCapabilitySummary(plan, schema_types, nested_with_targets));
        };
        validatePlanReturnErrors(plan, nested_with_targets, BodyErrorSet(Body));
    }
    return plan;
}

fn BodyValueSchemaTypes(comptime Body: type) type {
    if (comptime hasDeclSafe(Body, "value_schema_types")) {
        return struct {
            /// Exact Zig type tuple matching ProgramPlan product and sum schema tables.
            pub const values = Body.value_schema_types;
        };
    }
    return struct {
        /// Empty schema registry for scalar-only plans.
        pub const values = .{};
    };
}

fn BodyNestedWithTargets(comptime Body: type) type {
    if (comptime hasDeclSafe(Body, "nested_with_targets")) {
        return struct {
            /// Exact metadata-to-function resolver rows for executable nested lexical-with instructions.
            pub const values = Body.nested_with_targets;
        };
    }
    return struct {
        /// No nested lexical-with rows are executable unless the body opts in with targets.
        pub const values = .{};
    };
}

fn BodySiteMetadata(comptime Body: type) type {
    if (comptime hasDeclSafe(Body, "site_metadata")) {
        return struct {
            /// Optional display/debug labels for lowered semantic operation sites.
            pub const values = Body.site_metadata;
        };
    }
    return struct {
        /// Raw ProgramPlan construction has no semantic site labels by default.
        pub const values = .{};
    };
}

fn schemaIndexLabel(comptime index: usize) []const u8 {
    return std.fmt.comptimePrint("{d}", .{index});
}

fn valueSchemaPlansEqual(comptime actual: anytype, comptime expected: anytype) bool {
    return std.mem.eql(u8, actual.label, expected.label) and
        actual.codec == expected.codec and
        actual.first_field == expected.first_field and
        actual.field_count == expected.field_count and
        actual.first_variant == expected.first_variant and
        actual.variant_count == expected.variant_count;
}

fn schemaRefsMatch(comptime schema_types: anytype, actual: ?u16, expected: ?u16) bool {
    if (actual == expected) return true;
    const actual_index = actual orelse return false;
    const expected_index = expected orelse return false;
    if (actual_index >= schema_types.len or expected_index >= schema_types.len) return false;
    return schema_types[actual_index] == schema_types[expected_index];
}

fn valueFieldPlansEqual(comptime schema_types: anytype, comptime actual: anytype, comptime expected: anytype) bool {
    return std.mem.eql(u8, actual.name, expected.name) and
        actual.codec == expected.codec and
        schemaRefsMatch(schema_types, actual.schema_index, expected.schema_index);
}

fn valueVariantPlansEqual(comptime schema_types: anytype, comptime actual: anytype, comptime expected: anytype) bool {
    return std.mem.eql(u8, actual.name, expected.name) and
        actual.codec == expected.codec and
        schemaRefsMatch(schema_types, actual.schema_index, expected.schema_index);
}

fn validateBodyValueSchemaTypes(
    comptime plan: lowering_api.ProgramPlan,
    comptime Body: type,
    comptime nested_with_targets: anytype,
) void {
    const plan_schema_count = plan.value_schemas.len;
    if (comptime !hasDeclSafe(Body, "value_schema_types")) {
        if (lowering_api.executablePlanNeedsBodyValueSchemaTypes(plan, nested_with_targets)) {
            @compileError("Body.value_schema_types is required when reachable Body.compiled_plan execution uses product or sum value schemas");
        }
        return;
    }

    const schema_types = Body.value_schema_types;
    if (schema_types.len != plan_schema_count) {
        @compileError(std.fmt.comptimePrint(
            "Body.value_schema_types length mismatch: expected {d}, found {d}",
            .{ plan_schema_count, schema_types.len },
        ));
    }

    const registry = lowering_api.ValueSchemaRegistryForTypes(schema_types);
    if (registry.value_fields.len != plan.value_fields.len) {
        @compileError(std.fmt.comptimePrint(
            "Body.value_schema_types field table length mismatch: expected {d}, found {d}",
            .{ plan.value_fields.len, registry.value_fields.len },
        ));
    }
    if (registry.value_variants.len != plan.value_variants.len) {
        @compileError(std.fmt.comptimePrint(
            "Body.value_schema_types variant table length mismatch: expected {d}, found {d}",
            .{ plan.value_variants.len, registry.value_variants.len },
        ));
    }

    inline for (registry.value_schemas, 0..) |expected, index| {
        if (!valueSchemaPlansEqual(plan.value_schemas[index], expected)) {
            @compileError("Body.value_schema_types does not match Body.compiled_plan.value_schemas[" ++ schemaIndexLabel(index) ++ "]");
        }
    }
    inline for (registry.value_fields, 0..) |expected, index| {
        if (!valueFieldPlansEqual(schema_types, plan.value_fields[index], expected)) {
            @compileError("Body.value_schema_types does not match Body.compiled_plan.value_fields[" ++ schemaIndexLabel(index) ++ "]");
        }
    }
    inline for (registry.value_variants, 0..) |expected, index| {
        if (!valueVariantPlansEqual(schema_types, plan.value_variants[index], expected)) {
            @compileError("Body.value_schema_types does not match Body.compiled_plan.value_variants[" ++ schemaIndexLabel(index) ++ "]");
        }
    }
}

fn BodyErrorSet(comptime Body: type) type {
    if (comptime !hasDeclSafe(Body, "Error")) return error{};
    if (@typeInfo(Body.Error) != .error_set) @compileError("Body.Error must be an error set");
    return Body.Error;
}

fn errorSetContains(comptime ErrorSet: type, literal: []const u8) bool {
    return switch (@typeInfo(ErrorSet)) {
        .error_set => |errors| blk: {
            if (errors) |decls| {
                inline for (decls) |decl| {
                    if (std.mem.eql(u8, decl.name, literal)) break :blk true;
                }
            } else {
                break :blk true;
            }
            break :blk false;
        },
        else => @compileError("Body.Error must be an error set"),
    };
}

fn validatePlanReturnErrors(
    comptime plan: lowering_api.ProgramPlan,
    comptime nested_targets: anytype,
    comptime ErrorSet: type,
) void {
    const analysis = comptime plan_types.entryExecutionAnalysisWithNestedTargets(plan, nested_targets) catch |err|
        @compileError("Body.compiled_plan entry execution analysis failed: " ++ @errorName(err));
    for (plan.instructions, 0..) |instruction, instruction_index| {
        if (!analysis.reachable_instructions[instruction_index] or instruction.kind != .return_error) continue;
        if (!errorSetContains(ErrorSet, instruction.string_literal)) {
            @compileError("Body.compiled_plan reachable return_error is not declared in Body.Error: " ++ instruction.string_literal);
        }
    }
}

fn ProgramValueTypeForRef(
    comptime plan: lowering_api.ProgramPlan,
    comptime schema_types: anytype,
    comptime ref: lowering_api.ValueRef,
) type {
    _ = plan;
    return switch (ref.codec) {
        .unit => void,
        .bool => bool,
        .i32 => i32,
        .product => schema_types[ref.schema_index orelse @compileError("product ProgramPlan result is missing a schema index")],
        .usize => usize,
        .string => []const u8,
        .string_list => []const []const u8,
        .sum => schema_types[ref.schema_index orelse @compileError("sum ProgramPlan result is missing a schema index")],
    };
}

fn maxProgramValueStorageSize(comptime schema_types: anytype) comptime_int {
    var max_size: comptime_int = 1;
    inline for (.{ void, bool, i32, usize, []const u8, []const []const u8 }) |T| {
        max_size = @max(max_size, @sizeOf(T));
    }
    inline for (schema_types) |T| {
        max_size = @max(max_size, @sizeOf(T));
    }
    return max_size;
}

fn maxProgramValueStorageAlign(comptime schema_types: anytype) comptime_int {
    var max_align: comptime_int = 1;
    inline for (.{ void, bool, i32, usize, []const u8, []const []const u8 }) |T| {
        max_align = @max(max_align, @alignOf(T));
    }
    inline for (schema_types) |T| {
        max_align = @max(max_align, @alignOf(T));
    }
    return max_align;
}

fn ProgramValueRefForType(comptime schema_types: anytype, comptime ValueType: type) lowering_api.ValueRef {
    if (ValueType == void) return .{ .codec = .unit };
    if (ValueType == bool) return .{ .codec = .bool };
    if (ValueType == i32) return .{ .codec = .i32 };
    if (ValueType == usize) return .{ .codec = .usize };
    if (ValueType == []const u8) return .{ .codec = .string };
    if (ValueType == []const []const u8 or ValueType == [][]const u8) return .{ .codec = .string_list };

    inline for (schema_types, 0..) |SchemaType, schema_index| {
        if (ValueType == SchemaType) {
            return switch (@typeInfo(ValueType)) {
                .@"struct" => .{ .codec = .product, .schema_index = @intCast(schema_index) },
                .@"enum", .@"union", .optional => .{ .codec = .sum, .schema_index = @intCast(schema_index) },
                else => @compileError("Program.Handler value schema type must be product or sum: " ++ @typeName(ValueType)),
            };
        }
    }

    @compileError("Program.Handler value type is not representable by this Program: " ++ @typeName(ValueType));
}

fn ProgramValueCodecForType(comptime ValueType: type) lowering_api.ValueCodec {
    if (ValueType == void) return .unit;
    if (ValueType == bool) return .bool;
    if (ValueType == i32) return .i32;
    if (ValueType == usize) return .usize;
    if (ValueType == []const u8) return .string;
    if (ValueType == []const []const u8 or ValueType == [][]const u8) return .string_list;
    return switch (@typeInfo(ValueType)) {
        .@"struct" => .product,
        .@"enum", .@"union", .optional => .sum,
        else => @compileError("Program.Handler value type is not representable by Program values: " ++ @typeName(ValueType)),
    };
}

fn ProgramValueRefCompatibleWithType(ref: lowering_api.ValueRef, comptime ValueType: type) bool {
    const codec = comptime ProgramValueCodecForType(ValueType);
    if (ref.codec != codec) return false;
    return switch (codec) {
        .product, .sum => true,
        else => ref.schema_index == null,
    };
}

fn ProgramValueRefMatchesType(comptime schema_types: anytype, comptime ref: lowering_api.ValueRef, comptime ValueType: type) bool {
    const codec = comptime ProgramValueCodecForType(ValueType);
    if (ref.codec != codec) return false;
    return switch (codec) {
        .product, .sum => {
            const schema_index = ref.schema_index orelse return false;
            if (schema_index >= schema_types.len) return false;
            return schema_types[schema_index] == ValueType;
        },
        else => ref.schema_index == null,
    };
}

fn ProgramValueStandaloneRefForType(comptime ValueType: type) lowering_api.ValueRef {
    const codec = comptime ProgramValueCodecForType(ValueType);
    return .{ .codec = codec };
}

fn ProgramErrorSet(comptime Body: type) type {
    if (comptime hasDeclSafe(Body, "Error")) return lowered_machine.ResetError(Body.Error);
    return lowered_machine.ResetError(error{});
}

const ContractOutputView = struct {
    label: []const u8,
    codec: lowering_api.ValueCodec,
    schema_index: ?u16 = null,
};

const ContractValueSchemaView = struct {
    label: []const u8,
    codec: lowering_api.ValueCodec,
    first_field: u16,
    field_count: u16,
    first_variant: u16,
    variant_count: u16,
};

const ContractValueFieldView = struct {
    name: []const u8,
    ref: lowering_api.ValueRef,
};

const ContractValueVariantView = struct {
    name: []const u8,
    ref: lowering_api.ValueRef,
};

const ContractEntryParameterView = struct {
    local_index: u16,
    ref: lowering_api.ValueRef,
};

const ContractNestedWithTargetView = struct {
    metadata: []const u8,
    function_index: u16,
};

const ContractRequirementView = struct {
    label: []const u8,
    first_op: u16,
    op_count: u16,
    lifecycle_tag: @TypeOf(@as(plan_types.RequirementPlan, undefined).lifecycle_tag),
    output_tag: @TypeOf(@as(plan_types.RequirementPlan, undefined).output_tag),
};

const ContractOpView = struct {
    requirement_index: u16,
    requirement_label: []const u8,
    op_name: []const u8,
    mode: plan_types.ControlMode,
    payload_ref: lowering_api.ValueRef,
    resume_ref: lowering_api.ValueRef,
    has_after: bool,
};

fn contractOutputs(comptime plan: lowering_api.ProgramPlan) [plan.outputs.len]ContractOutputView {
    var views: [plan.outputs.len]ContractOutputView = undefined;
    for (plan.outputs, 0..) |output, index| {
        views[index] = .{
            .label = output.label,
            .codec = output.codec,
            .schema_index = output.schema_index,
        };
    }
    return views;
}

fn contractValueSchemas(comptime plan: lowering_api.ProgramPlan) [plan.value_schemas.len]ContractValueSchemaView {
    var views: [plan.value_schemas.len]ContractValueSchemaView = undefined;
    for (plan.value_schemas, 0..) |schema, index| {
        views[index] = .{
            .label = schema.label,
            .codec = schema.codec,
            .first_field = schema.first_field,
            .field_count = schema.field_count,
            .first_variant = schema.first_variant,
            .variant_count = schema.variant_count,
        };
    }
    return views;
}

fn contractValueFields(comptime plan: lowering_api.ProgramPlan) [plan.value_fields.len]ContractValueFieldView {
    var views: [plan.value_fields.len]ContractValueFieldView = undefined;
    for (plan.value_fields, 0..) |field, index| {
        views[index] = .{
            .name = field.name,
            .ref = .{ .codec = field.codec, .schema_index = field.schema_index },
        };
    }
    return views;
}

fn contractValueVariants(comptime plan: lowering_api.ProgramPlan) [plan.value_variants.len]ContractValueVariantView {
    var views: [plan.value_variants.len]ContractValueVariantView = undefined;
    for (plan.value_variants, 0..) |variant, index| {
        views[index] = .{
            .name = variant.name,
            .ref = .{ .codec = variant.codec, .schema_index = variant.schema_index },
        };
    }
    return views;
}

fn contractEntryParameters(comptime plan: lowering_api.ProgramPlan) [plan.functions[plan.entry_index].parameter_count]ContractEntryParameterView {
    const entry = plan.functions[plan.entry_index];
    var views: [entry.parameter_count]ContractEntryParameterView = undefined;
    for (0..entry.parameter_count) |parameter_index| {
        const local = plan.locals[entry.first_local + parameter_index];
        views[parameter_index] = .{
            .local_index = @intCast(parameter_index),
            .ref = .{ .codec = local.codec, .schema_index = local.schema_index },
        };
    }
    return views;
}

fn contractNestedWithTargets(comptime nested_with_targets: anytype) [nested_with_targets.len]ContractNestedWithTargetView {
    var views: [nested_with_targets.len]ContractNestedWithTargetView = undefined;
    for (nested_with_targets, 0..) |target, index| {
        views[index] = .{
            .metadata = target.metadata,
            .function_index = target.function_index,
        };
    }
    return views;
}

fn contractRequirements(comptime plan: lowering_api.ProgramPlan) [plan.requirements.len]ContractRequirementView {
    var views: [plan.requirements.len]ContractRequirementView = undefined;
    for (plan.requirements, 0..) |requirement, index| {
        views[index] = .{
            .label = requirement.label,
            .first_op = requirement.first_op,
            .op_count = requirement.op_count,
            .lifecycle_tag = requirement.lifecycle_tag,
            .output_tag = requirement.output_tag,
        };
    }
    return views;
}

fn contractOps(comptime plan: lowering_api.ProgramPlan) [plan.ops.len]ContractOpView {
    var views: [plan.ops.len]ContractOpView = undefined;
    for (plan.ops, 0..) |op, index| {
        const requirement = plan.requirements[op.requirement_index];
        views[index] = .{
            .requirement_index = op.requirement_index,
            .requirement_label = requirement.label,
            .op_name = op.op_name,
            .mode = op.mode,
            .payload_ref = .{ .codec = op.payload_codec, .schema_index = op.payload_schema_index },
            .resume_ref = .{ .codec = op.resume_codec, .schema_index = op.resume_schema_index },
            .has_after = op.has_after,
        };
    }
    return views;
}

fn contractReturnErrorSeen(comptime values: []const []const u8, comptime len: usize, comptime literal: []const u8) bool {
    for (values[0..len]) |value| {
        if (std.mem.eql(u8, value, literal)) return true;
    }
    return false;
}

fn contractReturnErrorCount(comptime plan: lowering_api.ProgramPlan, comptime nested_targets: anytype) usize {
    const analysis = comptime plan_types.entryExecutionAnalysisWithNestedTargets(plan, nested_targets) catch |err|
        @compileError("Body.compiled_plan entry execution analysis failed: " ++ @errorName(err));
    var values: [plan.instructions.len][]const u8 = undefined;
    var count: usize = 0;
    for (plan.instructions, 0..) |instruction, instruction_index| {
        if (!analysis.reachable_instructions[instruction_index] or instruction.kind != .return_error) continue;
        if (contractReturnErrorSeen(values[0..], count, instruction.string_literal)) continue;
        values[count] = instruction.string_literal;
        count += 1;
    }
    return count;
}

fn contractReturnErrors(
    comptime plan: lowering_api.ProgramPlan,
    comptime nested_targets: anytype,
) [contractReturnErrorCount(plan, nested_targets)][]const u8 {
    const analysis = comptime plan_types.entryExecutionAnalysisWithNestedTargets(plan, nested_targets) catch |err|
        @compileError("Body.compiled_plan entry execution analysis failed: " ++ @errorName(err));
    var views: [contractReturnErrorCount(plan, nested_targets)][]const u8 = undefined;
    var count: usize = 0;
    for (plan.instructions, 0..) |instruction, instruction_index| {
        if (!analysis.reachable_instructions[instruction_index] or instruction.kind != .return_error) continue;
        if (contractReturnErrorSeen(views[0..], count, instruction.string_literal)) continue;
        views[count] = instruction.string_literal;
        count += 1;
    }
    return views;
}

fn ProgramContractFor(
    comptime program_label: []const u8,
    comptime plan: lowering_api.ProgramPlan,
    comptime ResultValue: type,
    comptime OutputsValue: type,
    comptime schema_types: anytype,
    comptime nested_targets: anytype,
    comptime site_metadata: anytype,
) type {
    const contract_result_ref = lowering_api.executableResultRefForPlan(plan);
    const output_views = contractOutputs(plan);
    const value_schema_views = contractValueSchemas(plan);
    const value_field_views = contractValueFields(plan);
    const value_variant_views = contractValueVariants(plan);
    const entry_parameter_views = contractEntryParameters(plan);
    const nested_with_target_views = contractNestedWithTargets(nested_targets);
    const requirement_views = contractRequirements(plan);
    const op_views = contractOps(plan);
    const return_error_views = contractReturnErrors(plan, nested_targets);
    const session_yield_site_views = lowering_api.sessionOperationYieldSitesForPlanWithMetadata(plan, nested_targets, site_metadata);
    const session_after_site_views = lowering_api.sessionAfterYieldSitesForPlanWithMetadata(plan, nested_targets, site_metadata);
    const Ledger = lowering_api.ExecutableCapabilityLedgerForPlan(plan, schema_types, nested_targets);
    const first_blocker: ?lowering_api.CapabilityBlocker = if (Ledger.blockers.len == 0) null else Ledger.blockers[0];
    const SessionLedger = lowering_api.TypedSessionCapabilityLedgerForPlan(plan, schema_types, nested_targets);
    const first_session_blocker: ?lowering_api.SessionBlocker = if (SessionLedger.blockers.len == 0) null else SessionLedger.blockers[0];

    return struct {
        /// Public program label passed to ability.program.
        pub const label = program_label;
        /// Result value reference declared by the entry ProgramPlan function.
        pub const result_ref = contract_result_ref;
        /// Result codec declared by the entry ProgramPlan function.
        pub const result_codec = contract_result_ref.codec;
        /// Result schema index when the result is product or sum typed.
        pub const result_schema_index = contract_result_ref.schema_index;
        /// Zig value type produced by Program.run.
        pub const ResultType = ResultValue;
        /// Zig outputs type produced by Program.run.
        pub const OutputsType = OutputsValue;
        /// Whether ResultType is backed by a typed ProgramPlan schema entry.
        pub const has_typed_result_schema = contract_result_ref.schema_index != null;
        /// Output declarations visible to callers without exposing mutable plan tables.
        pub const outputs = &output_views;
        /// Value schema declarations visible to callers without exposing mutable plan tables.
        pub const value_schemas = &value_schema_views;
        /// Product field declarations visible to callers without exposing mutable plan tables.
        pub const value_fields = &value_field_views;
        /// Sum variant declarations visible to callers without exposing mutable plan tables.
        pub const value_variants = &value_variant_views;
        /// Entry parameter declarations visible to callers without exposing mutable plan tables.
        pub const entry_parameters = &entry_parameter_views;
        /// Declared nested lexical-with resolver rows visible to callers.
        pub const nested_with_targets = &nested_with_target_views;
        /// Requirement declarations visible to callers without exposing mutable plan tables.
        pub const requirements = &requirement_views;
        /// Operation declarations visible to callers without exposing mutable plan tables.
        pub const ops = &op_views;
        /// Unique return_error literals declared by the compiled plan.
        pub const return_errors = &return_error_views;
        /// Whether the body declared explicit nested lexical-with resolver rows.
        pub const has_nested_with_targets = nested_targets.len != 0;
        /// Executable support ledger summary for the validated plan.
        pub const executable = struct {
            /// Whether the validated ProgramPlan has no executable capability blockers.
            pub const supported = Ledger.blockers.len == 0;
            /// Number of blockers retained in the capped executable ledger.
            pub const blocker_count = Ledger.blockers.len;
            /// Maximum blocker records retained by the executable ledger.
            pub const blocker_cap = lowering_api.max_capability_blockers;
            /// Whether executable ledger diagnostics were truncated at blocker_cap.
            pub const truncated = Ledger.truncated;
            /// Stable human-readable executable capability summary.
            pub const summary = lowering_api.executableCapabilitySummary(plan, schema_types, nested_targets);
            /// First blocker tag, if the executable ledger is non-empty.
            pub const first_blocker_tag: ?lowering_api.CapabilityBlockerTag = if (first_blocker) |blocker| blocker.tag else null;
            /// First blocker function index, if the executable ledger is non-empty.
            pub const first_blocker_function: ?u16 = if (first_blocker) |blocker| blocker.function_index else null;
            /// First blocker instruction index, if the executable ledger is non-empty.
            pub const first_blocker_instruction: ?u32 = if (first_blocker) |blocker| blocker.instruction_index else null;
        };
        /// Session-execution support summary for the validated plan.
        pub const session = struct {
            /// Whether Program.Session can start for this plan.
            pub const supported = SessionLedger.blockers.len == 0;
            /// Whether yielded requests park runtime active execution before returning to the host.
            pub const parks_runtime = true;
            /// Whether the owning Runtime must outlive all live sessions.
            pub const requires_runtime_lifetime = true;
            /// Whether yielded session requests expose deterministic trace metadata.
            pub const trace_supported = true;
            /// Stable fingerprint algorithm version mixed into all session trace hashes.
            pub const fingerprint_version = lowering_api.trace_fingerprint_version;
            /// Whether typed Program.Session values can be fingerprinted for trace/audit metadata.
            pub const value_fingerprint_supported = true;
            /// Entry-reachable operation yield sites exposed by Program.Session.
            pub const yield_sites = &session_yield_site_views;
            /// Entry-reachable after-continuation sites exposed by Program.Session.
            pub const after_sites = &session_after_site_views;
            /// Number of retained blockers for session execution.
            pub const blocker_count = SessionLedger.blockers.len;
            /// Maximum blocker records retained by the session ledger.
            pub const blocker_cap = lowering_api.max_capability_blockers;
            /// Whether session ledger diagnostics were truncated at blocker_cap.
            pub const truncated = SessionLedger.truncated;
            /// Stable human-readable session capability summary.
            pub const summary = lowering_api.typedSessionCapabilitySummary(plan, schema_types, nested_targets);
            /// First blocker tag, if the session ledger is non-empty.
            pub const first_blocker_tag: ?lowering_api.SessionBlockerTag = if (first_session_blocker) |blocker| blocker.tag else null;
            /// First blocker function index, if the session ledger is non-empty.
            pub const first_blocker_function: ?u16 = if (first_session_blocker) |blocker| blocker.function_index else null;
            /// First blocker instruction index, if the session ledger is non-empty.
            pub const first_blocker_instruction: ?u32 = if (first_session_blocker) |blocker| blocker.instruction_index else null;
            /// First blocker op index, if the session ledger is non-empty.
            pub const first_blocker_op: ?u16 = if (first_session_blocker) |blocker| blocker.op_index else null;
        };
    };
}

// zlinter-disable require_doc_comment
fn ProgramProtocolFor(
    comptime program_label: []const u8,
    comptime plan: lowering_api.ProgramPlan,
    comptime schema_types: anytype,
    comptime nested_targets: anytype,
    comptime HandlersType: type,
    comptime ProtocolOwner: type,
    comptime site_metadata: anytype,
    comptime InterpreterToken: type,
) type {
    const operation_sites = lowering_api.sessionOperationYieldSitesForPlanWithMetadata(plan, nested_targets, site_metadata);
    const after_sites = lowering_api.sessionAfterYieldSitesForPlanWithMetadata(plan, nested_targets, site_metadata);
    const plan_hash = plan.hash();

    return struct {
        pub const Owner = ProtocolOwner;
        pub const label = program_label;
        pub const hash = plan_hash;
        pub const OwnerHandlers = HandlersType;
        pub const operation_site_count = operation_sites.len;
        pub const after_site_count = after_sites.len;
        pub const operation_site_metadata = &operation_sites;
        pub const after_site_metadata = &after_sites;

        fn operationDescriptor(comptime site: lowering_api.SessionOperationYieldSite) type {
            const PayloadType = ProgramValueTypeForRef(plan, schema_types, site.payload_ref);
            const ResumeType = ProgramValueTypeForRef(plan, schema_types, site.resume_ref);
            const ResultType = ProgramValueTypeForRef(plan, schema_types, site.result_ref);
            return struct {
                pub const kind = .operation;
                pub const Owner = ProtocolOwner;
                pub const owner_label = program_label;
                pub const owner_plan_hash = plan_hash;
                pub const OwnerHandlers = HandlersType;
                pub const Payload = PayloadType;
                pub const Resume = ResumeType;
                pub const Result = ResultType;
                pub const metadata = site;
                pub const index = site.index;
                pub const fingerprint = site.fingerprint;
                pub const semantic_label = site.semantic_label;
                pub const function_index = site.function_index;
                pub const function_symbol_name = site.function_symbol_name;
                pub const block_index = site.block_index;
                pub const instruction_index = site.instruction_index;
                pub const requirement_index = site.requirement_index;
                pub const requirement_label = site.requirement_label;
                pub const op_index = site.op_index;
                pub const op_name = site.op_name;
                pub const op_mode = site.op_mode;
                pub const payload_ref = site.payload_ref;
                pub const resume_ref = site.resume_ref;
                pub const result_ref = site.result_ref;
                pub const has_after = site.has_after;
                pub const may_resume = site.host_may_resume;
                pub const may_return_now = site.host_may_return_now;
                pub const can_yield_after = site.can_yield_after;
            };
        }

        fn afterDescriptor(comptime site: lowering_api.SessionAfterYieldSite) type {
            const operation_site = operation_sites[site.source_operation_site_index];
            const static_input_ref = lowering_api.sessionAfterProtocolInputRefForOperationSite(plan, schema_types, HandlersType, operation_site);
            const static_output_ref = lowering_api.sessionAfterProtocolOutputRefForOperationSite(plan, schema_types, HandlersType, operation_site);
            const OutputType = ProgramValueTypeForRef(plan, schema_types, static_output_ref);
            const ResultType = ProgramValueTypeForRef(plan, schema_types, site.result_ref);
            if (static_input_ref) |static_ref| {
                const InputType = ProgramValueTypeForRef(plan, schema_types, static_ref);
                return struct {
                    pub const kind = .after;
                    pub const Owner = ProtocolOwner;
                    pub const owner_label = program_label;
                    pub const owner_plan_hash = plan_hash;
                    pub const OwnerHandlers = HandlersType;
                    pub const has_static_input_ref = true;
                    pub const Input = InputType;
                    pub const Output = OutputType;
                    pub const Result = ResultType;
                    pub const metadata = site;
                    pub const index = site.index;
                    pub const fingerprint = site.fingerprint;
                    pub const semantic_label = site.semantic_label;
                    pub const source_operation_site_index = site.source_operation_site_index;
                    pub const source_operation_site_fingerprint = site.source_operation_site_fingerprint;
                    pub const source_function_index = site.source_function_index;
                    pub const source_block_index = site.source_block_index;
                    pub const source_instruction_index = site.source_instruction_index;
                    pub const original_requirement_index = site.original_requirement_index;
                    pub const original_requirement_label = site.original_requirement_label;
                    pub const original_op_index = site.original_op_index;
                    pub const original_op_name = site.original_op_name;
                    pub const input_ref: ?lowering_api.ValueRef = static_ref;
                    pub const current_value_ref: ?lowering_api.ValueRef = static_ref;
                    pub const output_ref = static_output_ref;
                    pub const result_ref = site.result_ref;
                };
            }
            return struct {
                pub const kind = .after;
                pub const Owner = ProtocolOwner;
                pub const owner_label = program_label;
                pub const owner_plan_hash = plan_hash;
                pub const OwnerHandlers = HandlersType;
                pub const has_static_input_ref = false;
                pub const Output = OutputType;
                pub const Result = ResultType;
                pub const metadata = site;
                pub const index = site.index;
                pub const fingerprint = site.fingerprint;
                pub const semantic_label = site.semantic_label;
                pub const source_operation_site_index = site.source_operation_site_index;
                pub const source_operation_site_fingerprint = site.source_operation_site_fingerprint;
                pub const source_function_index = site.source_function_index;
                pub const source_block_index = site.source_block_index;
                pub const source_instruction_index = site.source_instruction_index;
                pub const original_requirement_index = site.original_requirement_index;
                pub const original_requirement_label = site.original_requirement_label;
                pub const original_op_index = site.original_op_index;
                pub const original_op_name = site.original_op_name;
                pub const input_ref: ?lowering_api.ValueRef = null;
                pub const current_value_ref: ?lowering_api.ValueRef = null;
                pub const output_ref = static_output_ref;
                pub const result_ref = site.result_ref;
            };
        }

        pub fn operationSite(
            comptime requirement_label: []const u8,
            comptime op_name: []const u8,
            comptime occurrence_index: usize,
        ) type {
            comptime var occurrence: usize = 0;
            inline for (operation_sites) |site| {
                if (std.mem.eql(u8, site.requirement_label, requirement_label) and std.mem.eql(u8, site.op_name, op_name)) {
                    if (occurrence == occurrence_index) return operationDescriptor(site);
                    occurrence += 1;
                }
            }
            @compileError("Program.protocol.operationSite could not find requested operation site");
        }

        pub fn afterSite(
            comptime requirement_label: []const u8,
            comptime op_name: []const u8,
            comptime occurrence_index: usize,
        ) type {
            comptime var occurrence: usize = 0;
            inline for (after_sites) |site| {
                if (std.mem.eql(u8, site.original_requirement_label, requirement_label) and std.mem.eql(u8, site.original_op_name, op_name)) {
                    if (occurrence == occurrence_index) return afterDescriptor(site);
                    occurrence += 1;
                }
            }
            @compileError("Program.protocol.afterSite could not find requested after site");
        }

        pub fn siteByIndex(comptime index: usize) type {
            inline for (operation_sites) |site| {
                if (site.index == index) return operationDescriptor(site);
            }
            @compileError("Program.protocol.siteByIndex could not find requested operation site");
        }

        pub fn afterSiteByIndex(comptime index: usize) type {
            inline for (after_sites) |site| {
                if (site.index == index) return afterDescriptor(site);
            }
            @compileError("Program.protocol.afterSiteByIndex could not find requested after site");
        }

        fn validateProtocolOwner(comptime Site: type) void {
            if (!hasDeclSafe(Site, "Owner")) @compileError("Program.protocol coverage listed non-protocol site descriptor");
            if (!hasDeclSafe(Site, "owner_label") or
                !std.mem.eql(u8, Site.owner_label, program_label) or
                !hasDeclSafe(Site, "owner_plan_hash") or
                Site.owner_plan_hash != plan_hash or
                !hasDeclSafe(Site, "OwnerHandlers") or
                Site.OwnerHandlers != HandlersType or
                Site.Owner != ProtocolOwner)
            {
                @compileError("Program.protocol coverage descriptor belongs to another program");
            }
        }

        fn validateOperationSite(comptime Site: type) void {
            validateProtocolOwner(Site);
            if (!hasDeclSafe(Site, "kind") or Site.kind != .operation) @compileError("Program.protocol coverage listed non-operation site");
        }

        fn validateAfterSite(comptime Site: type) void {
            validateProtocolOwner(Site);
            if (!hasDeclSafe(Site, "kind") or Site.kind != .after) @compileError("Program.protocol coverage listed non-after site");
        }

        pub fn assertOperationSitesCovered(comptime Sites: anytype) void {
            var covered: [operation_sites.len]bool = [_]bool{false} ** operation_sites.len;
            inline for (Sites) |Site| {
                comptime validateOperationSite(Site);
                if (Site.index >= operation_sites.len or operation_sites[Site.index].fingerprint != Site.fingerprint) {
                    @compileError("Program.protocol coverage descriptor belongs to another program");
                }
                if (covered[Site.index]) @compileError("Program.protocol coverage listed duplicate operation site");
                covered[Site.index] = true;
            }
            inline for (covered) |is_covered| {
                if (!is_covered) @compileError("Program.protocol coverage omitted reachable operation site");
            }
        }

        pub fn assertAfterSitesCovered(comptime Sites: anytype) void {
            var covered: [after_sites.len]bool = [_]bool{false} ** after_sites.len;
            inline for (Sites) |Site| {
                comptime validateAfterSite(Site);
                if (Site.index >= after_sites.len or after_sites[Site.index].fingerprint != Site.fingerprint) {
                    @compileError("Program.protocol coverage descriptor belongs to another program");
                }
                if (covered[Site.index]) @compileError("Program.protocol coverage listed duplicate after site");
                covered[Site.index] = true;
            }
            inline for (covered) |is_covered| {
                if (!is_covered) @compileError("Program.protocol coverage omitted reachable after site");
            }
        }

        pub fn assertAllSitesCovered(comptime Sites: anytype) void {
            var operation_covered: [operation_sites.len]bool = [_]bool{false} ** operation_sites.len;
            var after_covered: [after_sites.len]bool = [_]bool{false} ** after_sites.len;
            inline for (Sites) |Site| {
                comptime validateProtocolOwner(Site);
                switch (Site.kind) {
                    .operation => {
                        if (Site.index >= operation_sites.len or operation_sites[Site.index].fingerprint != Site.fingerprint) {
                            @compileError("Program.protocol coverage descriptor belongs to another program");
                        }
                        if (operation_covered[Site.index]) @compileError("Program.protocol coverage listed duplicate operation site");
                        operation_covered[Site.index] = true;
                    },
                    .after => {
                        if (Site.index >= after_sites.len or after_sites[Site.index].fingerprint != Site.fingerprint) {
                            @compileError("Program.protocol coverage descriptor belongs to another program");
                        }
                        if (after_covered[Site.index]) @compileError("Program.protocol coverage listed duplicate after site");
                        after_covered[Site.index] = true;
                    },
                    else => @compileError("Program.protocol coverage listed non-protocol site descriptor"),
                }
            }
            inline for (operation_covered) |is_covered| {
                if (!is_covered) @compileError("Program.protocol coverage omitted reachable operation site");
            }
            inline for (after_covered) |is_covered| {
                if (!is_covered) @compileError("Program.protocol coverage omitted reachable after site");
            }
        }

        pub fn assertAllSitesCoveredBy(comptime InterpreterType: type) void {
            if (!hasDeclSafe(InterpreterType, "InterpreterToken") or
                InterpreterType.InterpreterToken != InterpreterToken or
                !hasDeclSafe(InterpreterType, "assertCoversAll"))
            {
                @compileError("Program.protocol expected a Program.Interpreter type");
            }
            InterpreterType.assertCoversAll();
        }
    };
}
// zlinter-enable require_doc_comment

fn ProgramOutputsType(comptime Body: type) type {
    if (comptime hasDeclSafe(Body, "Outputs")) return Body.Outputs;
    return void;
}

fn collectBodyOutputs(
    comptime Body: type,
    comptime Outputs: type,
    allocator: std.mem.Allocator,
    handlers: anytype,
) anyerror!Outputs {
    if (comptime hasDeclSafe(Body, "collectOutputs")) {
        return try Body.collectOutputs(allocator, handlers);
    }
    if (Outputs != void) @compileError("Body.Outputs requires Body.collectOutputs");
    return {};
}

const DeinitResultMode = enum {
    none,
    value_and_outputs,
    value_only,
};

fn bodyDeinitResultMode(comptime Body: type, comptime Value: type, comptime Outputs: type) DeinitResultMode {
    if (comptime !hasDeclSafe(Body, "deinitResult")) return .none;
    const DeinitFn = @TypeOf(Body.deinitResult);
    if (DeinitFn == fn (std.mem.Allocator, Value) void) return .value_only;
    if (DeinitFn == fn (std.mem.Allocator, Value, Outputs) void) {
        if (Outputs != void) {
            @compileError("Body.deinitResult with Body.Outputs must have type fn (std.mem.Allocator, value) void; release outputs separately with Body.deinitOutputs");
        }
        return .value_and_outputs;
    }
    @compileError("Body.deinitResult must have type fn (std.mem.Allocator, value) void");
}

fn DeinitBodyResultArgs(comptime Value: type, comptime Outputs: type) type {
    return struct {
        allocator: std.mem.Allocator,
        value: Value,
        outputs: ?Outputs,
    };
}

fn deinitBodyResult(
    comptime Body: type,
    comptime Value: type,
    comptime Outputs: type,
    args: DeinitBodyResultArgs(Value, Outputs),
) void {
    switch (comptime bodyDeinitResultMode(Body, Value, Outputs)) {
        .none => {},
        .value_only => Body.deinitResult(args.allocator, args.value),
        .value_and_outputs => Body.deinitResult(args.allocator, args.value, args.outputs orelse {}),
    }
}

fn cloneBodyOwnedStringList(comptime T: type, allocator: std.mem.Allocator, value: T) std.mem.Allocator.Error!T {
    var owned = try allocator.alloc([]const u8, value.len);
    errdefer allocator.free(owned);
    var cloned_len: usize = 0;
    errdefer for (owned[0..cloned_len]) |item| allocator.free(item);
    for (value, 0..) |item, index| {
        owned[index] = try allocator.dupe(u8, item);
        cloned_len += 1;
    }
    return owned;
}

fn deinitBodyOwnedStringList(allocator: std.mem.Allocator, value: anytype) void {
    for (value) |item| allocator.free(item);
    allocator.free(value);
}

fn cloneBodyOwnedResultValue(allocator: std.mem.Allocator, value: anytype) std.mem.Allocator.Error!@TypeOf(value) {
    const Value = @TypeOf(value);
    if (Value == []const u8) return try allocator.dupe(u8, value);
    if (Value == []const []const u8 or Value == [][]const u8) return try cloneBodyOwnedStringList(Value, allocator, value);

    return switch (@typeInfo(Value)) {
        .void, .bool, .int, .@"enum" => value,
        .optional => blk: {
            if (value) |payload| break :blk try cloneBodyOwnedResultValue(allocator, payload);
            break :blk null;
        },
        .@"struct" => |struct_info| blk: {
            var cloned: Value = undefined;
            var initialized_fields: usize = 0;
            errdefer inline for (struct_info.fields, 0..) |field, field_index| {
                if (field_index < initialized_fields) {
                    deinitBodyOwnedResultValue(allocator, @field(cloned, field.name));
                }
            };
            inline for (struct_info.fields) |field| {
                @field(cloned, field.name) = try cloneBodyOwnedResultValue(allocator, @field(value, field.name));
                initialized_fields += 1;
            }
            break :blk cloned;
        },
        .@"union" => |union_info| blk: {
            const Tag = union_info.tag_type orelse @compileError("Program.Session result cleanup requires tagged union values");
            const active_tag = std.meta.activeTag(value);
            inline for (union_info.fields) |field| {
                if (active_tag == @field(Tag, field.name)) {
                    if (field.type == void) break :blk @unionInit(Value, field.name, {});
                    break :blk @unionInit(Value, field.name, try cloneBodyOwnedResultValue(allocator, @field(value, field.name)));
                }
            }
            unreachable;
        },
        else => @compileError("unsupported Program.Session result cleanup value type: " ++ @typeName(Value)),
    };
}

fn deinitBodyOwnedResultValue(allocator: std.mem.Allocator, value: anytype) void {
    const Value = @TypeOf(value);
    if (Value == []const u8) {
        allocator.free(value);
        return;
    }
    if (Value == []const []const u8 or Value == [][]const u8) {
        deinitBodyOwnedStringList(allocator, value);
        return;
    }

    switch (@typeInfo(Value)) {
        .void, .bool, .int, .@"enum" => {},
        .optional => if (value) |payload| deinitBodyOwnedResultValue(allocator, payload),
        .@"struct" => |struct_info| inline for (struct_info.fields) |field| {
            deinitBodyOwnedResultValue(allocator, @field(value, field.name));
        },
        .@"union" => |union_info| {
            const Tag = union_info.tag_type orelse return;
            const active_tag = std.meta.activeTag(value);
            inline for (union_info.fields) |field| {
                if (active_tag == @field(Tag, field.name)) {
                    if (field.type != void) deinitBodyOwnedResultValue(allocator, @field(value, field.name));
                    return;
                }
            }
        },
        else => {},
    }
}

fn typeMayBorrowExchangeStorage(comptime T: type) bool {
    if (T == []const u8 or T == []const []const u8 or T == [][]const u8) return true;
    return switch (@typeInfo(T)) {
        .optional => |optional| typeMayBorrowExchangeStorage(optional.child),
        .@"struct" => |info| {
            inline for (info.fields) |field| {
                if (typeMayBorrowExchangeStorage(field.type)) return true;
            }
            return false;
        },
        .@"union" => |info| {
            inline for (info.fields) |field| {
                if (typeMayBorrowExchangeStorage(field.type)) return true;
            }
            return false;
        },
        else => false,
    };
}

const TrackedAllocation = struct {
    memory: []u8,
    alignment: std.mem.Alignment,
};

const TrackedResultAllocator = struct {
    child: std.mem.Allocator,
    allocations: std.ArrayList(TrackedAllocation) = .empty,

    fn init(child: std.mem.Allocator) @This() {
        return .{ .child = child };
    }

    fn allocator(self: *@This()) std.mem.Allocator {
        return .{
            .ptr = self,
            .vtable = &.{
                .alloc = alloc,
                .resize = resize,
                .remap = remap,
                .free = free,
            },
        };
    }

    fn deinit(self: *@This()) void {
        for (self.allocations.items) |allocation| {
            self.child.rawFree(allocation.memory, allocation.alignment, @returnAddress());
        }
        self.allocations.deinit(self.child);
        self.* = .{ .child = self.child };
    }

    fn findAllocation(self: *@This(), memory: []u8, alignment: std.mem.Alignment) ?usize {
        for (self.allocations.items, 0..) |allocation, index| {
            if (allocation.memory.ptr == memory.ptr and allocation.memory.len == memory.len and allocation.alignment == alignment) {
                return index;
            }
        }
        return null;
    }

    fn alloc(ctx: *anyopaque, len: usize, alignment: std.mem.Alignment, ret_addr: usize) ?[*]u8 {
        const self: *@This() = @ptrCast(@alignCast(ctx));
        const ptr = self.child.rawAlloc(len, alignment, ret_addr) orelse return null;
        self.allocations.append(self.child, .{
            .memory = ptr[0..len],
            .alignment = alignment,
        }) catch {
            self.child.rawFree(ptr[0..len], alignment, ret_addr);
            return null;
        };
        return ptr;
    }

    fn resize(ctx: *anyopaque, memory: []u8, alignment: std.mem.Alignment, new_len: usize, ret_addr: usize) bool {
        const self: *@This() = @ptrCast(@alignCast(ctx));
        const allocation_index = self.findAllocation(memory, alignment);
        const resized = self.child.rawResize(memory, alignment, new_len, ret_addr);
        if (resized) {
            if (allocation_index) |index| self.allocations.items[index].memory.len = new_len;
        }
        return resized;
    }

    fn remap(ctx: *anyopaque, memory: []u8, alignment: std.mem.Alignment, new_len: usize, ret_addr: usize) ?[*]u8 {
        const self: *@This() = @ptrCast(@alignCast(ctx));
        const allocation_index = self.findAllocation(memory, alignment);
        const ptr = self.child.rawRemap(memory, alignment, new_len, ret_addr) orelse return null;
        if (allocation_index) |index| {
            self.allocations.items[index].memory = ptr[0..new_len];
        }
        return ptr;
    }

    fn free(ctx: *anyopaque, memory: []u8, alignment: std.mem.Alignment, ret_addr: usize) void {
        const self: *@This() = @ptrCast(@alignCast(ctx));
        if (self.findAllocation(memory, alignment)) |index| {
            _ = self.allocations.swapRemove(index);
        }
        self.child.rawFree(memory, alignment, ret_addr);
    }
};

const TrackedBodyResultStorage = struct {
    tracker: TrackedResultAllocator,

    fn deinit(self: *@This()) void {
        self.tracker.deinit();
    }
};

fn TrackedBodyResultClone(comptime Value: type) type {
    return struct {
        value: Value,
        storage: ResultOwnedStorage,
        cleanup_allocator: std.mem.Allocator,
    };
}

fn cloneBodyOwnedResultWithTrackedStorage(
    comptime Value: type,
    allocator: std.mem.Allocator,
    value: Value,
) std.mem.Allocator.Error!TrackedBodyResultClone(Value) {
    const boxed = try allocator.create(TrackedBodyResultStorage);
    errdefer allocator.destroy(boxed);
    boxed.* = .{ .tracker = TrackedResultAllocator.init(allocator) };
    errdefer boxed.tracker.deinit();

    const cleanup_allocator = boxed.tracker.allocator();
    const cloned = try cloneBodyOwnedResultValue(cleanup_allocator, value);
    return .{
        .value = cloned,
        .storage = .{
            .allocator = allocator,
            .ptr = boxed,
            .destroy = ResultStorageDestroyer(TrackedBodyResultStorage).destroy,
        },
        .cleanup_allocator = cleanup_allocator,
    };
}

const ResultOwnedStorage = struct {
    allocator: std.mem.Allocator,
    ptr: *anyopaque,
    destroy: *const fn (std.mem.Allocator, *anyopaque) void,

    fn deinit(self: *@This()) void {
        self.destroy(self.allocator, self.ptr);
    }
};

fn ResultStorageDestroyer(comptime Storage: type) type {
    return struct {
        fn destroy(allocator: std.mem.Allocator, ptr: *anyopaque) void {
            const storage: *Storage = @ptrCast(@alignCast(ptr));
            storage.deinit();
            allocator.destroy(storage);
        }
    };
}

fn errorValueInSet(comptime ErrorSet: type, err: anyerror) bool {
    return switch (@typeInfo(ErrorSet)) {
        .error_set => |errors| blk: {
            if (errors) |decls| {
                inline for (decls) |decl| {
                    if (err == @field(ErrorSet, decl.name)) break :blk true;
                }
                break :blk false;
            }
            break :blk true;
        },
        else => @compileError("Program.Error must be an error set"),
    };
}

fn mapProgramRunError(comptime ErrorSet: type, err: anyerror) ErrorSet {
    if (errorValueInSet(ErrorSet, err)) return @errorCast(err);
    return error.ProgramContractViolation;
}

/// Declare one reusable explicit local effect program.
pub fn program(
    comptime label: []const u8,
    comptime HandlersType: type,
    comptime Body: type,
) type {
    if (label.len == 0) @compileError("ability.program label must be non-empty");
    const body_compiled_plan = ProgramPlanForBody(Body);
    const body_value_schema_types = BodyValueSchemaTypes(Body).values;
    const body_nested_with_targets = BodyNestedWithTargets(Body).values;
    const body_site_metadata = BodySiteMetadata(Body).values;
    const body_compiled_plan_hash = body_compiled_plan.hash();
    const InterpreterAuthenticityToken = opaque {};
    const handler_value_storage_size = maxProgramValueStorageSize(body_value_schema_types);
    const handler_value_storage_align = maxProgramValueStorageAlign(body_value_schema_types);
    const Value = ProgramValueTypeForRef(body_compiled_plan, body_value_schema_types, lowering_api.executableResultRefForPlan(body_compiled_plan));
    const ProgramOutputs = ProgramOutputsType(Body);

    return struct {
        const InterpreterToken = InterpreterAuthenticityToken;

        /// Runtime-owned executable plan for this public program.
        pub const compiled_plan = body_compiled_plan;
        /// Exact Zig type tuple backing compiled_plan product and sum value schemas.
        pub const value_schema_types = body_value_schema_types;
        /// Handler/context type accepted by Program.run and Program.Session.start.
        pub const Handlers = HandlersType;
        /// Read-only projection of the compiled ProgramPlan contract.
        pub const contract = ProgramContractFor(label, body_compiled_plan, Value, ProgramOutputs, body_value_schema_types, body_nested_with_targets, body_site_metadata);
        /// Typed defunctionalized protocol descriptors derived from Program.Session static sites.
        pub const protocol = ProgramProtocolFor(label, body_compiled_plan, body_value_schema_types, body_nested_with_targets, HandlersType, Body, body_site_metadata, InterpreterAuthenticityToken);
        /// Public execution error for this program.
        pub const Error = ProgramErrorSet(Body);
        /// Canonical evidence, fingerprint, validation, and projection substrate.
        pub const Evidence = program_evidence;
        /// Separate fingerprint domain for protocol reinterpretation metadata.
        pub const reinterpret_fingerprint_version: u32 = Evidence.domains.reinterpretation.fingerprint_version;
        /// Separate fingerprint domain for residual ProgramPlan transformation metadata.
        pub const residual_fingerprint_version: u32 = Evidence.domains.residualization.fingerprint_version;
        /// Separate fingerprint domain for proof-carrying effect pipeline metadata.
        pub const pipeline_fingerprint_version: u32 = Evidence.domains.pipeline.fingerprint_version;
        /// Stable format version for Program.Session.Capsule durable images.
        pub const capsule_image_format_version: u32 = Evidence.domains.capsule_image.format_version.?;
        /// Stable fingerprint version for Program.Session.Capsule durable images.
        pub const capsule_image_fingerprint_version: u32 = Evidence.domains.capsule_image.fingerprint_version;
        /// Stable format version for Program.Session interaction journals.
        /// Version 6 preserves v5 fields and adds provider-program event kinds.
        pub const journal_format_version: u32 = Evidence.domains.journal.format_version.?;
        /// Stable fingerprint version for Program.Session interaction journals.
        pub const journal_fingerprint_version: u32 = Evidence.domains.journal.fingerprint_version;
        /// Stable format version for Program.Exchange manifest images.
        pub const exchange_manifest_format_version: u32 = Evidence.domains.exchange_manifest.format_version.?;
        /// Stable fingerprint version for Program.Exchange manifest images.
        pub const exchange_manifest_fingerprint_version: u32 = Evidence.domains.exchange_manifest.fingerprint_version;
        /// Stable format version for Program.Exchange request envelopes.
        /// Version 3 preserves v2 fields and adds optional linear-session metadata.
        pub const exchange_request_format_version: u32 = Evidence.domains.exchange_request_envelope.format_version.?;
        /// Stable fingerprint version for Program.Exchange request envelopes.
        pub const exchange_request_fingerprint_version: u32 = Evidence.domains.exchange_request_envelope.fingerprint_version;
        /// Stable format version for Program.Exchange response envelopes.
        pub const exchange_response_format_version: u32 = Evidence.domains.exchange_response_envelope.format_version.?;
        /// Stable fingerprint version for Program.Exchange response envelopes.
        pub const exchange_response_fingerprint_version: u32 = Evidence.domains.exchange_response_envelope.fingerprint_version;
        /// Stable format version for Program.Exchange provider manifest images.
        pub const exchange_provider_format_version: u32 = Evidence.domains.provider_manifest.format_version.?;
        /// Stable fingerprint version for Program.Exchange provider manifest images.
        pub const exchange_provider_fingerprint_version: u32 = Evidence.domains.provider_manifest.fingerprint_version;
        /// Stable fingerprint version for Program.Exchange provider identities.
        pub const exchange_provider_identity_fingerprint_version: u32 = Evidence.domains.provider_identity.fingerprint_version;
        /// Stable format version for Program.Exchange provider offer images.
        pub const exchange_provider_offer_format_version: u32 = Evidence.domains.provider_offer.format_version.?;
        /// Stable format version for Program.Exchange program-backed provider offer images.
        pub const exchange_provider_program_offer_format_version: u32 = 2;
        /// Stable fingerprint version for Program.Exchange provider offer images.
        pub const exchange_provider_offer_fingerprint_version: u32 = Evidence.domains.provider_offer.fingerprint_version;
        /// Stable fingerprint version for Program.Exchange provider harness declarations.
        pub const exchange_provider_harness_fingerprint_version: u32 = Evidence.domains.provider_harness.fingerprint_version;
        /// Stable fingerprint version for provider-program execution metadata.
        pub const exchange_provider_program_execution_fingerprint_version: u32 = Evidence.domains.provider_program_execution.fingerprint_version;
        /// Stable fingerprint version for provider-program mapping metadata.
        pub const exchange_provider_program_mapping_fingerprint_version: u32 = Evidence.domains.provider_program_mapping.fingerprint_version;
        /// Stable fingerprint version for provider-program nested request linkage metadata.
        pub const exchange_provider_program_nested_request_fingerprint_version: u32 = Evidence.domains.provider_program_nested_request.fingerprint_version;
        /// Stable fingerprint version for Program.Exchange morphism offer witnesses.
        pub const exchange_morphism_offer_fingerprint_version: u32 = Evidence.domains.morphism_offer.fingerprint_version;
        /// Stable format version for Program.Exchange capability grant images.
        pub const exchange_capability_format_version: u32 = Evidence.domains.capability.format_version.?;
        /// Stable fingerprint version for Program.Exchange capability grant images.
        pub const exchange_capability_fingerprint_version: u32 = Evidence.domains.capability.fingerprint_version;
        /// Stable fingerprint version for Program.Exchange authorization witnesses.
        pub const exchange_authorization_fingerprint_version: u32 = Evidence.domains.authorization.fingerprint_version;
        /// Stable fingerprint version for Program.Exchange route witnesses.
        pub const exchange_route_fingerprint_version: u32 = Evidence.domains.route.fingerprint_version;
        /// Stable format version for Program.Exchange effect-session specs.
        pub const exchange_effect_session_format_version: u32 = Evidence.domains.effect_session_spec.format_version.?;
        /// Stable fingerprint version for Program.Exchange effect-session specs.
        pub const exchange_effect_session_fingerprint_version: u32 = Evidence.domains.effect_session_spec.fingerprint_version;
        /// Stable format version for Program.Exchange capability instances.
        pub const exchange_capability_instance_format_version: u32 = Evidence.domains.capability_instance.format_version.?;
        /// Stable fingerprint version for Program.Exchange capability instances.
        pub const exchange_capability_instance_fingerprint_version: u32 = Evidence.domains.capability_instance.fingerprint_version;
        /// Stable format version for Program.Exchange obligations.
        pub const exchange_obligation_format_version: u32 = Evidence.domains.obligation.format_version.?;
        /// Stable fingerprint version for Program.Exchange obligations.
        pub const exchange_obligation_fingerprint_version: u32 = Evidence.domains.obligation.fingerprint_version;
        /// Stable fingerprint version for Program.Exchange obligation transitions.
        pub const exchange_obligation_transition_fingerprint_version: u32 = Evidence.domains.obligation_transition.fingerprint_version;
        /// Stable fingerprint version for Program.Exchange authorization results.
        pub const exchange_authorization_result_fingerprint_version: u32 = Evidence.domains.authorization_result.fingerprint_version;
        /// Stable format version for Program.Exchange Effect Treaties.
        pub const exchange_treaty_format_version: u32 = Evidence.domains.treaty.format_version.?;
        /// Stable fingerprint version for Program.Exchange Effect Treaties.
        /// Version 2 preserves v1 fields and adds provider usage and provider response refs.
        pub const exchange_treaty_fingerprint_version: u32 = Evidence.domains.treaty.fingerprint_version;
        /// Stable fingerprint version for Program.Exchange treaty certificates.
        /// Version 3 preserves v2 fields and adds the request envelope format witness.
        pub const exchange_treaty_certificate_fingerprint_version: u32 = Evidence.domains.treaty_certificate.fingerprint_version;
        /// Stable fingerprint version for Program.Exchange treaty-bound response authorization.
        /// Version 4 preserves v3 fields and adds the request envelope format witness.
        pub const exchange_treaty_authorization_fingerprint_version: u32 = Evidence.domains.treaty_authorization.fingerprint_version;

        /// Public result value plus outputs. Cleanup is uniform even for void outputs.
        pub const Result = struct {
            allocator: std.mem.Allocator,
            value: Value,
            outputs: ProgramOutputs,
            _session_storage: ?ResultOwnedStorage = null,
            _result_cleanup_allocator: ?std.mem.Allocator = null,

            /// Release owned result resources declared by the program body.
            pub fn deinit(self: *@This()) void {
                deinitBodyResult(Body, Value, ProgramOutputs, .{
                    .allocator = self._result_cleanup_allocator orelse self.allocator,
                    .value = self.value,
                    .outputs = self.outputs,
                });
                if (comptime hasDeclSafe(Body, "deinitOutputs")) {
                    const DeinitOutputsFn = @TypeOf(Body.deinitOutputs);
                    if (DeinitOutputsFn != fn (std.mem.Allocator, ProgramOutputs) void) {
                        @compileError("Body.deinitOutputs must have type fn (std.mem.Allocator, outputs) void");
                    }
                    Body.deinitOutputs(self.allocator, self.outputs);
                }
                if (self._session_storage) |*storage| storage.deinit();
                self._session_storage = null;
                self._result_cleanup_allocator = null;
            }
        };

        fn finishResultWithStorage(
            allocator: std.mem.Allocator,
            handlers: anytype,
            value: Value,
            session_storage: ?ResultOwnedStorage,
            result_cleanup_allocator: ?std.mem.Allocator,
        ) Error!Result {
            var storage = session_storage;
            const outputs = collectBodyOutputs(Body, ProgramOutputs, allocator, handlers) catch |err| {
                deinitBodyResult(Body, Value, ProgramOutputs, .{
                    .allocator = result_cleanup_allocator orelse allocator,
                    .value = value,
                    .outputs = null,
                });
                if (storage) |*owned| owned.deinit();
                return mapProgramRunError(Error, err);
            };
            return .{
                .allocator = allocator,
                .value = value,
                .outputs = outputs,
                ._session_storage = storage,
                ._result_cleanup_allocator = result_cleanup_allocator,
            };
        }

        fn finishResult(allocator: std.mem.Allocator, handlers: anytype, value: Value) Error!Result {
            return finishResultWithStorage(allocator, handlers, value, null, null);
        }

        /// Execute the compiled ProgramPlan against one caller-owned runtime.
        /// Bodies may provide scalar ProgramValue args, typed tuple args, schema types,
        /// nested-with targets, output collection, and explicit deinit hooks.
        pub fn run(runtime: *lowered_machine.Runtime, handlers: HandlersType) Error!Result {
            var mutable_handlers = handlers;
            lowered_machine.beginExecution(runtime) catch |err| return mapProgramRunError(Error, err);
            defer lowered_machine.endExecution(runtime);
            const args = if (comptime hasDeclSafe(Body, "encodeArgs"))
                Body.encodeArgs(mutable_handlers)
            else
                @as([]const lowered_machine.ProgramValue, &.{});
            const raw = if (comptime @typeInfo(HandlersType) == .pointer)
                lowering_api.runExecutablePlanWithTypedArgsForErrorSetAndNestedTargetsInRuntimeExecution(BodyErrorSet(Body), runtime, compiled_plan, body_value_schema_types, body_nested_with_targets, mutable_handlers, args) catch |err| return mapProgramRunError(Error, err)
            else
                lowering_api.runExecutablePlanWithTypedArgsForErrorSetAndNestedTargetsInRuntimeExecution(BodyErrorSet(Body), runtime, compiled_plan, body_value_schema_types, body_nested_with_targets, &mutable_handlers, args) catch |err| return mapProgramRunError(Error, err);
            const allocator = lowered_machine.runtimeAllocator(runtime);
            if (comptime @typeInfo(HandlersType) == .pointer) {
                return finishResult(allocator, mutable_handlers, raw.value);
            }
            return finishResult(allocator, &mutable_handlers, raw.value);
        }

        /// Execute the compiled ProgramPlan with explicit caller-provided entry args.
        pub fn runWithArgs(runtime: *lowered_machine.Runtime, handlers: HandlersType, args: anytype) Error!Result {
            var mutable_handlers = handlers;
            lowered_machine.beginExecution(runtime) catch |err| return mapProgramRunError(Error, err);
            defer lowered_machine.endExecution(runtime);
            const raw = if (comptime @typeInfo(HandlersType) == .pointer)
                lowering_api.runExecutablePlanWithTypedArgsForErrorSetAndNestedTargetsInRuntimeExecution(BodyErrorSet(Body), runtime, compiled_plan, body_value_schema_types, body_nested_with_targets, mutable_handlers, args) catch |err| return mapProgramRunError(Error, err)
            else
                lowering_api.runExecutablePlanWithTypedArgsForErrorSetAndNestedTargetsInRuntimeExecution(BodyErrorSet(Body), runtime, compiled_plan, body_value_schema_types, body_nested_with_targets, &mutable_handlers, args) catch |err| return mapProgramRunError(Error, err);
            const allocator = lowered_machine.runtimeAllocator(runtime);
            if (comptime @typeInfo(HandlersType) == .pointer) {
                return finishResult(allocator, mutable_handlers, raw.value);
            }
            return finishResult(allocator, &mutable_handlers, raw.value);
        }

        /// Host-driven session execution for plans with defunctionalized operation and after-continuation requests.
        pub const Session = struct {
            const Core = lowering_api.ExecutableSessionForPlan(
                BodyErrorSet(Body),
                label,
                body_compiled_plan,
                body_value_schema_types,
                body_nested_with_targets,
                HandlersType,
                Body,
            );

            runtime: *lowered_machine.Runtime,
            handlers: HandlersType,
            core: Core,
            lifecycle: Lifecycle = .ready,
            live_registered: bool = true,
            exchange_response_storage: ?*TrackedBodyResultStorage = null,

            const ExchangeSessionResultStorage = struct {
                allocator: std.mem.Allocator,
                core: ?ResultOwnedStorage,
                exchange: *TrackedBodyResultStorage,

                fn deinit(self: *@This()) void {
                    if (self.core) |*storage| storage.deinit();
                    self.exchange.deinit();
                    self.allocator.destroy(self.exchange);
                }
            };

            fn deinitExchangeResponseStorage(allocator: std.mem.Allocator, storage: *?*TrackedBodyResultStorage) void {
                if (storage.*) |owned| {
                    owned.deinit();
                    allocator.destroy(owned);
                    storage.* = null;
                }
            }

            fn takeExchangeResponseStorage(self: *Session) ?*TrackedBodyResultStorage {
                const storage = self.exchange_response_storage;
                self.exchange_response_storage = null;
                return storage;
            }

            fn attachExchangeResponseStorageToResult(
                allocator: std.mem.Allocator,
                result: *Result,
                storage: *?*TrackedBodyResultStorage,
            ) Error!void {
                const exchange = storage.* orelse return;
                const boxed = allocator.create(ExchangeSessionResultStorage) catch |err| return mapProgramRunError(Error, err);
                boxed.* = .{
                    .allocator = allocator,
                    .core = result._session_storage,
                    .exchange = exchange,
                };
                armExchangeResponseCleanupAllocator(result, exchange);
                result._session_storage = .{
                    .allocator = allocator,
                    .ptr = boxed,
                    .destroy = ResultStorageDestroyer(ExchangeSessionResultStorage).destroy,
                };
                storage.* = null;
            }

            fn armExchangeResponseCleanupAllocator(result: *Result, exchange: *TrackedBodyResultStorage) void {
                if (comptime bodyDeinitResultMode(Body, Value, ProgramOutputs) != .none) {
                    if (result._result_cleanup_allocator == null) {
                        result._result_cleanup_allocator = exchange.tracker.allocator();
                    }
                }
            }

            fn ensureExchangeResponseStorage(self: *Session, allocator: std.mem.Allocator) Error!*TrackedBodyResultStorage {
                if (self.exchange_response_storage) |storage| return storage;
                const storage = allocator.create(TrackedBodyResultStorage) catch |err| return mapProgramRunError(Error, err);
                storage.* = .{ .tracker = TrackedResultAllocator.init(allocator) };
                self.exchange_response_storage = storage;
                return storage;
            }

            fn storeExchangeResponseValue(self: *Session, value: anytype) Error!@TypeOf(value) {
                const ValueType = @TypeOf(value);
                if (comptime !typeMayBorrowExchangeStorage(ValueType)) return value;

                const allocator = lowered_machine.runtimeAllocator(self.runtime);
                const storage = try self.ensureExchangeResponseStorage(allocator);
                const cleanup_allocator = storage.tracker.allocator();
                return cloneBodyOwnedResultValue(cleanup_allocator, value) catch |err| return mapProgramRunError(Error, err);
            }

            fn boxResultStorage(
                allocator: std.mem.Allocator,
                session_storage: ?Core.ResultStorage,
            ) Error!?ResultOwnedStorage {
                var storage = session_storage orelse return null;
                errdefer storage.deinit();
                const boxed = allocator.create(Core.ResultStorage) catch |err| return mapProgramRunError(Error, err);
                boxed.* = storage;
                return .{
                    .allocator = allocator,
                    .ptr = boxed,
                    .destroy = ResultStorageDestroyer(Core.ResultStorage).destroy,
                };
            }

            fn finishSessionResult(
                allocator: std.mem.Allocator,
                handlers: anytype,
                raw: *Core.RawResult,
                result_cleanup_allocator: ?std.mem.Allocator,
            ) Error!Result {
                const result_cleanup = comptime bodyDeinitResultMode(Body, Value, ProgramOutputs);
                if (result_cleanup != .none) {
                    var storage = raw.takeStorage();
                    defer if (storage) |*owned| owned.deinit();
                    if (storage != null) {
                        const owned = cloneBodyOwnedResultWithTrackedStorage(Value, allocator, raw.value) catch |err| return mapProgramRunError(Error, err);
                        return finishResultWithStorage(allocator, handlers, owned.value, owned.storage, owned.cleanup_allocator);
                    }
                    return finishResultWithStorage(allocator, handlers, raw.value, null, result_cleanup_allocator);
                }
                const storage = try boxResultStorage(allocator, raw.takeStorage());
                return finishResultWithStorage(allocator, handlers, raw.value, storage, null);
            }

            const Lifecycle = enum {
                deinitialized,
                done,
                parked_on_after,
                parked_on_request,
                ready,
                running,
            };

            /// Defunctionalized effect operation request yielded by `next`.
            pub const Request = Core.Request;
            /// Defunctionalized after-continuation request yielded by `next`.
            pub const AfterRequest = Core.AfterRequest;
            /// Read-only request/response trace metadata and fingerprint views.
            pub const Trace = Core.Trace;
            /// Read-only continuation capsule metadata.
            pub const CapsuleMetadata = Core.CapsuleMetadata;
            /// Parked continuation kind captured in a capsule.
            pub const ParkedKind = Core.ParkedKind;
            /// Capsule schema version for in-process parked continuation snapshots.
            pub const capsule_version = Core.capsule_version;
            /// Continuation fingerprint version for capsule fingerprints.
            pub const continuation_fingerprint_version = Core.continuation_fingerprint_version;
            /// Durable capsule image format version.
            pub const capsule_image_format_version = Core.capsule_image_format_version;
            /// Durable capsule image fingerprint version.
            pub const capsule_image_fingerprint_version = Core.capsule_image_fingerprint_version;
            const session_journal_format_version: u32 = 6;
            const session_journal_fingerprint_version = Core.journal_fingerprint_version;
            /// Durable interaction journal format version.
            pub const journal_format_version = session_journal_format_version;
            /// Durable interaction journal fingerprint version.
            pub const journal_fingerprint_version = session_journal_fingerprint_version;
            /// Current parked request view without advancing the interpreter.
            pub const Current = Core.Current;
            /// First-class in-process snapshot of a parked continuation.
            pub const Capsule = struct {
                _core: Core.Capsule,

                /// Owned deterministic byte image of a reusable parked continuation capsule.
                pub const Image = struct {
                    allocator: std.mem.Allocator,
                    bytes: []u8,
                    image_fingerprint: u64,
                    image_version: u32 = Core.capsule_image_format_version,
                    capsule_version: u32 = Session.capsule_version,
                    continuation_fingerprint_version: u32 = Session.continuation_fingerprint_version,
                    trace_fingerprint_version: u32 = Trace.fingerprint_version,
                    program_label: []const u8 = label,
                    plan_label: []const u8 = body_compiled_plan.label,
                    plan_hash: u64 = body_compiled_plan_hash,
                    capsule_fingerprint: u64,
                    continuation_fingerprint: u64,
                    parked_kind: ParkedKind,
                    current_request_fingerprint: u64,
                    semantic_label: ?[]const u8 = null,
                    metadata: CapsuleMetadata,

                    /// Encode an owned image from an in-process capsule.
                    pub fn fromCapsule(allocator: std.mem.Allocator, capsule: *const Capsule) Error!@This() {
                        const bytes = capsule._core.encode(allocator) catch |err| return mapProgramRunError(Error, err);
                        errdefer allocator.free(bytes);
                        const capsule_metadata = capsule.metadata();
                        return .{
                            .allocator = allocator,
                            .bytes = bytes,
                            .image_fingerprint = capsuleImageFingerprint(bytes),
                            .capsule_fingerprint = capsule.fingerprint(),
                            .continuation_fingerprint = capsule_metadata.continuation_fingerprint,
                            .parked_kind = capsule_metadata.parked_kind,
                            .current_request_fingerprint = capsule_metadata.current_request_fingerprint,
                            .semantic_label = semanticLabelForCapsuleMetadata(capsule_metadata),
                            .metadata = capsule_metadata,
                        };
                    }

                    /// Release image-owned bytes.
                    pub fn deinit(self: *@This()) void {
                        self.allocator.free(self.bytes);
                        self.bytes = &.{};
                    }
                };

                /// Release capsule-owned continuation values.
                pub fn deinit(self: *@This()) void {
                    self._core.deinit();
                }

                /// Return read-only capsule metadata.
                pub fn metadata(self: *const @This()) CapsuleMetadata {
                    return self._core.metadata();
                }

                /// Return the deterministic continuation fingerprint.
                pub fn fingerprint(self: *const @This()) u64 {
                    return self._core.fingerprint();
                }

                /// Return an independent owned copy of this reusable capsule.
                pub fn clone(self: *const @This(), allocator: std.mem.Allocator) Error!@This() {
                    return .{
                        ._core = self._core.clone(allocator) catch |err| return mapProgramRunError(Error, err),
                    };
                }

                /// Encode this reusable capsule into deterministic owned bytes plus metadata.
                pub fn encode(self: *const @This(), allocator: std.mem.Allocator) Error!Image {
                    return Image.fromCapsule(allocator, self);
                }

                /// Decode deterministic capsule image bytes into an owned reusable capsule.
                pub fn decode(allocator: std.mem.Allocator, image_bytes: []const u8) Error!@This() {
                    return .{
                        ._core = Core.Capsule.decode(allocator, image_bytes) catch |err| return mapProgramRunError(Error, err),
                    };
                }
            };

            fn capsuleImageFingerprint(image_bytes: []const u8) u64 {
                var hasher = std.hash.Wyhash.init(0);
                hashBytes(&hasher, "ability.program.capsule.image");
                hashU32(&hasher, Core.capsule_image_fingerprint_version);
                hashBytes(&hasher, image_bytes);
                return hasher.final();
            }

            fn semanticLabelForCapsuleMetadata(metadata: CapsuleMetadata) ?[]const u8 {
                return switch (metadata.parked_kind) {
                    .operation => blk: {
                        const site_index = metadata.current_operation_site_index orelse break :blk null;
                        inline for (protocol.operation_site_metadata) |site| {
                            if (site.index == site_index) break :blk site.semantic_label;
                        }
                        break :blk null;
                    },
                    .after => blk: {
                        const site_index = metadata.current_after_site_index orelse break :blk null;
                        inline for (protocol.after_site_metadata) |site| {
                            if (site.index == site_index) break :blk site.semantic_label;
                        }
                        break :blk null;
                    },
                };
            }

            /// One session step: either a terminal result, yielded operation request, or yielded after continuation.
            pub const Step = union(enum) {
                after: AfterRequest,
                done: Result,
                request: Request,
            };

            /// Deterministic host-owned interaction transcript for request/response replay validation.
            pub const Journal = struct {
                allocator: std.mem.Allocator,
                entries: std.ArrayList(Entry) = .empty,

                /// Request-side trace entry recorded before a host response.
                pub const RequestTrace = union(enum) {
                    operation: Trace.OperationRequest,
                    after: Trace.AfterRequest,

                    /// Return the request fingerprint for operation or after entries.
                    pub fn fingerprint(self: @This()) u64 {
                        return switch (self) {
                            .operation => |trace| trace.fingerprint,
                            .after => |trace| trace.fingerprint,
                        };
                    }
                };

                /// One deterministic journal entry.
                pub const Entry = union(enum) {
                    request: RequestTrace,
                    response: ResponseEntry,
                    capsule_image: CapsuleImageEntry,
                    exchange_event: ExchangeEvent,
                    done: u64,
                };

                /// Response trace plus an optional replayable typed value image.
                pub const ResponseEntry = struct {
                    trace: Trace.Response,
                    value_image: ?[]u8 = null,
                };

                /// Owned capsule image entry copied into a journal.
                pub const CapsuleImageEntry = struct {
                    image_fingerprint: u64,
                    capsule_fingerprint: u64,
                    current_request_fingerprint: u64,
                    bytes: []u8,
                };

                /// Inspectable Effect Exchange capability/routing ledger entry.
                pub const ExchangeEvent = struct {
                    kind: Kind,
                    provider_fingerprint: ?u64 = null,
                    capability_fingerprint: ?u64 = null,
                    route_fingerprint: ?u64 = null,
                    authorization_fingerprint: ?u64 = null,
                    request_envelope_fingerprint: ?u64 = null,
                    response_envelope_fingerprint: ?u64 = null,
                    capability_instance_fingerprint: ?u64 = null,
                    obligation_fingerprint: ?u64 = null,
                    obligation_transition_fingerprint: ?u64 = null,
                    treaty_fingerprint: ?u64 = null,
                    treaty_certificate_fingerprint: ?u64 = null,
                    provider_offer_fingerprint: ?u64 = null,
                    morphism_offer_fingerprint: ?u64 = null,
                    branch_id: ?u64 = null,
                    previous_state_fingerprint: ?u64 = null,
                    next_state_fingerprint: ?u64 = null,
                    provider_program_execution_fingerprint: ?u64 = null,
                    provider_program_nested_request_fingerprint: ?u64 = null,
                    blocker_tag: ?[]const u8 = null,

                    /// Exchange ledger event kind.
                    pub const Kind = enum {
                        provider_manifest_recorded,
                        capability_granted,
                        capability_attenuated,
                        route_selected,
                        route_blocked,
                        response_authorized,
                        response_rejected,
                        effect_session_opened,
                        capability_instance_created,
                        capability_instance_split,
                        capability_instance_consumed,
                        obligation_opened,
                        obligation_consumed,
                        obligation_replayed,
                        obligation_canceled,
                        obligation_rejected,
                        branch_policy_checked,
                        branch_rejected,
                        provider_offer_recorded,
                        morphism_offer_recorded,
                        treaty_requested,
                        treaty_selected,
                        treaty_blocked,
                        treaty_certificate_recorded,
                        treaty_authorization_recorded,
                        treaty_response_rejected,
                        treaty_response_accepted,
                        treaty_obligation_opened,
                        treaty_capability_attenuated,
                        treaty_capability_instance_selected,
                        treaty_replay_policy_checked,
                        treaty_branch_policy_checked,
                        provider_manifest_derived,
                        provider_offer_derived,
                        provider_request_received,
                        provider_request_validated,
                        provider_request_rejected,
                        provider_handler_invoked,
                        provider_response_built,
                        provider_response_authorized,
                        provider_response_forwarded,
                        provider_pending,
                        provider_program_started,
                        provider_program_parked,
                        provider_program_nested_request,
                        provider_program_nested_response,
                        provider_program_resumed,
                        provider_program_completed,
                        provider_program_rejected,
                        provider_program_failed,
                    };
                };

                /// Append-only recorder used by interpreters and host code.
                pub const Recorder = struct {
                    journal: *Journal,

                    /// Record a request/response pair without a typed response value image.
                    pub fn record(self: *@This(), request_trace: anytype, response_trace: Trace.Response) Error!void {
                        const request = requestTraceFromAny(request_trace);
                        try validateJournalResponseForRequest(request, response_trace);
                        const start_len = self.journal.entries.items.len;
                        errdefer self.journal.truncateEntries(start_len);
                        try self.journal.appendRequest(request);
                        try self.journal.appendResponse(response_trace);
                    }

                    /// Record a request/response pair with a replayable typed response value image.
                    pub fn recordValue(self: *@This(), request_trace: anytype, response_trace: Trace.Response, value: anytype) Error!void {
                        const request = requestTraceFromAny(request_trace);
                        try validateJournalResponseForRequest(request, response_trace);
                        const start_len = self.journal.entries.items.len;
                        errdefer self.journal.truncateEntries(start_len);
                        try self.journal.appendRequest(request);
                        try self.journal.appendResponseValue(response_trace, value);
                    }
                };

                /// Cursor that validates fresh yielded requests against recorded journal entries.
                pub const Replayer = struct {
                    journal: *const Journal,
                    index: usize = 0,
                    string_lists: std.ArrayList([]const []const u8) = .empty,

                    /// Release replay-owned decoded slice tables.
                    pub fn deinit(self: *@This()) void {
                        for (self.string_lists.items) |items| self.journal.allocator.free(items);
                        self.string_lists.deinit(self.journal.allocator);
                    }

                    /// Validate the current request and return the matching recorded response trace.
                    pub fn expectCurrent(self: *@This(), current_value: Current) Error!Trace.Response {
                        return (try self.expectCurrentEntry(current_value)).trace;
                    }

                    /// Validate the current request and decode the matching recorded response value.
                    pub fn expectCurrentValue(self: *@This(), current_value: Current, comptime ValueType: type) Error!ValueType {
                        const replayed = try self.expectCurrentResponseValue(current_value, ValueType);
                        return replayed.value;
                    }

                    /// Validate the current request and decode its recorded response trace and value.
                    pub fn expectCurrentResponseValue(
                        self: *@This(),
                        current_value: Current,
                        comptime ValueType: type,
                    ) Error!struct { trace: Trace.Response, value: ValueType } {
                        const response = try self.expectCurrentEntry(current_value);
                        const value_image = response.value_image orelse return error.ProgramContractViolation;
                        return .{
                            .trace = response.trace,
                            .value = decodeJournalResponseValue(self, ValueType, response.trace, value_image) catch |err| return mapProgramRunError(Error, err),
                        };
                    }

                    /// Validate the recorded terminal result fingerprint and require replay EOF.
                    pub fn expectDone(self: *@This(), result_fingerprint: u64) Error!void {
                        const done_entry = self.nextReplayEntry() orelse return error.ProgramContractViolation;
                        const recorded = switch (done_entry) {
                            .done => |recorded_fingerprint| recorded_fingerprint,
                            else => return error.ProgramContractViolation,
                        };
                        if (recorded != result_fingerprint) return error.ProgramContractViolation;
                        try self.drainSkippableReplayEntries();
                        if (self.index != self.journal.entries.items.len) return error.ProgramContractViolation;
                    }

                    fn expectCurrentEntry(self: *@This(), current_value: Current) Error!ResponseEntry {
                        const request_entry = self.nextReplayEntry() orelse return error.ProgramContractViolation;
                        const request_trace = switch (request_entry) {
                            .request => |request_trace| request_trace,
                            else => return error.ProgramContractViolation,
                        };
                        const expected = request_trace.fingerprint();
                        const actual = switch (current_value) {
                            .request => |request| request.fingerprint(),
                            .after => |after_request| after_request.fingerprint(),
                            .none => return error.ProgramContractViolation,
                        };
                        if (actual != expected) return error.ProgramContractViolation;
                        const response_entry = self.nextReplayEntry() orelse return error.ProgramContractViolation;
                        const response = switch (response_entry) {
                            .response => |response| response,
                            else => return error.ProgramContractViolation,
                        };
                        try validateJournalResponseForRequest(request_trace, response.trace);
                        return response;
                    }

                    fn nextReplayEntry(self: *@This()) ?Entry {
                        if (self.index >= self.journal.entries.items.len) return null;
                        while (self.index < self.journal.entries.items.len) {
                            const entry = self.journal.entries.items[self.index];
                            self.index += 1;
                            switch (entry) {
                                .capsule_image => continue,
                                .exchange_event => continue,
                                else => return entry,
                            }
                        }
                        return null;
                    }

                    fn drainSkippableReplayEntries(self: *@This()) Error!void {
                        while (self.index < self.journal.entries.items.len) {
                            switch (self.journal.entries.items[self.index]) {
                                .capsule_image, .exchange_event => self.index += 1,
                                else => return error.ProgramContractViolation,
                            }
                        }
                    }
                };

                fn validateJournalResponseForRequest(request_trace: RequestTrace, response: Trace.Response) Error!void {
                    if (response.request_fingerprint != request_trace.fingerprint()) return error.ProgramContractViolation;
                    try validateJournalResponseTrace(response);
                    switch (request_trace) {
                        .operation => |request| switch (response.kind) {
                            .@"resume" => {
                                if (request.mode == .abort) return error.ProgramContractViolation;
                                if (!response.response_ref.eql(request.resume_ref)) return error.ProgramContractViolation;
                            },
                            .return_now => {
                                if (request.mode == .transform) return error.ProgramContractViolation;
                                if (!response.response_ref.eql(request.result_ref)) return error.ProgramContractViolation;
                            },
                            .resume_after => return error.ProgramContractViolation,
                        },
                        .after => |request| {
                            if (response.kind != .resume_after) return error.ProgramContractViolation;
                            if (!response.response_ref.eql(request.expected_output_ref)) return error.ProgramContractViolation;
                        },
                    }
                }

                fn validateJournalResponseTrace(response: Trace.Response) Error!void {
                    if (response.fingerprint != fingerprintJournalResponseTrace(response)) return error.ProgramContractViolation;
                }

                fn validateJournalCapsuleImage(allocator: std.mem.Allocator, image: Capsule.Image) Error!void {
                    if (image.image_fingerprint != capsuleImageFingerprint(image.bytes)) return error.ProgramContractViolation;
                    var decoded = Core.Capsule.decode(allocator, image.bytes) catch |err| return mapProgramRunError(Error, err);
                    defer decoded.deinit();
                    const metadata = decoded.metadata();
                    if (image.capsule_fingerprint != decoded.fingerprint() or
                        image.current_request_fingerprint != metadata.current_request_fingerprint)
                    {
                        return error.ProgramContractViolation;
                    }
                }

                fn validateJournalRequestTrace(request_trace: RequestTrace) Error!void {
                    switch (request_trace) {
                        .operation => |request| {
                            if (request.has_payload != (request.payload_ref.codec != .unit)) return error.ProgramContractViolation;
                            if (request.fingerprint != fingerprintJournalOperationRequestTrace(request)) return error.ProgramContractViolation;
                        },
                        .after => |request| {
                            if (request.fingerprint != fingerprintJournalAfterRequestTrace(request)) return error.ProgramContractViolation;
                        },
                    }
                }

                /// Create an empty host-owned journal.
                pub fn init(allocator: std.mem.Allocator) @This() {
                    return .{ .allocator = allocator };
                }

                /// Release all journal-owned entries and byte images.
                pub fn deinit(self: *@This()) void {
                    for (self.entries.items) |*entry| deinitJournalEntry(self.allocator, entry);
                    self.entries.deinit(self.allocator);
                }

                fn truncateEntries(self: *@This(), len: usize) void {
                    for (self.entries.items[len..]) |*entry| deinitJournalEntry(self.allocator, entry);
                    self.entries.shrinkRetainingCapacity(len);
                }

                /// Return an interpreter-compatible journal recorder.
                pub fn recorder(self: *@This()) Recorder {
                    return .{ .journal = self };
                }

                /// Return a replay cursor starting at the first entry.
                pub fn replayer(self: *const @This()) Replayer {
                    return .{ .journal = self };
                }

                /// Append an owned copy of a request trace.
                pub fn appendRequest(self: *@This(), trace: RequestTrace) Error!void {
                    try validateJournalRequestTrace(trace);
                    var owned = cloneJournalRequestTrace(self.allocator, trace) catch |err| return mapProgramRunError(Error, err);
                    errdefer deinitJournalRequestTrace(self.allocator, &owned);
                    self.entries.append(self.allocator, .{ .request = owned }) catch |err| return mapProgramRunError(Error, err);
                }

                /// Append a response trace without a typed value image.
                pub fn appendResponse(self: *@This(), trace: Trace.Response) Error!void {
                    try validateJournalResponseTrace(trace);
                    self.entries.append(self.allocator, .{ .response = .{ .trace = trace } }) catch |err| return mapProgramRunError(Error, err);
                }

                /// Append a response trace with a deterministic typed value image.
                pub fn appendResponseValue(self: *@This(), trace: Trace.Response, value: anytype) Error!void {
                    try validateJournalResponseTrace(trace);
                    const value_image = encodeJournalResponseValue(self.allocator, trace, value) catch |err| return mapProgramRunError(Error, err);
                    errdefer self.allocator.free(value_image);
                    self.entries.append(self.allocator, .{ .response = .{
                        .trace = trace,
                        .value_image = value_image,
                    } }) catch |err| return mapProgramRunError(Error, err);
                }

                fn appendValidatedResponseValueImage(self: *@This(), trace: Trace.Response, value_image: []const u8) Error!void {
                    try validateJournalResponseTrace(trace);
                    const owned = self.allocator.dupe(u8, value_image) catch |err| return mapProgramRunError(Error, err);
                    errdefer self.allocator.free(owned);
                    self.entries.append(self.allocator, .{ .response = .{
                        .trace = trace,
                        .value_image = owned,
                    } }) catch |err| return mapProgramRunError(Error, err);
                }

                /// Append an owned copy of a durable capsule image.
                pub fn appendCapsuleImage(self: *@This(), image: Capsule.Image) Error!void {
                    try validateJournalCapsuleImage(self.allocator, image);
                    const bytes = self.allocator.dupe(u8, image.bytes) catch |err| return mapProgramRunError(Error, err);
                    errdefer self.allocator.free(bytes);
                    self.entries.append(self.allocator, .{ .capsule_image = .{
                        .image_fingerprint = image.image_fingerprint,
                        .capsule_fingerprint = image.capsule_fingerprint,
                        .current_request_fingerprint = image.current_request_fingerprint,
                        .bytes = bytes,
                    } }) catch |err| return mapProgramRunError(Error, err);
                }

                /// Append a terminal result fingerprint.
                pub fn appendDone(self: *@This(), result_fingerprint: u64) Error!void {
                    self.entries.append(self.allocator, .{ .done = result_fingerprint }) catch |err| return mapProgramRunError(Error, err);
                }

                /// Append an exchange capability/routing event.
                pub fn appendExchangeEvent(self: *@This(), event: ExchangeEvent) Error!void {
                    const owned_tag = if (event.blocker_tag) |tag| self.allocator.dupe(u8, tag) catch |err| return mapProgramRunError(Error, err) else null;
                    errdefer if (owned_tag) |tag| self.allocator.free(tag);
                    var owned = event;
                    owned.blocker_tag = owned_tag;
                    self.entries.append(self.allocator, .{ .exchange_event = owned }) catch |err| return mapProgramRunError(Error, err);
                }

                /// Record that a provider manifest was observed by the host ledger.
                pub fn appendProviderManifestRecorded(self: *@This(), provider_fingerprint: u64) Error!void {
                    try self.appendExchangeEvent(.{ .kind = .provider_manifest_recorded, .provider_fingerprint = provider_fingerprint });
                }

                /// Record that a capability was granted.
                pub fn appendCapabilityGranted(self: *@This(), capability_fingerprint: u64, provider_fingerprint: u64) Error!void {
                    try self.appendExchangeEvent(.{
                        .kind = .capability_granted,
                        .provider_fingerprint = provider_fingerprint,
                        .capability_fingerprint = capability_fingerprint,
                    });
                }

                /// Record that a capability was attenuated.
                pub fn appendCapabilityAttenuated(self: *@This(), capability_fingerprint: u64, provider_fingerprint: u64) Error!void {
                    try self.appendExchangeEvent(.{
                        .kind = .capability_attenuated,
                        .provider_fingerprint = provider_fingerprint,
                        .capability_fingerprint = capability_fingerprint,
                    });
                }

                /// Encode the journal to deterministic owned bytes.
                pub fn encode(self: *const @This(), allocator: std.mem.Allocator) Error![]u8 {
                    var writer = ExchangeByteWriter.init(allocator);
                    errdefer writer.deinit();
                    writer.writeBytes("ABL_JRN1") catch |err| return mapProgramRunError(Error, err);
                    writer.writeU32(session_journal_format_version) catch |err| return mapProgramRunError(Error, err);
                    writer.writeU32(session_journal_fingerprint_version) catch |err| return mapProgramRunError(Error, err);
                    writer.writeUsize(self.entries.items.len) catch |err| return mapProgramRunError(Error, err);
                    for (self.entries.items) |entry| {
                        writeJournalEntry(&writer, entry) catch |err| return mapProgramRunError(Error, err);
                    }
                    const payload = writer.bytes.items;
                    writer.writeU64(journalFingerprintBytes(payload)) catch |err| return mapProgramRunError(Error, err);
                    return writer.toOwnedSlice() catch |err| return mapProgramRunError(Error, err);
                }

                /// Decode deterministic journal bytes into an owned journal.
                pub fn decode(allocator: std.mem.Allocator, bytes: []const u8) Error!@This() {
                    if (bytes.len < "ABL_JRN1".len + 4 + 4 + 8) return error.ProgramContractViolation;
                    const payload = bytes[0 .. bytes.len - 8];
                    const checksum = std.mem.readInt(u64, bytes[bytes.len - 8 ..][0..8], .little);
                    if (checksum != journalFingerprintBytes(payload)) return error.ProgramContractViolation;
                    var reader = ExchangeByteReader.init(payload);
                    try reader.expectBytes("ABL_JRN1");
                    const format_version = try reader.readU32();
                    if (format_version != 1 and format_version != 2 and format_version != 3 and format_version != 4 and format_version != 5 and format_version != session_journal_format_version) return error.ProgramContractViolation;
                    if (try reader.readU32() != session_journal_fingerprint_version) return error.ProgramContractViolation;
                    var journal = Journal.init(allocator);
                    errdefer journal.deinit();
                    const count = try reader.readUsize();
                    for (0..count) |_| {
                        var entry = readJournalEntry(&reader, allocator, format_version) catch |err| return mapProgramRunError(Error, err);
                        errdefer deinitJournalEntry(allocator, &entry);
                        journal.entries.append(allocator, entry) catch |err| return mapProgramRunError(Error, err);
                    }
                    if (!reader.eof()) return error.ProgramContractViolation;
                    return journal;
                }

                /// Compute the journal fingerprint from its deterministic byte image.
                pub fn fingerprint(self: *const @This()) Error!u64 {
                    const bytes = try self.encode(self.allocator);
                    defer self.allocator.free(bytes);
                    return journalFingerprintBytes(bytes);
                }
            };

            const ValueImageContext = struct {
                allocator: std.mem.Allocator,
                strings: std.ArrayList([]const u8) = .empty,
                string_lists: std.ArrayList([]const []const u8) = .empty,
                content_canonicalization: bool = false,

                fn init(allocator: std.mem.Allocator) @This() {
                    return .{ .allocator = allocator };
                }

                fn initCanonical(allocator: std.mem.Allocator) @This() {
                    return .{
                        .allocator = allocator,
                        .content_canonicalization = true,
                    };
                }

                fn deinit(self: *@This()) void {
                    self.strings.deinit(self.allocator);
                    self.string_lists.deinit(self.allocator);
                }

                fn stringIndex(self: *const @This(), value: []const u8) ?usize {
                    for (self.strings.items, 0..) |existing, index| {
                        if (self.content_canonicalization) {
                            if (std.mem.eql(u8, existing, value)) return index;
                        } else if (existing.ptr == value.ptr and existing.len == value.len) {
                            return index;
                        }
                    }
                    return null;
                }

                fn stringListIndex(self: *const @This(), value: []const []const u8) ?usize {
                    for (self.string_lists.items, 0..) |existing, index| {
                        if (self.content_canonicalization) {
                            if (stringListsEql(existing, value)) return index;
                        } else if (existing.ptr == value.ptr and existing.len == value.len) {
                            return index;
                        }
                    }
                    return null;
                }
            };

            fn stringListsEql(a: []const []const u8, b: []const []const u8) bool {
                if (a.len != b.len) return false;
                for (a, b) |a_item, b_item| {
                    if (!std.mem.eql(u8, a_item, b_item)) return false;
                }
                return true;
            }

            // Canonical deterministic byte helpers shared by journals and Effect Exchange envelopes.
            const ExchangeByteWriter = struct {
                allocator: std.mem.Allocator,
                bytes: std.ArrayList(u8) = .empty,

                fn init(allocator: std.mem.Allocator) @This() {
                    return .{ .allocator = allocator };
                }

                fn deinit(self: *@This()) void {
                    self.bytes.deinit(self.allocator);
                }

                fn toOwnedSlice(self: *@This()) std.mem.Allocator.Error![]u8 {
                    return self.bytes.toOwnedSlice(self.allocator);
                }

                fn writeBytes(self: *@This(), bytes: []const u8) std.mem.Allocator.Error!void {
                    try self.bytes.appendSlice(self.allocator, bytes);
                }

                fn writeLenBytes(self: *@This(), bytes: []const u8) std.mem.Allocator.Error!void {
                    try self.writeUsize(bytes.len);
                    try self.writeBytes(bytes);
                }

                fn writeBool(self: *@This(), value: bool) std.mem.Allocator.Error!void {
                    try self.bytes.append(self.allocator, @intFromBool(value));
                }

                fn writeU8(self: *@This(), value: u8) std.mem.Allocator.Error!void {
                    try self.bytes.append(self.allocator, value);
                }

                fn writeU16(self: *@This(), value: u16) std.mem.Allocator.Error!void {
                    var buffer: [2]u8 = undefined;
                    std.mem.writeInt(u16, &buffer, value, .little);
                    try self.writeBytes(&buffer);
                }

                fn writeU32(self: *@This(), value: u32) std.mem.Allocator.Error!void {
                    var buffer: [4]u8 = undefined;
                    std.mem.writeInt(u32, &buffer, value, .little);
                    try self.writeBytes(&buffer);
                }

                fn writeU64(self: *@This(), value: u64) std.mem.Allocator.Error!void {
                    var buffer: [8]u8 = undefined;
                    std.mem.writeInt(u64, &buffer, value, .little);
                    try self.writeBytes(&buffer);
                }

                fn writeUsize(self: *@This(), value: usize) std.mem.Allocator.Error!void {
                    try self.writeU64(@intCast(value));
                }
            };

            const ExchangeByteReader = struct {
                bytes: []const u8,
                index: usize = 0,

                fn init(bytes: []const u8) @This() {
                    return .{ .bytes = bytes };
                }

                fn eof(self: @This()) bool {
                    return self.index == self.bytes.len;
                }

                fn remaining(self: @This()) usize {
                    return self.bytes.len - self.index;
                }

                fn readBytes(self: *@This(), len: usize) error{ProgramContractViolation}![]const u8 {
                    const end = std.math.add(usize, self.index, len) catch return error.ProgramContractViolation;
                    if (end > self.bytes.len) return error.ProgramContractViolation;
                    const slice = self.bytes[self.index..end];
                    self.index = end;
                    return slice;
                }

                fn expectBytes(self: *@This(), expected: []const u8) error{ProgramContractViolation}!void {
                    if (!std.mem.eql(u8, try self.readBytes(expected.len), expected)) return error.ProgramContractViolation;
                }

                fn readLenBytes(self: *@This()) error{ProgramContractViolation}![]const u8 {
                    return self.readBytes(try self.readUsize());
                }

                fn readBool(self: *@This()) error{ProgramContractViolation}!bool {
                    return switch (try self.readU8()) {
                        0 => false,
                        1 => true,
                        else => error.ProgramContractViolation,
                    };
                }

                fn readU8(self: *@This()) error{ProgramContractViolation}!u8 {
                    return (try self.readBytes(1))[0];
                }

                fn readU16(self: *@This()) error{ProgramContractViolation}!u16 {
                    return std.mem.readInt(u16, (try self.readBytes(2))[0..2], .little);
                }

                fn readU32(self: *@This()) error{ProgramContractViolation}!u32 {
                    return std.mem.readInt(u32, (try self.readBytes(4))[0..4], .little);
                }

                fn readU64(self: *@This()) error{ProgramContractViolation}!u64 {
                    return std.mem.readInt(u64, (try self.readBytes(8))[0..8], .little);
                }

                fn readUsize(self: *@This()) error{ProgramContractViolation}!usize {
                    const value = try self.readU64();
                    if (value > std.math.maxInt(usize)) return error.ProgramContractViolation;
                    return @intCast(value);
                }
            };

            fn journalFingerprintBytes(bytes: []const u8) u64 {
                var hasher = std.hash.Wyhash.init(0);
                hashBytes(&hasher, "ability.program.session.journal");
                hashU32(&hasher, session_journal_fingerprint_version);
                hashBytes(&hasher, bytes);
                return hasher.final();
            }

            fn requestTraceFromAny(trace: anytype) Journal.RequestTrace {
                if (@TypeOf(trace) == Trace.OperationRequest) return .{ .operation = trace };
                if (@TypeOf(trace) == Trace.AfterRequest) return .{ .after = trace };
                @compileError("Journal recorder expected a Program.Session request or after trace");
            }

            fn cloneOptionalJournalLabel(allocator: std.mem.Allocator, label_value: ?[]const u8) std.mem.Allocator.Error!?[]u8 {
                if (label_value) |value| return try allocator.dupe(u8, value);
                return null;
            }

            fn cloneJournalRequestTrace(allocator: std.mem.Allocator, trace: Journal.RequestTrace) std.mem.Allocator.Error!Journal.RequestTrace {
                return switch (trace) {
                    .operation => |operation| blk: {
                        var owned = operation;
                        owned.semantic_label = try cloneOptionalJournalLabel(allocator, operation.semantic_label);
                        errdefer if (owned.semantic_label) |semantic_label| allocator.free(semantic_label);
                        owned.requirement_label = try allocator.dupe(u8, operation.requirement_label);
                        errdefer allocator.free(owned.requirement_label);
                        owned.op_name = try allocator.dupe(u8, operation.op_name);
                        break :blk .{ .operation = owned };
                    },
                    .after => |after| blk: {
                        var owned = after;
                        owned.semantic_label = try cloneOptionalJournalLabel(allocator, after.semantic_label);
                        errdefer if (owned.semantic_label) |semantic_label| allocator.free(semantic_label);
                        owned.original_requirement_label = try allocator.dupe(u8, after.original_requirement_label);
                        errdefer allocator.free(owned.original_requirement_label);
                        owned.original_op_name = try allocator.dupe(u8, after.original_op_name);
                        break :blk .{ .after = owned };
                    },
                };
            }

            fn deinitJournalRequestTrace(allocator: std.mem.Allocator, trace: *Journal.RequestTrace) void {
                switch (trace.*) {
                    .operation => |*operation| {
                        if (operation.semantic_label) |semantic_label| allocator.free(semantic_label);
                        allocator.free(operation.requirement_label);
                        allocator.free(operation.op_name);
                    },
                    .after => |*after| {
                        if (after.semantic_label) |semantic_label| allocator.free(semantic_label);
                        allocator.free(after.original_requirement_label);
                        allocator.free(after.original_op_name);
                    },
                }
            }

            fn deinitJournalEntry(allocator: std.mem.Allocator, entry: *Journal.Entry) void {
                switch (entry.*) {
                    .request => |*trace| deinitJournalRequestTrace(allocator, trace),
                    .response => |*response| if (response.value_image) |value_image| allocator.free(value_image),
                    .capsule_image => |*image| allocator.free(image.bytes),
                    .exchange_event => |*event| if (event.blocker_tag) |tag| allocator.free(tag),
                    else => {},
                }
            }

            fn encodeJournalResponseValue(
                allocator: std.mem.Allocator,
                response_trace: Trace.Response,
                value: anytype,
            ) anyerror![]u8 {
                const ValueType = @TypeOf(value);
                return switch (response_trace.response_ref.codec) {
                    .unit => encodeJournalResponseValueAs(allocator, response_trace, .{ .codec = .unit }, value),
                    .bool => encodeJournalResponseValueAs(allocator, response_trace, .{ .codec = .bool }, value),
                    .i32 => encodeJournalResponseValueAs(allocator, response_trace, .{ .codec = .i32 }, value),
                    .usize => encodeJournalResponseValueAs(allocator, response_trace, .{ .codec = .usize }, value),
                    .string => encodeJournalResponseValueAs(allocator, response_trace, .{ .codec = .string }, value),
                    .string_list => encodeJournalResponseValueAs(allocator, response_trace, .{ .codec = .string_list }, value),
                    .product, .sum => blk: {
                        const schema_index = response_trace.response_ref.schema_index orelse return error.ProgramContractViolation;
                        inline for (body_value_schema_types, 0..) |SchemaType, index| {
                            if (schema_index == index) {
                                if (ValueType != SchemaType) return error.ProgramContractViolation;
                                const expected_ref: lowering_api.ValueRef = comptime .{
                                    .codec = compiled_plan.value_schemas[index].codec,
                                    .schema_index = @intCast(index),
                                };
                                break :blk encodeJournalResponseValueAs(allocator, response_trace, expected_ref, value);
                            }
                        }
                        return error.ProgramContractViolation;
                    },
                };
            }

            fn encodeJournalResponseValueAs(
                allocator: std.mem.Allocator,
                response_trace: Trace.Response,
                comptime expected_ref: lowering_api.ValueRef,
                value: anytype,
            ) anyerror![]u8 {
                if (!response_trace.response_ref.eql(expected_ref)) return error.ProgramContractViolation;
                if (try fingerprintTypedValueImage(expected_ref, value) != response_trace.response_value_fingerprint) return error.ProgramContractViolation;
                var writer = ExchangeByteWriter.init(allocator);
                errdefer writer.deinit();
                var context = ValueImageContext.init(allocator);
                defer context.deinit();
                try writeExchangeValueRef(&writer, expected_ref);
                try writeTypedValueImage(&writer, &context, expected_ref, value);
                return writer.toOwnedSlice();
            }

            fn decodeJournalResponseValue(
                replayer: *Journal.Replayer,
                comptime ValueType: type,
                response_trace: Trace.Response,
                value_image: []const u8,
            ) anyerror!ValueType {
                return switch (response_trace.response_ref.codec) {
                    .unit => decodeJournalResponseValueAs(replayer, ValueType, response_trace, value_image, .{ .codec = .unit }),
                    .bool => decodeJournalResponseValueAs(replayer, ValueType, response_trace, value_image, .{ .codec = .bool }),
                    .i32 => decodeJournalResponseValueAs(replayer, ValueType, response_trace, value_image, .{ .codec = .i32 }),
                    .usize => decodeJournalResponseValueAs(replayer, ValueType, response_trace, value_image, .{ .codec = .usize }),
                    .string => decodeJournalResponseValueAs(replayer, ValueType, response_trace, value_image, .{ .codec = .string }),
                    .string_list => decodeJournalResponseValueAs(replayer, ValueType, response_trace, value_image, .{ .codec = .string_list }),
                    .product, .sum => blk: {
                        const schema_index = response_trace.response_ref.schema_index orelse return error.ProgramContractViolation;
                        inline for (body_value_schema_types, 0..) |SchemaType, index| {
                            if (schema_index == index) {
                                if (ValueType != SchemaType) return error.ProgramContractViolation;
                                const expected_ref: lowering_api.ValueRef = comptime .{
                                    .codec = compiled_plan.value_schemas[index].codec,
                                    .schema_index = @intCast(index),
                                };
                                break :blk decodeJournalResponseValueAs(replayer, ValueType, response_trace, value_image, expected_ref);
                            }
                        }
                        return error.ProgramContractViolation;
                    },
                };
            }

            fn decodeJournalResponseValueAs(
                replayer: *Journal.Replayer,
                comptime ValueType: type,
                response_trace: Trace.Response,
                value_image: []const u8,
                comptime expected_ref: lowering_api.ValueRef,
            ) anyerror!ValueType {
                if (!response_trace.response_ref.eql(expected_ref)) return error.ProgramContractViolation;
                var reader = ExchangeByteReader.init(value_image);
                const encoded_ref = try readExchangeValueRef(&reader);
                if (!encoded_ref.eql(expected_ref)) return error.ProgramContractViolation;
                var context = ValueImageContext.init(replayer.journal.allocator);
                defer context.deinit();
                const value = try readTypedValueImage(&reader, replayer, &context, expected_ref, ValueType);
                if (!reader.eof()) return error.ProgramContractViolation;
                if (try fingerprintTypedValueImage(expected_ref, value) != response_trace.response_value_fingerprint) return error.ProgramContractViolation;
                return value;
            }

            fn validateJournalResponseValueImage(
                allocator: std.mem.Allocator,
                response_trace: Trace.Response,
                value_image: []const u8,
            ) anyerror!void {
                var validation_journal = Journal.init(allocator);
                defer validation_journal.deinit();
                var replayer = validation_journal.replayer();
                defer replayer.deinit();

                var reader = ExchangeByteReader.init(value_image);
                const encoded_ref = try readExchangeValueRef(&reader);
                if (!encoded_ref.eql(response_trace.response_ref)) return error.ProgramContractViolation;
                return switch (response_trace.response_ref.codec) {
                    .unit => validateJournalResponseValueImageAs(&reader, &replayer, response_trace, .{ .codec = .unit }, void),
                    .bool => validateJournalResponseValueImageAs(&reader, &replayer, response_trace, .{ .codec = .bool }, bool),
                    .i32 => validateJournalResponseValueImageAs(&reader, &replayer, response_trace, .{ .codec = .i32 }, i32),
                    .usize => validateJournalResponseValueImageAs(&reader, &replayer, response_trace, .{ .codec = .usize }, usize),
                    .string => validateJournalResponseValueImageAs(&reader, &replayer, response_trace, .{ .codec = .string }, []const u8),
                    .string_list => validateJournalResponseValueImageAs(&reader, &replayer, response_trace, .{ .codec = .string_list }, []const []const u8),
                    .product, .sum => blk: {
                        const schema_index = response_trace.response_ref.schema_index orelse return error.ProgramContractViolation;
                        inline for (body_value_schema_types, 0..) |SchemaType, index| {
                            if (schema_index == index) {
                                const expected_ref: lowering_api.ValueRef = comptime .{
                                    .codec = compiled_plan.value_schemas[index].codec,
                                    .schema_index = @intCast(index),
                                };
                                if (!response_trace.response_ref.eql(expected_ref)) return error.ProgramContractViolation;
                                break :blk validateJournalResponseValueImageAs(&reader, &replayer, response_trace, expected_ref, SchemaType);
                            }
                        }
                        return error.ProgramContractViolation;
                    },
                };
            }

            fn validateJournalResponseValueImageAs(
                reader: *ExchangeByteReader,
                replayer: *Journal.Replayer,
                response_trace: Trace.Response,
                comptime expected_ref: lowering_api.ValueRef,
                comptime ValueType: type,
            ) anyerror!void {
                var context = ValueImageContext.init(replayer.journal.allocator);
                defer context.deinit();
                const value = try readTypedValueImage(reader, replayer, &context, expected_ref, ValueType);
                if (!reader.eof()) return error.ProgramContractViolation;
                if (try fingerprintTypedValueImage(expected_ref, value) != response_trace.response_value_fingerprint) {
                    return error.ProgramContractViolation;
                }
            }

            fn fingerprintJournalResponseTrace(trace: Trace.Response) u64 {
                var hasher = std.hash.Wyhash.init(0);
                hashBytes(&hasher, "ability.session.response");
                hashU32(&hasher, Trace.fingerprint_version);
                hashU64(&hasher, trace.request_fingerprint);
                hashBytes(&hasher, @tagName(trace.kind));
                hashJournalTraceValueRef(&hasher, trace.response_ref);
                hashU64(&hasher, trace.response_value_fingerprint);
                return hasher.final();
            }

            fn hashJournalRequestPrefix(hasher: *std.hash.Wyhash, turn_index: usize, kind: Trace.RequestKind) void {
                hashBytes(hasher, "ability.session.request");
                hashU32(hasher, Trace.fingerprint_version);
                hashBytes(hasher, label);
                hashBytes(hasher, body_compiled_plan.label);
                hashU64(hasher, body_compiled_plan_hash);
                hashUsize(hasher, turn_index);
                hashBytes(hasher, @tagName(kind));
            }

            fn fingerprintJournalOperationRequestTrace(trace: Trace.OperationRequest) u64 {
                var hasher = std.hash.Wyhash.init(0);
                hashJournalRequestPrefix(&hasher, trace.turn_index, .operation);
                hashUsize(&hasher, trace.operation_site_index);
                hashU64(&hasher, trace.operation_site_fingerprint);
                hashUsize(&hasher, trace.function_index);
                hashUsize(&hasher, trace.block_index);
                hashUsize(&hasher, trace.instruction_index);
                hashU16(&hasher, trace.requirement_index);
                hashBytes(&hasher, trace.requirement_label);
                hashU16(&hasher, trace.op_index);
                hashBytes(&hasher, trace.op_name);
                hashBytes(&hasher, @tagName(trace.mode));
                hashJournalTraceValueRef(&hasher, trace.payload_ref);
                hashU64(&hasher, trace.payload_value_fingerprint);
                hashJournalTraceValueRef(&hasher, trace.resume_ref);
                hashJournalTraceValueRef(&hasher, trace.result_ref);
                hashBool(&hasher, trace.has_after);
                return hasher.final();
            }

            fn fingerprintJournalAfterRequestTrace(trace: Trace.AfterRequest) u64 {
                var hasher = std.hash.Wyhash.init(0);
                hashJournalRequestPrefix(&hasher, trace.turn_index, .after);
                hashUsize(&hasher, trace.after_site_index);
                hashU64(&hasher, trace.after_site_fingerprint);
                hashUsize(&hasher, trace.source_operation_site_index);
                hashU64(&hasher, trace.source_operation_site_fingerprint);
                hashUsize(&hasher, trace.function_index);
                hashUsize(&hasher, trace.block_index);
                hashUsize(&hasher, trace.instruction_index);
                hashU16(&hasher, trace.original_requirement_index);
                hashBytes(&hasher, trace.original_requirement_label);
                hashU16(&hasher, trace.original_op_index);
                hashBytes(&hasher, trace.original_op_name);
                hashJournalTraceValueRef(&hasher, trace.current_value_ref);
                hashU64(&hasher, trace.current_value_fingerprint);
                hashJournalTraceValueRef(&hasher, trace.expected_output_ref);
                hashJournalTraceValueRef(&hasher, trace.result_ref);
                return hasher.final();
            }

            fn hashJournalTraceValueRef(hasher: *std.hash.Wyhash, ref: lowering_api.ValueRef) void {
                hasher.update(&[_]u8{@intFromEnum(ref.codec)});
                hashBool(hasher, ref.schema_index != null);
                if (ref.schema_index) |schema_index| hashU16(hasher, schema_index);
            }

            fn hashJournalCodec(hasher: *std.hash.Wyhash, codec: lowering_api.ValueCodec) void {
                hasher.update(&[_]u8{@intFromEnum(codec)});
            }

            fn fingerprintTypedValueImage(comptime ref: lowering_api.ValueRef, value: anytype) Error!u64 {
                const ValueType = @TypeOf(value);
                if (comptime !ProgramValueRefMatchesType(body_value_schema_types, ref, ValueType)) return error.ProgramContractViolation;
                var hasher = std.hash.Wyhash.init(0);
                hashBytes(&hasher, "ability.session.value");
                hashU32(&hasher, Trace.fingerprint_version);
                hashJournalTraceValueRef(&hasher, ref);
                try hashTypedValueImagePayload(&hasher, ref, value);
                return hasher.final();
            }

            fn hashTypedValueImagePayload(hasher: *std.hash.Wyhash, comptime ref: lowering_api.ValueRef, value: anytype) Error!void {
                const ValueType = @TypeOf(value);
                if (comptime !ProgramValueRefMatchesType(body_value_schema_types, ref, ValueType)) return error.ProgramContractViolation;
                switch (comptime ref.codec) {
                    .unit => {},
                    .bool => hashBool(hasher, value),
                    .i32 => hashI32(hasher, value),
                    .usize => hashUsize(hasher, value),
                    .string => hashBytes(hasher, value),
                    .string_list => {
                        hashUsize(hasher, value.len);
                        for (value) |item| hashBytes(hasher, item);
                    },
                    .product => try hashProductValueImagePayload(hasher, ref, ValueType, value),
                    .sum => try hashSumValueImagePayload(hasher, ref, ValueType, value),
                }
            }

            fn hashJournalStructuredSchemaPrefix(
                hasher: *std.hash.Wyhash,
                comptime ref: lowering_api.ValueRef,
                comptime ValueType: type,
                comptime schema_index: usize,
            ) Error!void {
                inline for (body_value_schema_types, 0..) |SchemaType, index| {
                    if (schema_index == index) {
                        if (SchemaType != ValueType) return error.ProgramContractViolation;
                        const schema = compiled_plan.value_schemas[index];
                        if (schema.codec != ref.codec) return error.ProgramContractViolation;
                        hashU16(hasher, @intCast(index));
                        hashBytes(hasher, schema.label);
                        hashJournalCodec(hasher, schema.codec);
                        return;
                    }
                }
                return error.ProgramContractViolation;
            }

            fn hashProductValueImagePayload(
                hasher: *std.hash.Wyhash,
                comptime ref: lowering_api.ValueRef,
                comptime ValueType: type,
                value: ValueType,
            ) Error!void {
                const schema_index = comptime ref.schema_index orelse return error.ProgramContractViolation;
                try hashJournalStructuredSchemaPrefix(hasher, ref, ValueType, schema_index);
                const schema = compiled_plan.value_schemas[schema_index];
                if (schema.codec != .product) return error.ProgramContractViolation;
                const fields = std.meta.fields(ValueType);
                if (fields.len != schema.field_count) return error.ProgramContractViolation;
                hashU16(hasher, schema.first_field);
                hashU16(hasher, schema.field_count);
                inline for (0..schema.field_count) |field_offset| {
                    const field = compiled_plan.value_fields[@as(usize, schema.first_field) + field_offset];
                    const field_ref: lowering_api.ValueRef = .{
                        .codec = field.codec,
                        .schema_index = field.schema_index,
                    };
                    hashU16(hasher, @intCast(field_offset));
                    hashBytes(hasher, field.name);
                    hashJournalTraceValueRef(hasher, field_ref);
                    const field_fingerprint = try fingerprintTypedValueImage(field_ref, @field(value, field.name));
                    hashU64(hasher, field_fingerprint);
                }
            }

            fn activeValueImageVariantOrdinal(comptime ValueType: type, value: ValueType) Error!u16 {
                return switch (@typeInfo(ValueType)) {
                    .@"enum" => |enum_info| {
                        inline for (enum_info.fields, 0..) |field, field_index| {
                            if (value == @field(ValueType, field.name)) return @intCast(field_index);
                        }
                        return error.ProgramContractViolation;
                    },
                    .@"union" => |union_info| {
                        const Tag = union_info.tag_type orelse return error.ProgramContractViolation;
                        const active = std.meta.activeTag(value);
                        inline for (union_info.fields, 0..) |field, field_index| {
                            if (active == @field(Tag, field.name)) return @intCast(field_index);
                        }
                        return error.ProgramContractViolation;
                    },
                    .optional => if (value == null) 0 else 1,
                    else => error.ProgramContractViolation,
                };
            }

            fn hashSumValueImagePayload(
                hasher: *std.hash.Wyhash,
                comptime ref: lowering_api.ValueRef,
                comptime ValueType: type,
                value: ValueType,
            ) Error!void {
                const schema_index = comptime ref.schema_index orelse return error.ProgramContractViolation;
                try hashJournalStructuredSchemaPrefix(hasher, ref, ValueType, schema_index);
                const schema = compiled_plan.value_schemas[schema_index];
                if (schema.codec != .sum) return error.ProgramContractViolation;
                const active = try activeValueImageVariantOrdinal(ValueType, value);
                if (active >= schema.variant_count) return error.ProgramContractViolation;
                hashU16(hasher, schema.first_variant);
                hashU16(hasher, schema.variant_count);
                hashU16(hasher, active);
                inline for (0..schema.variant_count) |variant_offset| {
                    if (active == variant_offset) {
                        const variant = compiled_plan.value_variants[@as(usize, schema.first_variant) + variant_offset];
                        const variant_ref: lowering_api.ValueRef = .{
                            .codec = variant.codec,
                            .schema_index = variant.schema_index,
                        };
                        hashBytes(hasher, variant.name);
                        hashJournalTraceValueRef(hasher, variant_ref);
                        const payload_fingerprint = try sumVariantPayloadValueImageFingerprint(variant_offset, variant_ref, ValueType, value);
                        hashU64(hasher, payload_fingerprint);
                        return;
                    }
                }
                return error.ProgramContractViolation;
            }

            fn sumVariantPayloadValueImageFingerprint(
                comptime variant_offset: usize,
                comptime variant_ref: lowering_api.ValueRef,
                comptime ValueType: type,
                value: ValueType,
            ) Error!u64 {
                return switch (@typeInfo(ValueType)) {
                    .@"enum" => fingerprintTypedValueImage(variant_ref, {}),
                    .optional => if (variant_offset == 0)
                        fingerprintTypedValueImage(variant_ref, {})
                    else
                        fingerprintTypedValueImage(variant_ref, value.?),
                    .@"union" => |union_info| blk: {
                        inline for (union_info.fields, 0..) |field, field_index| {
                            if (variant_offset == field_index) {
                                if (field.type == void) break :blk fingerprintTypedValueImage(variant_ref, {});
                                break :blk fingerprintTypedValueImage(variant_ref, @field(value, field.name));
                            }
                        }
                        return error.ProgramContractViolation;
                    },
                    else => error.ProgramContractViolation,
                };
            }

            fn writeExchangeValueRef(writer: *ExchangeByteWriter, ref: lowering_api.ValueRef) std.mem.Allocator.Error!void {
                try writer.writeU8(@intFromEnum(ref.codec));
                try writer.writeBool(ref.schema_index != null);
                if (ref.schema_index) |schema_index| try writer.writeU16(schema_index);
            }

            fn readExchangeCodec(reader: *ExchangeByteReader) error{ProgramContractViolation}!lowering_api.ValueCodec {
                return switch (try reader.readU8()) {
                    @intFromEnum(lowering_api.ValueCodec.unit) => .unit,
                    @intFromEnum(lowering_api.ValueCodec.bool) => .bool,
                    @intFromEnum(lowering_api.ValueCodec.i32) => .i32,
                    @intFromEnum(lowering_api.ValueCodec.product) => .product,
                    @intFromEnum(lowering_api.ValueCodec.usize) => .usize,
                    @intFromEnum(lowering_api.ValueCodec.string) => .string,
                    @intFromEnum(lowering_api.ValueCodec.string_list) => .string_list,
                    @intFromEnum(lowering_api.ValueCodec.sum) => .sum,
                    else => error.ProgramContractViolation,
                };
            }

            fn readExchangeValueRef(reader: *ExchangeByteReader) error{ProgramContractViolation}!lowering_api.ValueRef {
                return .{
                    .codec = try readExchangeCodec(reader),
                    .schema_index = if (try reader.readBool()) try reader.readU16() else null,
                };
            }

            fn writeJournalResponseKind(writer: *ExchangeByteWriter, kind: Trace.ResponseKind) std.mem.Allocator.Error!void {
                try writer.writeU8(switch (kind) {
                    .@"resume" => 0,
                    .return_now => 1,
                    .resume_after => 2,
                });
            }

            fn readJournalResponseKind(reader: *ExchangeByteReader) error{ProgramContractViolation}!Trace.ResponseKind {
                return switch (try reader.readU8()) {
                    0 => .@"resume",
                    1 => .return_now,
                    2 => .resume_after,
                    else => error.ProgramContractViolation,
                };
            }

            fn writeJournalControlMode(writer: *ExchangeByteWriter, mode: plan_types.ControlMode) std.mem.Allocator.Error!void {
                try writer.writeU8(switch (mode) {
                    .abort => 0,
                    .choice => 1,
                    .transform => 2,
                });
            }

            fn readJournalControlMode(reader: *ExchangeByteReader) error{ProgramContractViolation}!plan_types.ControlMode {
                return switch (try reader.readU8()) {
                    0 => .abort,
                    1 => .choice,
                    2 => .transform,
                    else => error.ProgramContractViolation,
                };
            }

            fn writeValueImageString(
                writer: *ExchangeByteWriter,
                context: *ValueImageContext,
                value: []const u8,
            ) std.mem.Allocator.Error!void {
                if (context.stringIndex(value)) |index| {
                    try writer.writeU8(1);
                    try writer.writeUsize(index);
                    return;
                }
                try writer.writeU8(0);
                try context.strings.append(context.allocator, value);
                try writer.writeLenBytes(value);
            }

            fn readValueImageString(
                reader: *ExchangeByteReader,
                context: *ValueImageContext,
            ) anyerror![]const u8 {
                return switch (try reader.readU8()) {
                    0 => blk: {
                        const value = try reader.readLenBytes();
                        try context.strings.append(context.allocator, value);
                        break :blk value;
                    },
                    1 => blk: {
                        const index = try reader.readUsize();
                        if (index >= context.strings.items.len) return error.ProgramContractViolation;
                        break :blk context.strings.items[index];
                    },
                    else => error.ProgramContractViolation,
                };
            }

            fn writeValueImageStringList(
                writer: *ExchangeByteWriter,
                context: *ValueImageContext,
                value: []const []const u8,
            ) anyerror!void {
                if (context.stringListIndex(value)) |index| {
                    try writer.writeU8(1);
                    try writer.writeUsize(index);
                    return;
                }
                try writer.writeU8(0);
                try context.string_lists.append(context.allocator, value);
                try writer.writeUsize(value.len);
                for (value) |item| try writeValueImageString(writer, context, item);
            }

            fn writeTypedValueImage(
                writer: *ExchangeByteWriter,
                context: *ValueImageContext,
                comptime ref: lowering_api.ValueRef,
                value: anytype,
            ) anyerror!void {
                const ValueType = @TypeOf(value);
                if (comptime !ProgramValueRefMatchesType(body_value_schema_types, ref, ValueType)) return error.ProgramContractViolation;
                switch (comptime ref.codec) {
                    .unit => {},
                    .bool => try writer.writeBool(value),
                    .i32 => try writer.writeU32(@bitCast(value)),
                    .usize => try writer.writeUsize(value),
                    .string => try writeValueImageString(writer, context, value),
                    .string_list => try writeValueImageStringList(writer, context, value),
                    .product => {
                        const schema_index = comptime ref.schema_index orelse return error.ProgramContractViolation;
                        const schema = compiled_plan.value_schemas[schema_index];
                        if (schema.codec != .product) return error.ProgramContractViolation;
                        const info = @typeInfo(ValueType).@"struct";
                        if (info.fields.len != schema.field_count) return error.ProgramContractViolation;
                        inline for (0..schema.field_count) |field_offset| {
                            const field = compiled_plan.value_fields[@as(usize, schema.first_field) + field_offset];
                            try writer.writeLenBytes(field.name);
                            const field_ref: lowering_api.ValueRef = comptime .{ .codec = field.codec, .schema_index = field.schema_index };
                            try writeExchangeValueRef(writer, field_ref);
                            const FieldType = @TypeOf(@field(value, field.name));
                            try writeTypedValueImage(writer, context, field_ref, @as(FieldType, @field(value, field.name)));
                        }
                    },
                    .sum => switch (@typeInfo(ValueType)) {
                        .@"enum" => try writer.writeLenBytes(@tagName(value)),
                        .optional => {
                            const schema_index = comptime ref.schema_index orelse return error.ProgramContractViolation;
                            const schema = compiled_plan.value_schemas[schema_index];
                            if (schema.codec != .sum or schema.variant_count != 2) return error.ProgramContractViolation;
                            if (value) |payload| {
                                const variant = compiled_plan.value_variants[@as(usize, schema.first_variant) + 1];
                                try writer.writeLenBytes(variant.name);
                                const payload_ref: lowering_api.ValueRef = comptime .{ .codec = variant.codec, .schema_index = variant.schema_index };
                                try writeExchangeValueRef(writer, payload_ref);
                                try writeTypedValueImage(writer, context, payload_ref, payload);
                            } else {
                                const variant = compiled_plan.value_variants[schema.first_variant];
                                try writer.writeLenBytes(variant.name);
                            }
                        },
                        .@"union" => |union_info| {
                            const schema_index = comptime ref.schema_index orelse return error.ProgramContractViolation;
                            const schema = compiled_plan.value_schemas[schema_index];
                            if (schema.codec != .sum) return error.ProgramContractViolation;
                            const tag = std.meta.activeTag(value);
                            inline for (union_info.fields, 0..) |field, field_index| {
                                if (tag == @field(union_info.tag_type.?, field.name)) {
                                    const variant = compiled_plan.value_variants[@as(usize, schema.first_variant) + field_index];
                                    try writer.writeLenBytes(variant.name);
                                    if (field.type == void) return;
                                    const payload_ref: lowering_api.ValueRef = comptime .{ .codec = variant.codec, .schema_index = variant.schema_index };
                                    try writeExchangeValueRef(writer, payload_ref);
                                    try writeTypedValueImage(writer, context, payload_ref, @field(value, field.name));
                                    return;
                                }
                            }
                            return error.ProgramContractViolation;
                        },
                        else => return error.ProgramContractViolation,
                    },
                }
            }

            fn readTypedValueImage(
                reader: *ExchangeByteReader,
                replayer: *Journal.Replayer,
                context: *ValueImageContext,
                comptime ref: lowering_api.ValueRef,
                comptime ValueType: type,
            ) anyerror!ValueType {
                if (comptime !ProgramValueRefMatchesType(body_value_schema_types, ref, ValueType)) return error.ProgramContractViolation;
                return switch (comptime ref.codec) {
                    .unit => {},
                    .bool => try reader.readBool(),
                    .i32 => @as(i32, @bitCast(try reader.readU32())),
                    .usize => try reader.readUsize(),
                    .string => try readValueImageString(reader, context),
                    .string_list => blk: {
                        const items = try readValueImageStringList(reader, replayer, context);
                        if (ValueType == []const []const u8) break :blk items;
                        if (ValueType == [][]const u8) break :blk @constCast(items);
                        return error.ProgramContractViolation;
                    },
                    .product => blk: {
                        var value: ValueType = undefined;
                        const schema_index = comptime ref.schema_index orelse return error.ProgramContractViolation;
                        const schema = compiled_plan.value_schemas[schema_index];
                        if (schema.codec != .product) return error.ProgramContractViolation;
                        const info = @typeInfo(ValueType).@"struct";
                        if (info.fields.len != schema.field_count) return error.ProgramContractViolation;
                        inline for (0..schema.field_count) |field_offset| {
                            const field = compiled_plan.value_fields[@as(usize, schema.first_field) + field_offset];
                            if (!std.mem.eql(u8, try reader.readLenBytes(), field.name)) return error.ProgramContractViolation;
                            const field_ref: lowering_api.ValueRef = comptime .{ .codec = field.codec, .schema_index = field.schema_index };
                            const encoded_ref = try readExchangeValueRef(reader);
                            if (!encoded_ref.eql(field_ref)) return error.ProgramContractViolation;
                            const struct_field = std.meta.fields(ValueType)[field_offset];
                            const decoded_field = try readTypedValueImage(reader, replayer, context, field_ref, struct_field.type);
                            if (comptime field.codec == .string_list and struct_field.type == [][]const u8) {
                                @field(value, field.name) = @constCast(decoded_field);
                            } else {
                                @field(value, field.name) = decoded_field;
                            }
                        }
                        break :blk value;
                    },
                    .sum => switch (@typeInfo(ValueType)) {
                        .@"enum" => blk: {
                            const tag_name = try reader.readLenBytes();
                            inline for (@typeInfo(ValueType).@"enum".fields) |field| {
                                if (std.mem.eql(u8, tag_name, field.name)) break :blk @field(ValueType, field.name);
                            }
                            return error.ProgramContractViolation;
                        },
                        .optional => |optional| blk: {
                            const schema_index = comptime ref.schema_index orelse return error.ProgramContractViolation;
                            const schema = compiled_plan.value_schemas[schema_index];
                            if (schema.codec != .sum or schema.variant_count != 2) return error.ProgramContractViolation;
                            const tag_name = try reader.readLenBytes();
                            const none_variant = compiled_plan.value_variants[schema.first_variant];
                            const some_variant = compiled_plan.value_variants[@as(usize, schema.first_variant) + 1];
                            if (std.mem.eql(u8, tag_name, none_variant.name)) break :blk null;
                            if (!std.mem.eql(u8, tag_name, some_variant.name)) return error.ProgramContractViolation;
                            const variant = compiled_plan.value_variants[@as(usize, schema.first_variant) + 1];
                            const payload_ref: lowering_api.ValueRef = comptime .{ .codec = variant.codec, .schema_index = variant.schema_index };
                            const encoded_ref = try readExchangeValueRef(reader);
                            if (!encoded_ref.eql(payload_ref)) return error.ProgramContractViolation;
                            break :blk try readTypedValueImage(reader, replayer, context, payload_ref, optional.child);
                        },
                        .@"union" => |union_info| blk: {
                            const schema_index = comptime ref.schema_index orelse return error.ProgramContractViolation;
                            const schema = compiled_plan.value_schemas[schema_index];
                            if (schema.codec != .sum) return error.ProgramContractViolation;
                            const tag_name = try reader.readLenBytes();
                            inline for (union_info.fields, 0..) |field, field_index| {
                                if (std.mem.eql(u8, tag_name, field.name)) {
                                    if (field.type == void) break :blk @unionInit(ValueType, field.name, {});
                                    const variant = compiled_plan.value_variants[@as(usize, schema.first_variant) + field_index];
                                    const payload_ref: lowering_api.ValueRef = comptime .{ .codec = variant.codec, .schema_index = variant.schema_index };
                                    const encoded_ref = try readExchangeValueRef(reader);
                                    if (!encoded_ref.eql(payload_ref)) return error.ProgramContractViolation;
                                    break :blk @unionInit(ValueType, field.name, try readTypedValueImage(reader, replayer, context, payload_ref, field.type));
                                }
                            }
                            return error.ProgramContractViolation;
                        },
                        else => return error.ProgramContractViolation,
                    },
                };
            }

            fn readValueImageStringList(
                reader: *ExchangeByteReader,
                replayer: *Journal.Replayer,
                context: *ValueImageContext,
            ) anyerror![]const []const u8 {
                return switch (try reader.readU8()) {
                    0 => blk: {
                        const count = try reader.readUsize();
                        if (count > reader.remaining() / 8) return error.ProgramContractViolation;
                        const items = try replayer.journal.allocator.alloc([]const u8, count);
                        var items_owned = false;
                        errdefer if (!items_owned) replayer.journal.allocator.free(items);
                        for (items) |*item| item.* = try readValueImageString(reader, context);
                        try context.string_lists.append(context.allocator, items);
                        try replayer.string_lists.append(replayer.journal.allocator, items);
                        items_owned = true;
                        break :blk items;
                    },
                    1 => blk: {
                        const index = try reader.readUsize();
                        if (index >= context.string_lists.items.len) return error.ProgramContractViolation;
                        break :blk context.string_lists.items[index];
                    },
                    else => error.ProgramContractViolation,
                };
            }

            fn writeJournalRequestTrace(writer: *ExchangeByteWriter, trace: Journal.RequestTrace) anyerror!void {
                try Journal.validateJournalRequestTrace(trace);
                switch (trace) {
                    .operation => |operation| {
                        try writer.writeU8(0);
                        try writer.writeU64(operation.fingerprint);
                        try writer.writeUsize(operation.turn_index);
                        try writer.writeUsize(operation.operation_site_index);
                        try writer.writeU64(operation.operation_site_fingerprint);
                        try writer.writeBool(operation.semantic_label != null);
                        if (operation.semantic_label) |semantic_label| try writer.writeLenBytes(semantic_label);
                        try writer.writeUsize(operation.function_index);
                        try writer.writeUsize(operation.block_index);
                        try writer.writeUsize(operation.instruction_index);
                        try writer.writeU16(operation.requirement_index);
                        try writer.writeLenBytes(operation.requirement_label);
                        try writer.writeU16(operation.op_index);
                        try writer.writeLenBytes(operation.op_name);
                        try writeJournalControlMode(writer, operation.mode);
                        try writeExchangeValueRef(writer, operation.payload_ref);
                        try writer.writeBool(operation.has_payload);
                        try writer.writeU64(operation.payload_value_fingerprint);
                        try writeExchangeValueRef(writer, operation.resume_ref);
                        try writeExchangeValueRef(writer, operation.result_ref);
                        try writer.writeBool(operation.has_after);
                    },
                    .after => |after| {
                        try writer.writeU8(1);
                        try writer.writeU64(after.fingerprint);
                        try writer.writeUsize(after.turn_index);
                        try writer.writeUsize(after.after_site_index);
                        try writer.writeU64(after.after_site_fingerprint);
                        try writer.writeUsize(after.source_operation_site_index);
                        try writer.writeU64(after.source_operation_site_fingerprint);
                        try writer.writeBool(after.semantic_label != null);
                        if (after.semantic_label) |semantic_label| try writer.writeLenBytes(semantic_label);
                        try writer.writeUsize(after.function_index);
                        try writer.writeUsize(after.block_index);
                        try writer.writeUsize(after.instruction_index);
                        try writer.writeU16(after.original_requirement_index);
                        try writer.writeLenBytes(after.original_requirement_label);
                        try writer.writeU16(after.original_op_index);
                        try writer.writeLenBytes(after.original_op_name);
                        try writeExchangeValueRef(writer, after.current_value_ref);
                        try writer.writeU64(after.current_value_fingerprint);
                        try writeExchangeValueRef(writer, after.expected_output_ref);
                        try writeExchangeValueRef(writer, after.result_ref);
                    },
                }
            }

            fn readJournalRequestTrace(reader: *ExchangeByteReader, allocator: std.mem.Allocator) anyerror!Journal.RequestTrace {
                return switch (try reader.readU8()) {
                    0 => blk: {
                        const fingerprint = try reader.readU64();
                        const turn_index = try reader.readUsize();
                        const operation_site_index = try reader.readUsize();
                        const operation_site_fingerprint = try reader.readU64();
                        const semantic_label = if (try reader.readBool()) try allocator.dupe(u8, try reader.readLenBytes()) else null;
                        errdefer if (semantic_label) |label_bytes| allocator.free(label_bytes);
                        const function_index = try reader.readUsize();
                        const block_index = try reader.readUsize();
                        const instruction_index = try reader.readUsize();
                        const requirement_index = try reader.readU16();
                        const requirement_label = try allocator.dupe(u8, try reader.readLenBytes());
                        errdefer allocator.free(requirement_label);
                        const op_index = try reader.readU16();
                        const op_name = try allocator.dupe(u8, try reader.readLenBytes());
                        errdefer allocator.free(op_name);
                        const mode = try readJournalControlMode(reader);
                        const trace: Trace.OperationRequest = .{
                            .program_label = label,
                            .plan_label = body_compiled_plan.label,
                            .plan_hash = body_compiled_plan_hash,
                            .fingerprint = fingerprint,
                            .turn_index = turn_index,
                            .operation_site_index = operation_site_index,
                            .operation_site_fingerprint = operation_site_fingerprint,
                            .semantic_label = semantic_label,
                            .function_index = function_index,
                            .block_index = block_index,
                            .instruction_index = instruction_index,
                            .requirement_index = requirement_index,
                            .requirement_label = requirement_label,
                            .op_index = op_index,
                            .op_name = op_name,
                            .mode = mode,
                            .payload_ref = try readExchangeValueRef(reader),
                            .has_payload = try reader.readBool(),
                            .payload_value_fingerprint = try reader.readU64(),
                            .resume_ref = try readExchangeValueRef(reader),
                            .result_ref = try readExchangeValueRef(reader),
                            .has_after = try reader.readBool(),
                        };
                        try Journal.validateJournalRequestTrace(.{ .operation = trace });
                        if (trace.fingerprint != fingerprintJournalOperationRequestTrace(trace)) return error.ProgramContractViolation;
                        break :blk .{ .operation = trace };
                    },
                    1 => blk: {
                        const fingerprint = try reader.readU64();
                        const turn_index = try reader.readUsize();
                        const after_site_index = try reader.readUsize();
                        const after_site_fingerprint = try reader.readU64();
                        const source_operation_site_index = try reader.readUsize();
                        const source_operation_site_fingerprint = try reader.readU64();
                        const semantic_label = if (try reader.readBool()) try allocator.dupe(u8, try reader.readLenBytes()) else null;
                        errdefer if (semantic_label) |label_bytes| allocator.free(label_bytes);
                        const function_index = try reader.readUsize();
                        const block_index = try reader.readUsize();
                        const instruction_index = try reader.readUsize();
                        const original_requirement_index = try reader.readU16();
                        const original_requirement_label = try allocator.dupe(u8, try reader.readLenBytes());
                        errdefer allocator.free(original_requirement_label);
                        const original_op_index = try reader.readU16();
                        const original_op_name = try allocator.dupe(u8, try reader.readLenBytes());
                        errdefer allocator.free(original_op_name);
                        const trace: Trace.AfterRequest = .{
                            .program_label = label,
                            .plan_label = body_compiled_plan.label,
                            .plan_hash = body_compiled_plan_hash,
                            .fingerprint = fingerprint,
                            .turn_index = turn_index,
                            .after_site_index = after_site_index,
                            .after_site_fingerprint = after_site_fingerprint,
                            .source_operation_site_index = source_operation_site_index,
                            .source_operation_site_fingerprint = source_operation_site_fingerprint,
                            .semantic_label = semantic_label,
                            .function_index = function_index,
                            .block_index = block_index,
                            .instruction_index = instruction_index,
                            .original_requirement_index = original_requirement_index,
                            .original_requirement_label = original_requirement_label,
                            .original_op_index = original_op_index,
                            .original_op_name = original_op_name,
                            .current_value_ref = try readExchangeValueRef(reader),
                            .current_value_fingerprint = try reader.readU64(),
                            .expected_output_ref = try readExchangeValueRef(reader),
                            .result_ref = try readExchangeValueRef(reader),
                        };
                        if (trace.fingerprint != fingerprintJournalAfterRequestTrace(trace)) return error.ProgramContractViolation;
                        break :blk .{ .after = trace };
                    },
                    else => error.ProgramContractViolation,
                };
            }

            fn writeJournalEntry(writer: *ExchangeByteWriter, entry: Journal.Entry) anyerror!void {
                switch (entry) {
                    .request => |trace| {
                        try writer.writeU8(0);
                        try writeJournalRequestTrace(writer, trace);
                    },
                    .response => |response| {
                        try writer.writeU8(1);
                        try writer.writeU64(response.trace.request_fingerprint);
                        try writeJournalResponseKind(writer, response.trace.kind);
                        try writeExchangeValueRef(writer, response.trace.response_ref);
                        try writer.writeU64(response.trace.response_value_fingerprint);
                        try writer.writeU64(response.trace.fingerprint);
                        try writer.writeBool(response.value_image != null);
                        if (response.value_image) |value_image| try writer.writeLenBytes(value_image);
                    },
                    .capsule_image => |image| {
                        try writer.writeU8(2);
                        try writer.writeU64(image.image_fingerprint);
                        try writer.writeU64(image.capsule_fingerprint);
                        try writer.writeU64(image.current_request_fingerprint);
                        try writer.writeLenBytes(image.bytes);
                    },
                    .done => |fingerprint| {
                        try writer.writeU8(3);
                        try writer.writeU64(fingerprint);
                    },
                    .exchange_event => |event| {
                        try writer.writeU8(4);
                        try writeJournalExchangeEvent(writer, event);
                    },
                }
            }

            fn readJournalEntry(reader: *ExchangeByteReader, allocator: std.mem.Allocator, format_version: u32) anyerror!Journal.Entry {
                return switch (try reader.readU8()) {
                    0 => .{ .request = try readJournalRequestTrace(reader, allocator) },
                    1 => blk: {
                        const trace: Trace.Response = .{
                            .request_fingerprint = try reader.readU64(),
                            .kind = try readJournalResponseKind(reader),
                            .response_ref = try readExchangeValueRef(reader),
                            .response_value_fingerprint = try reader.readU64(),
                            .fingerprint = try reader.readU64(),
                        };
                        if (trace.fingerprint != fingerprintJournalResponseTrace(trace)) return error.ProgramContractViolation;
                        const value_image = if (try reader.readBool()) blk_value: {
                            const image = try allocator.dupe(u8, try reader.readLenBytes());
                            errdefer allocator.free(image);
                            try validateJournalResponseValueImage(allocator, trace, image);
                            break :blk_value image;
                        } else null;
                        break :blk .{ .response = .{
                            .trace = trace,
                            .value_image = value_image,
                        } };
                    },
                    2 => blk: {
                        const image_fingerprint = try reader.readU64();
                        const capsule_fingerprint = try reader.readU64();
                        const current_request_fingerprint = try reader.readU64();
                        const source = try reader.readLenBytes();
                        const bytes = try allocator.dupe(u8, source);
                        errdefer allocator.free(bytes);
                        if (image_fingerprint != capsuleImageFingerprint(bytes)) return error.ProgramContractViolation;
                        var decoded = Core.Capsule.decode(allocator, bytes) catch |err| return mapProgramRunError(Error, err);
                        defer decoded.deinit();
                        const metadata = decoded.metadata();
                        if (capsule_fingerprint != decoded.fingerprint() or
                            current_request_fingerprint != metadata.current_request_fingerprint)
                        {
                            return error.ProgramContractViolation;
                        }
                        break :blk .{ .capsule_image = .{
                            .image_fingerprint = image_fingerprint,
                            .capsule_fingerprint = capsule_fingerprint,
                            .current_request_fingerprint = current_request_fingerprint,
                            .bytes = bytes,
                        } };
                    },
                    3 => .{ .done = try reader.readU64() },
                    4 => if (format_version >= 2)
                        .{ .exchange_event = try readJournalExchangeEvent(reader, allocator, format_version) }
                    else
                        error.ProgramContractViolation,
                    else => error.ProgramContractViolation,
                };
            }

            fn writeOptionalJournalU64(writer: *ExchangeByteWriter, value: ?u64) std.mem.Allocator.Error!void {
                try writer.writeBool(value != null);
                if (value) |actual| try writer.writeU64(actual);
            }

            fn readOptionalJournalU64(reader: *ExchangeByteReader) error{ProgramContractViolation}!?u64 {
                if (!try reader.readBool()) return null;
                return try reader.readU64();
            }

            fn writeJournalExchangeEventKind(writer: *ExchangeByteWriter, kind: Journal.ExchangeEvent.Kind) std.mem.Allocator.Error!void {
                try writer.writeU8(switch (kind) {
                    .provider_manifest_recorded => 0,
                    .capability_granted => 1,
                    .capability_attenuated => 2,
                    .route_selected => 3,
                    .route_blocked => 4,
                    .response_authorized => 5,
                    .response_rejected => 6,
                    .effect_session_opened => 7,
                    .capability_instance_created => 8,
                    .capability_instance_split => 9,
                    .capability_instance_consumed => 10,
                    .obligation_opened => 11,
                    .obligation_consumed => 12,
                    .obligation_replayed => 13,
                    .obligation_canceled => 14,
                    .obligation_rejected => 15,
                    .branch_policy_checked => 16,
                    .branch_rejected => 17,
                    .provider_offer_recorded => 18,
                    .morphism_offer_recorded => 19,
                    .treaty_requested => 20,
                    .treaty_selected => 21,
                    .treaty_blocked => 22,
                    .treaty_certificate_recorded => 23,
                    .treaty_authorization_recorded => 24,
                    .treaty_response_rejected => 25,
                    .treaty_response_accepted => 26,
                    .treaty_obligation_opened => 27,
                    .treaty_capability_attenuated => 28,
                    .treaty_capability_instance_selected => 29,
                    .treaty_replay_policy_checked => 30,
                    .treaty_branch_policy_checked => 31,
                    .provider_manifest_derived => 32,
                    .provider_offer_derived => 33,
                    .provider_request_received => 34,
                    .provider_request_validated => 35,
                    .provider_request_rejected => 36,
                    .provider_handler_invoked => 37,
                    .provider_response_built => 38,
                    .provider_response_authorized => 39,
                    .provider_response_forwarded => 40,
                    .provider_pending => 41,
                    .provider_program_started => 42,
                    .provider_program_parked => 43,
                    .provider_program_nested_request => 44,
                    .provider_program_nested_response => 45,
                    .provider_program_resumed => 46,
                    .provider_program_completed => 47,
                    .provider_program_rejected => 48,
                    .provider_program_failed => 49,
                });
            }

            fn readJournalExchangeEventKind(reader: *ExchangeByteReader, format_version: u32) error{ProgramContractViolation}!Journal.ExchangeEvent.Kind {
                const tag = try reader.readU8();
                if (format_version < 3 and tag > 6) return error.ProgramContractViolation;
                if (format_version < 4 and tag > 17) return error.ProgramContractViolation;
                if (format_version < 5 and tag > 31) return error.ProgramContractViolation;
                if (format_version < 6 and tag > 41) return error.ProgramContractViolation;
                return switch (tag) {
                    0 => .provider_manifest_recorded,
                    1 => .capability_granted,
                    2 => .capability_attenuated,
                    3 => .route_selected,
                    4 => .route_blocked,
                    5 => .response_authorized,
                    6 => .response_rejected,
                    7 => .effect_session_opened,
                    8 => .capability_instance_created,
                    9 => .capability_instance_split,
                    10 => .capability_instance_consumed,
                    11 => .obligation_opened,
                    12 => .obligation_consumed,
                    13 => .obligation_replayed,
                    14 => .obligation_canceled,
                    15 => .obligation_rejected,
                    16 => .branch_policy_checked,
                    17 => .branch_rejected,
                    18 => .provider_offer_recorded,
                    19 => .morphism_offer_recorded,
                    20 => .treaty_requested,
                    21 => .treaty_selected,
                    22 => .treaty_blocked,
                    23 => .treaty_certificate_recorded,
                    24 => .treaty_authorization_recorded,
                    25 => .treaty_response_rejected,
                    26 => .treaty_response_accepted,
                    27 => .treaty_obligation_opened,
                    28 => .treaty_capability_attenuated,
                    29 => .treaty_capability_instance_selected,
                    30 => .treaty_replay_policy_checked,
                    31 => .treaty_branch_policy_checked,
                    32 => .provider_manifest_derived,
                    33 => .provider_offer_derived,
                    34 => .provider_request_received,
                    35 => .provider_request_validated,
                    36 => .provider_request_rejected,
                    37 => .provider_handler_invoked,
                    38 => .provider_response_built,
                    39 => .provider_response_authorized,
                    40 => .provider_response_forwarded,
                    41 => .provider_pending,
                    42 => .provider_program_started,
                    43 => .provider_program_parked,
                    44 => .provider_program_nested_request,
                    45 => .provider_program_nested_response,
                    46 => .provider_program_resumed,
                    47 => .provider_program_completed,
                    48 => .provider_program_rejected,
                    49 => .provider_program_failed,
                    else => error.ProgramContractViolation,
                };
            }

            fn writeJournalExchangeEvent(writer: *ExchangeByteWriter, event: Journal.ExchangeEvent) anyerror!void {
                try writeJournalExchangeEventKind(writer, event.kind);
                try writeOptionalJournalU64(writer, event.provider_fingerprint);
                try writeOptionalJournalU64(writer, event.capability_fingerprint);
                try writeOptionalJournalU64(writer, event.route_fingerprint);
                try writeOptionalJournalU64(writer, event.authorization_fingerprint);
                try writeOptionalJournalU64(writer, event.request_envelope_fingerprint);
                try writeOptionalJournalU64(writer, event.response_envelope_fingerprint);
                try writeOptionalJournalU64(writer, event.capability_instance_fingerprint);
                try writeOptionalJournalU64(writer, event.obligation_fingerprint);
                try writeOptionalJournalU64(writer, event.obligation_transition_fingerprint);
                try writeOptionalJournalU64(writer, event.treaty_fingerprint);
                try writeOptionalJournalU64(writer, event.treaty_certificate_fingerprint);
                try writeOptionalJournalU64(writer, event.provider_offer_fingerprint);
                try writeOptionalJournalU64(writer, event.morphism_offer_fingerprint);
                try writeOptionalJournalU64(writer, event.branch_id);
                try writeOptionalJournalU64(writer, event.previous_state_fingerprint);
                try writeOptionalJournalU64(writer, event.next_state_fingerprint);
                try writeOptionalJournalU64(writer, event.provider_program_execution_fingerprint);
                try writeOptionalJournalU64(writer, event.provider_program_nested_request_fingerprint);
                try writer.writeBool(event.blocker_tag != null);
                if (event.blocker_tag) |tag| try writer.writeLenBytes(tag);
            }

            fn readJournalExchangeEvent(reader: *ExchangeByteReader, allocator: std.mem.Allocator, format_version: u32) anyerror!Journal.ExchangeEvent {
                const kind = try readJournalExchangeEventKind(reader, format_version);
                const provider_fingerprint = try readOptionalJournalU64(reader);
                const capability_fingerprint = try readOptionalJournalU64(reader);
                const route_fingerprint = try readOptionalJournalU64(reader);
                const authorization_fingerprint = try readOptionalJournalU64(reader);
                const request_envelope_fingerprint = try readOptionalJournalU64(reader);
                const response_envelope_fingerprint = try readOptionalJournalU64(reader);
                const capability_instance_fingerprint = if (format_version >= 3) try readOptionalJournalU64(reader) else null;
                const obligation_fingerprint = if (format_version >= 3) try readOptionalJournalU64(reader) else null;
                const obligation_transition_fingerprint = if (format_version >= 3) try readOptionalJournalU64(reader) else null;
                const treaty_fingerprint = if (format_version >= 4) try readOptionalJournalU64(reader) else null;
                const treaty_certificate_fingerprint = if (format_version >= 4) try readOptionalJournalU64(reader) else null;
                const provider_offer_fingerprint = if (format_version >= 4) try readOptionalJournalU64(reader) else null;
                const morphism_offer_fingerprint = if (format_version >= 4) try readOptionalJournalU64(reader) else null;
                const branch_id = if (format_version >= 3) try readOptionalJournalU64(reader) else null;
                const previous_state_fingerprint = if (format_version >= 3) try readOptionalJournalU64(reader) else null;
                const next_state_fingerprint = if (format_version >= 3) try readOptionalJournalU64(reader) else null;
                const provider_program_execution_fingerprint = if (format_version >= 6) try readOptionalJournalU64(reader) else null;
                const provider_program_nested_request_fingerprint = if (format_version >= 6) try readOptionalJournalU64(reader) else null;
                const blocker_tag = if (try reader.readBool()) blk: {
                    const tag = try allocator.dupe(u8, try reader.readLenBytes());
                    break :blk tag;
                } else null;
                return .{
                    .kind = kind,
                    .provider_fingerprint = provider_fingerprint,
                    .capability_fingerprint = capability_fingerprint,
                    .route_fingerprint = route_fingerprint,
                    .authorization_fingerprint = authorization_fingerprint,
                    .request_envelope_fingerprint = request_envelope_fingerprint,
                    .response_envelope_fingerprint = response_envelope_fingerprint,
                    .capability_instance_fingerprint = capability_instance_fingerprint,
                    .obligation_fingerprint = obligation_fingerprint,
                    .obligation_transition_fingerprint = obligation_transition_fingerprint,
                    .treaty_fingerprint = treaty_fingerprint,
                    .treaty_certificate_fingerprint = treaty_certificate_fingerprint,
                    .provider_offer_fingerprint = provider_offer_fingerprint,
                    .morphism_offer_fingerprint = morphism_offer_fingerprint,
                    .branch_id = branch_id,
                    .previous_state_fingerprint = previous_state_fingerprint,
                    .next_state_fingerprint = next_state_fingerprint,
                    .provider_program_execution_fingerprint = provider_program_execution_fingerprint,
                    .provider_program_nested_request_fingerprint = provider_program_nested_request_fingerprint,
                    .blocker_tag = blocker_tag,
                };
            }

            /// Start a host-driven execution session without leaving runtime execution active.
            pub fn start(runtime: *lowered_machine.Runtime, handlers: HandlersType) Error!Session {
                const mutable_handlers = handlers;
                const args = blk: {
                    try ensureRuntimeCanEnter(runtime);
                    lowered_machine.beginExecution(runtime) catch |err| return mapProgramRunError(Error, err);
                    defer lowered_machine.endExecution(runtime);
                    break :blk if (comptime hasDeclSafe(Body, "encodeArgs"))
                        Body.encodeArgs(mutable_handlers)
                    else
                        @as([]const lowered_machine.ProgramValue, &.{});
                };
                return startWithArgs(runtime, mutable_handlers, args);
            }

            /// Start a host-driven execution session with explicit caller-provided entry args.
            pub fn startWithArgs(runtime: *lowered_machine.Runtime, handlers: HandlersType, args: anytype) Error!Session {
                const mutable_handlers = handlers;
                try ensureRuntimeCanEnter(runtime);
                lowered_machine.beginExecution(runtime) catch |err| return mapProgramRunError(Error, err);
                defer lowered_machine.endExecution(runtime);

                var core = Core.start(lowered_machine.runtimeAllocator(runtime), args) catch |err| return mapProgramRunError(Error, err);
                var core_owned = true;
                errdefer if (core_owned) core.deinit();
                lowered_machine.registerLiveSession(runtime) catch |err| return mapProgramRunError(Error, err);
                core_owned = false;
                return .{
                    .runtime = runtime,
                    .handlers = mutable_handlers,
                    .core = core,
                };
            }

            /// Restore a fresh parked session from a reusable capsule for this program.
            pub fn restore(runtime: *lowered_machine.Runtime, handlers: HandlersType, capsule: *const Capsule) Error!Session {
                const mutable_handlers = handlers;
                try ensureRuntimeCanEnter(runtime);
                var core = Core.restore(lowered_machine.runtimeAllocator(runtime), &capsule._core) catch |err| return mapProgramRunError(Error, err);
                errdefer core.deinit();
                const lifecycle: Lifecycle = switch (core.current() catch |err| return mapProgramRunError(Error, err)) {
                    .request => .parked_on_request,
                    .after => .parked_on_after,
                    .none => return error.ProgramContractViolation,
                };
                lowered_machine.registerLiveSession(runtime) catch |err| return mapProgramRunError(Error, err);
                return .{
                    .runtime = runtime,
                    .handlers = mutable_handlers,
                    .core = core,
                    .lifecycle = lifecycle,
                };
            }

            /// Close an unfinished session and release runtime ownership.
            pub fn deinit(self: *Session) void {
                self.deinitChecked() catch |err|
                    std.debug.panic("runtime execution teardown misuse: {s}", .{@errorName(err)});
            }

            /// Close an unfinished session, returning an error on runtime ownership misuse.
            pub fn deinitChecked(self: *Session) Error!void {
                switch (self.lifecycle) {
                    .done, .deinitialized => return,
                    .running => return error.RuntimeBusy,
                    .parked_on_after, .parked_on_request, .ready => {},
                }
                try ensureRuntimeCanEnter(self.runtime);
                try self.closeChecked(.deinitialized);
            }

            /// Capture the currently parked continuation as a reusable capsule.
            pub fn capture(self: *Session, allocator: std.mem.Allocator) Error!Capsule {
                try ensureRuntimeCanEnter(self.runtime);
                switch (self.lifecycle) {
                    .parked_on_after, .parked_on_request => {},
                    .ready, .running, .done, .deinitialized => return error.ProgramContractViolation,
                }
                return .{
                    ._core = self.core.capture(allocator) catch |err| return mapProgramRunError(Error, err),
                };
            }

            /// Return the current parked request without advancing or entering runtime execution.
            pub fn current(self: *Session) Error!Current {
                try ensureRuntimeCanEnter(self.runtime);
                return switch (self.lifecycle) {
                    .ready, .done => .none,
                    .parked_on_after, .parked_on_request => self.core.current() catch |err| return mapProgramRunError(Error, err),
                    .running, .deinitialized => error.ProgramContractViolation,
                };
            }

            /// Advance until the next yielded request or terminal result.
            pub fn next(self: *Session) Error!Step {
                try self.enterRuntimeFrom(.ready);
                defer self.leaveRuntime();

                if (self.core.hasPendingRequest()) return error.ProgramContractViolation;
                const core_step = self.core.next() catch |err| {
                    self.closeAs(.deinitialized);
                    return mapProgramRunError(Error, err);
                };
                return switch (core_step) {
                    .request => |request| request: {
                        self.lifecycle = .parked_on_request;
                        break :request .{ .request = request };
                    },
                    .after => |after| after: {
                        self.lifecycle = .parked_on_after;
                        break :after .{ .after = after };
                    },
                    .done => |raw_result| done: {
                        var raw = raw_result;
                        const allocator = lowered_machine.runtimeAllocator(self.runtime);
                        var exchange_storage = self.takeExchangeResponseStorage();
                        errdefer deinitExchangeResponseStorage(allocator, &exchange_storage);
                        const exchange_cleanup_allocator = if (exchange_storage) |exchange| exchange.tracker.allocator() else null;
                        const result = if (comptime @typeInfo(HandlersType) == .pointer)
                            finishSessionResult(allocator, self.handlers, &raw, exchange_cleanup_allocator)
                        else
                            finishSessionResult(allocator, &self.handlers, &raw, exchange_cleanup_allocator);
                        var finished = result catch |err| {
                            raw.deinit();
                            self.closeAs(.deinitialized);
                            return err;
                        };
                        if (exchange_storage) |exchange| armExchangeResponseCleanupAllocator(&finished, exchange);
                        errdefer finished.deinit();
                        try attachExchangeResponseStorageToResult(allocator, &finished, &exchange_storage);
                        self.closeAs(.done);
                        break :done .{ .done = finished };
                    },
                };
            }

            /// Resume a yielded transform or choice request with a typed value.
            pub fn @"resume"(self: *Session, request: Request, value: anytype) Error!void {
                try self.enterRuntimeFrom(.parked_on_request);
                defer self.leaveRuntime();

                self.core.@"resume"(request, value) catch |err| {
                    self.lifecycle = .parked_on_request;
                    return mapProgramRunError(Error, err);
                };
                self.lifecycle = .ready;
            }

            /// Resume a typed operation request view with a value matching its static site descriptor.
            pub fn resumeTyped(self: *Session, typed_request: anytype, value: anytype) Error!void {
                const Site = @TypeOf(typed_request).Descriptor;
                _ = typed_request.request.responseTraceFor(Site, .@"resume", value) catch |err| return mapProgramRunError(Error, err);
                try self.@"resume"(typed_request.request, value);
            }

            /// Resume a yielded after-continuation request with the transformed value.
            pub fn resumeAfter(self: *Session, request: AfterRequest, value: anytype) Error!void {
                try self.enterRuntimeFrom(.parked_on_after);
                defer self.leaveRuntime();

                self.core.resumeAfter(request, value) catch |err| {
                    self.lifecycle = .parked_on_after;
                    return mapProgramRunError(Error, err);
                };
                self.lifecycle = .ready;
            }

            /// Resume a typed after-continuation request view with a value matching the live request output ref.
            pub fn resumeAfterTyped(self: *Session, typed_request: anytype, value: anytype) Error!void {
                const Site = @TypeOf(typed_request).Descriptor;
                _ = typed_request.request.responseTraceFor(Site, value) catch |err| return mapProgramRunError(Error, err);
                try self.resumeAfter(typed_request.request, value);
            }

            /// Complete a yielded choice or abort request with a terminal value.
            pub fn returnNow(self: *Session, request: Request, value: anytype) Error!void {
                try self.enterRuntimeFrom(.parked_on_request);
                defer self.leaveRuntime();

                self.core.returnNow(request, value) catch |err| {
                    self.lifecycle = .parked_on_request;
                    return mapProgramRunError(Error, err);
                };
                self.lifecycle = .ready;
            }

            /// Complete a typed choice or abort request view with a terminal value matching its static site descriptor.
            pub fn returnNowTyped(self: *Session, typed_request: anytype, value: anytype) Error!void {
                const Site = @TypeOf(typed_request).Descriptor;
                _ = typed_request.request.responseTraceFor(Site, .return_now, value) catch |err| return mapProgramRunError(Error, err);
                try self.returnNow(typed_request.request, value);
            }

            fn ensureRuntimeCanEnter(runtime: *lowered_machine.Runtime) Error!void {
                runtime.ensureThread() catch |err| return mapProgramRunError(Error, err);
                if (lowered_machine.activeRuntime() != null) return error.RuntimeBusy;
            }

            fn enterRuntimeFrom(self: *Session, expected: Lifecycle) Error!void {
                try ensureRuntimeCanEnter(self.runtime);
                if (self.lifecycle != expected) return error.ProgramContractViolation;
                lowered_machine.beginExecution(self.runtime) catch |err| return mapProgramRunError(Error, err);
                self.lifecycle = .running;
            }

            fn leaveRuntime(self: *Session) void {
                lowered_machine.endExecution(self.runtime);
            }

            fn close(self: *Session) void {
                self.closeChecked(.deinitialized) catch |err|
                    std.debug.panic("runtime execution teardown misuse: {s}", .{@errorName(err)});
            }

            fn closeAs(self: *Session, final_lifecycle: Lifecycle) void {
                self.closeChecked(final_lifecycle) catch |err|
                    std.debug.panic("runtime execution teardown misuse: {s}", .{@errorName(err)});
            }

            fn closeChecked(self: *Session, final_lifecycle: Lifecycle) Error!void {
                switch (self.lifecycle) {
                    .done, .deinitialized => return,
                    .parked_on_after, .parked_on_request, .ready, .running => {},
                }
                if (self.live_registered) {
                    lowered_machine.unregisterLiveSession(self.runtime) catch |err| return mapProgramRunError(Error, err);
                    self.live_registered = false;
                }
                self.deinitCompletedResult();
                self.core.deinit();
                self.lifecycle = final_lifecycle;
            }

            fn deinitCompletedResult(self: *Session) void {
                const allocator = lowered_machine.runtimeAllocator(self.runtime);
                var exchange_storage = self.takeExchangeResponseStorage();
                defer deinitExchangeResponseStorage(allocator, &exchange_storage);
                const completed = self.core.takeCompleted() catch |err|
                    std.debug.panic("completed session result decode failed during deinit: {s}", .{@errorName(err)});
                if (completed) |raw_result| {
                    var raw = raw_result;
                    defer raw.deinit();
                    const result_cleanup = comptime bodyDeinitResultMode(Body, Value, ProgramOutputs);
                    if (result_cleanup == .none) return;
                    var storage = raw.takeStorage();
                    defer if (storage) |*owned| owned.deinit();
                    if (storage != null) {
                        var owned = cloneBodyOwnedResultWithTrackedStorage(Value, allocator, raw.value) catch |err|
                            std.debug.panic("completed session result clone failed during deinit: {s}", .{@errorName(err)});
                        defer owned.storage.deinit();
                        deinitBodyResult(Body, Value, ProgramOutputs, .{
                            .allocator = owned.cleanup_allocator,
                            .value = owned.value,
                            .outputs = null,
                        });
                        return;
                    }
                    if (exchange_storage) |exchange| {
                        deinitBodyResult(Body, Value, ProgramOutputs, .{
                            .allocator = exchange.tracker.allocator(),
                            .value = raw.value,
                            .outputs = null,
                        });
                        return;
                    }
                    deinitBodyResult(Body, Value, ProgramOutputs, .{
                        .allocator = allocator,
                        .value = raw.value,
                        .outputs = null,
                    });
                }
            }
        };

        /// Transport-neutral typed envelopes for exchanging yielded effects across host boundaries.
        pub const Exchange = struct {
            const manifest_magic = "ABL_EXM1";
            const request_magic = "ABL_EXQ1";
            const response_magic = "ABL_EXR1";
            const provider_magic = "ABL_EXP1";
            const provider_offer_magic = "ABL_EXO1";
            const provider_offer_program_format_version: u32 = exchange_provider_program_offer_format_version;
            const treaty_authorization_magic = "ABL_EXT1";
            const capability_magic = "ABL_EXC1";
            const authorization_magic = "ABL_EXA1";
            const exchange_manifest_journal_format_version: u32 = 5;

            /// Current encoded manifest image format version.
            pub const manifest_format_version = exchange_manifest_format_version;
            /// Current manifest image fingerprint domain version.
            pub const manifest_fingerprint_version = exchange_manifest_fingerprint_version;
            /// Current encoded request envelope format version.
            pub const request_format_version = exchange_request_format_version;
            /// Current request envelope fingerprint domain version.
            pub const request_fingerprint_version = exchange_request_fingerprint_version;
            /// Current encoded response envelope format version.
            pub const response_format_version = exchange_response_format_version;
            /// Current response envelope fingerprint domain version.
            pub const response_fingerprint_version = exchange_response_fingerprint_version;
            /// Current provider manifest image format version.
            pub const provider_format_version = exchange_provider_format_version;
            /// Current provider manifest image fingerprint domain version.
            pub const provider_fingerprint_version = exchange_provider_fingerprint_version;
            /// Current provider identity fingerprint domain version.
            pub const provider_identity_fingerprint_version = exchange_provider_identity_fingerprint_version;
            /// Current provider offer image format version.
            pub const provider_offer_format_version = exchange_provider_offer_format_version;
            /// Current program-backed provider offer image format version.
            pub const provider_program_offer_format_version = exchange_provider_program_offer_format_version;
            /// Current provider offer image fingerprint domain version.
            pub const provider_offer_fingerprint_version = exchange_provider_offer_fingerprint_version;
            /// Current provider harness declaration fingerprint domain version.
            pub const provider_harness_fingerprint_version = exchange_provider_harness_fingerprint_version;
            /// Current provider-program execution fingerprint domain version.
            pub const provider_program_execution_fingerprint_version = exchange_provider_program_execution_fingerprint_version;
            /// Current provider-program mapping fingerprint domain version.
            pub const provider_program_mapping_fingerprint_version = exchange_provider_program_mapping_fingerprint_version;
            /// Current provider-program nested request fingerprint domain version.
            pub const provider_program_nested_request_fingerprint_version = exchange_provider_program_nested_request_fingerprint_version;
            /// Current morphism offer fingerprint domain version.
            pub const morphism_offer_fingerprint_version = exchange_morphism_offer_fingerprint_version;
            /// Current capability grant image format version.
            pub const capability_format_version = exchange_capability_format_version;
            /// Current capability grant image fingerprint domain version.
            pub const capability_fingerprint_version = exchange_capability_fingerprint_version;
            /// Current authorization witness fingerprint domain version.
            pub const authorization_fingerprint_version = exchange_authorization_fingerprint_version;
            /// Current route witness fingerprint domain version.
            pub const route_fingerprint_version = exchange_route_fingerprint_version;
            /// Current effect-session spec image format version.
            pub const effect_session_format_version = exchange_effect_session_format_version;
            /// Current effect-session spec fingerprint domain version.
            pub const effect_session_fingerprint_version = exchange_effect_session_fingerprint_version;
            /// Current capability-instance image format version.
            pub const capability_instance_format_version = exchange_capability_instance_format_version;
            /// Current capability-instance fingerprint domain version.
            pub const capability_instance_fingerprint_version = exchange_capability_instance_fingerprint_version;
            /// Current obligation image format version.
            pub const obligation_format_version = exchange_obligation_format_version;
            /// Current obligation fingerprint domain version.
            pub const obligation_fingerprint_version = exchange_obligation_fingerprint_version;
            /// Current obligation transition fingerprint domain version.
            pub const obligation_transition_fingerprint_version = exchange_obligation_transition_fingerprint_version;
            /// Current authorization-result fingerprint domain version.
            pub const authorization_result_fingerprint_version = exchange_authorization_result_fingerprint_version;
            /// Current treaty format version.
            pub const treaty_format_version = exchange_treaty_format_version;
            /// Current treaty fingerprint domain version.
            pub const treaty_fingerprint_version = exchange_treaty_fingerprint_version;
            /// Current treaty certificate fingerprint domain version.
            pub const treaty_certificate_fingerprint_version = exchange_treaty_certificate_fingerprint_version;
            /// Current treaty authorization fingerprint domain version.
            pub const treaty_authorization_fingerprint_version = exchange_treaty_authorization_fingerprint_version;
            /// Stable fingerprint for scoping capability grants to a journal branch id.
            pub fn journalPolicyFingerprint(journal_branch_id: []const u8) u64 {
                return journalBranchPolicyFingerprint(journal_branch_id);
            }

            /// Dynamic exchange request kind yielded by a parked session.
            pub const RequestKind = enum {
                operation,
                after,
            };

            /// Dynamic exchange response kind accepted by a parked session.
            pub const ResponseKind = Session.Trace.ResponseKind;

            /// Usage discipline for an externalized exchanged effect.
            pub const Usage = enum {
                copyable,
                replayable,
                affine,
                linear,
                ephemeral,
            };

            /// Class of response use when satisfying an exchange obligation.
            pub const ResponseUse = enum {
                fresh,
                replayed,
                deterministic_replay,
                override,
            };

            /// Branch discipline applied to reusable capsules while an effect is open.
            pub const BranchPolicy = enum {
                unrestricted,
                replay_only,
                single_live_branch,
                split_required,
                no_branch,
                host_owned,
            };

            /// Capsule export policy used by provider offers and treaty requests.
            pub const CapsulePolicy = enum {
                required,
                allowed,
                forbidden,

                /// Return true when this capsule policy admits the request shape.
                pub fn allows(self: @This(), has_capsule: bool) bool {
                    return switch (self) {
                        .required => has_capsule,
                        .allowed => true,
                        .forbidden => !has_capsule,
                    };
                }
            };

            /// Compact allow set for exchange usage modes.
            pub const UsageSet = struct {
                copyable: bool = true,
                replayable: bool = true,
                affine: bool = true,
                linear: bool = true,
                ephemeral: bool = true,

                /// Return true when this set allows the usage mode.
                pub fn allows(self: @This(), usage: Usage) bool {
                    return switch (usage) {
                        .copyable => self.copyable,
                        .replayable => self.replayable,
                        .affine => self.affine,
                        .linear => self.linear,
                        .ephemeral => self.ephemeral,
                    };
                }
            };

            /// Compact allow set for response-use classes and replay policies.
            pub const ResponseUseSet = struct {
                fresh: bool = true,
                replayed: bool = true,
                deterministic_replay: bool = true,
                override: bool = true,

                /// Return true when this set allows the response-use class.
                pub fn allows(self: @This(), use_value: ResponseUse) bool {
                    return switch (use_value) {
                        .fresh => self.fresh,
                        .replayed => self.replayed,
                        .deterministic_replay => self.deterministic_replay,
                        .override => self.override,
                    };
                }
            };

            /// Compact allow set for branch policies.
            pub const BranchPolicySet = struct {
                unrestricted: bool = true,
                replay_only: bool = true,
                single_live_branch: bool = true,
                split_required: bool = true,
                no_branch: bool = true,
                host_owned: bool = true,

                /// Return true when this set allows the branch policy.
                pub fn allows(self: @This(), policy_value: BranchPolicy) bool {
                    return switch (policy_value) {
                        .unrestricted => self.unrestricted,
                        .replay_only => self.replay_only,
                        .single_live_branch => self.single_live_branch,
                        .split_required => self.split_required,
                        .no_branch => self.no_branch,
                        .host_owned => self.host_owned,
                    };
                }
            };

            /// Lifecycle status for an exchange obligation.
            pub const ObligationStatus = enum {
                open,
                consumed,
                canceled,
                replayed,
                abandoned,
            };

            /// Declarative state-machine descriptor for exchanged effect usage.
            pub const EffectSessionSpec = struct {
                label: []const u8,
                initial_state: []const u8,
                states: []const []const u8,
                terminal_states: []const []const u8 = &.{},
                transitions: []const Transition = &.{},
                usage: Usage = .copyable,
                branch_policy: BranchPolicy = .unrestricted,
                replay_policy: ResponseUse = .fresh,
                provider_fingerprint: ?u64 = null,
                capability_fingerprint: ?u64 = null,

                /// One request, response, or cancel transition in an effect session spec.
                pub const Transition = struct {
                    kind: Kind,
                    from: []const u8,
                    to: []const u8,
                    site_fingerprint: ?u64 = null,
                    response_kind: ?ResponseKind = null,
                    response_ref: ?lowering_api.ValueRef = null,

                    /// Transition class.
                    pub const Kind = enum {
                        request,
                        response,
                        cancel,
                    };
                };

                /// Validate that labels, states, and transitions are internally coherent.
                pub fn validate(self: @This()) Error!void {
                    if (self.label.len == 0 or self.initial_state.len == 0) return error.ProgramContractViolation;
                    if (!self.hasState(self.initial_state)) return error.ProgramContractViolation;
                    for (self.terminal_states) |state| if (!self.hasState(state)) return error.ProgramContractViolation;
                    for (self.transitions, 0..) |transition, index| {
                        if (!self.hasState(transition.from) or !self.hasState(transition.to)) return error.ProgramContractViolation;
                        if (transition.kind == .response and transition.response_kind == null) return error.ProgramContractViolation;
                        if (transition.kind == .cancel) {
                            for (self.transitions[index + 1 ..]) |other| {
                                if (other.kind == .cancel and std.mem.eql(u8, other.from, transition.from)) return error.ProgramContractViolation;
                            }
                        }
                    }
                }

                /// Deterministic fingerprint for this session spec.
                pub fn fingerprint(self: @This()) u64 {
                    return fingerprintEffectSessionSpec(self);
                }

                /// Canonical evidence reference for this effect-session spec.
                pub fn evidenceRef(self: @This()) Evidence.Ref {
                    return Evidence.refFor(Evidence.domains.effect_session_spec, self.fingerprint(), .{ .label = self.label });
                }

                /// Return true when this state is terminal.
                pub fn terminal(self: @This(), state: []const u8) bool {
                    for (self.terminal_states) |terminal_state| {
                        if (std.mem.eql(u8, terminal_state, state)) return true;
                    }
                    return false;
                }

                /// Return the target state for a valid response transition.
                pub fn responseTarget(self: @This(), from: []const u8, kind_value: ResponseKind, response_ref: lowering_api.ValueRef, site_fingerprint: u64) Error![]const u8 {
                    try self.validate();
                    var target: ?[]const u8 = null;
                    for (self.transitions) |transition| {
                        if (transition.kind != .response) continue;
                        if (!std.mem.eql(u8, transition.from, from)) continue;
                        if (transition.response_kind != null and transition.response_kind.? != kind_value) continue;
                        if (transition.response_ref) |ref| {
                            if (!ref.eql(response_ref)) continue;
                        }
                        if (transition.site_fingerprint) |transition_site_fingerprint| {
                            if (transition_site_fingerprint != site_fingerprint) continue;
                        }
                        if (target != null) return error.ProgramContractViolation;
                        target = transition.to;
                    }
                    return target orelse error.ProgramContractViolation;
                }

                /// Return the target state for a matching request transition, if one is declared.
                pub fn requestTarget(self: @This(), from: []const u8, site_fingerprint: u64) Error!?[]const u8 {
                    try self.validate();
                    var target: ?[]const u8 = null;
                    for (self.transitions) |transition| {
                        if (transition.kind != .request) continue;
                        if (!std.mem.eql(u8, transition.from, from)) continue;
                        if (transition.site_fingerprint) |transition_site_fingerprint| {
                            if (transition_site_fingerprint != site_fingerprint) continue;
                        }
                        if (target != null) return error.ProgramContractViolation;
                        target = transition.to;
                    }
                    return target;
                }

                /// Return the target state for a valid cancellation transition.
                pub fn cancelTarget(self: @This(), from: []const u8) Error![]const u8 {
                    try self.validate();
                    var target: ?[]const u8 = null;
                    for (self.transitions) |transition| {
                        if (transition.kind != .cancel or !std.mem.eql(u8, transition.from, from)) continue;
                        if (target != null) return error.ProgramContractViolation;
                        target = transition.to;
                    }
                    return target orelse error.ProgramContractViolation;
                }

                fn hasState(self: @This(), state: []const u8) bool {
                    for (self.states) |known| if (std.mem.eql(u8, known, state)) return true;
                    return false;
                }
            };

            /// Deterministic metadata for one live consumable capability instance.
            pub const CapabilityInstance = struct {
                instance_version: u32 = exchange_capability_instance_format_version,
                instance_fingerprint: u64 = 0,
                parent_capability_fingerprint: u64,
                provider_fingerprint: u64,
                manifest_fingerprint: u64,
                effect_session_spec_fingerprint: u64,
                current_state: []const u8,
                usage: Usage,
                branch_id: u64 = 0,
                opened_request_fingerprint: ?u64 = null,
                consumed_response_fingerprint: ?u64 = null,
                canceled: bool = false,
                replay_source_fingerprint: ?u64 = null,
                logical_generation: u64 = 0,
                parent_instance_fingerprint: ?u64 = null,
                path_fingerprint: u64 = 0,
                branch_policy: BranchPolicy = .unrestricted,
                replay_policy: ResponseUse = .fresh,
                allowed_request_kinds: RequestKindSet = .{},
                allowed_operation_sites: []const usize = &.{},
                allowed_after_sites: []const usize = &.{},
                allowed_protocol_op_fingerprints: []const u64 = &.{},
                allowed_requirement_labels: []const []const u8 = &.{},
                allowed_op_names: []const []const u8 = &.{},
                allowed_response_kinds: Policy.ResponseKindSet = .{},
                allowed_response_refs: []const lowering_api.ValueRef = &.{},
                allow_embedded_capsule_response_handling: bool = true,
                max_request_bytes: usize = std.math.maxInt(usize),
                max_response_bytes: usize = std.math.maxInt(usize),
                max_payload_bytes: usize = std.math.maxInt(usize),
                max_capsule_image_bytes: usize = std.math.maxInt(usize),
                journal_policy_fingerprint: ?u64 = null,
                expires_at_generation: ?u64 = null,
                snapshot_allocator: ?std.mem.Allocator = null,

                /// Options for creating a capability instance.
                pub const CreateOptions = struct {
                    snapshot_allocator: std.mem.Allocator,
                    branch_id: u64 = 0,
                    initial_state: ?[]const u8 = null,
                    usage: ?Usage = null,
                    branch_policy: ?BranchPolicy = null,
                };

                /// Options for splitting a capability instance.
                pub const SplitOptions = struct {
                    branch_id: u64,
                    policy: BranchPolicy = .single_live_branch,
                };

                /// Create a consumable instance from a capability grant and session spec.
                pub fn create(capability: Capability, provider: ProviderManifest, spec: EffectSessionSpec, options: CreateOptions) Error!@This() {
                    try spec.validate();
                    if (!capabilityFieldsBoundToBytes(capability)) return error.ProgramContractViolation;
                    if (!providerFieldsBoundToBytes(provider)) return error.ProgramContractViolation;
                    if (capability.provider_fingerprint != provider.provider_fingerprint) return error.ProgramContractViolation;
                    if (!listAllowsU64(provider.supported_program_manifest_fingerprints, capability.manifest_fingerprint)) return error.ProgramContractViolation;
                    if (!providerCoversCapabilityScope(provider, capability)) return error.ProgramContractViolation;
                    if (!listAllowsString(capability.allowed_program_labels, label)) return error.ProgramContractViolation;
                    if (!listAllowsU64(capability.allowed_plan_hashes, body_compiled_plan_hash)) return error.ProgramContractViolation;
                    if (spec.provider_fingerprint) |fingerprint| {
                        if (fingerprint != provider.provider_fingerprint) return error.ProgramContractViolation;
                    }
                    if (spec.capability_fingerprint) |fingerprint| {
                        if (fingerprint != capability.fingerprint) return error.ProgramContractViolation;
                    }
                    const usage = options.usage orelse spec.usage;
                    const branch_policy = options.branch_policy orelse spec.branch_policy;
                    if (!usageDisciplineAllowsInstance(spec.usage, usage)) return error.ProgramContractViolation;
                    if (!branchPolicyAllowsInstance(spec.branch_policy, branch_policy)) return error.ProgramContractViolation;
                    const current_state = options.initial_state orelse spec.initial_state;
                    if (!spec.hasState(current_state)) return error.ProgramContractViolation;
                    const allocator = options.snapshot_allocator;
                    const owned_state = try allocator.dupe(u8, current_state);
                    errdefer allocator.free(owned_state);
                    const operation_sites = try cloneUsizes(allocator, capability.allowed_operation_sites);
                    errdefer allocator.free(operation_sites);
                    const after_sites = try cloneUsizes(allocator, capability.allowed_after_sites);
                    errdefer allocator.free(after_sites);
                    const protocol_ops = try cloneU64s(allocator, capability.allowed_protocol_op_fingerprints);
                    errdefer allocator.free(protocol_ops);
                    const requirement_labels = try cloneStringList(allocator, capability.allowed_requirement_labels);
                    errdefer freeStringList(allocator, requirement_labels);
                    const op_names = try cloneStringList(allocator, capability.allowed_op_names);
                    errdefer freeStringList(allocator, op_names);
                    const response_refs = try cloneValueRefs(allocator, capability.allowed_response_refs);
                    errdefer allocator.free(response_refs);
                    var instance = CapabilityInstance{
                        .parent_capability_fingerprint = capability.fingerprint,
                        .provider_fingerprint = provider.provider_fingerprint,
                        .manifest_fingerprint = capability.manifest_fingerprint,
                        .effect_session_spec_fingerprint = spec.fingerprint(),
                        .current_state = owned_state,
                        .usage = usage,
                        .branch_id = options.branch_id,
                        .path_fingerprint = capability.attenuation_path_fingerprint,
                        .branch_policy = branch_policy,
                        .replay_policy = spec.replay_policy,
                        .allowed_request_kinds = capability.allowed_request_kinds,
                        .allowed_operation_sites = operation_sites,
                        .allowed_after_sites = after_sites,
                        .allowed_protocol_op_fingerprints = protocol_ops,
                        .allowed_requirement_labels = requirement_labels,
                        .allowed_op_names = op_names,
                        .allowed_response_kinds = capability.allowed_response_kinds,
                        .allowed_response_refs = response_refs,
                        .allow_embedded_capsule_response_handling = capability.allow_embedded_capsule_response_handling,
                        .max_request_bytes = capability.max_request_bytes,
                        .max_response_bytes = capability.max_response_bytes,
                        .max_payload_bytes = capability.max_payload_bytes,
                        .max_capsule_image_bytes = capability.max_capsule_image_bytes,
                        .journal_policy_fingerprint = capability.journal_policy_fingerprint,
                        .expires_at_generation = capability.expires_at_generation,
                        .snapshot_allocator = allocator,
                    };
                    instance.instance_fingerprint = fingerprintCapabilityInstance(instance);
                    return instance;
                }

                /// Return true once this instance can no longer accept a fresh response.
                pub fn closed(self: @This()) bool {
                    return self.canceled or self.consumed_response_fingerprint != null;
                }

                /// Return true when the stored fingerprint still matches the instance fields.
                pub fn validFingerprint(self: @This()) bool {
                    if (self.instance_fingerprint == 0) return false;
                    return self.instance_fingerprint == fingerprintCapabilityInstance(self);
                }

                /// Canonical evidence reference for this capability instance.
                pub fn evidenceRef(self: @This()) Evidence.Ref {
                    return Evidence.refFor(Evidence.domains.capability_instance, self.instance_fingerprint, .{
                        .format_version = self.instance_version,
                        .branch_id = self.branch_id,
                    });
                }

                /// Release capability-instance-owned authority snapshots.
                pub fn deinit(self: *@This()) void {
                    const allocator = self.snapshot_allocator orelse return;
                    allocator.free(self.current_state);
                    allocator.free(self.allowed_operation_sites);
                    allocator.free(self.allowed_after_sites);
                    allocator.free(self.allowed_protocol_op_fingerprints);
                    freeStringList(allocator, self.allowed_requirement_labels);
                    freeStringList(allocator, self.allowed_op_names);
                    allocator.free(self.allowed_response_refs);
                    self.current_state = &.{};
                    self.allowed_operation_sites = &.{};
                    self.allowed_after_sites = &.{};
                    self.allowed_protocol_op_fingerprints = &.{};
                    self.allowed_requirement_labels = &.{};
                    self.allowed_op_names = &.{};
                    self.allowed_response_refs = &.{};
                    self.snapshot_allocator = null;
                }

                /// Clone this owned instance image so value-returning transitions do not alias owned snapshots.
                pub fn clone(self: @This()) Error!@This() {
                    if (!self.validFingerprint()) return error.ProgramContractViolation;
                    const allocator = self.snapshot_allocator orelse return error.ProgramContractViolation;
                    const owned_state = try allocator.dupe(u8, self.current_state);
                    errdefer allocator.free(owned_state);
                    const operation_sites = try cloneUsizes(allocator, self.allowed_operation_sites);
                    errdefer allocator.free(operation_sites);
                    const after_sites = try cloneUsizes(allocator, self.allowed_after_sites);
                    errdefer allocator.free(after_sites);
                    const protocol_ops = try cloneU64s(allocator, self.allowed_protocol_op_fingerprints);
                    errdefer allocator.free(protocol_ops);
                    const requirement_labels = try cloneStringList(allocator, self.allowed_requirement_labels);
                    errdefer freeStringList(allocator, requirement_labels);
                    const op_names = try cloneStringList(allocator, self.allowed_op_names);
                    errdefer freeStringList(allocator, op_names);
                    const response_refs = try cloneValueRefs(allocator, self.allowed_response_refs);
                    errdefer allocator.free(response_refs);
                    var cloned = self;
                    cloned.current_state = owned_state;
                    cloned.allowed_operation_sites = operation_sites;
                    cloned.allowed_after_sites = after_sites;
                    cloned.allowed_protocol_op_fingerprints = protocol_ops;
                    cloned.allowed_requirement_labels = requirement_labels;
                    cloned.allowed_op_names = op_names;
                    cloned.allowed_response_refs = response_refs;
                    return cloned;
                }

                fn requestMetadataInstanceFingerprint(self: @This(), request_fingerprint: u64, state_at_open: ?[]const u8) u64 {
                    if (self.opened_request_fingerprint) |opened_request| {
                        if (opened_request == request_fingerprint) {
                            var unopened = self;
                            if (state_at_open) |state| unopened.current_state = state;
                            unopened.opened_request_fingerprint = null;
                            unopened.consumed_response_fingerprint = null;
                            unopened.canceled = false;
                            unopened.replay_source_fingerprint = null;
                            unopened.instance_fingerprint = 0;
                            return fingerprintCapabilityInstance(unopened);
                        }
                    }
                    return self.instance_fingerprint;
                }

                /// Split or delegate this live capability instance for another branch.
                pub fn split(self: *@This(), options: SplitOptions) Error!@This() {
                    if (!self.validFingerprint()) return error.ProgramContractViolation;
                    if (self.closed()) return error.ProgramContractViolation;
                    if (!branchPolicyAllowsSplit(self.branch_policy, options.policy, self.usage)) return error.ProgramContractViolation;
                    const parent_fingerprint = self.instance_fingerprint;
                    const parent_path_fingerprint = self.path_fingerprint;
                    const consumes_live_split = (self.usage == .linear or self.usage == .affine) and
                        self.branch_policy == .split_required and
                        options.policy == .single_live_branch;
                    const allocator = self.snapshot_allocator orelse return error.ProgramContractViolation;
                    const operation_sites = try cloneUsizes(allocator, self.allowed_operation_sites);
                    errdefer allocator.free(operation_sites);
                    const after_sites = try cloneUsizes(allocator, self.allowed_after_sites);
                    errdefer allocator.free(after_sites);
                    const protocol_ops = try cloneU64s(allocator, self.allowed_protocol_op_fingerprints);
                    errdefer allocator.free(protocol_ops);
                    const requirement_labels = try cloneStringList(allocator, self.allowed_requirement_labels);
                    errdefer freeStringList(allocator, requirement_labels);
                    const op_names = try cloneStringList(allocator, self.allowed_op_names);
                    errdefer freeStringList(allocator, op_names);
                    const response_refs = try cloneValueRefs(allocator, self.allowed_response_refs);
                    errdefer allocator.free(response_refs);
                    var child = self.*;
                    const owned_state = try allocator.dupe(u8, self.current_state);
                    errdefer allocator.free(owned_state);
                    child.current_state = owned_state;
                    child.allowed_operation_sites = operation_sites;
                    child.allowed_after_sites = after_sites;
                    child.allowed_protocol_op_fingerprints = protocol_ops;
                    child.allowed_requirement_labels = requirement_labels;
                    child.allowed_op_names = op_names;
                    child.allowed_response_refs = response_refs;
                    child.branch_id = options.branch_id;
                    child.logical_generation = self.logical_generation + 1;
                    child.parent_instance_fingerprint = parent_fingerprint;
                    child.branch_policy = options.policy;
                    child.path_fingerprint = capabilityInstancePathFingerprint(parent_fingerprint, parent_path_fingerprint, options.branch_id, options.policy);
                    child.instance_fingerprint = 0;
                    child.instance_fingerprint = fingerprintCapabilityInstance(child);
                    if (consumes_live_split) {
                        self.branch_policy = .replay_only;
                        self.instance_fingerprint = 0;
                        self.instance_fingerprint = fingerprintCapabilityInstance(self.*);
                    }
                    return child;
                }

                /// Mark the capability instance as having opened a request.
                pub fn opened(self: @This(), request_fingerprint: u64) Error!@This() {
                    if (!self.validFingerprint()) return error.ProgramContractViolation;
                    if (self.closed()) return error.ProgramContractViolation;
                    if ((self.usage == .linear or self.usage == .affine) and self.opened_request_fingerprint != null) return error.ProgramContractViolation;
                    var next = try self.clone();
                    next.opened_request_fingerprint = request_fingerprint;
                    next.instance_fingerprint = 0;
                    next.instance_fingerprint = fingerprintCapabilityInstance(next);
                    return next;
                }

                /// Mark this instance consumed by a response fingerprint.
                pub fn consume(self: @This(), response_fingerprint: u64) Error!@This() {
                    return self.consumeWithState(response_fingerprint, self.current_state);
                }

                /// Mark this instance consumed and advance to a validated effect-session state.
                pub fn consumeWithState(self: @This(), response_fingerprint: u64, next_state: []const u8) Error!@This() {
                    if (!self.validFingerprint()) return error.ProgramContractViolation;
                    if (self.closed()) return error.ProgramContractViolation;
                    var next = try self.clone();
                    errdefer next.deinit();
                    const allocator = next.snapshot_allocator orelse return error.ProgramContractViolation;
                    const owned_state = try allocator.dupe(u8, next_state);
                    allocator.free(next.current_state);
                    next.current_state = owned_state;
                    next.consumed_response_fingerprint = response_fingerprint;
                    next.instance_fingerprint = 0;
                    next.instance_fingerprint = fingerprintCapabilityInstance(next);
                    return next;
                }

                /// Advance a reusable instance to a validated session state without consuming it.
                pub fn advanceState(self: @This(), next_state: []const u8) Error!@This() {
                    if (!self.validFingerprint()) return error.ProgramContractViolation;
                    if (self.canceled) return error.ProgramContractViolation;
                    var next = try self.clone();
                    errdefer next.deinit();
                    const allocator = next.snapshot_allocator orelse return error.ProgramContractViolation;
                    const owned_state = try allocator.dupe(u8, next_state);
                    allocator.free(next.current_state);
                    next.current_state = owned_state;
                    next.instance_fingerprint = 0;
                    next.instance_fingerprint = fingerprintCapabilityInstance(next);
                    return next;
                }

                /// Apply a validated response authorization to the instance image.
                pub fn applyAuthorization(self: @This(), response_fingerprint: u64, authorization: AuthorizationResult) Error!@This() {
                    if (!self.validFingerprint()) return error.ProgramContractViolation;
                    if (self.canceled) return error.ProgramContractViolation;
                    if (authorization.result_fingerprint != fingerprintAuthorizationResult(authorization)) return error.ProgramContractViolation;
                    const response_uses_replay = authorization.response_use == .replayed or authorization.response_use == .deterministic_replay;
                    if (authorization.capability_instance_fingerprint != self.instance_fingerprint) return error.ProgramContractViolation;
                    if (authorization.response_fingerprint != response_fingerprint) return error.ProgramContractViolation;
                    if (self.closed() and !response_uses_replay) return error.ProgramContractViolation;
                    if ((self.usage == .linear or self.usage == .affine) and !authorization.capability_instance_consumed and !self.closed()) return error.ProgramContractViolation;
                    if (response_uses_replay and authorization.capability_instance_consumed) return error.ProgramContractViolation;
                    var next = try self.clone();
                    errdefer next.deinit();
                    const allocator = next.snapshot_allocator orelse return error.ProgramContractViolation;
                    const owned_state = try allocator.dupe(u8, authorization.next_session_state);
                    allocator.free(next.current_state);
                    next.current_state = owned_state;
                    if (authorization.capability_instance_consumed) {
                        if (self.closed()) return error.ProgramContractViolation;
                        next.consumed_response_fingerprint = response_fingerprint;
                    }
                    next.instance_fingerprint = 0;
                    next.instance_fingerprint = fingerprintCapabilityInstance(next);
                    return next;
                }

                /// Mark this instance canceled.
                pub fn cancel(self: @This()) Error!@This() {
                    return self.cancelWithState(self.current_state);
                }

                /// Mark this instance canceled at a validated session state.
                pub fn cancelWithState(self: @This(), next_state: []const u8) Error!@This() {
                    if (!self.validFingerprint()) return error.ProgramContractViolation;
                    if (self.closed()) return error.ProgramContractViolation;
                    var next = try self.clone();
                    errdefer next.deinit();
                    const allocator = next.snapshot_allocator orelse return error.ProgramContractViolation;
                    const owned_state = try allocator.dupe(u8, next_state);
                    allocator.free(next.current_state);
                    next.current_state = owned_state;
                    next.canceled = true;
                    next.instance_fingerprint = 0;
                    next.instance_fingerprint = fingerprintCapabilityInstance(next);
                    return next;
                }
            };

            fn usageDisciplineAllowsInstance(spec_usage: Usage, instance_usage: Usage) bool {
                return instance_usage == spec_usage;
            }

            fn branchPolicyAllowsInstance(spec_policy: BranchPolicy, instance_policy: BranchPolicy) bool {
                if (instance_policy == spec_policy) return true;
                return switch (spec_policy) {
                    .unrestricted => instance_policy != .host_owned,
                    .single_live_branch => instance_policy == .no_branch,
                    .split_required => false,
                    .replay_only, .no_branch, .host_owned => false,
                };
            }

            fn branchPolicyAllowsSplit(parent_policy: BranchPolicy, child_policy: BranchPolicy, usage: Usage) bool {
                if (parent_policy == .no_branch or child_policy == .no_branch) return false;
                if (usage == .linear or usage == .affine) {
                    return switch (parent_policy) {
                        .split_required => child_policy == .single_live_branch or child_policy == .replay_only,
                        .no_branch => false,
                        .unrestricted,
                        .replay_only,
                        .single_live_branch,
                        .host_owned,
                        => child_policy == .replay_only,
                    };
                }
                if (parent_policy == child_policy) return true;
                return switch (parent_policy) {
                    .unrestricted => child_policy != .host_owned,
                    .single_live_branch => child_policy == .replay_only,
                    .split_required => child_policy == .single_live_branch or child_policy == .replay_only,
                    .replay_only, .no_branch, .host_owned => false,
                };
            }

            fn providerSupportedRequestKinds(provider: ProviderManifest) RequestKindSet {
                const operation_sites_constrained = provider.supported_operation_sites.len != 0;
                const after_sites_constrained = provider.supported_after_sites.len != 0;
                if (operation_sites_constrained or after_sites_constrained) {
                    return .{
                        .operation = operation_sites_constrained,
                        .after = after_sites_constrained,
                    };
                }
                return .{};
            }

            fn providerCoversCapabilityScope(provider: ProviderManifest, capability: Capability) bool {
                if (!capability.allowed_request_kinds.subsetOf(providerSupportedRequestKinds(provider))) return false;
                if (!stringListSubset(capability.allowed_requirement_labels, provider.supported_protocol_labels)) return false;
                if (capability.allowed_request_kinds.operation and !usizeListSubset(capability.allowed_operation_sites, provider.supported_operation_sites)) return false;
                if (capability.allowed_request_kinds.after and !usizeListSubset(capability.allowed_after_sites, provider.supported_after_sites)) return false;
                if (!u64ListSubset(capability.allowed_protocol_op_fingerprints, provider.supported_protocol_op_fingerprints)) return false;
                if (!responseKindSetSubset(capability.allowed_response_kinds, provider.allowed_response_kinds)) return false;
                if (capability.allow_embedded_capsule_response_handling and !provider.accepts_embedded_capsules) return false;
                if (capability.allow_capsule_restore and !provider.accepts_capsule_restore) return false;
                if (capability.max_request_bytes > provider.max_request_envelope_bytes) return false;
                if (capability.max_response_bytes > provider.max_response_envelope_bytes) return false;
                return true;
            }

            fn validateCapabilityInstanceRequestScope(instance: CapabilityInstance, request: RequestEnvelope) Error!void {
                const protocol_op_fingerprint = requestProtocolOperationFingerprint(request) orelse return error.ProgramContractViolation;
                try validateCapabilityInstanceRequestScopeWithProtocolOp(instance, request, protocol_op_fingerprint);
            }

            fn validateCapabilityInstanceRequestScopeWithProtocolOp(instance: CapabilityInstance, request: RequestEnvelope, protocol_op_fingerprint: u64) Error!void {
                const requirement_label = requestRequirementLabel(request) orelse return error.ProgramContractViolation;
                if (!instance.allowed_request_kinds.allows(request.kind)) return error.ProgramContractViolation;
                if (instance.expires_at_generation) |expires_at| {
                    if (request.turn_index >= expires_at) return error.ProgramContractViolation;
                }
                if (instance.journal_policy_fingerprint) |expected_policy| {
                    const branch_id = request.journal_branch_id orelse return error.ProgramContractViolation;
                    if (journalBranchPolicyFingerprint(branch_id) != expected_policy) return error.ProgramContractViolation;
                }
                switch (request.kind) {
                    .operation => if (!listAllowsUsize(instance.allowed_operation_sites, request.site_index)) return error.ProgramContractViolation,
                    .after => if (!listAllowsUsize(instance.allowed_after_sites, request.site_index)) return error.ProgramContractViolation,
                }
                if (!listAllowsU64(instance.allowed_protocol_op_fingerprints, protocol_op_fingerprint)) return error.ProgramContractViolation;
                if (!listAllowsString(instance.allowed_requirement_labels, requirement_label)) return error.ProgramContractViolation;
                if (!listAllowsString(instance.allowed_op_names, request.name)) return error.ProgramContractViolation;
                if (request.bytes.len > instance.max_request_bytes) return error.ProgramContractViolation;
                if (request.value_image.len > instance.max_payload_bytes) return error.ProgramContractViolation;
                if (request.capsule_image) |image| {
                    if (!instance.allow_embedded_capsule_response_handling) return error.ProgramContractViolation;
                    if (image.len > instance.max_capsule_image_bytes) return error.ProgramContractViolation;
                }
            }

            fn validateCapabilityInstanceMorphismTargetScope(instance: CapabilityInstance, request: RequestEnvelope, target_protocol_op_fingerprint: u64) Error!void {
                try request.validate();
                if (!instance.allowed_request_kinds.allows(request.kind)) return error.ProgramContractViolation;
                if (instance.expires_at_generation) |expires_at| {
                    if (request.turn_index >= expires_at) return error.ProgramContractViolation;
                }
                if (instance.journal_policy_fingerprint) |expected_policy| {
                    const branch_id = request.journal_branch_id orelse return error.ProgramContractViolation;
                    if (journalBranchPolicyFingerprint(branch_id) != expected_policy) return error.ProgramContractViolation;
                }
                if (instance.allowed_protocol_op_fingerprints.len == 0 and
                    (instance.allowed_requirement_labels.len != 0 or instance.allowed_op_names.len != 0))
                {
                    return error.ProgramContractViolation;
                }
                switch (request.kind) {
                    .operation => if (!listAllowsUsize(instance.allowed_operation_sites, request.site_index)) return error.ProgramContractViolation,
                    .after => if (!listAllowsUsize(instance.allowed_after_sites, request.site_index)) return error.ProgramContractViolation,
                }
                if (!listAllowsU64(instance.allowed_protocol_op_fingerprints, target_protocol_op_fingerprint)) return error.ProgramContractViolation;
                if (request.bytes.len > instance.max_request_bytes) return error.ProgramContractViolation;
                if (request.value_image.len > instance.max_payload_bytes) return error.ProgramContractViolation;
                if (request.capsule_image) |image| {
                    if (!instance.allow_embedded_capsule_response_handling) return error.ProgramContractViolation;
                    if (image.len > instance.max_capsule_image_bytes) return error.ProgramContractViolation;
                }
            }

            fn effectiveObligationResponseRefs(instance_refs: []const lowering_api.ValueRef, requested_refs: []const lowering_api.ValueRef) Error![]const lowering_api.ValueRef {
                if (requested_refs.len == 0) return instance_refs;
                if (!valueRefListSubset(requested_refs, instance_refs)) return error.ProgramContractViolation;
                return requested_refs;
            }

            /// Ledgered bridge between a request envelope and an external effect usage rule.
            pub const Obligation = struct {
                obligation_version: u32 = exchange_obligation_format_version,
                obligation_fingerprint: u64 = 0,
                effect_session_instance_fingerprint: u64,
                request_envelope_fingerprint: u64,
                request_fingerprint: u64,
                site_fingerprint: u64,
                usage: Usage,
                branch_id: u64 = 0,
                state_at_open: []const u8,
                allowed_response_kinds: Policy.ResponseKindSet = .{},
                allowed_response_refs: []const lowering_api.ValueRef = &.{},
                response_refs_allocator: ?std.mem.Allocator = null,
                max_response_bytes: usize = std.math.maxInt(usize),
                capsule_image_fingerprint: ?u64 = null,
                status: ObligationStatus = .open,
                consumed_response_fingerprint: ?u64 = null,
                replay_source_response_fingerprint: ?u64 = null,
                provider_fingerprint: ?u64 = null,
                capability_instance_fingerprint: ?u64 = null,
                authority_instance_fingerprint: ?u64 = null,
                branch_policy: BranchPolicy = .unrestricted,
                replay_policy: ResponseUse = .fresh,

                /// Empty runner-owned obligation slot for MailboxRunner opening.
                pub fn placeholder() @This() {
                    return .{
                        .effect_session_instance_fingerprint = 0,
                        .request_envelope_fingerprint = 0,
                        .request_fingerprint = 0,
                        .site_fingerprint = 0,
                        .usage = .copyable,
                        .state_at_open = "",
                    };
                }

                /// Return true when the stored fingerprint matches the current obligation fields.
                pub fn validFingerprint(self: @This()) bool {
                    if (self.obligation_fingerprint == 0) return false;
                    return self.obligation_fingerprint == fingerprintObligation(self);
                }

                /// Canonical evidence reference for this obligation.
                pub fn evidenceRef(self: @This()) Evidence.Ref {
                    return Evidence.refForObligation(self);
                }

                /// Release obligation-owned response-ref storage.
                pub fn deinit(self: *@This()) void {
                    if (self.response_refs_allocator) |allocator| {
                        allocator.free(self.state_at_open);
                        allocator.free(self.allowed_response_refs);
                    }
                    self.state_at_open = "";
                    self.allowed_response_refs = &.{};
                    self.response_refs_allocator = null;
                }

                /// Clone this obligation image so transition results do not alias owned snapshots.
                pub fn clone(self: @This()) Error!@This() {
                    if (!self.validFingerprint()) return error.ProgramContractViolation;
                    const allocator = self.response_refs_allocator orelse return self;
                    const state_at_open = try allocator.dupe(u8, self.state_at_open);
                    errdefer allocator.free(state_at_open);
                    const response_refs = try cloneValueRefs(allocator, self.allowed_response_refs);
                    errdefer allocator.free(response_refs);
                    var cloned = self;
                    cloned.state_at_open = state_at_open;
                    cloned.allowed_response_refs = response_refs;
                    return cloned;
                }

                /// Open an obligation from a request envelope and consume the instance's open slot.
                pub fn open(instance: *CapabilityInstance, request: RequestEnvelope, allowed_response_kinds: Policy.ResponseKindSet, allowed_response_refs: []const lowering_api.ValueRef) Error!@This() {
                    try request.validate();
                    if (!instance.validFingerprint()) return error.ProgramContractViolation;
                    if (instance.closed()) return error.ProgramContractViolation;
                    if (instance.manifest_fingerprint != request.manifest_fingerprint) return error.ProgramContractViolation;
                    try validateCapabilityInstanceRequestScope(instance.*, request);
                    if ((instance.usage == .linear or instance.usage == .affine) and instance.opened_request_fingerprint != null) return error.ProgramContractViolation;
                    if (instance.usage == .ephemeral and request.capsule_image != null) return error.ProgramContractViolation;
                    if (instance.branch_policy == .split_required) return error.ProgramContractViolation;
                    if (instance.branch_policy == .no_branch and request.capsule_image != null) return error.ProgramContractViolation;
                    if (request.usage_metadata) |metadata| {
                        if (metadata.effect_session_spec_fingerprint) |fingerprint| {
                            if (fingerprint != instance.effect_session_spec_fingerprint) return error.ProgramContractViolation;
                        }
                        if (metadata.capability_instance_fingerprint) |fingerprint| {
                            if (fingerprint != instance.requestMetadataInstanceFingerprint(request.request_fingerprint, null)) return error.ProgramContractViolation;
                        }
                        if (metadata.obligation_fingerprint != null) return error.ProgramContractViolation;
                        if (metadata.usage != instance.usage) return error.ProgramContractViolation;
                        if (metadata.branch_id != instance.branch_id) return error.ProgramContractViolation;
                        if (metadata.branch_policy != instance.branch_policy) return error.ProgramContractViolation;
                        if (!metadataReplayPolicyAllows(.open, instance.replay_policy, metadata.replay_policy)) return error.ProgramContractViolation;
                    }
                    var opened_instance = try instance.opened(request.request_fingerprint);
                    errdefer opened_instance.deinit();
                    if (!requestAcceptsAnyResponseKind(request, opened_instance.allowed_response_kinds)) return error.ProgramContractViolation;
                    if (!requestAcceptsAnyResponseRef(request, opened_instance.allowed_response_kinds, opened_instance.allowed_response_refs)) return error.ProgramContractViolation;
                    const response_kinds = responseKindSetIntersection(allowed_response_kinds, opened_instance.allowed_response_kinds);
                    const response_refs = try effectiveObligationResponseRefs(opened_instance.allowed_response_refs, allowed_response_refs);
                    if (!requestAcceptsAnyResponseKind(request, response_kinds)) return error.ProgramContractViolation;
                    if (!requestAcceptsAnyResponseRef(request, response_kinds, response_refs)) return error.ProgramContractViolation;
                    const allocator = opened_instance.snapshot_allocator orelse return error.ProgramContractViolation;
                    const stable_response_refs = try cloneValueRefs(allocator, response_refs);
                    errdefer allocator.free(stable_response_refs);
                    const state_at_open = try allocator.dupe(u8, opened_instance.current_state);
                    errdefer allocator.free(state_at_open);
                    var obligation = Obligation{
                        .effect_session_instance_fingerprint = opened_instance.instance_fingerprint,
                        .request_envelope_fingerprint = request.fingerprint,
                        .request_fingerprint = request.request_fingerprint,
                        .site_fingerprint = request.site_fingerprint,
                        .usage = opened_instance.usage,
                        .branch_id = opened_instance.branch_id,
                        .state_at_open = state_at_open,
                        .allowed_response_kinds = response_kinds,
                        .allowed_response_refs = stable_response_refs,
                        .response_refs_allocator = allocator,
                        .max_response_bytes = opened_instance.max_response_bytes,
                        .capsule_image_fingerprint = request.capsule_image_fingerprint,
                        .provider_fingerprint = opened_instance.provider_fingerprint,
                        .capability_instance_fingerprint = opened_instance.instance_fingerprint,
                        .authority_instance_fingerprint = instance.instance_fingerprint,
                        .branch_policy = opened_instance.branch_policy,
                        .replay_policy = opened_instance.replay_policy,
                    };
                    obligation.obligation_fingerprint = fingerprintObligation(obligation);
                    instance.deinit();
                    instance.* = opened_instance;
                    return obligation;
                }

                /// Consume an open obligation with a fresh response.
                pub fn consume(self: @This(), response: ResponseEnvelope, use_value: ResponseUse) Error!ObligationTransition {
                    if (!self.validFingerprint()) return error.ProgramContractViolation;
                    if (use_value != .fresh and use_value != .override) return error.ProgramContractViolation;
                    if (!metadataReplayPolicyAllows(self.status, self.replay_policy, use_value)) return error.ProgramContractViolation;
                    if (self.branch_policy == .replay_only) return error.ProgramContractViolation;
                    if (self.status != .open) return error.ProgramContractViolation;
                    try validateResponseEnvelopeFieldsBoundToBytes(response);
                    if (response.request_envelope_fingerprint != self.request_envelope_fingerprint) return error.ProgramContractViolation;
                    if (response.request_fingerprint != self.request_fingerprint) return error.ProgramContractViolation;
                    if (!self.allowed_response_kinds.allows(response.kind)) return error.ProgramContractViolation;
                    if (!listAllowsValueRef(self.allowed_response_refs, response.response_ref)) return error.ProgramContractViolation;
                    if (response.bytes.len > self.max_response_bytes) return error.ProgramContractViolation;
                    return obligationTransition(self, .consumed, response.fingerprint, null, use_value);
                }

                /// Replay an obligation from a recorded response fingerprint.
                pub fn replay(self: @This(), response: ResponseEnvelope, source_response_fingerprint: u64, use_value: ResponseUse) Error!ObligationTransition {
                    return self.replayWithSourceValue(response, source_response_fingerprint, null, use_value);
                }

                /// Replay an open branch from a recorded response plus a stable response-value witness.
                pub fn replayFromSourceValue(self: @This(), response: ResponseEnvelope, source_response_fingerprint: u64, source_response_value_fingerprint: u64, use_value: ResponseUse) Error!ObligationTransition {
                    return self.replayWithSourceValue(response, source_response_fingerprint, source_response_value_fingerprint, use_value);
                }

                fn replayWithSourceValue(self: @This(), response: ResponseEnvelope, source_response_fingerprint: u64, source_response_value_fingerprint: ?u64, use_value: ResponseUse) Error!ObligationTransition {
                    if (!self.validFingerprint()) return error.ProgramContractViolation;
                    if (use_value != .replayed and use_value != .deterministic_replay) return error.ProgramContractViolation;
                    if (!obligationReplayPolicyAllows(self.status, self.branch_policy, self.replay_policy, use_value)) return error.ProgramContractViolation;
                    if (self.usage == .ephemeral) return error.ProgramContractViolation;
                    if (self.status != .open and self.status != .consumed and self.status != .replayed) return error.ProgramContractViolation;
                    if (self.status == .open and (self.usage == .linear or self.usage == .affine) and self.branch_policy != .replay_only) return error.ProgramContractViolation;
                    try validateResponseEnvelopeFieldsBoundToBytes(response);
                    if (self.status == .consumed or self.status == .replayed) {
                        const recorded_response_fingerprint = self.consumed_response_fingerprint orelse return error.ProgramContractViolation;
                        if (recorded_response_fingerprint != source_response_fingerprint) return error.ProgramContractViolation;
                    }
                    if (response.fingerprint != source_response_fingerprint) {
                        if (self.status != .open) return error.ProgramContractViolation;
                        const source_value_fingerprint = source_response_value_fingerprint orelse return error.ProgramContractViolation;
                        if (response.response_value_fingerprint != source_value_fingerprint) return error.ProgramContractViolation;
                    }
                    if (response.request_envelope_fingerprint != self.request_envelope_fingerprint) return error.ProgramContractViolation;
                    if (response.request_fingerprint != self.request_fingerprint) return error.ProgramContractViolation;
                    if (!self.allowed_response_kinds.allows(response.kind)) return error.ProgramContractViolation;
                    if (!listAllowsValueRef(self.allowed_response_refs, response.response_ref)) return error.ProgramContractViolation;
                    if (response.bytes.len > self.max_response_bytes) return error.ProgramContractViolation;
                    return obligationTransition(self, .replayed, response.fingerprint, source_response_fingerprint, use_value);
                }

                /// Cancel an open affine or linear obligation.
                pub fn cancel(self: @This()) Error!ObligationTransition {
                    if (!self.validFingerprint()) return error.ProgramContractViolation;
                    if (self.status != .open) return error.ProgramContractViolation;
                    if (!(self.usage == .affine or self.usage == .linear)) return error.ProgramContractViolation;
                    return obligationTransition(self, .canceled, null, null, .fresh);
                }

                /// Cancel an open affine or linear obligation using the effect-session spec transition.
                pub fn cancelWithSpec(self: @This(), spec: EffectSessionSpec) Error!ObligationTransition {
                    var transition = try self.cancel();
                    const cancel_start_state = (try spec.requestTarget(self.state_at_open, self.site_fingerprint)) orelse self.state_at_open;
                    transition.previous_session_state = cancel_start_state;
                    transition.next_session_state = try spec.cancelTarget(cancel_start_state);
                    transition.transition_fingerprint = 0;
                    transition.transition_fingerprint = fingerprintObligationTransition(transition);
                    return transition;
                }

                /// Abandon an open obligation when policy allows host-owned abandonment.
                pub fn abandon(self: @This()) Error!ObligationTransition {
                    if (!self.validFingerprint()) return error.ProgramContractViolation;
                    if (self.status != .open) return error.ProgramContractViolation;
                    if (self.branch_policy != .host_owned) return error.ProgramContractViolation;
                    return obligationTransition(self, .abandoned, null, null, .fresh);
                }

                /// Apply a validated transition and return the next valid obligation image.
                pub fn applyTransition(self: @This(), transition: ObligationTransition) Error!@This() {
                    if (!self.validFingerprint()) return error.ProgramContractViolation;
                    if (transition.transition_fingerprint != fingerprintObligationTransition(transition)) return error.ProgramContractViolation;
                    if (!obligationMatchesTransition(self, transition)) return error.ProgramContractViolation;
                    if (self.branch_id != transition.branch_id) return error.ProgramContractViolation;
                    if (self.status != transition.previous_obligation_status) return error.ProgramContractViolation;
                    var updated = try self.clone();
                    updated.status = transition.next_obligation_status;
                    updated.consumed_response_fingerprint = if (transition.next_obligation_status == .replayed)
                        transition.replay_source_response_fingerprint orelse transition.response_fingerprint
                    else
                        transition.response_fingerprint;
                    updated.replay_source_response_fingerprint = transition.replay_source_response_fingerprint;
                    updated.obligation_fingerprint = 0;
                    updated.obligation_fingerprint = fingerprintObligation(updated);
                    return updated;
                }
            };

            /// Deterministic transition applied to an obligation/session pair.
            pub const ObligationTransition = struct {
                transition_fingerprint: u64 = 0,
                obligation_fingerprint: u64,
                previous_obligation_status: ObligationStatus,
                next_obligation_status: ObligationStatus,
                previous_session_state: []const u8,
                next_session_state: []const u8,
                response_use: ResponseUse,
                response_fingerprint: ?u64 = null,
                replay_source_response_fingerprint: ?u64 = null,
                capability_instance_consumed: bool = false,
                branch_remains_open: bool = true,
                branch_id: u64 = 0,
            };

            /// Result of validating response authority and obligation transition together.
            pub const AuthorizationResult = struct {
                result_fingerprint: u64 = 0,
                authorization_fingerprint: u64,
                obligation_transition_fingerprint: u64,
                capability_instance_fingerprint: u64,
                previous_obligation_status: ObligationStatus,
                next_obligation_status: ObligationStatus,
                previous_session_state: []const u8,
                next_session_state: []const u8,
                response_use: ResponseUse,
                response_fingerprint: u64,
                replay_source_response_fingerprint: ?u64 = null,
                capability_instance_consumed: bool,
                branch_remains_open: bool,
            };

            /// Journal/ledger validator for linear effect obligations.
            pub const ObligationLedger = struct {
                obligations: []const Obligation = &.{},
                transitions: []const ObligationTransition = &.{},
                expected_provider_fingerprint: ?u64 = null,
                expected_capability_instance_fingerprint: ?u64 = null,

                /// Validate obligation transitions for duplicate consumption and unresolved linear effects.
                pub fn validate(self: @This()) ValidationReport {
                    var report: ValidationReport = .{};
                    for (self.transitions, 0..) |transition, index| {
                        var has_obligation = false;
                        var matched_obligation_status: ?ObligationStatus = null;
                        for (self.obligations) |obligation| {
                            if (obligationMatchesTransition(obligation, transition)) {
                                has_obligation = true;
                                matched_obligation_status = obligation.status;
                                if (obligation.branch_id != transition.branch_id) report.add(.branch_policy);
                                if (obligation.branch_policy == .replay_only and (transition.response_use == .fresh or transition.response_use == .override)) report.add(.replay_policy);
                                if (!obligationReplayPolicyAllows(obligation.status, obligation.branch_policy, obligation.replay_policy, transition.response_use)) report.add(.replay_policy);
                                if (!obligationTransitionShapeValid(obligation, transition)) report.add(.invalid_obligation_transition);
                                if (transition.next_obligation_status == .abandoned and obligation.branch_policy != .host_owned) report.add(.branch_policy);
                                break;
                            }
                        }
                        if (!has_obligation) report.add(.wrong_obligation);
                        if (transition.previous_obligation_status == .canceled and
                            (transition.next_obligation_status == .consumed or transition.next_obligation_status == .replayed))
                        {
                            report.add(.response_after_cancel);
                        }
                        if (transition.previous_obligation_status != .open and
                            (transition.next_obligation_status == .consumed or
                                transition.next_obligation_status == .canceled or
                                transition.next_obligation_status == .abandoned))
                        {
                            report.add(.obligation_not_open);
                        }
                        var expected_previous_status: ?ObligationStatus = null;
                        var consumed_authority_instance: ?u64 = null;
                        if (transition.next_obligation_status == .consumed) {
                            for (self.obligations) |obligation| {
                                if (obligationMatchesTransition(obligation, transition)) {
                                    if (obligation.usage == .linear or obligation.usage == .affine) {
                                        consumed_authority_instance = obligationAuthorityFingerprint(obligation);
                                    }
                                    break;
                                }
                            }
                        }
                        for (self.transitions[0..index]) |prior| {
                            if (prior.obligation_fingerprint == transition.obligation_fingerprint and
                                prior.next_obligation_status == .consumed and transition.next_obligation_status == .consumed)
                            {
                                report.add(.duplicate_obligation_consume);
                            }
                            if (consumed_authority_instance) |current_authority_instance| {
                                if (prior.next_obligation_status == .consumed) {
                                    for (self.obligations) |obligation| {
                                        if (obligationMatchesTransition(obligation, prior) and
                                            obligationAuthorityFingerprint(obligation) == current_authority_instance)
                                        {
                                            report.add(.duplicate_obligation_consume);
                                            break;
                                        }
                                    }
                                }
                            }
                            if (prior.obligation_fingerprint == transition.obligation_fingerprint or
                                transitionsShareObligation(self.obligations, prior, transition))
                            {
                                expected_previous_status = prior.next_obligation_status;
                            }
                        }
                        if (expected_previous_status) |status| {
                            if (status != transition.previous_obligation_status) report.add(.invalid_obligation_transition);
                        } else if (matched_obligation_status) |status| {
                            if (status != transition.previous_obligation_status and status != transition.next_obligation_status) report.add(.invalid_obligation_transition);
                        }
                        if (transition.transition_fingerprint != fingerprintObligationTransition(transition)) report.add(.invalid_obligation_transition);
                    }
                    for (self.obligations) |obligation| {
                        if (!obligation.validFingerprint()) report.add(.invalid_obligation_transition);
                        if (obligation.capability_instance_fingerprint) |fingerprint| {
                            if (fingerprint != obligation.effect_session_instance_fingerprint) report.add(.wrong_capability_instance);
                        }
                        if (self.expected_provider_fingerprint) |fingerprint| {
                            if (obligation.provider_fingerprint == null or obligation.provider_fingerprint.? != fingerprint) report.add(.wrong_provider);
                        }
                        if (self.expected_capability_instance_fingerprint) |fingerprint| {
                            if (obligation.capability_instance_fingerprint == null or obligation.capability_instance_fingerprint.? != fingerprint) report.add(.wrong_capability_instance);
                        }
                        var closed = false;
                        for (self.transitions) |transition| {
                            if (obligationMatchesTransition(obligation, transition)) {
                                if (transition.next_obligation_status == .consumed or transition.next_obligation_status == .canceled) closed = true;
                                if (transition.next_obligation_status == .replayed and
                                    (transition.previous_obligation_status == .consumed or
                                        transition.previous_obligation_status == .replayed or
                                        (transition.previous_obligation_status == .open and obligation.branch_policy == .replay_only))) closed = true;
                                if (transition.next_obligation_status == .abandoned and obligation.branch_policy == .host_owned) closed = true;
                            }
                        }
                        if (obligation.usage == .linear and !closed) report.add(.unresolved_linear_obligation);
                    }
                    return report;
                }
            };

            /// Canonical image of the Program exchange surface.
            pub const Manifest = struct {
                allocator: std.mem.Allocator,
                bytes: []u8,
                fingerprint: u64,
                program_label: []const u8 = label,
                plan_label: []const u8 = body_compiled_plan.label,
                plan_hash: u64 = body_compiled_plan_hash,
                operation_site_count: usize = protocol.operation_site_count,
                after_site_count: usize = protocol.after_site_count,
                value_schema_count: usize = compiled_plan.value_schemas.len,
                value_field_count: usize = compiled_plan.value_fields.len,
                value_variant_count: usize = compiled_plan.value_variants.len,

                /// Encode the current Program exchange manifest.
                pub fn encode(allocator: std.mem.Allocator) Error!@This() {
                    var writer = Writer.init(allocator);
                    errdefer writer.deinit();
                    writeManifestPayload(&writer) catch |err| return mapProgramRunError(Error, err);
                    const payload = writer.bytes.items;
                    const fingerprint = exchangeFingerprint("ability.exchange.manifest", exchange_manifest_fingerprint_version, payload);
                    try writer.writeU64(fingerprint);
                    return .{
                        .allocator = allocator,
                        .bytes = try writer.toOwnedSlice(),
                        .fingerprint = fingerprint,
                    };
                }

                /// Decode and validate a Program exchange manifest image.
                pub fn decode(allocator: std.mem.Allocator, bytes: []const u8) Error!@This() {
                    const payload = try checkedPayload(bytes, "ability.exchange.manifest", exchange_manifest_fingerprint_version);
                    var reader = Reader.init(payload);
                    try reader.expectBytes(manifest_magic);
                    if (try reader.readU32() != exchange_manifest_format_version) return error.ProgramContractViolation;
                    if (try reader.readU32() != exchange_manifest_fingerprint_version) return error.ProgramContractViolation;
                    const manifest_request_format_version = try reader.readU32();
                    const manifest_request_fingerprint_version = try reader.readU32();
                    if (!supportedRequestEnvelopeVersions(manifest_request_format_version, manifest_request_fingerprint_version)) return error.ProgramContractViolation;
                    if (try reader.readU32() != exchange_response_format_version) return error.ProgramContractViolation;
                    if (try reader.readU32() != exchange_response_fingerprint_version) return error.ProgramContractViolation;
                    if (!std.mem.eql(u8, try reader.readLenBytes(), label)) return error.ProgramContractViolation;
                    if (!std.mem.eql(u8, try reader.readLenBytes(), body_compiled_plan.label)) return error.ProgramContractViolation;
                    if (try reader.readU64() != body_compiled_plan_hash) return error.ProgramContractViolation;
                    if (try reader.readU32() != lowering_api.trace_fingerprint_version) return error.ProgramContractViolation;
                    if (try reader.readU32() != capsule_image_format_version) return error.ProgramContractViolation;
                    if (try reader.readU32() != capsule_image_fingerprint_version) return error.ProgramContractViolation;
                    const manifest_journal_format = try reader.readU32();
                    if (!emittedManifestVersionTuple(manifest_request_format_version, manifest_request_fingerprint_version, manifest_journal_format)) return error.ProgramContractViolation;
                    if (try reader.readU32() != journal_fingerprint_version) return error.ProgramContractViolation;
                    try readManifestValueSchemas(&reader);
                    try readManifestOperationSites(&reader);
                    try readManifestAfterSites(&reader);
                    if (!reader.eof()) return error.ProgramContractViolation;
                    const owned = allocator.dupe(u8, bytes) catch |err| return mapProgramRunError(Error, err);
                    return .{
                        .allocator = allocator,
                        .bytes = owned,
                        .fingerprint = try checkedBytesFingerprint(bytes, "ability.exchange.manifest", exchange_manifest_fingerprint_version),
                    };
                }

                /// Release manifest image storage.
                pub fn deinit(self: *@This()) void {
                    self.allocator.free(self.bytes);
                    self.bytes = &.{};
                }
            };

            /// Local guardrails for envelope size, capsule, site, and response-kind acceptance.
            pub const Policy = struct {
                allow_capsules: bool = true,
                allow_response_value_images: bool = true,
                max_envelope_bytes: usize = std.math.maxInt(usize),
                max_payload_bytes: usize = std.math.maxInt(usize),
                max_capsule_image_bytes: ?usize = null,
                allowed_response_kinds: ResponseKindSet = .{},
                allowed_operation_sites: ?[]const usize = null,
                allowed_after_sites: ?[]const usize = null,
                require_route: bool = false,
                reject_ambiguous_routes: bool = true,
                require_response_capability: bool = false,
                allowed_provider_fingerprints: ?[]const u64 = null,
                allowed_capability_fingerprints: ?[]const u64 = null,
                allow_capsule_restore: bool = true,
                usage: ?Usage = null,
                branch_policy: ?BranchPolicy = null,
                replay_policy: ?ResponseUse = null,

                /// Response-kind allow list used by Policy.
                pub const ResponseKindSet = struct {
                    @"resume": bool = true,
                    return_now: bool = true,
                    resume_after: bool = true,

                    /// Return true when this set allows the response kind.
                    pub fn allows(self: @This(), kind_value: ResponseKind) bool {
                        return switch (kind_value) {
                            .@"resume" => self.@"resume",
                            .return_now => self.return_now,
                            .resume_after => self.resume_after,
                        };
                    }
                };

                /// Validate a request envelope against this policy.
                pub fn validateRequest(self: @This(), envelope: RequestEnvelope) Error!void {
                    if (envelope.bytes.len > self.max_envelope_bytes) return error.ProgramContractViolation;
                    if (envelope.value_image.len > self.max_payload_bytes) return error.ProgramContractViolation;
                    if (!self.allow_capsules and envelope.capsule_image != null) return error.ProgramContractViolation;
                    if (envelope.capsule_image) |image| {
                        if (image.len > (self.max_capsule_image_bytes orelse self.max_payload_bytes)) return error.ProgramContractViolation;
                    }
                    if (self.usage) |usage_value| {
                        if (envelope.usage_metadata == null or envelope.usage_metadata.?.usage != usage_value) return error.ProgramContractViolation;
                    }
                    if ((self.branch_policy != null or self.replay_policy != null) and envelope.usage_metadata == null) return error.ProgramContractViolation;
                    if (envelope.usage_metadata) |metadata| {
                        if (metadata.ephemeral and envelope.capsule_image != null) return error.ProgramContractViolation;
                        if (metadata.usage == .ephemeral and envelope.capsule_image != null) return error.ProgramContractViolation;
                        if (metadata.branch_policy == .no_branch and envelope.capsule_image != null) return error.ProgramContractViolation;
                        if (self.branch_policy) |policy_value| {
                            if (metadata.branch_policy != policy_value) return error.ProgramContractViolation;
                        }
                        if (self.replay_policy) |policy_value| {
                            if (metadata.replay_policy != policy_value) return error.ProgramContractViolation;
                        }
                    }
                    switch (envelope.kind) {
                        .operation => if (!policyAllowsSite(self.allowed_operation_sites, envelope.site_index)) return error.ProgramContractViolation,
                        .after => if (!policyAllowsSite(self.allowed_after_sites, envelope.site_index)) return error.ProgramContractViolation,
                    }
                }

                /// Validate a response envelope against this policy.
                pub fn validateResponse(self: @This(), envelope: ResponseEnvelope) Error!void {
                    if (envelope.bytes.len > self.max_envelope_bytes) return error.ProgramContractViolation;
                    if (envelope.value_image.len > self.max_payload_bytes) return error.ProgramContractViolation;
                    if (!self.allow_response_value_images and envelope.value_image.len != 0) return error.ProgramContractViolation;
                    if (!self.allowed_response_kinds.allows(envelope.kind)) return error.ProgramContractViolation;
                }

                fn policyAllowsSite(allowed: ?[]const usize, site_index: usize) bool {
                    const list = allowed orelse return true;
                    for (list) |allowed_index| if (allowed_index == site_index) return true;
                    return false;
                }
            };

            /// Structured capability/routing validation blockers.
            pub const BlockerTag = enum {
                wrong_provider,
                wrong_manifest,
                wrong_program_label,
                wrong_plan_hash,
                wrong_journal_policy,
                request_kind,
                operation_site,
                after_site,
                protocol_operation,
                response_kind,
                response_ref,
                embedded_capsule,
                capsule_restore,
                request_too_large,
                response_too_large,
                payload_too_large,
                capsule_too_large,
                missing_capability_fingerprint,
                wrong_capability,
                wrong_capability_path,
                wrong_route,
                wrong_request,
                invalid_envelope,
                provider_not_allowed,
                capability_not_allowed,
                ambiguous_route,
                no_route,
                broadened_authority,
                expired_capability,
                usage_mode,
                branch_policy,
                replay_policy,
                duplicate_obligation_consume,
                unresolved_linear_obligation,
                invalid_obligation_transition,
                obligation_not_open,
                response_after_cancel,
                wrong_obligation,
                wrong_capability_instance,
            };

            /// Fixed-capacity structured validation report. Extra blockers are saturated, not allocated.
            pub const ValidationReport = struct {
                blockers: [16]BlockerTag = undefined,
                count: usize = 0,
                saturated: bool = false,

                /// Options for lowering validation blockers into Evidence blockers.
                pub const EvidenceBlockerOptions = struct {
                    domain: Evidence.Domain.Id = Evidence.domains.capability.id,
                    subject: ?Evidence.Ref = null,
                    primary: ?Evidence.Ref = null,
                    source: Evidence.SourceSubsystem = .capability,
                    summary_prefix: []const u8 = "validation blocker",
                };

                /// Return true when the report contains no blockers.
                pub fn allowed(self: @This()) bool {
                    return self.count == 0 and !self.saturated;
                }

                /// Add a blocker tag if it is not already present.
                pub fn add(self: *@This(), tag: BlockerTag) void {
                    if (self.has(tag)) return;
                    if (self.count < self.blockers.len) {
                        self.blockers[self.count] = tag;
                        self.count += 1;
                    } else {
                        self.saturated = true;
                    }
                }

                /// Add all blockers from another validation report.
                pub fn merge(self: *@This(), other: @This()) void {
                    for (other.blockers[0..other.count]) |tag| self.add(tag);
                    if (other.saturated) self.saturated = true;
                }

                /// Return true when the report contains the blocker tag.
                pub fn has(self: @This(), tag: BlockerTag) bool {
                    for (self.blockers[0..self.count]) |existing| if (existing == tag) return true;
                    return false;
                }

                /// Return the first blocker tag name, if present.
                pub fn firstTagName(self: @This()) ?[]const u8 {
                    if (self.count == 0) return null;
                    return @tagName(self.blockers[0]);
                }

                /// Lower retained blocker tags into caller-owned shared Evidence blockers.
                pub fn toEvidenceBlockers(self: @This(), storage: []Evidence.Blocker, options: EvidenceBlockerOptions) []const Evidence.Blocker {
                    const limit = @min(storage.len, self.count);
                    for (self.blockers[0..limit], 0..) |tag, index| {
                        storage[index] = .{
                            .domain = options.domain,
                            .tag = @tagName(tag),
                            .subject = options.subject,
                            .primary = options.primary orelse options.subject,
                            .short_code = @tagName(tag),
                            .summary = if (options.summary_prefix.len == 0) @tagName(tag) else options.summary_prefix,
                            .source = options.source,
                        };
                    }
                    return storage[0..limit];
                }

                fn evidenceOmittedFingerprint(self: @This(), report_domain: Evidence.Domain.Id, lowered_count: usize) ?u64 {
                    if (!self.saturated and lowered_count >= self.count) return null;
                    var builder = Evidence.FingerprintBuilder.init(Evidence.domainById(report_domain) orelse Evidence.domains.program_plan);
                    builder.fieldBytes("kind", "validation_report_omitted_blockers");
                    builder.fieldBool("saturated", self.saturated);
                    builder.fieldUsize("retained_count", self.count);
                    builder.fieldUsize("lowered_count", lowered_count);
                    for (self.blockers[0..self.count], 0..) |tag, index| {
                        builder.fieldUsize("blocker.index", index);
                        builder.fieldBytes("blocker.tag", @tagName(tag));
                        builder.fieldBool("blocker.omitted", index >= lowered_count);
                    }
                    return builder.finish();
                }

                /// Lower this validation report into a shared Evidence report.
                pub fn toEvidenceReport(
                    self: @This(),
                    subject: Evidence.Ref,
                    report_domain: Evidence.Domain.Id,
                    dependencies: []const Evidence.Dependency,
                    blocker_storage: []Evidence.Blocker,
                    options: EvidenceBlockerOptions,
                ) Evidence.Report {
                    var evidence_options = options;
                    evidence_options.domain = report_domain;
                    evidence_options.subject = evidence_options.subject orelse subject;
                    const blockers = self.toEvidenceBlockers(blocker_storage, evidence_options);
                    if (self.allowed()) return Evidence.Report.ok(subject, report_domain, dependencies);
                    if (self.evidenceOmittedFingerprint(report_domain, blockers.len)) |omitted_fingerprint| {
                        return Evidence.Report.withIncompleteFailure(subject, report_domain, dependencies, blockers, &.{}, omitted_fingerprint, null, "validation report");
                    }
                    return Evidence.Report.withFailure(subject, report_domain, dependencies, blockers, &.{}, null, "validation report");
                }
            };

            /// Request-kind allow set used by capability grants.
            pub const RequestKindSet = struct {
                operation: bool = true,
                after: bool = true,

                fn allows(self: @This(), kind_value: RequestKind) bool {
                    return switch (kind_value) {
                        .operation => self.operation,
                        .after => self.after,
                    };
                }

                fn subsetOf(self: @This(), parent: @This()) bool {
                    return (!self.operation or parent.operation) and (!self.after or parent.after);
                }
            };

            /// Host-side claim describing what a provider says it can handle.
            pub const ProviderManifest = struct {
                allocator: std.mem.Allocator,
                bytes: []u8,
                fingerprint: u64,
                label: []u8,
                provider_fingerprint: u64,
                supported_program_manifest_fingerprints: []const u64,
                supported_protocol_labels: []const []const u8,
                supported_operation_sites: []const usize,
                supported_after_sites: []const usize,
                supported_protocol_op_fingerprints: []const u64,
                allowed_response_kinds: Policy.ResponseKindSet,
                max_request_envelope_bytes: usize,
                max_response_envelope_bytes: usize,
                accepts_embedded_capsules: bool,
                accepts_capsule_restore: bool,
                semantic_tags: []const []const u8,
                metadata: []u8,

                /// Options used to encode a provider manifest.
                pub const Options = struct {
                    label: []const u8,
                    provider_fingerprint: ?u64 = null,
                    supported_program_manifest_fingerprints: []const u64 = &.{},
                    supported_protocol_labels: []const []const u8 = &.{},
                    supported_operation_sites: []const usize = &.{},
                    supported_after_sites: []const usize = &.{},
                    supported_protocol_op_fingerprints: []const u64 = &.{},
                    allowed_response_kinds: Policy.ResponseKindSet = .{},
                    max_request_envelope_bytes: usize = std.math.maxInt(usize),
                    max_response_envelope_bytes: usize = std.math.maxInt(usize),
                    accepts_embedded_capsules: bool = true,
                    accepts_capsule_restore: bool = true,
                    semantic_tags: []const []const u8 = &.{},
                    metadata: []const u8 = &.{},
                };

                /// Encode a provider manifest into deterministic owned bytes.
                pub fn encode(allocator: std.mem.Allocator, options: Options) Error!@This() {
                    const provider_fp = options.provider_fingerprint orelse providerIdentityFingerprint(options.label, options.metadata);
                    var writer = Writer.init(allocator);
                    errdefer writer.deinit();
                    try writeProviderPayload(&writer, provider_fp, options);
                    const payload = writer.bytes.items;
                    const fingerprint = exchangeFingerprint("ability.exchange.provider", exchange_provider_fingerprint_version, payload);
                    try writer.writeU64(fingerprint);
                    const owned_bytes = try writer.toOwnedSlice();
                    errdefer allocator.free(owned_bytes);
                    const label_value = try allocator.dupe(u8, options.label);
                    errdefer allocator.free(label_value);
                    const manifests = try cloneU64s(allocator, options.supported_program_manifest_fingerprints);
                    errdefer allocator.free(manifests);
                    const protocol_labels = try cloneStringList(allocator, options.supported_protocol_labels);
                    errdefer freeStringList(allocator, protocol_labels);
                    const operation_sites = try cloneUsizes(allocator, options.supported_operation_sites);
                    errdefer allocator.free(operation_sites);
                    const after_sites = try cloneUsizes(allocator, options.supported_after_sites);
                    errdefer allocator.free(after_sites);
                    const protocol_ops = try cloneU64s(allocator, options.supported_protocol_op_fingerprints);
                    errdefer allocator.free(protocol_ops);
                    const tags = try cloneStringList(allocator, options.semantic_tags);
                    errdefer freeStringList(allocator, tags);
                    const metadata = try allocator.dupe(u8, options.metadata);
                    errdefer allocator.free(metadata);
                    return .{
                        .allocator = allocator,
                        .bytes = owned_bytes,
                        .fingerprint = fingerprint,
                        .label = label_value,
                        .provider_fingerprint = provider_fp,
                        .supported_program_manifest_fingerprints = manifests,
                        .supported_protocol_labels = protocol_labels,
                        .supported_operation_sites = operation_sites,
                        .supported_after_sites = after_sites,
                        .supported_protocol_op_fingerprints = protocol_ops,
                        .allowed_response_kinds = options.allowed_response_kinds,
                        .max_request_envelope_bytes = options.max_request_envelope_bytes,
                        .max_response_envelope_bytes = options.max_response_envelope_bytes,
                        .accepts_embedded_capsules = options.accepts_embedded_capsules,
                        .accepts_capsule_restore = options.accepts_capsule_restore,
                        .semantic_tags = tags,
                        .metadata = metadata,
                    };
                }

                /// Decode and validate a provider manifest image.
                pub fn decode(allocator: std.mem.Allocator, bytes: []const u8) Error!@This() {
                    const payload = try checkedPayload(bytes, "ability.exchange.provider", exchange_provider_fingerprint_version);
                    var reader = Reader.init(payload);
                    try reader.expectBytes(provider_magic);
                    if (try reader.readU32() != exchange_provider_format_version) return error.ProgramContractViolation;
                    if (try reader.readU32() != exchange_provider_fingerprint_version) return error.ProgramContractViolation;
                    const provider_fp = try reader.readU64();
                    const label_value = try allocator.dupe(u8, try reader.readLenBytes());
                    errdefer allocator.free(label_value);
                    const manifests = try readU64List(allocator, &reader);
                    errdefer allocator.free(manifests);
                    const protocol_labels = try readStringList(allocator, &reader);
                    errdefer freeStringList(allocator, protocol_labels);
                    const operation_sites = try readUsizeList(allocator, &reader);
                    errdefer allocator.free(operation_sites);
                    const after_sites = try readUsizeList(allocator, &reader);
                    errdefer allocator.free(after_sites);
                    const protocol_ops = try readU64List(allocator, &reader);
                    errdefer allocator.free(protocol_ops);
                    const response_kinds = try readResponseKindSet(&reader);
                    const max_request = try reader.readUsize();
                    const max_response = try reader.readUsize();
                    const accepts_capsules = try reader.readBool();
                    const accepts_restore = try reader.readBool();
                    const tags = try readStringList(allocator, &reader);
                    errdefer freeStringList(allocator, tags);
                    const metadata = try allocator.dupe(u8, try reader.readLenBytes());
                    errdefer allocator.free(metadata);
                    if (!reader.eof()) return error.ProgramContractViolation;
                    const owned = try allocator.dupe(u8, bytes);
                    errdefer allocator.free(owned);
                    return .{
                        .allocator = allocator,
                        .bytes = owned,
                        .fingerprint = try checkedBytesFingerprint(bytes, "ability.exchange.provider", exchange_provider_fingerprint_version),
                        .label = label_value,
                        .provider_fingerprint = provider_fp,
                        .supported_program_manifest_fingerprints = manifests,
                        .supported_protocol_labels = protocol_labels,
                        .supported_operation_sites = operation_sites,
                        .supported_after_sites = after_sites,
                        .supported_protocol_op_fingerprints = protocol_ops,
                        .allowed_response_kinds = response_kinds,
                        .max_request_envelope_bytes = max_request,
                        .max_response_envelope_bytes = max_response,
                        .accepts_embedded_capsules = accepts_capsules,
                        .accepts_capsule_restore = accepts_restore,
                        .semantic_tags = tags,
                        .metadata = metadata,
                    };
                }

                /// Release provider manifest owned storage.
                pub fn deinit(self: *@This()) void {
                    self.allocator.free(self.bytes);
                    self.allocator.free(self.label);
                    self.allocator.free(self.supported_program_manifest_fingerprints);
                    freeStringList(self.allocator, self.supported_protocol_labels);
                    self.allocator.free(self.supported_operation_sites);
                    self.allocator.free(self.supported_after_sites);
                    self.allocator.free(self.supported_protocol_op_fingerprints);
                    freeStringList(self.allocator, self.semantic_tags);
                    self.allocator.free(self.metadata);
                    self.bytes = &.{};
                }

                /// Return true when the provider claim covers the request envelope.
                pub fn supportsRequest(self: @This(), request: RequestEnvelope) bool {
                    if (!providerFieldsBoundToBytes(self)) return false;
                    request.validate() catch return false;
                    const requirement_label = requestRequirementLabel(request) orelse return false;
                    const protocol_op_fingerprint = requestProtocolOperationFingerprint(request) orelse return false;
                    if (!listAllowsString(self.supported_protocol_labels, requirement_label)) return false;
                    if (!listAllowsU64(self.supported_program_manifest_fingerprints, request.manifest_fingerprint)) return false;
                    if (request.bytes.len > self.max_request_envelope_bytes) return false;
                    if (request.capsule_image != null and !self.accepts_embedded_capsules) return false;
                    if (self.supported_protocol_op_fingerprints.len != 0 and !listAllowsU64(self.supported_protocol_op_fingerprints, protocol_op_fingerprint)) return false;
                    const operation_sites_constrained = self.supported_operation_sites.len != 0;
                    const after_sites_constrained = self.supported_after_sites.len != 0;
                    switch (request.kind) {
                        .operation => {
                            if (!operation_sites_constrained and after_sites_constrained) return false;
                            if (operation_sites_constrained and !listAllowsUsize(self.supported_operation_sites, request.site_index)) return false;
                            return true;
                        },
                        .after => {
                            if (!after_sites_constrained and operation_sites_constrained) return false;
                            if (after_sites_constrained and !listAllowsUsize(self.supported_after_sites, request.site_index)) return false;
                            return true;
                        },
                    }
                }

                /// Canonical evidence reference for this provider manifest.
                pub fn evidenceRef(self: @This()) Evidence.Ref {
                    return Evidence.refForProviderManifest(self);
                }
            };

            /// Deterministic typed handling claim for one provider-offered effect surface.
            pub const ProviderOffer = struct {
                allocator: std.mem.Allocator,
                bytes: []u8,
                format_version: u32 = exchange_provider_offer_format_version,
                fingerprint: u64,
                label: []u8,
                provider_fingerprint: u64,
                manifest_fingerprint: u64,
                supported_operation_sites: []const usize,
                supported_after_sites: []const usize,
                supported_protocol_op_fingerprints: []const u64,
                supported_protocol_labels: []const []const u8,
                accepted_payload_refs: []const lowering_api.ValueRef,
                accepted_current_value_refs: []const lowering_api.ValueRef,
                produced_response_refs: []const lowering_api.ValueRef,
                allowed_response_kinds: Policy.ResponseKindSet,
                supported_usage_modes: UsageSet,
                supported_response_uses: ResponseUseSet,
                supported_replay_policies: ResponseUseSet,
                supported_branch_policies: BranchPolicySet,
                capsule_policy: CapsulePolicy = .allowed,
                opens_obligation: bool = false,
                max_request_bytes: usize = std.math.maxInt(usize),
                max_response_bytes: usize = std.math.maxInt(usize),
                max_capsule_bytes: usize = std.math.maxInt(usize),
                tags: []const []const u8,
                metadata: []u8,
                provider_program_mapping_fingerprint: ?u64 = null,

                /// Options used to encode a provider offer.
                pub const Options = struct {
                    label: []const u8,
                    provider_fingerprint: u64,
                    manifest_fingerprint: u64,
                    supported_operation_sites: []const usize = &.{},
                    supported_after_sites: []const usize = &.{},
                    supported_protocol_op_fingerprints: []const u64 = &.{},
                    supported_protocol_labels: []const []const u8 = &.{},
                    accepted_payload_refs: []const lowering_api.ValueRef = &.{},
                    accepted_current_value_refs: []const lowering_api.ValueRef = &.{},
                    produced_response_refs: []const lowering_api.ValueRef = &.{},
                    allowed_response_kinds: Policy.ResponseKindSet = .{},
                    supported_usage_modes: UsageSet = .{},
                    supported_response_uses: ResponseUseSet = .{},
                    supported_replay_policies: ResponseUseSet = .{},
                    supported_branch_policies: BranchPolicySet = .{},
                    capsule_policy: CapsulePolicy = .allowed,
                    opens_obligation: bool = false,
                    max_request_bytes: usize = std.math.maxInt(usize),
                    max_response_bytes: usize = std.math.maxInt(usize),
                    max_capsule_bytes: usize = std.math.maxInt(usize),
                    tags: []const []const u8 = &.{},
                    metadata: []const u8 = &.{},
                    provider_program_mapping_fingerprint: ?u64 = null,
                };

                /// Encode a provider offer into deterministic owned bytes.
                pub fn encode(allocator: std.mem.Allocator, options: Options) Error!@This() {
                    try validateProviderOfferOptions(options);
                    var writer = Writer.init(allocator);
                    errdefer writer.deinit();
                    try writeProviderOfferPayload(&writer, options);
                    const payload = writer.bytes.items;
                    const fingerprint = exchangeFingerprint("ability.exchange.provider_offer", exchange_provider_offer_fingerprint_version, payload);
                    try writer.writeU64(fingerprint);
                    return providerOfferFromOptions(allocator, try writer.toOwnedSlice(), fingerprint, options);
                }

                /// Decode and validate a provider offer image.
                pub fn decode(allocator: std.mem.Allocator, bytes: []const u8) Error!@This() {
                    const payload = try checkedPayload(bytes, "ability.exchange.provider_offer", exchange_provider_offer_fingerprint_version);
                    var reader = Reader.init(payload);
                    try reader.expectBytes(provider_offer_magic);
                    const format_version = try reader.readU32();
                    if (format_version != exchange_provider_offer_format_version and format_version != provider_offer_program_format_version) return error.ProgramContractViolation;
                    if (try reader.readU32() != exchange_provider_offer_fingerprint_version) return error.ProgramContractViolation;
                    const label_value = try allocator.dupe(u8, try reader.readLenBytes());
                    errdefer allocator.free(label_value);
                    const provider_fp = try reader.readU64();
                    const manifest_fp = try reader.readU64();
                    const operation_sites = try readUsizeList(allocator, &reader);
                    errdefer allocator.free(operation_sites);
                    const after_sites = try readUsizeList(allocator, &reader);
                    errdefer allocator.free(after_sites);
                    const protocol_ops = try readU64List(allocator, &reader);
                    errdefer allocator.free(protocol_ops);
                    const protocol_labels = try readStringList(allocator, &reader);
                    errdefer freeStringList(allocator, protocol_labels);
                    const payload_refs = try readValueRefList(allocator, &reader);
                    errdefer allocator.free(payload_refs);
                    const current_refs = try readValueRefList(allocator, &reader);
                    errdefer allocator.free(current_refs);
                    const response_refs = try readValueRefList(allocator, &reader);
                    errdefer allocator.free(response_refs);
                    const response_kinds = try readResponseKindSet(&reader);
                    const usage_modes = try readUsageSet(&reader);
                    const response_uses = try readResponseUseSet(&reader);
                    const replay_policies = try readResponseUseSet(&reader);
                    const branch_policies = try readBranchPolicySet(&reader);
                    const capsule_policy_value = try readCapsulePolicy(&reader);
                    const opens_obligation_value = try reader.readBool();
                    const max_request = try reader.readUsize();
                    const max_response = try reader.readUsize();
                    const max_capsule = try reader.readUsize();
                    if (max_response == 0 or max_request == 0) return error.ProgramContractViolation;
                    const tags_value = try readStringList(allocator, &reader);
                    errdefer freeStringList(allocator, tags_value);
                    const metadata_value = try allocator.dupe(u8, try reader.readLenBytes());
                    errdefer allocator.free(metadata_value);
                    const program_mapping_fingerprint: ?u64 = if (format_version == provider_offer_program_format_version) try reader.readU64() else null;
                    if (!reader.eof()) return error.ProgramContractViolation;
                    const owned = try allocator.dupe(u8, bytes);
                    errdefer allocator.free(owned);
                    var offer = ProviderOffer{
                        .allocator = allocator,
                        .bytes = owned,
                        .format_version = format_version,
                        .fingerprint = try checkedBytesFingerprint(bytes, "ability.exchange.provider_offer", exchange_provider_offer_fingerprint_version),
                        .label = label_value,
                        .provider_fingerprint = provider_fp,
                        .manifest_fingerprint = manifest_fp,
                        .supported_operation_sites = operation_sites,
                        .supported_after_sites = after_sites,
                        .supported_protocol_op_fingerprints = protocol_ops,
                        .supported_protocol_labels = protocol_labels,
                        .accepted_payload_refs = payload_refs,
                        .accepted_current_value_refs = current_refs,
                        .produced_response_refs = response_refs,
                        .allowed_response_kinds = response_kinds,
                        .supported_usage_modes = usage_modes,
                        .supported_response_uses = response_uses,
                        .supported_replay_policies = replay_policies,
                        .supported_branch_policies = branch_policies,
                        .capsule_policy = capsule_policy_value,
                        .opens_obligation = opens_obligation_value,
                        .max_request_bytes = max_request,
                        .max_response_bytes = max_response,
                        .max_capsule_bytes = max_capsule,
                        .tags = tags_value,
                        .metadata = metadata_value,
                        .provider_program_mapping_fingerprint = program_mapping_fingerprint,
                    };
                    try offer.validate();
                    return offer;
                }

                /// Validate the offer fields and byte binding.
                pub fn validate(self: @This()) Error!void {
                    if (self.label.len == 0) return error.ProgramContractViolation;
                    if (self.max_response_bytes == 0 or self.max_request_bytes == 0) return error.ProgramContractViolation;
                    if (self.provider_program_mapping_fingerprint) |fingerprint| {
                        if (fingerprint == 0) return error.ProgramContractViolation;
                    }
                    if (!providerOfferFieldsBoundToBytes(self)) return error.ProgramContractViolation;
                }

                /// Release provider offer owned storage.
                pub fn deinit(self: *@This()) void {
                    self.allocator.free(self.bytes);
                    self.allocator.free(self.label);
                    self.allocator.free(self.supported_operation_sites);
                    self.allocator.free(self.supported_after_sites);
                    self.allocator.free(self.supported_protocol_op_fingerprints);
                    freeStringList(self.allocator, self.supported_protocol_labels);
                    self.allocator.free(self.accepted_payload_refs);
                    self.allocator.free(self.accepted_current_value_refs);
                    self.allocator.free(self.produced_response_refs);
                    freeStringList(self.allocator, self.tags);
                    self.allocator.free(self.metadata);
                    self.bytes = &.{};
                }

                /// Return true when the offer can handle the source request envelope.
                pub fn supportsRequest(self: @This(), request: RequestEnvelope) bool {
                    self.validate() catch return false;
                    request.validate() catch return false;
                    if (self.manifest_fingerprint != request.manifest_fingerprint) return false;
                    if (request.bytes.len > self.max_request_bytes) return false;
                    if (request.capsule_image) |image| {
                        const has_capsule = true;
                        if (!self.capsule_policy.allows(has_capsule) or image.len > self.max_capsule_bytes) return false;
                    } else {
                        const has_capsule = false;
                        if (!self.capsule_policy.allows(has_capsule)) return false;
                    }
                    const requirement_label = requestRequirementLabel(request) orelse return false;
                    if (!listAllowsString(self.supported_protocol_labels, requirement_label)) return false;
                    const protocol_op = requestProtocolOperationFingerprint(request) orelse return false;
                    if (!listAllowsU64(self.supported_protocol_op_fingerprints, protocol_op)) return false;
                    const operation_sites_constrained = self.supported_operation_sites.len != 0;
                    const after_sites_constrained = self.supported_after_sites.len != 0;
                    if (!offerUsageCompatible(self, request)) return false;
                    if (!offerResponseCompatible(self, request)) return false;
                    switch (request.kind) {
                        .operation => {
                            if (!operation_sites_constrained and after_sites_constrained) return false;
                            return listAllowsValueRef(self.accepted_payload_refs, request.value_ref) and listAllowsUsize(self.supported_operation_sites, request.site_index);
                        },
                        .after => {
                            if (!after_sites_constrained and operation_sites_constrained) return false;
                            return offerAllowsCurrentValueRef(self.accepted_current_value_refs, request.value_ref) and listAllowsUsize(self.supported_after_sites, request.site_index);
                        },
                    }
                }

                /// Canonical evidence reference for this provider offer.
                pub fn evidenceRef(self: @This()) Evidence.Ref {
                    return Evidence.refForProviderOffer(self);
                }

                /// Return true when the offer supports a target protocol operation.
                pub fn supportsProtocolOperation(self: @This(), protocol_op_fingerprint: u64, response_refs: []const lowering_api.ValueRef) bool {
                    self.validate() catch return false;
                    if (self.supported_protocol_op_fingerprints.len == 0 and self.supported_protocol_labels.len != 0) return false;
                    if (!listAllowsU64(self.supported_protocol_op_fingerprints, protocol_op_fingerprint)) return false;
                    for (response_refs) |response_ref| {
                        if (!listAllowsValueRef(self.produced_response_refs, response_ref)) return false;
                    }
                    return true;
                }

                /// Return true when a morphism-adapted request still satisfies source-envelope offer limits.
                pub fn supportsMorphismRequest(self: @This(), source_request: RequestEnvelope, target_protocol_op_fingerprint: u64, response_refs: []const lowering_api.ValueRef) bool {
                    self.validate() catch return false;
                    source_request.validate() catch return false;
                    if (self.manifest_fingerprint != source_request.manifest_fingerprint) return false;
                    if (source_request.bytes.len > self.max_request_bytes) return false;
                    if (source_request.capsule_image) |image| {
                        const has_capsule = true;
                        if (!self.capsule_policy.allows(has_capsule) or image.len > self.max_capsule_bytes) return false;
                    } else {
                        const has_capsule = false;
                        if (!self.capsule_policy.allows(has_capsule)) return false;
                    }
                    const operation_sites_constrained = self.supported_operation_sites.len != 0;
                    const after_sites_constrained = self.supported_after_sites.len != 0;
                    switch (source_request.kind) {
                        .operation => {
                            if (!operation_sites_constrained and after_sites_constrained) return false;
                            if (!listAllowsUsize(self.supported_operation_sites, source_request.site_index)) return false;
                            if (!listAllowsValueRef(self.accepted_payload_refs, source_request.value_ref)) return false;
                        },
                        .after => {
                            if (!after_sites_constrained and operation_sites_constrained) return false;
                            if (!listAllowsUsize(self.supported_after_sites, source_request.site_index)) return false;
                            if (!offerAllowsCurrentValueRef(self.accepted_current_value_refs, source_request.value_ref)) return false;
                        },
                    }
                    return self.supportsProtocolOperation(target_protocol_op_fingerprint, response_refs);
                }
            };

            /// Deterministic ways to map a parent request into a provider Program invocation.
            pub const RequestToProgramArgs = enum {
                payload_to_args,
                payload_and_metadata_to_args,
                unit_args,
                custom_comptime_mapper,
            };

            /// Deterministic ways to map a provider Program result into a provider outcome.
            pub const ProgramResultToProviderOutcome = enum {
                result_to_resume,
                result_to_return_now,
                result_to_resume_after,
                result_to_outcome_union,
            };

            /// Options attached to one handler-first provider declaration.
            pub const ProviderHandlerOptions = struct {
                label: ?[]const u8 = null,
                allowed_response_kinds: ?Policy.ResponseKindSet = null,
                supported_usage_modes: UsageSet = .{},
                supported_response_uses: ResponseUseSet = .{},
                supported_replay_policies: ResponseUseSet = .{},
                supported_branch_policies: BranchPolicySet = .{},
                capsule_policy: CapsulePolicy = .allowed,
                opens_obligation: bool = false,
                max_request_bytes: usize = std.math.maxInt(usize),
                max_response_bytes: usize = std.math.maxInt(usize),
                max_capsule_bytes: usize = std.math.maxInt(usize),
                protocol_label: ?[]const u8 = null,
                protocol_op_fingerprint: ?u64 = null,
                tags: []const []const u8 = &.{},
                metadata: []const u8 = &.{},
            };

            /// Handler-first declarations for provider harness catalogs.
            pub const ProviderHandler = struct {
                /// Declare an operation handler for a concrete Program protocol site.
                pub fn operation(comptime SiteType: type, comptime handler_value: anytype, comptime options: ProviderHandlerOptions) type {
                    return struct {
                        /// Declaration kind.
                        pub const kind = .operation;
                        /// Program protocol site handled by this provider declaration.
                        pub const Site = SiteType;
                        /// Handler function or value associated with the declaration.
                        pub const handler = handler_value;
                        /// Provider-offer options for this handler declaration.
                        pub const offer_options = options;
                    };
                }

                /// Declare an after-continuation handler for a concrete Program protocol site.
                pub fn after(comptime SiteType: type, comptime handler_value: anytype, comptime options: ProviderHandlerOptions) type {
                    return struct {
                        /// Declaration kind.
                        pub const kind = .after;
                        /// Program protocol after site handled by this provider declaration.
                        pub const Site = SiteType;
                        /// Handler function or value associated with the declaration.
                        pub const handler = handler_value;
                        /// Provider-offer options for this handler declaration.
                        pub const offer_options = options;
                    };
                }

                /// Declare a provider handler backed by another Ability Program.
                pub fn program(comptime options: anytype) type {
                    const has_operation_site = comptime providerHarnessHasField(@TypeOf(options), "op");
                    const has_after_site = comptime providerHarnessHasField(@TypeOf(options), "after");
                    if (has_operation_site == has_after_site) {
                        @compileError("Program.Exchange.ProviderHandler.program requires exactly one of op or after");
                    }
                    if (comptime !providerHarnessHasField(@TypeOf(options), "program")) {
                        @compileError("Program.Exchange.ProviderHandler.program requires program");
                    }

                    const SiteType = if (has_operation_site) options.op else options.after;
                    const ProgramType = options.program;
                    if (!hasDeclSafe(ProgramType, "compiled_plan") or !hasDeclSafe(ProgramType, "contract")) {
                        @compileError("Program.Exchange.ProviderHandler.program requires an Ability Program type");
                    }
                    const request_mapping = providerHarnessField(options, "map_request", RequestToProgramArgs.payload_to_args);
                    const result_mapping = providerHarnessField(options, "map_result", if (has_after_site) ProgramResultToProviderOutcome.result_to_resume_after else ProgramResultToProviderOutcome.result_to_resume);
                    const custom_mapper_fingerprint = providerHarnessField(options, "mapper_fingerprint", @as(?u64, null));
                    switch (request_mapping) {
                        .payload_to_args, .unit_args => {},
                        .payload_and_metadata_to_args => @compileError("provider Program payload_and_metadata_to_args is reserved until provider-program metadata argument execution is implemented"),
                        .custom_comptime_mapper => @compileError("provider Program custom_comptime_mapper is reserved until provider-program custom mapper execution is implemented"),
                    }
                    switch (result_mapping) {
                        .result_to_resume, .result_to_return_now, .result_to_resume_after => {},
                        .result_to_outcome_union => @compileError("provider Program result_to_outcome_union is reserved until provider-program outcome-union execution is implemented"),
                    }
                    validateProviderProgramRequestMapping(
                        if (has_operation_site) .operation else .after,
                        SiteType,
                        ProgramType,
                        request_mapping,
                        custom_mapper_fingerprint,
                    );
                    const mapping_fingerprint = providerProgramMappingFingerprint(
                        if (has_operation_site) .operation else .after,
                        SiteType,
                        ProgramType,
                        request_mapping,
                        result_mapping,
                        custom_mapper_fingerprint,
                    );

                    return struct {
                        /// Declaration kind.
                        pub const kind = if (has_operation_site) .operation else .after;
                        /// Program protocol site handled by this provider declaration.
                        pub const Site = SiteType;
                        /// Handler implementation Program run by provider-program APIs.
                        pub const handler_program = ProgramType;
                        /// Compatibility alias for declaration consumers.
                        pub const Program = ProgramType;
                        /// Program-backed declarations are handled through provider-program execution APIs.
                        pub const program_backed = true;
                        /// Request-to-handler-Program argument mapping.
                        pub const request_to_program_args = request_mapping;
                        /// Handler-Program-result-to-provider-outcome mapping.
                        pub const program_result_to_provider_outcome = result_mapping;
                        /// Entry parameter refs expected by the request mapping.
                        pub const handler_program_entry_parameters = ProgramType.contract.entry_parameters;
                        /// Result ref consumed by the outcome mapping.
                        pub const handler_program_result_ref = ProgramType.contract.result_ref;
                        /// Stable witness for the handler Program and mapping agreement.
                        pub const provider_program_mapping_fingerprint = mapping_fingerprint;
                        /// Provider-offer options for this handler declaration.
                        pub const offer_options = providerProgramOfferOptions(options);
                    };
                }
            };

            /// Compatibility namespace for handler-first provider declarations.
            pub const Provider = struct {
                /// Declare one operation-site provider handler with derived catalog metadata.
                pub fn operation(comptime site: type, comptime handler_fn: anytype) type {
                    return ProviderHandler.operation(site, handler_fn, .{});
                }

                /// Declare one operation-site provider handler with explicit catalog metadata.
                pub fn operationWithOffer(comptime site: type, comptime handler_fn: anytype, comptime offer_options: ProviderHandlerOptions) type {
                    return ProviderHandler.operation(site, handler_fn, offer_options);
                }

                /// Declare one after-continuation provider handler with derived catalog metadata.
                pub fn after(comptime site: type, comptime handler_fn: anytype) type {
                    return ProviderHandler.after(site, handler_fn, .{});
                }

                /// Declare one after-continuation provider handler with explicit catalog metadata.
                pub fn afterWithOffer(comptime site: type, comptime handler_fn: anytype, comptime offer_options: ProviderHandlerOptions) type {
                    return ProviderHandler.after(site, handler_fn, offer_options);
                }
            };

            /// Handler-first provider catalog derived from Program protocol descriptors.
            pub fn ProviderHarness(comptime options: anytype) type {
                comptime validateProviderHarnessOptions(options);
                const Options = @TypeOf(options);
                const provider_label = options.label;
                const provider_metadata = providerHarnessField(options, "metadata", @as([]const u8, &.{}));
                const provider_fp = providerHarnessField(options, "provider_fingerprint", @as(?u64, null)) orelse providerIdentityFingerprint(provider_label, provider_metadata);
                const entries = if (comptime providerHarnessHasField(Options, "entries")) options.entries else options.handlers;
                const operation_site_count = providerHarnessOperationSiteCount(entries);
                const after_site_count = providerHarnessAfterSiteCount(entries);
                const operation_sites = providerHarnessOperationSites(entries);
                const after_sites = providerHarnessAfterSites(entries);
                const protocol_labels = providerHarnessProtocolLabels(entries);
                const protocol_ops = providerHarnessProtocolOps(entries);
                const manifest_response_kinds_value = providerHarnessManifestResponseKinds(options, entries);
                const manifest_max_request_bytes_value = providerHarnessManifestMaxRequestBytes(options, entries);
                const manifest_max_response_bytes_value = providerHarnessManifestMaxResponseBytes(options, entries);
                const manifest_accepts_embedded_capsules_value = providerHarnessField(options, "accepts_embedded_capsules", @as(bool, true));
                const manifest_accepts_capsule_restore_value = providerHarnessField(options, "accepts_capsule_restore", @as(bool, true));
                const manifest_semantic_tags_value = providerHarnessField(options, "semantic_tags", @as([]const []const u8, &.{}));

                return struct {
                    /// Provider label used for the derived manifest.
                    pub const provider_label_text = provider_label;
                    /// Stable provider identity used by every derived offer.
                    pub const provider_fingerprint = provider_fp;
                    /// Number of handler declarations in the harness.
                    pub const offer_count = entries.len;
                    /// Number of provider handler declarations.
                    pub const declaration_count = entries.len;
                    /// Number of operation sites covered by the harness.
                    pub const handled_operation_site_count = operation_site_count;
                    /// Number of after-continuation sites covered by the harness.
                    pub const handled_after_site_count = after_site_count;
                    /// Operation-site indexes covered by this provider harness.
                    pub const supported_operation_sites = operation_sites[0..];
                    /// After-continuation site indexes covered by this provider harness.
                    pub const supported_after_sites = after_sites[0..];
                    /// Protocol labels covered by this provider harness.
                    pub const supported_protocol_labels = protocol_labels[0..];
                    /// Protocol-operation fingerprints covered by this provider harness.
                    pub const supported_protocol_op_fingerprints = protocol_ops[0..];
                    /// Manifest-level response-kind policy derived from harness options and declarations.
                    pub const manifest_allowed_response_kinds = manifest_response_kinds_value;
                    /// Manifest-level maximum request envelope bytes.
                    pub const manifest_max_request_envelope_bytes = manifest_max_request_bytes_value;
                    /// Manifest-level maximum response envelope bytes.
                    pub const manifest_max_response_envelope_bytes = manifest_max_response_bytes_value;
                    /// Manifest-level embedded-capsule admission policy.
                    pub const manifest_accepts_embedded_capsules = manifest_accepts_embedded_capsules_value;
                    /// Manifest-level capsule-restore admission policy.
                    pub const manifest_accepts_capsule_restore = manifest_accepts_capsule_restore_value;
                    /// Manifest-level semantic tags.
                    pub const manifest_semantic_tags = manifest_semantic_tags_value;
                    /// Manifest-level metadata bytes.
                    pub const manifest_metadata = provider_metadata;
                    /// Handler declaration entries.
                    pub const declarations = entries;

                    /// Canonical evidence domain for this handler-first provider harness.
                    pub const evidenceDomain = Evidence.domains.provider_harness;
                    /// Canonical evidence reference for this handler-first provider harness.
                    pub const evidence_ref = Evidence.refForProviderHarness(@This());

                    /// Return the canonical evidence reference for this provider harness type.
                    pub fn evidenceRef() Evidence.Ref {
                        return evidence_ref;
                    }

                    /// Static provider catalog metadata.
                    pub const Metadata = struct {
                        label: []const u8,
                        provider_fingerprint: u64,
                        offer_count: usize,
                        handled_operation_site_count: usize,
                        handled_after_site_count: usize,
                    };

                    /// Static provider catalog metadata value.
                    pub const metadata = Metadata{
                        .label = provider_label_text,
                        .provider_fingerprint = provider_fingerprint,
                        .offer_count = offer_count,
                        .handled_operation_site_count = handled_operation_site_count,
                        .handled_after_site_count = handled_after_site_count,
                    };

                    /// Owned provider catalog images derived from this harness.
                    pub const Catalog = struct {
                        allocator: std.mem.Allocator,
                        manifest: Manifest,
                        provider_manifest: ProviderManifest,
                        provider_offers: []ProviderOffer,
                        offer_fingerprints: []u64,
                        metadata: Metadata,

                        /// Release provider catalog storage.
                        pub fn deinit(self: *@This()) void {
                            for (self.provider_offers) |*offer| offer.deinit();
                            self.allocator.free(self.provider_offers);
                            self.allocator.free(self.offer_fingerprints);
                            self.provider_manifest.deinit();
                            self.manifest.deinit();
                            self.provider_offers = &.{};
                            self.offer_fingerprints = &.{};
                        }
                    };

                    /// Assert every reachable Program exchange site is covered by this provider harness.
                    pub fn assertCoversAll() void {
                        comptime assertProviderHarnessCoversAll(entries);
                    }

                    /// Assert every reachable Program exchange site is covered by this provider harness.
                    pub fn assertAllSitesCovered() void {
                        comptime assertProviderHarnessCoversAll(entries);
                    }

                    /// Return provider-manifest options derived from this harness for one Program manifest.
                    pub fn manifestOptions(manifest_fingerprints: []const u64) ProviderManifest.Options {
                        return .{
                            .label = provider_label_text,
                            .provider_fingerprint = provider_fingerprint,
                            .supported_program_manifest_fingerprints = manifest_fingerprints,
                            .supported_protocol_labels = supported_protocol_labels,
                            .supported_operation_sites = supported_operation_sites,
                            .supported_after_sites = supported_after_sites,
                            .supported_protocol_op_fingerprints = supported_protocol_op_fingerprints,
                            .allowed_response_kinds = manifest_allowed_response_kinds,
                            .max_request_envelope_bytes = manifest_max_request_envelope_bytes,
                            .max_response_envelope_bytes = manifest_max_response_envelope_bytes,
                            .accepts_embedded_capsules = manifest_accepts_embedded_capsules,
                            .accepts_capsule_restore = manifest_accepts_capsule_restore,
                            .semantic_tags = manifest_semantic_tags,
                            .metadata = provider_metadata,
                        };
                    }

                    /// Build the provider manifest derived from this harness.
                    pub fn providerManifest(allocator: std.mem.Allocator) Error!ProviderManifest {
                        var manifest = try Manifest.encode(allocator);
                        defer manifest.deinit();
                        const manifest_fingerprints = [_]u64{manifest.fingerprint};
                        return ProviderManifest.encode(allocator, manifestOptions(manifest_fingerprints[0..]));
                    }

                    /// Build deterministic manifest and offer images for this provider harness.
                    pub fn buildCatalog(allocator: std.mem.Allocator) Error!Catalog {
                        var manifest = try Manifest.encode(allocator);
                        errdefer manifest.deinit();

                        const manifest_fingerprints = [_]u64{manifest.fingerprint};
                        var provider_manifest = try ProviderManifest.encode(allocator, manifestOptions(manifest_fingerprints[0..]));
                        errdefer provider_manifest.deinit();

                        var offers = try allocator.alloc(ProviderOffer, entries.len);
                        errdefer allocator.free(offers);
                        var initialized: usize = 0;
                        errdefer for (offers[0..initialized]) |*offer| offer.deinit();
                        inline for (entries, 0..) |_, index| {
                            offers[index] = try ProviderOffer.encode(allocator, offerOptions(index, manifest.fingerprint));
                            initialized += 1;
                        }

                        var offer_fingerprints = try allocator.alloc(u64, entries.len);
                        errdefer allocator.free(offer_fingerprints);
                        for (offers, 0..) |offer, index| offer_fingerprints[index] = offer.fingerprint;

                        return .{
                            .allocator = allocator,
                            .manifest = manifest,
                            .provider_manifest = provider_manifest,
                            .provider_offers = offers,
                            .offer_fingerprints = offer_fingerprints,
                            .metadata = metadata,
                        };
                    }

                    /// Alias for `buildCatalog`.
                    pub fn catalog(allocator: std.mem.Allocator) Error!Catalog {
                        return buildCatalog(allocator);
                    }

                    /// Return the derived provider offer options for one handler declaration.
                    pub fn offerOptions(comptime index: usize, manifest_fingerprint: u64) ProviderOffer.Options {
                        if (index >= entries.len) @compileError("Program.Exchange.ProviderHarness providerOffer handler index out of range");
                        return providerHarnessOfferOptions(entries[index], manifest_fingerprint, provider_fingerprint);
                    }

                    /// Build the provider offer derived for one handler declaration.
                    pub fn providerOffer(allocator: std.mem.Allocator, comptime index: usize) Error!ProviderOffer {
                        var manifest = try Manifest.encode(allocator);
                        defer manifest.deinit();
                        return ProviderOffer.encode(allocator, offerOptions(index, manifest.fingerprint));
                    }

                    /// Build every provider offer derived from this harness.
                    pub fn providerOffers(allocator: std.mem.Allocator) Error![]ProviderOffer {
                        var manifest = try Manifest.encode(allocator);
                        defer manifest.deinit();
                        var offers = try allocator.alloc(ProviderOffer, entries.len);
                        errdefer allocator.free(offers);
                        var initialized: usize = 0;
                        errdefer for (offers[0..initialized]) |*offer| offer.deinit();
                        inline for (entries, 0..) |_, index| {
                            offers[index] = try ProviderOffer.encode(allocator, offerOptions(index, manifest.fingerprint));
                            initialized += 1;
                        }
                        return offers;
                    }

                    /// Validate a manually supplied provider catalog against the derived exact images.
                    pub fn validateManualCatalog(
                        allocator: std.mem.Allocator,
                        provider_manifest: ProviderManifest,
                        provider_offers: []const ProviderOffer,
                    ) Error!void {
                        var derived = try buildCatalog(allocator);
                        defer derived.deinit();

                        if (!providerFieldsBoundToBytes(provider_manifest)) return error.ProgramContractViolation;
                        if (provider_manifest.fingerprint != derived.provider_manifest.fingerprint or
                            !std.mem.eql(u8, provider_manifest.bytes, derived.provider_manifest.bytes))
                        {
                            return error.ProgramContractViolation;
                        }
                        if (provider_offers.len != derived.provider_offers.len) return error.ProgramContractViolation;
                        var seen: [entries.len]bool = [_]bool{false} ** entries.len;
                        for (provider_offers) |offer| {
                            try offer.validate();
                            if (offer.provider_fingerprint != provider_fingerprint) return error.ProgramContractViolation;
                            if (offer.manifest_fingerprint != derived.manifest.fingerprint) return error.ProgramContractViolation;
                            var matched: ?usize = null;
                            derived_match: for (derived.provider_offers, 0..) |expected, expected_index| {
                                if (seen[expected_index]) continue :derived_match;
                                if (offer.fingerprint == expected.fingerprint and std.mem.eql(u8, offer.bytes, expected.bytes)) {
                                    matched = expected_index;
                                    break;
                                }
                            }
                            const expected_index = matched orelse return error.ProgramContractViolation;
                            seen[expected_index] = true;
                        }
                    }

                    /// Validate that one manually supplied offer exactly matches the derived offer.
                    pub fn validateManualOffer(allocator: std.mem.Allocator, comptime index: usize, offer: ProviderOffer) Error!void {
                        var manifest = try Manifest.encode(allocator);
                        defer manifest.deinit();
                        var expected = try ProviderOffer.encode(allocator, offerOptions(index, manifest.fingerprint));
                        defer expected.deinit();
                        try offer.validate();
                        if (offer.fingerprint != expected.fingerprint or !std.mem.eql(u8, offer.bytes, expected.bytes)) return error.ProgramContractViolation;
                    }

                    /// Validate that manually supplied offers exactly match the derived catalog order.
                    pub fn validateManualOffers(allocator: std.mem.Allocator, offers: []const ProviderOffer) Error!void {
                        if (offers.len != entries.len) return error.ProgramContractViolation;
                        inline for (entries, 0..) |_, index| {
                            try validateManualOffer(allocator, index, offers[index]);
                        }
                    }

                    /// Structured provider-side rejection reason.
                    pub const ProviderBlockerTag = enum {
                        malformed_request_envelope,
                        manifest_mismatch,
                        treaty_missing,
                        treaty_mismatch,
                        treaty_certificate_invalid,
                        provider_mismatch,
                        offer_mismatch,
                        offer_not_in_harness,
                        capability_mismatch,
                        attenuated_capability_mismatch,
                        route_mismatch,
                        usage_mode_not_supported,
                        response_use_not_supported,
                        branch_policy_not_supported,
                        replay_policy_not_supported,
                        obligation_state_invalid,
                        capability_instance_invalid,
                        payload_ref_mismatch,
                        payload_decode_failed,
                        capsule_policy_violation,
                        byte_limit_exceeded,
                        handler_rejected,
                        handler_forwarded,
                        pending_response,
                        handler_program_requires_step_api,
                        handler_program_arg_mismatch,
                        handler_program_result_mapping_invalid,
                        handler_program_effect_unhandled,
                        handler_program_nested_request_invalid,
                        handler_program_restore_mismatch,
                        handler_program_capsule_missing,
                        invalid_provider_outcome,
                        response_build_failed,
                    };

                    /// Provider-side blocker with stable exchange witnesses when available.
                    pub const Blocker = struct {
                        tag: ProviderBlockerTag,
                        provider_fingerprint: ?u64 = provider_fingerprint,
                        offer_fingerprint: ?u64 = null,
                        treaty_fingerprint: ?u64 = null,
                        route_fingerprint: ?u64 = null,
                        request_envelope_fingerprint: ?u64 = null,
                        request_envelope_format_version: ?u32 = null,
                        capability_fingerprint: ?u64 = null,
                        obligation_fingerprint: ?u64 = null,
                        summary: []const u8,

                        /// Lower provider-specific blocker metadata into the shared Evidence blocker shape.
                        pub fn toEvidenceBlocker(self: @This()) Evidence.Blocker {
                            var related_storage = [_]Evidence.Ref{Evidence.refForProviderIdentity(0)} ** 6;
                            var related_len: usize = 0;
                            if (self.provider_fingerprint) |fingerprint| {
                                related_storage[related_len] = Evidence.refForProviderIdentity(fingerprint);
                                related_len += 1;
                            }
                            if (self.offer_fingerprint) |fingerprint| {
                                related_storage[related_len] = Evidence.refFor(Evidence.domains.provider_offer, fingerprint, .{});
                                related_len += 1;
                            }
                            if (self.treaty_fingerprint) |fingerprint| {
                                related_storage[related_len] = Evidence.refFor(Evidence.domains.treaty, fingerprint, .{});
                                related_len += 1;
                            }
                            if (self.route_fingerprint) |fingerprint| {
                                related_storage[related_len] = Evidence.refFor(Evidence.domains.route, fingerprint, .{});
                                related_len += 1;
                            }
                            if (self.capability_fingerprint) |fingerprint| {
                                related_storage[related_len] = Evidence.refFor(Evidence.domains.capability, fingerprint, .{});
                                related_len += 1;
                            }
                            if (self.obligation_fingerprint) |fingerprint| {
                                related_storage[related_len] = Evidence.refFor(Evidence.domains.obligation, fingerprint, .{});
                                related_len += 1;
                            }
                            var evidence_blocker = self.toEvidenceBlockerWithRelated(null);
                            evidence_blocker.related_ref_storage = related_storage;
                            evidence_blocker.related_ref_count = related_len;
                            return evidence_blocker;
                        }

                        /// Lower provider-specific blocker metadata with caller-owned related-ref storage.
                        pub fn toEvidenceBlockerWithRelated(self: @This(), storage: ?*[6]Evidence.Ref) Evidence.Blocker {
                            var related_len: usize = 0;
                            const related_refs = if (storage) |related_storage| blk: {
                                if (self.provider_fingerprint) |fingerprint| {
                                    related_storage[related_len] = Evidence.refForProviderIdentity(fingerprint);
                                    related_len += 1;
                                }
                                if (self.offer_fingerprint) |fingerprint| {
                                    related_storage[related_len] = Evidence.refFor(Evidence.domains.provider_offer, fingerprint, .{});
                                    related_len += 1;
                                }
                                if (self.treaty_fingerprint) |fingerprint| {
                                    related_storage[related_len] = Evidence.refFor(Evidence.domains.treaty, fingerprint, .{});
                                    related_len += 1;
                                }
                                if (self.route_fingerprint) |fingerprint| {
                                    related_storage[related_len] = Evidence.refFor(Evidence.domains.route, fingerprint, .{});
                                    related_len += 1;
                                }
                                if (self.capability_fingerprint) |fingerprint| {
                                    related_storage[related_len] = Evidence.refFor(Evidence.domains.capability, fingerprint, .{});
                                    related_len += 1;
                                }
                                if (self.obligation_fingerprint) |fingerprint| {
                                    related_storage[related_len] = Evidence.refFor(Evidence.domains.obligation, fingerprint, .{});
                                    related_len += 1;
                                }
                                break :blk related_storage[0..related_len];
                            } else &.{};
                            const subject = if (self.request_envelope_fingerprint) |fingerprint| Evidence.refFor(Evidence.domains.exchange_request_envelope, fingerprint, .{ .format_version = self.request_envelope_format_version }) else null;
                            const primary = if (self.offer_fingerprint) |fingerprint|
                                Evidence.refFor(Evidence.domains.provider_offer, fingerprint, .{})
                            else if (self.route_fingerprint) |fingerprint|
                                Evidence.refFor(Evidence.domains.route, fingerprint, .{})
                            else if (self.capability_fingerprint) |fingerprint|
                                Evidence.refFor(Evidence.domains.capability, fingerprint, .{})
                            else if (self.obligation_fingerprint) |fingerprint|
                                Evidence.refFor(Evidence.domains.obligation, fingerprint, .{})
                            else if (self.treaty_fingerprint) |fingerprint|
                                Evidence.refFor(Evidence.domains.treaty, fingerprint, .{})
                            else if (self.provider_fingerprint) |fingerprint|
                                Evidence.refForProviderIdentity(fingerprint)
                            else
                                subject;
                            return .{
                                .domain = Evidence.domains.provider_request_validation.id,
                                .tag = @tagName(self.tag),
                                .subject = subject,
                                .primary = primary,
                                .related_refs = related_refs,
                                .short_code = @tagName(self.tag),
                                .summary = if (self.summary.len == 0) @tagName(self.tag) else self.summary,
                                .source = .provider_harness,
                            };
                        }
                    };

                    /// Provider-side journal and replay options.
                    pub const HandleOptions = struct {
                        journal: ?*Session.Journal = null,
                        treaty: ?Treaty = null,
                        capability_instance_state: ?*const CapabilityInstance = null,
                        obligation_state: ?*const Obligation = null,
                        response_use: ?ResponseUse = null,
                        replay_source_journal: ?*const Session.Journal = null,
                        replay_source_response_trace: ?Session.Trace.Response = null,
                        replay_source_response: ?ResponseEnvelope = null,
                        replay_source_response_fingerprint: ?u64 = null,
                        replay_source_response_value_fingerprint: ?u64 = null,
                    };

                    /// Provider-built response packet.
                    pub const ResponsePacket = struct {
                        response: ResponseEnvelope,
                        treaty_authorization: Treaty.Authorization,
                        provider_fingerprint: u64,
                        provider_offer_fingerprint: u64,
                        treaty_fingerprint: u64,
                        route_fingerprint: u64,
                        capability_fingerprint: u64,
                        attenuated_capability_fingerprint: ?u64 = null,
                        response_use: ResponseUse,
                        obligation_transition_fingerprint: ?u64 = null,
                        provider_program_execution_fingerprint: ?u64 = null,

                        /// Release response packet storage.
                        pub fn deinit(self: *@This()) void {
                            self.response.deinit();
                        }

                        /// Clone packet-owned response storage before transferring it to another owner.
                        pub fn clone(self: @This(), allocator: std.mem.Allocator) Error!@This() {
                            var response = try ResponseEnvelope.decode(allocator, self.response.bytes);
                            errdefer response.deinit();
                            response.authorization = self.response.authorization;
                            response.treaty_authorization = self.response.treaty_authorization;
                            return .{
                                .response = response,
                                .treaty_authorization = self.treaty_authorization,
                                .provider_fingerprint = self.provider_fingerprint,
                                .provider_offer_fingerprint = self.provider_offer_fingerprint,
                                .treaty_fingerprint = self.treaty_fingerprint,
                                .route_fingerprint = self.route_fingerprint,
                                .capability_fingerprint = self.capability_fingerprint,
                                .attenuated_capability_fingerprint = self.attenuated_capability_fingerprint,
                                .response_use = self.response_use,
                                .obligation_transition_fingerprint = self.obligation_transition_fingerprint,
                                .provider_program_execution_fingerprint = self.provider_program_execution_fingerprint,
                            };
                        }
                    };

                    /// Provider harness handling result.
                    pub const HandleResult = union(enum) {
                        response: ResponsePacket,
                        rejected: Blocker,
                        forwarded: Blocker,
                        pending: Blocker,
                    };

                    /// Provider-program execution lifecycle state.
                    pub const ProviderProgramExecutionState = enum {
                        ready,
                        running,
                        parked_on_nested_request,
                        parked_on_nested_after,
                        done,
                        rejected,
                        failed,
                    };

                    /// Provider-program execution state for one program-backed declaration.
                    pub fn ProviderProgramExecution(comptime index: usize) type {
                        const Entry = entries[index];
                        if (comptime (!@hasDecl(Entry, "program_backed") or !Entry.program_backed)) {
                            @compileError("ProviderProgramExecution requires a program-backed provider declaration");
                        }
                        return struct {
                            execution_fingerprint: u64,
                            parent_request_envelope_fingerprint: u64,
                            parent_request_fingerprint: u64,
                            treaty_fingerprint: u64,
                            treaty_certificate_fingerprint: u64,
                            provider_fingerprint: u64,
                            provider_offer_fingerprint: u64,
                            route_fingerprint: u64,
                            capability_fingerprint: u64,
                            capability_instance_fingerprint: ?u64 = null,
                            obligation_fingerprint: ?u64 = null,
                            handler_program_label: []const u8 = Entry.handler_program.contract.label,
                            handler_program_plan_hash: u64 = Entry.handler_program.compiled_plan.hash(),
                            nested_turn_index: usize = 0,
                            branch_id: ?u64 = null,
                            state: ProviderProgramExecutionState = .ready,
                            session: ?Entry.handler_program.Session = null,
                            nested_request_envelope: ?Entry.handler_program.Exchange.RequestEnvelope = null,
                            nested_request_envelope_fingerprint: ?u64 = null,
                            nested_request_fingerprint: ?u64 = null,
                            provider_program_capsule_image_fingerprint: ?u64 = null,

                            /// Release parked handler Program state, if any.
                            pub fn deinit(self: *@This()) void {
                                if (self.session) |*session| session.deinit();
                                self.session = null;
                                if (self.nested_request_envelope) |*envelope| envelope.deinit();
                                self.nested_request_envelope = null;
                            }

                            /// Canonical Evidence reference for this provider-program execution.
                            pub fn evidenceRef(self: @This()) Evidence.Ref {
                                return Evidence.refForProviderProgramExecution(self);
                            }
                        };
                    }

                    /// Result of starting or stepping a provider-backed handler Program.
                    pub fn ProviderProgramResult(comptime index: usize) type {
                        return union(enum) {
                            response: ResponsePacket,
                            rejected: Blocker,
                            provider_suspended: ProviderProgramExecution(index),
                        };
                    }

                    /// Typed provider request view for one handler declaration.
                    pub fn Request(comptime Entry: type) type {
                        return struct {
                            request_envelope_fingerprint: u64,
                            source_request_fingerprint: u64,
                            treaty_fingerprint: u64,
                            treaty_certificate_fingerprint: u64,
                            provider_fingerprint: u64,
                            provider_offer_fingerprint: u64,
                            route_fingerprint: u64,
                            capability_fingerprint: u64,
                            attenuated_capability_fingerprint: ?u64,
                            capability_instance_fingerprint: ?u64,
                            obligation_fingerprint: ?u64,
                            usage: Usage,
                            response_use: ResponseUse,
                            replay_policy: ResponseUse,
                            branch_policy: BranchPolicy,
                            payload_value_fingerprint: u64,
                            capsule_image_fingerprint: ?u64,
                            journal_branch_id: ?[]const u8,
                            semantic_label: ?[]const u8,
                            source_protocol_op_fingerprint: ?u64,
                            target_protocol_op_fingerprint: ?u64,
                            request_kind: RequestKind,
                            target_site_fingerprint: u64,
                            target_operation_name: []const u8,
                            value_ref: lowering_api.ValueRef,
                            value_image: []const u8,

                            /// Decode the operation payload for this provider declaration.
                            pub fn payload(self: @This(), allocator: std.mem.Allocator) Error!Entry.Site.Payload {
                                if (Entry.kind != .operation) return error.ProgramContractViolation;
                                return decodeExchangeValueImageValue(allocator, self.value_ref, self.payload_value_fingerprint, self.value_image, Entry.Site.Payload) catch |err| switch (err) {
                                    error.ProgramContractViolation => error.ProgramContractViolation,
                                    else => err,
                                };
                            }

                            /// Decode the current value for this after-provider declaration.
                            pub fn currentValue(self: @This(), allocator: std.mem.Allocator) Error!if (Entry.kind == .after and Entry.Site.has_static_input_ref) Entry.Site.Input else void {
                                if (Entry.kind != .after) return error.ProgramContractViolation;
                                if (!Entry.Site.has_static_input_ref) return {};
                                return decodeExchangeValueImageValue(allocator, self.value_ref, self.payload_value_fingerprint, self.value_image, Entry.Site.Input);
                            }
                        };
                    }

                    /// Typed provider handler outcome for one handler declaration.
                    pub fn Outcome(comptime Entry: type) type {
                        return union(enum) {
                            @"resume": if (Entry.kind == .operation) Entry.Site.Resume else void,
                            return_now: if (Entry.kind == .operation) Entry.Site.Result else void,
                            resume_after: if (Entry.kind == .after) Entry.Site.Output else void,
                            replay: if (Entry.kind == .operation) Entry.Site.Resume else void,
                            reject: []const u8,
                            forward,
                            pending,
                        };
                    }

                    fn blocker(tag: ProviderBlockerTag, request: ?RequestEnvelope, certificate: ?Treaty.Certificate, offer_fingerprint: ?u64, summary: []const u8) Blocker {
                        return .{
                            .tag = tag,
                            .offer_fingerprint = offer_fingerprint,
                            .treaty_fingerprint = if (certificate) |cert| cert.treaty_fingerprint else null,
                            .route_fingerprint = if (certificate) |cert| cert.route_fingerprint else null,
                            .request_envelope_fingerprint = if (request) |envelope| envelope.fingerprint else null,
                            .request_envelope_format_version = if (request) |envelope| envelope.request_format_version else null,
                            .capability_fingerprint = if (certificate) |cert| cert.capability_fingerprint else null,
                            .obligation_fingerprint = if (certificate) |cert| cert.obligation_fingerprint else null,
                            .summary = summary,
                        };
                    }

                    fn appendProviderEvent(journal: ?*Session.Journal, kind: Session.Journal.ExchangeEvent.Kind, request: RequestEnvelope, certificate: Treaty.Certificate, response_fingerprint: ?u64, authorization_fingerprint: ?u64, blocker_tag: ?ProviderBlockerTag) Error!void {
                        const ledger = journal orelse return;
                        try ledger.appendExchangeEvent(.{
                            .kind = kind,
                            .provider_fingerprint = provider_fingerprint,
                            .capability_fingerprint = certificate.capability_fingerprint,
                            .route_fingerprint = certificate.route_fingerprint,
                            .request_envelope_fingerprint = request.fingerprint,
                            .response_envelope_fingerprint = response_fingerprint,
                            .treaty_fingerprint = certificate.treaty_fingerprint,
                            .treaty_certificate_fingerprint = certificate.certificate_fingerprint,
                            .provider_offer_fingerprint = certificate.provider_offer_fingerprint,
                            .authorization_fingerprint = authorization_fingerprint,
                            .blocker_tag = if (blocker_tag) |tag| @tagName(tag) else null,
                            .branch_id = if (request.usage_metadata) |metadata_value| metadata_value.branch_id else null,
                        });
                    }

                    fn appendProviderProgramEvent(journal: ?*Session.Journal, kind: Session.Journal.ExchangeEvent.Kind, request: RequestEnvelope, certificate: Treaty.Certificate, execution_fingerprint: u64, nested_request_fingerprint: ?u64, nested_response_fingerprint: ?u64, blocker_tag: ?ProviderBlockerTag) Error!void {
                        const ledger = journal orelse return;
                        try ledger.appendExchangeEvent(.{
                            .kind = kind,
                            .provider_fingerprint = provider_fingerprint,
                            .capability_fingerprint = certificate.capability_fingerprint,
                            .route_fingerprint = certificate.route_fingerprint,
                            .request_envelope_fingerprint = request.fingerprint,
                            .response_envelope_fingerprint = nested_response_fingerprint,
                            .treaty_fingerprint = certificate.treaty_fingerprint,
                            .treaty_certificate_fingerprint = certificate.certificate_fingerprint,
                            .provider_offer_fingerprint = certificate.provider_offer_fingerprint,
                            .provider_program_execution_fingerprint = execution_fingerprint,
                            .provider_program_nested_request_fingerprint = nested_request_fingerprint,
                            .blocker_tag = if (blocker_tag) |tag| @tagName(tag) else null,
                            .branch_id = if (request.usage_metadata) |metadata_value| metadata_value.branch_id else null,
                        });
                    }

                    fn requestView(comptime Entry: type, request: RequestEnvelope, certificate: Treaty.Certificate, offer: ProviderOffer) Request(Entry) {
                        _ = offer;
                        return .{
                            .request_envelope_fingerprint = request.fingerprint,
                            .source_request_fingerprint = request.request_fingerprint,
                            .treaty_fingerprint = certificate.treaty_fingerprint,
                            .treaty_certificate_fingerprint = certificate.certificate_fingerprint,
                            .provider_fingerprint = certificate.provider_fingerprint,
                            .provider_offer_fingerprint = certificate.provider_offer_fingerprint,
                            .route_fingerprint = certificate.route_fingerprint,
                            .capability_fingerprint = certificate.capability_fingerprint,
                            .attenuated_capability_fingerprint = certificate.attenuated_capability_fingerprint,
                            .capability_instance_fingerprint = certificate.capability_instance_fingerprint,
                            .obligation_fingerprint = certificate.obligation_fingerprint,
                            .usage = certificate.usage,
                            .response_use = certificate.response_use,
                            .replay_policy = certificate.replay_policy,
                            .branch_policy = certificate.branch_policy,
                            .payload_value_fingerprint = request.value_fingerprint,
                            .capsule_image_fingerprint = request.capsule_image_fingerprint,
                            .journal_branch_id = request.journal_branch_id,
                            .semantic_label = request.semantic_label,
                            .source_protocol_op_fingerprint = certificate.source_protocol_op_fingerprint orelse requestProtocolOperationFingerprint(request),
                            .target_protocol_op_fingerprint = certificate.target_protocol_op_fingerprint orelse requestProtocolOperationFingerprint(request),
                            .request_kind = request.kind,
                            .target_site_fingerprint = Entry.Site.fingerprint,
                            .target_operation_name = providerHarnessDefaultOfferLabel(Entry),
                            .value_ref = request.value_ref,
                            .value_image = request.value_image,
                        };
                    }

                    fn validateLiveAuthority(request: RequestEnvelope, certificate: Treaty.Certificate, offer: ProviderOffer, treaty: Treaty, options_value: HandleOptions) ?Blocker {
                        if (treaty.request_envelope_format_version != request.request_format_version or
                            treaty.certificate.request_envelope_format_version != request.request_format_version)
                        {
                            return blocker(.treaty_mismatch, request, certificate, offer.fingerprint, "live treaty cites a different request envelope format");
                        }
                        treaty.checkCertificate() catch return blocker(.treaty_certificate_invalid, request, certificate, offer.fingerprint, "live treaty failed deterministic certificate validation");
                        if (treaty.fingerprint != certificate.treaty_fingerprint or
                            treaty.certificate.certificate_fingerprint != certificate.certificate_fingerprint)
                        {
                            return blocker(.treaty_mismatch, request, certificate, offer.fingerprint, "certificate does not match live treaty authority");
                        }
                        if (treaty.route.fingerprint != certificate.route_fingerprint) {
                            return blocker(.route_mismatch, request, certificate, offer.fingerprint, "certificate route does not match live treaty route");
                        }
                        if (treaty.capability_fingerprint != certificate.capability_fingerprint) {
                            return blocker(.capability_mismatch, request, certificate, offer.fingerprint, "certificate capability does not match live treaty capability");
                        }
                        if (treaty.certificate.attenuated_capability_fingerprint != certificate.attenuated_capability_fingerprint) {
                            return blocker(.attenuated_capability_mismatch, request, certificate, offer.fingerprint, "certificate attenuated capability does not match live treaty");
                        }

                        const response_uses_replay = certificate.response_use == .replayed or certificate.response_use == .deterministic_replay;
                        if (certificate.capability_instance_fingerprint) |fingerprint| {
                            const instance = options_value.capability_instance_state orelse return blocker(.capability_instance_invalid, request, certificate, offer.fingerprint, "live capability instance state is required before provider invocation");
                            if (!instance.*.validFingerprint() or instance.*.instance_fingerprint != fingerprint) {
                                return blocker(.capability_instance_invalid, request, certificate, offer.fingerprint, "live capability instance does not match treaty certificate");
                            }
                            if (instance.*.provider_fingerprint != certificate.provider_fingerprint or instance.*.manifest_fingerprint != certificate.manifest_fingerprint) {
                                return blocker(.capability_instance_invalid, request, certificate, offer.fingerprint, "live capability instance scope does not match treaty certificate");
                            }
                            if (!response_uses_replay and instance.*.closed()) {
                                return blocker(.capability_instance_invalid, request, certificate, offer.fingerprint, "live capability instance is already closed");
                            }
                            if (!capabilityInstanceParentMatchesTreatyCapability(instance.*, treaty)) {
                                return blocker(.capability_mismatch, request, certificate, offer.fingerprint, "live capability instance does not derive from treaty capability");
                            }
                            if (certificate.effect_session_spec_fingerprint) |spec_fingerprint| {
                                if (instance.*.effect_session_spec_fingerprint != spec_fingerprint) {
                                    return blocker(.capability_instance_invalid, request, certificate, offer.fingerprint, "live capability instance belongs to a different effect-session spec");
                                }
                            }
                        }

                        if (certificate.obligation_fingerprint) |fingerprint| {
                            const obligation = options_value.obligation_state orelse return blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "live obligation state is required before provider invocation");
                            if (!obligation.*.validFingerprint() or obligation.*.obligation_fingerprint != fingerprint) {
                                return blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "live obligation state does not match treaty certificate");
                            }
                            if (obligation.*.request_envelope_fingerprint != request.fingerprint or obligation.*.request_fingerprint != request.request_fingerprint) {
                                return blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "live obligation does not match request envelope");
                            }
                            if (obligation.*.site_fingerprint != request.site_fingerprint or obligation.*.usage != certificate.usage) {
                                return blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "live obligation request scope does not match treaty certificate");
                            }
                            if (obligation.*.branch_policy != certificate.branch_policy or obligation.*.replay_policy != certificate.replay_policy) {
                                return blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "live obligation policy does not match treaty certificate");
                            }
                            validateObligationResponseMetadata(obligation.*, request.usage_metadata, certificate.response_use) catch {
                                return blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "live obligation metadata does not admit treaty response-use");
                            };
                            if (response_uses_replay) {
                                if (obligation.*.usage == .ephemeral) return blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "ephemeral obligation cannot be replayed");
                                if (obligation.*.status != .open and obligation.*.status != .consumed and obligation.*.status != .replayed) {
                                    return blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "live obligation is not replayable");
                                }
                                if (obligation.*.status == .open and (obligation.*.usage == .linear or obligation.*.usage == .affine) and obligation.*.branch_policy != .replay_only) {
                                    return blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "linear or affine obligation must be consumed before replay");
                                }
                            } else {
                                if (obligation.*.status != .open) return blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "live obligation is already answered");
                                if (obligation.*.branch_policy == .replay_only) return blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "replay-only obligation cannot produce a fresh response");
                            }
                            if (!obligationReplayPolicyAllows(obligation.*.status, obligation.*.branch_policy, obligation.*.replay_policy, certificate.response_use)) {
                                return blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "live obligation replay policy rejects treaty response-use");
                            }
                            if (obligation.*.provider_fingerprint) |provider_value| {
                                if (provider_value != certificate.provider_fingerprint) return blocker(.provider_mismatch, request, certificate, offer.fingerprint, "live obligation provider does not match treaty certificate");
                            }
                            if (obligation.*.max_response_bytes < treaty.route.max_response_bytes) {
                                return blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "live obligation response limit is narrower than treaty route");
                            }
                            if (!responseKindSetSubset(certificate.expected_response_kinds, obligation.*.allowed_response_kinds)) {
                                return blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "live obligation response kinds do not admit treaty certificate");
                            }
                            for (certificate.expected_response_refs) |ref| {
                                if (!listAllowsValueRef(obligation.*.allowed_response_refs, ref)) {
                                    return blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "live obligation response refs do not admit treaty certificate");
                                }
                            }
                            if (certificate.capability_instance_fingerprint) |instance_fingerprint| {
                                const obligation_instance = obligation.*.capability_instance_fingerprint orelse obligation.*.effect_session_instance_fingerprint;
                                if (instance_fingerprint != obligation_instance) {
                                    return blocker(.capability_instance_invalid, request, certificate, offer.fingerprint, "live obligation cites a different capability instance");
                                }
                                const instance = options_value.capability_instance_state orelse return blocker(.capability_instance_invalid, request, certificate, offer.fingerprint, "live capability instance is required for obligation authority");
                                if (!instanceCanAnswerObligation(instance.*, obligation.*, response_uses_replay)) {
                                    return blocker(.capability_instance_invalid, request, certificate, offer.fingerprint, "live capability instance cannot answer obligation");
                                }
                                if (instance.*.usage != obligation.*.usage or instance.*.branch_id != obligation.*.branch_id) {
                                    return blocker(.capability_instance_invalid, request, certificate, offer.fingerprint, "live capability instance policy does not match obligation");
                                }
                            }
                        }
                        return null;
                    }

                    fn validateForEntry(comptime Entry: type, request: RequestEnvelope, certificate: Treaty.Certificate, offer: ProviderOffer, options_value: HandleOptions) ?Blocker {
                        request.validate() catch return blocker(.malformed_request_envelope, request, certificate, offer.fingerprint, "request envelope failed deterministic validation");
                        if (certificate.request_envelope_format_version != request.request_format_version) {
                            return blocker(.treaty_mismatch, request, certificate, offer.fingerprint, "certificate cites a different request envelope format");
                        }
                        certificate.check() catch return blocker(.treaty_certificate_invalid, request, certificate, offer.fingerprint, "treaty certificate failed deterministic validation");
                        const treaty = options_value.treaty orelse return blocker(.treaty_missing, request, certificate, offer.fingerprint, "live treaty authority is required before provider invocation");
                        if (validateLiveAuthority(request, certificate, offer, treaty, options_value)) |failed| return failed;
                        if (certificate.request_envelope_fingerprint != request.fingerprint or
                            certificate.request_fingerprint != request.request_fingerprint)
                        {
                            return blocker(.treaty_mismatch, request, certificate, offer.fingerprint, "certificate does not cite this request envelope");
                        }
                        if (certificate.manifest_fingerprint != request.manifest_fingerprint or offer.manifest_fingerprint != request.manifest_fingerprint) {
                            return blocker(.manifest_mismatch, request, certificate, offer.fingerprint, "manifest fingerprint mismatch");
                        }
                        if (certificate.provider_fingerprint != provider_fingerprint or offer.provider_fingerprint != provider_fingerprint) {
                            return blocker(.provider_mismatch, request, certificate, offer.fingerprint, "provider fingerprint mismatch");
                        }
                        if (certificate.provider_offer_fingerprint != offer.fingerprint) {
                            return blocker(.offer_mismatch, request, certificate, offer.fingerprint, "certificate selected a different provider offer");
                        }
                        if (request.bytes.len > offer.max_request_bytes) return blocker(.byte_limit_exceeded, request, certificate, offer.fingerprint, "request exceeds provider offer byte limit");
                        if (!offer.supported_usage_modes.allows(certificate.provider_usage)) return blocker(.usage_mode_not_supported, request, certificate, offer.fingerprint, "usage mode is not supported by provider offer");
                        if (!offer.supported_response_uses.allows(certificate.response_use)) return blocker(.response_use_not_supported, request, certificate, offer.fingerprint, "response-use class is not supported by provider offer");
                        if (!offer.supported_replay_policies.allows(certificate.replay_policy)) return blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "replay policy is not supported by provider offer");
                        if (!offer.supported_branch_policies.allows(certificate.branch_policy)) return blocker(.branch_policy_not_supported, request, certificate, offer.fingerprint, "branch policy is not supported by provider offer");
                        if (request.capsule_image) |image| {
                            if (!offer.capsule_policy.allows(@as(bool, true)) or image.len > offer.max_capsule_bytes) return blocker(.capsule_policy_violation, request, certificate, offer.fingerprint, "embedded capsule violates provider offer policy");
                        } else if (!offer.capsule_policy.allows(@as(bool, false))) {
                            return blocker(.capsule_policy_violation, request, certificate, offer.fingerprint, "missing embedded capsule violates provider offer policy");
                        }
                        const offer_supports = switch (certificate.handling) {
                            .direct => offerSupportsSelectedRequest(offer, request, certificate),
                            .dynamic_morphism, .residualized, .pipeline_adapted => if (certificate.target_protocol_op_fingerprint) |target|
                                offerSupportsSelectedMorphismRequest(offer, request, certificate, target)
                            else
                                false,
                        };
                        if (!offer_supports) return blocker(.offer_mismatch, request, certificate, offer.fingerprint, "derived offer does not support request shape");
                        switch (Entry.kind) {
                            .operation => if (request.kind != .operation or request.site_index != Entry.Site.index or !request.value_ref.eql(Entry.Site.payload_ref)) {
                                return blocker(.payload_ref_mismatch, request, certificate, offer.fingerprint, "request does not match operation provider declaration");
                            },
                            .after => if (request.kind != .after or request.site_index != Entry.Site.index) {
                                return blocker(.payload_ref_mismatch, request, certificate, offer.fingerprint, "request does not match after provider declaration");
                            } else if (Entry.Site.current_value_ref) |ref| {
                                if (!request.value_ref.eql(ref)) return blocker(.payload_ref_mismatch, request, certificate, offer.fingerprint, "after current-value ref mismatch");
                            },
                            else => unreachable,
                        }
                        return null;
                    }

                    fn offerSupportsSelectedRequest(offer: ProviderOffer, request: RequestEnvelope, certificate: Treaty.Certificate) bool {
                        if (!offerSupportsSelectedResponse(offer, request, certificate, certificate.expected_response_refs)) return false;
                        const requirement_label = requestRequirementLabel(request) orelse return false;
                        if (!listAllowsString(offer.supported_protocol_labels, requirement_label)) return false;
                        const protocol_op = certificate.source_protocol_op_fingerprint orelse requestProtocolOperationFingerprint(request) orelse return false;
                        if (!listAllowsU64(offer.supported_protocol_op_fingerprints, protocol_op)) return false;
                        const operation_sites_constrained = offer.supported_operation_sites.len != 0;
                        const after_sites_constrained = offer.supported_after_sites.len != 0;
                        return switch (request.kind) {
                            .operation => blk: {
                                if (!operation_sites_constrained and after_sites_constrained) break :blk false;
                                break :blk listAllowsValueRef(offer.accepted_payload_refs, request.value_ref) and listAllowsUsize(offer.supported_operation_sites, request.site_index);
                            },
                            .after => blk: {
                                if (!after_sites_constrained and operation_sites_constrained) break :blk false;
                                break :blk offerAllowsCurrentValueRef(offer.accepted_current_value_refs, request.value_ref) and listAllowsUsize(offer.supported_after_sites, request.site_index);
                            },
                        };
                    }

                    fn offerSupportsSelectedMorphismRequest(offer: ProviderOffer, request: RequestEnvelope, certificate: Treaty.Certificate, target_protocol_op_fingerprint: u64) bool {
                        if (!offerSupportsSelectedResponse(offer, request, certificate, certificate.provider_response_refs)) return false;
                        return offer.supportsMorphismRequest(request, target_protocol_op_fingerprint, certificate.provider_response_refs);
                    }

                    fn offerSupportsSelectedResponse(offer: ProviderOffer, request: RequestEnvelope, certificate: Treaty.Certificate, provider_response_refs: []const lowering_api.ValueRef) bool {
                        offer.validate() catch return false;
                        request.validate() catch return false;
                        if (offer.manifest_fingerprint != request.manifest_fingerprint) return false;
                        if (request.bytes.len > offer.max_request_bytes) return false;
                        if (request.capsule_image) |image| {
                            if (!offer.capsule_policy.allows(@as(bool, true)) or image.len > offer.max_capsule_bytes) return false;
                        } else if (!offer.capsule_policy.allows(@as(bool, false))) {
                            return false;
                        }
                        if (!responseKindSetSubset(certificate.expected_response_kinds, offer.allowed_response_kinds)) return false;
                        if (!requestAcceptsAnyResponseKind(request, certificate.expected_response_kinds)) return false;
                        if (!requestAcceptsAnyResponseRef(request, certificate.expected_response_kinds, certificate.expected_response_refs)) return false;
                        for (provider_response_refs) |ref| {
                            if (!listAllowsValueRef(offer.produced_response_refs, ref)) return false;
                        }
                        return true;
                    }

                    fn responsePacket(certificate: Treaty.Certificate, response: ResponseEnvelope, response_use: ResponseUse) Error!ResponsePacket {
                        var packet_response = response;
                        packet_response.treaty_authorization = try Treaty.Authorization.forCertificate(certificate, packet_response, response_use);
                        const authorization = packet_response.treaty_authorization.?;
                        return .{
                            .response = packet_response,
                            .treaty_authorization = authorization,
                            .provider_fingerprint = certificate.provider_fingerprint,
                            .provider_offer_fingerprint = certificate.provider_offer_fingerprint,
                            .treaty_fingerprint = certificate.treaty_fingerprint,
                            .route_fingerprint = certificate.route_fingerprint,
                            .capability_fingerprint = certificate.capability_fingerprint,
                            .attenuated_capability_fingerprint = certificate.attenuated_capability_fingerprint,
                            .response_use = response_use,
                        };
                    }

                    fn replayResponsePacket(certificate: Treaty.Certificate, response: ResponseEnvelope, response_use: ResponseUse, source_response_fingerprint: u64, source_response_value_fingerprint: u64) Error!ResponsePacket {
                        var packet_response = response;
                        packet_response.treaty_authorization = try Treaty.Authorization.forCertificateWithReplaySource(certificate, packet_response, response_use, source_response_fingerprint, source_response_value_fingerprint);
                        const authorization = packet_response.treaty_authorization.?;
                        return .{
                            .response = packet_response,
                            .treaty_authorization = authorization,
                            .provider_fingerprint = certificate.provider_fingerprint,
                            .provider_offer_fingerprint = certificate.provider_offer_fingerprint,
                            .treaty_fingerprint = certificate.treaty_fingerprint,
                            .route_fingerprint = certificate.route_fingerprint,
                            .capability_fingerprint = certificate.capability_fingerprint,
                            .attenuated_capability_fingerprint = certificate.attenuated_capability_fingerprint,
                            .response_use = response_use,
                        };
                    }

                    fn responseUseNeedsReplaySource(response_use: ResponseUse) bool {
                        return response_use == .replayed or response_use == .deterministic_replay;
                    }

                    fn journalContainsReplaySource(journal: *const Session.Journal, request: RequestEnvelope, source_trace: Session.Trace.Response) bool {
                        var matched_request = false;
                        for (journal.entries.items) |entry| {
                            switch (entry) {
                                .request => |request_trace| matched_request = request_trace.fingerprint() == request.request_fingerprint,
                                .response => |response_entry| {
                                    if (matched_request and response_entry.trace.fingerprint == source_trace.fingerprint and
                                        response_entry.trace.request_fingerprint == source_trace.request_fingerprint and
                                        response_entry.trace.kind == source_trace.kind and
                                        response_entry.trace.response_ref.eql(source_trace.response_ref) and
                                        response_entry.trace.response_value_fingerprint == source_trace.response_value_fingerprint)
                                    {
                                        return true;
                                    }
                                    matched_request = false;
                                },
                                else => {},
                            }
                        }
                        return false;
                    }

                    fn handleOptionsSupplyReplaySource(options_value: HandleOptions) bool {
                        return options_value.replay_source_journal != null or
                            options_value.replay_source_response_trace != null or
                            options_value.replay_source_response != null or
                            options_value.replay_source_response_fingerprint != null or
                            options_value.replay_source_response_value_fingerprint != null;
                    }

                    fn obligationReplaySourceFingerprint(options_value: HandleOptions, request: RequestEnvelope, certificate: Treaty.Certificate, offer: ProviderOffer, response: ResponseEnvelope) union(enum) {
                        source: u64,
                        failed: Blocker,
                    } {
                        const obligation = options_value.obligation_state orelse return .{ .failed = blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "live obligation state is required to derive replay source") };
                        if (!obligation.*.validFingerprint() or obligation.*.obligation_fingerprint != certificate.obligation_fingerprint.?) {
                            return .{ .failed = blocker(.obligation_state_invalid, request, certificate, offer.fingerprint, "live obligation state does not match treaty certificate") };
                        }
                        const source_fingerprint = obligation.*.consumed_response_fingerprint orelse obligation.*.replay_source_response_fingerprint orelse {
                            return .{ .failed = blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "obligation replay requires a recorded source response") };
                        };
                        if (source_fingerprint != response.fingerprint) {
                            return .{ .failed = blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "obligation replay source does not match provider response") };
                        }
                        return .{ .source = source_fingerprint };
                    }

                    fn rejectInvalidReplaySource(request: RequestEnvelope, certificate: Treaty.Certificate, offer: ProviderOffer, response_use: ResponseUse, options_value: HandleOptions) ?Blocker {
                        if (!responseUseNeedsReplaySource(response_use)) return null;
                        if (certificate.obligation_fingerprint != null and !handleOptionsSupplyReplaySource(options_value)) return null;
                        const source_journal = options_value.replay_source_journal orelse return blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "replay response requires a recorded replay source journal");
                        const source_trace = options_value.replay_source_response_trace orelse return blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "replay response requires a recorded replay source trace");
                        if (source_trace.fingerprint == 0 or source_trace.response_value_fingerprint == 0) return blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "replay response requires a nonzero replay source witness");
                        if (source_trace.request_fingerprint != request.request_fingerprint) return blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "replay source trace belongs to a different request");
                        if (!certificate.expected_response_kinds.allows(source_trace.kind) or !listAllowsValueRef(certificate.expected_response_refs, source_trace.response_ref)) return blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "replay source trace is outside the selected treaty response shape");
                        if (!journalContainsReplaySource(source_journal, request, source_trace)) return blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "replay source trace is not recorded in the replay journal");
                        const source_response = options_value.replay_source_response orelse return blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "replay response requires a recorded source response envelope");
                        validateResponseEnvelopeFieldsBoundToBytes(source_response) catch return blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "replay source response envelope is invalid");
                        if (source_response.request_fingerprint != source_trace.request_fingerprint or
                            source_response.kind != source_trace.kind or
                            !source_response.response_ref.eql(source_trace.response_ref) or
                            source_response.response_value_fingerprint != source_trace.response_value_fingerprint or
                            source_response.response_trace_fingerprint != source_trace.fingerprint)
                        {
                            return blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "replay source response envelope does not match recorded trace");
                        }
                        if (options_value.replay_source_response_fingerprint) |fingerprint| {
                            if (fingerprint != source_response.fingerprint) return blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "replay source fingerprint does not match recorded response envelope");
                        }
                        if (options_value.replay_source_response_value_fingerprint) |fingerprint| {
                            if (fingerprint != source_trace.response_value_fingerprint) return blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "replay source value fingerprint does not match recorded trace");
                        }
                        return null;
                    }

                    fn finishProviderResponse(options_value: HandleOptions, request: RequestEnvelope, certificate: Treaty.Certificate, offer: ProviderOffer, response: *ResponseEnvelope, response_use: ResponseUse) Error!HandleResult {
                        if (response.bytes.len > offer.max_response_bytes) {
                            const failed = blocker(.byte_limit_exceeded, request, certificate, offer.fingerprint, "response exceeds provider offer byte limit");
                            try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                            response.deinit();
                            return .{ .rejected = failed };
                        }
                        if (options_value.treaty) |treaty| {
                            if (response.bytes.len > treaty.route.max_response_bytes or response.value_image.len > treaty.route.max_payload_bytes) {
                                const failed = blocker(.byte_limit_exceeded, request, certificate, offer.fingerprint, "response exceeds treaty route byte or payload limit");
                                try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, response.fingerprint, null, failed.tag);
                                response.deinit();
                                return .{ .rejected = failed };
                            }
                        }
                        if (!certificate.expected_response_kinds.allows(response.kind) or !listAllowsValueRef(certificate.expected_response_refs, response.response_ref)) {
                            const failed = blocker(.invalid_provider_outcome, request, certificate, offer.fingerprint, "response is not admitted by treaty certificate");
                            try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, response.fingerprint, null, failed.tag);
                            response.deinit();
                            return .{ .rejected = failed };
                        }
                        var packet = if (responseUseNeedsReplaySource(response_use) and handleOptionsSupplyReplaySource(options_value)) packet: {
                            const source_trace = options_value.replay_source_response_trace orelse {
                                const failed = blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "replay response requires a recorded replay source response");
                                try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, response.fingerprint, null, failed.tag);
                                response.deinit();
                                return .{ .rejected = failed };
                            };
                            if (source_trace.kind != response.kind or !source_trace.response_ref.eql(response.response_ref) or source_trace.response_value_fingerprint != response.response_value_fingerprint) {
                                const failed = blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "replay source witness does not match provider response");
                                try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, response.fingerprint, null, failed.tag);
                                response.deinit();
                                return .{ .rejected = failed };
                            }
                            const source_response = options_value.replay_source_response orelse {
                                const failed = blocker(.replay_policy_not_supported, request, certificate, offer.fingerprint, "replay response requires a recorded source response envelope");
                                try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, response.fingerprint, null, failed.tag);
                                response.deinit();
                                return .{ .rejected = failed };
                            };
                            const source_value_fingerprint = options_value.replay_source_response_value_fingerprint orelse source_trace.response_value_fingerprint;
                            break :packet try replayResponsePacket(certificate, response.*, response_use, source_response.fingerprint, source_value_fingerprint);
                        } else if (responseUseNeedsReplaySource(response_use) and certificate.obligation_fingerprint != null) packet: {
                            switch (obligationReplaySourceFingerprint(options_value, request, certificate, offer, response.*)) {
                                .source => |source_fingerprint| break :packet try replayResponsePacket(certificate, response.*, response_use, source_fingerprint, response.response_value_fingerprint),
                                .failed => |failed| {
                                    try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, response.fingerprint, null, failed.tag);
                                    response.deinit();
                                    return .{ .rejected = failed };
                                },
                            }
                        } else try responsePacket(certificate, response.*, response_use);
                        response.bytes = &.{};
                        response.value_image = &.{};
                        errdefer packet.deinit();
                        try appendProviderEvent(options_value.journal, .provider_response_built, request, certificate, packet.response.fingerprint, null, null);
                        try appendProviderEvent(options_value.journal, .provider_response_authorized, request, certificate, packet.response.fingerprint, packet.treaty_authorization.authorization_fingerprint, null);
                        return .{ .response = packet };
                    }

                    /// Start a program-backed provider handler and step it until it completes or yields.
                    pub fn startProgramExecution(
                        comptime index: usize,
                        runtime: *lowered_machine.Runtime,
                        handler_handlers: anytype,
                        allocator: std.mem.Allocator,
                        request: RequestEnvelope,
                        certificate: Treaty.Certificate,
                        offer: ProviderOffer,
                        options_value: HandleOptions,
                    ) Error!ProviderProgramResult(index) {
                        const Entry = entries[index];
                        if (comptime (!@hasDecl(Entry, "program_backed") or !Entry.program_backed)) {
                            @compileError("startProgramExecution requires a program-backed provider declaration");
                        }
                        validateManualOffer(allocator, index, offer) catch |err| switch (err) {
                            error.ProgramContractViolation => {
                                const failed = blocker(.offer_mismatch, request, certificate, offer.fingerprint, "provider Program step API offer does not exactly match the selected harness declaration");
                                try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                                return .{ .rejected = failed };
                            },
                            else => return err,
                        };
                        if (validateForEntry(Entry, request, certificate, offer, options_value)) |failed| {
                            try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                            return .{ .rejected = failed };
                        }
                        const use_value = options_value.response_use orelse certificate.response_use;
                        if (use_value != certificate.response_use) {
                            const failed = blocker(.response_use_not_supported, request, certificate, offer.fingerprint, "provider response-use override differs from treaty certificate");
                            try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                            return .{ .rejected = failed };
                        }
                        if (rejectInvalidReplaySource(request, certificate, offer, use_value, options_value)) |failed| {
                            try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                            return .{ .rejected = failed };
                        }

                        try appendProviderEvent(options_value.journal, .provider_request_validated, request, certificate, null, null, null);
                        const execution_fingerprint = providerProgramExecutionFingerprint(Entry, request, certificate, offer);
                        try appendProviderProgramEvent(options_value.journal, .provider_program_started, request, certificate, execution_fingerprint, null, null, null);
                        var handler_start = startHandlerProgramSession(Entry, runtime, handler_handlers, allocator, request, certificate, offer) catch |err| switch (err) {
                            error.ProgramContractViolation => {
                                const failed = blocker(.handler_program_arg_mismatch, request, certificate, offer.fingerprint, "provider Program request-to-args mapping failed");
                                try appendProviderProgramEvent(options_value.journal, .provider_program_rejected, request, certificate, execution_fingerprint, null, null, failed.tag);
                                try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                                return .{ .rejected = failed };
                            },
                            else => return err,
                        };
                        defer handler_start.deinitMappedValue(allocator);
                        errdefer handler_start.session.deinit();
                        return stepStartedProviderProgram(index, &handler_start.session, allocator, request, certificate, offer, options_value, use_value, execution_fingerprint);
                    }

                    /// Resume a parked provider Program after its nested request is answered.
                    pub fn continueProgramExecution(
                        comptime index: usize,
                        execution: *ProviderProgramExecution(index),
                        runtime: *lowered_machine.Runtime,
                        handler_handlers: anytype,
                        allocator: std.mem.Allocator,
                        request: RequestEnvelope,
                        certificate: Treaty.Certificate,
                        offer: ProviderOffer,
                        nested_response: entries[index].handler_program.Exchange.ResponseEnvelope,
                        options_value: HandleOptions,
                    ) Error!ProviderProgramResult(index) {
                        const Entry = entries[index];
                        validateManualOffer(allocator, index, offer) catch |err| switch (err) {
                            error.ProgramContractViolation => {
                                const failed = blocker(.offer_mismatch, request, certificate, offer.fingerprint, "provider Program step API offer does not exactly match the selected harness declaration");
                                try appendProviderProgramEvent(options_value.journal, .provider_program_rejected, request, certificate, execution.execution_fingerprint, null, null, failed.tag);
                                return .{ .rejected = failed };
                            },
                            else => return err,
                        };
                        const expected_execution_fingerprint = providerProgramExecutionFingerprint(Entry, request, certificate, offer);
                        if (!providerProgramExecutionMatches(index, execution.*, request, certificate, offer, expected_execution_fingerprint)) {
                            const failed = blocker(.handler_program_restore_mismatch, request, certificate, offer.fingerprint, "provider Program execution does not match parent request/treaty/provider/offer");
                            return .{ .rejected = failed };
                        }
                        if (validateForEntry(Entry, request, certificate, offer, options_value)) |failed| {
                            try appendProviderProgramEvent(options_value.journal, .provider_program_rejected, request, certificate, expected_execution_fingerprint, null, null, failed.tag);
                            try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                            return .{ .rejected = failed };
                        }
                        const use_value = options_value.response_use orelse certificate.response_use;
                        if (use_value != certificate.response_use) {
                            const failed = blocker(.response_use_not_supported, request, certificate, offer.fingerprint, "provider response-use override differs from treaty certificate");
                            try appendProviderProgramEvent(options_value.journal, .provider_program_rejected, request, certificate, execution.execution_fingerprint, null, null, failed.tag);
                            try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                            return .{ .rejected = failed };
                        }
                        if (rejectInvalidReplaySource(request, certificate, offer, use_value, options_value)) |failed| {
                            try appendProviderProgramEvent(options_value.journal, .provider_program_rejected, request, certificate, execution.execution_fingerprint, null, null, failed.tag);
                            try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                            return .{ .rejected = failed };
                        }
                        if (execution.session != null) {
                            const failed = blocker(.handler_program_restore_mismatch, request, certificate, offer.fingerprint, "provider Program execution unexpectedly retained a live parked session");
                            return .{ .rejected = failed };
                        }
                        const nested_request = execution.nested_request_envelope orelse {
                            const failed = blocker(.handler_program_capsule_missing, request, certificate, offer.fingerprint, "provider Program execution has no parked session");
                            return .{ .rejected = failed };
                        };
                        if (!providerProgramNestedRequestMatchesExecution(execution.*, nested_request)) {
                            const failed = blocker(.handler_program_restore_mismatch, request, certificate, offer.fingerprint, "provider Program nested request does not match parked execution metadata");
                            return .{ .rejected = failed };
                        }
                        if (nested_response.request_envelope_fingerprint != nested_request.fingerprint) {
                            const failed = blocker(.handler_program_nested_request_invalid, request, certificate, offer.fingerprint, "nested response does not answer the parked provider Program request");
                            try appendProviderProgramEvent(options_value.journal, .provider_program_rejected, request, certificate, execution.execution_fingerprint, null, null, failed.tag);
                            return .{ .rejected = failed };
                        }
                        try appendProviderProgramEvent(options_value.journal, .provider_program_nested_response, request, certificate, execution.execution_fingerprint, nested_request.request_fingerprint, nested_response.fingerprint, null);
                        var session = Entry.handler_program.Exchange.restoreFromRequestEnvelope(runtime, handler_handlers, nested_request) catch |err| switch (err) {
                            error.ProgramContractViolation => {
                                const failed = blocker(.handler_program_capsule_missing, request, certificate, offer.fingerprint, "provider Program capsule image could not be restored");
                                try appendProviderProgramEvent(options_value.journal, .provider_program_rejected, request, certificate, execution.execution_fingerprint, null, null, failed.tag);
                                return .{ .rejected = failed };
                            },
                            else => |other| return providerProgramMapHandlerError(other),
                        };
                        errdefer session.deinit();
                        Entry.handler_program.Exchange.applyResponse(&session, nested_response, .{
                            .request_envelope_fingerprint = nested_request.fingerprint,
                            .request_manifest_fingerprint = nested_request.manifest_fingerprint,
                        }) catch |err| switch (err) {
                            error.ProgramContractViolation => {
                                session.deinit();
                                const failed = blocker(.handler_program_nested_request_invalid, request, certificate, offer.fingerprint, "nested response failed provider Program response application");
                                try appendProviderProgramEvent(options_value.journal, .provider_program_rejected, request, certificate, execution.execution_fingerprint, null, null, failed.tag);
                                return .{ .rejected = failed };
                            },
                            else => |other| return providerProgramMapHandlerError(other),
                        };
                        try appendProviderProgramEvent(options_value.journal, .provider_program_resumed, request, certificate, execution.execution_fingerprint, null, null, null);
                        const resumed_result = try stepStartedProviderProgram(index, &session, allocator, request, certificate, offer, options_value, use_value, execution.execution_fingerprint);
                        switch (resumed_result) {
                            .response, .provider_suspended => {
                                execution.nested_request_envelope.?.deinit();
                                execution.nested_request_envelope = null;
                            },
                            .rejected => {},
                        }
                        return resumed_result;
                    }

                    fn providerProgramExecutionMatches(
                        comptime index: usize,
                        execution: ProviderProgramExecution(index),
                        request: RequestEnvelope,
                        certificate: Treaty.Certificate,
                        offer: ProviderOffer,
                        expected_execution_fingerprint: u64,
                    ) bool {
                        return execution.execution_fingerprint == expected_execution_fingerprint and
                            execution.parent_request_envelope_fingerprint == request.fingerprint and
                            execution.parent_request_fingerprint == request.request_fingerprint and
                            execution.treaty_fingerprint == certificate.treaty_fingerprint and
                            execution.treaty_certificate_fingerprint == certificate.certificate_fingerprint and
                            execution.provider_fingerprint == certificate.provider_fingerprint and
                            execution.provider_offer_fingerprint == offer.fingerprint and
                            execution.route_fingerprint == certificate.route_fingerprint and
                            execution.capability_fingerprint == certificate.capability_fingerprint and
                            execution.capability_instance_fingerprint == certificate.capability_instance_fingerprint and
                            execution.obligation_fingerprint == certificate.obligation_fingerprint;
                    }

                    fn providerProgramNestedRequestMatchesExecution(
                        execution: anytype,
                        nested_request: anytype,
                    ) bool {
                        nested_request.validate() catch return false;
                        if (execution.nested_request_envelope_fingerprint == null or
                            execution.nested_request_fingerprint == null or
                            execution.provider_program_capsule_image_fingerprint == null or
                            nested_request.capsule_image == null or
                            nested_request.capsule_image_fingerprint == null)
                        {
                            return false;
                        }
                        if (nested_request.fingerprint != execution.nested_request_envelope_fingerprint.?) return false;
                        if (nested_request.request_fingerprint != execution.nested_request_fingerprint.?) return false;
                        if (nested_request.capsule_image_fingerprint.? != execution.provider_program_capsule_image_fingerprint.?) return false;
                        return switch (execution.state) {
                            .parked_on_nested_request => nested_request.kind == .operation,
                            .parked_on_nested_after => nested_request.kind == .after,
                            else => false,
                        };
                    }

                    fn stepStartedProviderProgram(
                        comptime index: usize,
                        session: *entries[index].handler_program.Session,
                        allocator: std.mem.Allocator,
                        request: RequestEnvelope,
                        certificate: Treaty.Certificate,
                        offer: ProviderOffer,
                        options_value: HandleOptions,
                        use_value: ResponseUse,
                        execution_fingerprint: u64,
                    ) Error!ProviderProgramResult(index) {
                        const Entry = entries[index];
                        const step = session.next() catch |err| switch (err) {
                            error.ProgramContractViolation => {
                                session.deinit();
                                const failed = blocker(.handler_program_effect_unhandled, request, certificate, offer.fingerprint, "provider Program execution failed before producing a provider outcome");
                                try appendProviderProgramEvent(options_value.journal, .provider_program_failed, request, certificate, execution_fingerprint, null, null, failed.tag);
                                try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                                return .{ .rejected = failed };
                            },
                            else => |other| return providerProgramMapHandlerError(other),
                        };
                        switch (step) {
                            .done => |result_value| {
                                var result = result_value;
                                defer result.deinit();
                                var packet_result = try finishProviderProgramDone(Entry, allocator, request, certificate, offer, options_value, use_value, result.value);
                                errdefer switch (packet_result) {
                                    .response => |*packet| packet.deinit(),
                                    else => {},
                                };
                                switch (packet_result) {
                                    .response => |*packet| {
                                        packet.provider_program_execution_fingerprint = execution_fingerprint;
                                        try appendProviderProgramEvent(options_value.journal, .provider_program_completed, request, certificate, execution_fingerprint, null, null, null);
                                    },
                                    .rejected => |failed| {
                                        try appendProviderProgramEvent(options_value.journal, .provider_program_rejected, request, certificate, execution_fingerprint, null, null, failed.tag);
                                    },
                                    else => {},
                                }
                                return switch (packet_result) {
                                    .response => |packet| .{ .response = packet },
                                    .rejected => |failed| .{ .rejected = failed },
                                    else => unreachable,
                                };
                            },
                            .request => |nested_request| {
                                var capsule = session.capture(allocator) catch |err| switch (err) {
                                    error.ProgramContractViolation => {
                                        session.deinit();
                                        const failed = blocker(.handler_program_capsule_missing, request, certificate, offer.fingerprint, "provider Program capsule could not be captured");
                                        try appendProviderProgramEvent(options_value.journal, .provider_program_failed, request, certificate, execution_fingerprint, null, null, failed.tag);
                                        return .{ .rejected = failed };
                                    },
                                    else => |other| return providerProgramMapHandlerError(other),
                                };
                                defer capsule.deinit();
                                var image = capsule.encode(allocator) catch |err| switch (err) {
                                    error.ProgramContractViolation => {
                                        session.deinit();
                                        const failed = blocker(.handler_program_capsule_missing, request, certificate, offer.fingerprint, "provider Program capsule image could not be encoded");
                                        try appendProviderProgramEvent(options_value.journal, .provider_program_failed, request, certificate, execution_fingerprint, null, null, failed.tag);
                                        return .{ .rejected = failed };
                                    },
                                    else => |other| return providerProgramMapHandlerError(other),
                                };
                                defer image.deinit();
                                var nested_envelope = Entry.handler_program.Exchange.RequestEnvelope.fromRequest(allocator, nested_request, .{ .capsule = image }) catch |err| switch (err) {
                                    error.ProgramContractViolation => {
                                        session.deinit();
                                        const failed = blocker(.handler_program_nested_request_invalid, request, certificate, offer.fingerprint, "provider Program nested request envelope could not be built");
                                        try appendProviderProgramEvent(options_value.journal, .provider_program_failed, request, certificate, execution_fingerprint, null, null, failed.tag);
                                        return .{ .rejected = failed };
                                    },
                                    else => |other| return providerProgramMapHandlerError(other),
                                };
                                errdefer nested_envelope.deinit();
                                try appendProviderProgramEvent(options_value.journal, .provider_program_nested_request, request, certificate, execution_fingerprint, nested_envelope.request_fingerprint, null, null);
                                try appendProviderProgramEvent(options_value.journal, .provider_program_parked, request, certificate, execution_fingerprint, nested_envelope.request_fingerprint, null, null);
                                session.deinit();
                                return .{ .provider_suspended = providerProgramExecutionValue(index, request, certificate, offer, execution_fingerprint, .parked_on_nested_request, null, nested_envelope, image.image_fingerprint) };
                            },
                            .after => |nested_after| {
                                var capsule = session.capture(allocator) catch |err| switch (err) {
                                    error.ProgramContractViolation => {
                                        session.deinit();
                                        const failed = blocker(.handler_program_capsule_missing, request, certificate, offer.fingerprint, "provider Program capsule could not be captured");
                                        try appendProviderProgramEvent(options_value.journal, .provider_program_failed, request, certificate, execution_fingerprint, null, null, failed.tag);
                                        return .{ .rejected = failed };
                                    },
                                    else => |other| return providerProgramMapHandlerError(other),
                                };
                                defer capsule.deinit();
                                var image = capsule.encode(allocator) catch |err| switch (err) {
                                    error.ProgramContractViolation => {
                                        session.deinit();
                                        const failed = blocker(.handler_program_capsule_missing, request, certificate, offer.fingerprint, "provider Program capsule image could not be encoded");
                                        try appendProviderProgramEvent(options_value.journal, .provider_program_failed, request, certificate, execution_fingerprint, null, null, failed.tag);
                                        return .{ .rejected = failed };
                                    },
                                    else => |other| return providerProgramMapHandlerError(other),
                                };
                                defer image.deinit();
                                var nested_envelope = Entry.handler_program.Exchange.RequestEnvelope.fromAfter(allocator, nested_after, .{ .capsule = image }) catch |err| switch (err) {
                                    error.ProgramContractViolation => {
                                        session.deinit();
                                        const failed = blocker(.handler_program_nested_request_invalid, request, certificate, offer.fingerprint, "provider Program nested after envelope could not be built");
                                        try appendProviderProgramEvent(options_value.journal, .provider_program_failed, request, certificate, execution_fingerprint, null, null, failed.tag);
                                        return .{ .rejected = failed };
                                    },
                                    else => |other| return providerProgramMapHandlerError(other),
                                };
                                errdefer nested_envelope.deinit();
                                try appendProviderProgramEvent(options_value.journal, .provider_program_nested_request, request, certificate, execution_fingerprint, nested_envelope.request_fingerprint, null, null);
                                try appendProviderProgramEvent(options_value.journal, .provider_program_parked, request, certificate, execution_fingerprint, nested_envelope.request_fingerprint, null, null);
                                session.deinit();
                                return .{ .provider_suspended = providerProgramExecutionValue(index, request, certificate, offer, execution_fingerprint, .parked_on_nested_after, null, nested_envelope, image.image_fingerprint) };
                            },
                        }
                    }

                    fn providerProgramExecutionFingerprint(comptime Entry: type, request: RequestEnvelope, certificate: Treaty.Certificate, offer: ProviderOffer) u64 {
                        var builder = Evidence.FingerprintBuilder.init(Evidence.domains.provider_program_execution);
                        builder.fieldU64("parent.request_envelope", request.fingerprint);
                        builder.fieldU64("parent.request", request.request_fingerprint);
                        builder.fieldU64("treaty", certificate.treaty_fingerprint);
                        builder.fieldU64("certificate", certificate.certificate_fingerprint);
                        builder.fieldU64("provider", certificate.provider_fingerprint);
                        builder.fieldU64("offer", offer.fingerprint);
                        builder.fieldU64("route", certificate.route_fingerprint);
                        builder.fieldU64("capability", certificate.capability_fingerprint);
                        builder.fieldOptionalU64("capability_instance", certificate.capability_instance_fingerprint);
                        builder.fieldOptionalU64("obligation", certificate.obligation_fingerprint);
                        builder.fieldBytes("handler_program.label", Entry.handler_program.contract.label);
                        builder.fieldU64("handler_program.plan_hash", Entry.handler_program.compiled_plan.hash());
                        builder.fieldU64("mapping", Entry.provider_program_mapping_fingerprint);
                        return builder.finish();
                    }

                    fn providerProgramExecutionValue(
                        comptime index: usize,
                        request: RequestEnvelope,
                        certificate: Treaty.Certificate,
                        offer: ProviderOffer,
                        execution_fingerprint: u64,
                        state: ProviderProgramExecutionState,
                        session: ?entries[index].handler_program.Session,
                        nested_request_envelope: entries[index].handler_program.Exchange.RequestEnvelope,
                        capsule_image_fingerprint: u64,
                    ) ProviderProgramExecution(index) {
                        return .{
                            .execution_fingerprint = execution_fingerprint,
                            .parent_request_envelope_fingerprint = request.fingerprint,
                            .parent_request_fingerprint = request.request_fingerprint,
                            .treaty_fingerprint = certificate.treaty_fingerprint,
                            .treaty_certificate_fingerprint = certificate.certificate_fingerprint,
                            .provider_fingerprint = certificate.provider_fingerprint,
                            .provider_offer_fingerprint = offer.fingerprint,
                            .route_fingerprint = certificate.route_fingerprint,
                            .capability_fingerprint = certificate.capability_fingerprint,
                            .capability_instance_fingerprint = certificate.capability_instance_fingerprint,
                            .obligation_fingerprint = certificate.obligation_fingerprint,
                            .branch_id = if (request.usage_metadata) |metadata_value| metadata_value.branch_id else null,
                            .state = state,
                            .session = session,
                            .nested_request_envelope_fingerprint = nested_request_envelope.fingerprint,
                            .nested_request_fingerprint = nested_request_envelope.request_fingerprint,
                            .provider_program_capsule_image_fingerprint = capsule_image_fingerprint,
                            .nested_request_envelope = nested_request_envelope,
                        };
                    }

                    fn HandlerProgramSessionStart(comptime Entry: type) type {
                        const ValueType = providerProgramRequestValueType(Entry);
                        return struct {
                            session: Entry.handler_program.Session,
                            mapped_request_value: ?ValueType = null,

                            fn deinitMappedValue(self: *@This(), allocator: std.mem.Allocator) void {
                                if (self.mapped_request_value) |value| {
                                    deinitBodyOwnedResultValue(allocator, value);
                                    self.mapped_request_value = null;
                                }
                            }
                        };
                    }

                    fn startHandlerProgramSession(
                        comptime Entry: type,
                        runtime: *lowered_machine.Runtime,
                        handler_handlers: anytype,
                        allocator: std.mem.Allocator,
                        request: RequestEnvelope,
                        certificate: Treaty.Certificate,
                        offer: ProviderOffer,
                    ) Error!HandlerProgramSessionStart(Entry) {
                        return switch (Entry.request_to_program_args) {
                            .unit_args => .{ .session = Entry.handler_program.Session.startWithArgs(runtime, handler_handlers, .{}) catch |err| return providerProgramMapHandlerError(err) },
                            .payload_to_args => startHandlerProgramSessionWithPayload(Entry, runtime, handler_handlers, allocator, request),
                            .payload_and_metadata_to_args, .custom_comptime_mapper => {
                                _ = certificate;
                                _ = offer;
                                return error.ProgramContractViolation;
                            },
                        };
                    }

                    fn startHandlerProgramSessionWithPayload(
                        comptime Entry: type,
                        runtime: *lowered_machine.Runtime,
                        handler_handlers: anytype,
                        allocator: std.mem.Allocator,
                        request: RequestEnvelope,
                    ) Error!HandlerProgramSessionStart(Entry) {
                        const ValueType = providerProgramRequestValueType(Entry);
                        const value = try decodeExchangeValueImageValue(allocator, request.value_ref, request.value_fingerprint, request.value_image, ValueType);
                        errdefer deinitBodyOwnedResultValue(allocator, value);
                        return .{
                            .session = Entry.handler_program.Session.startWithArgs(runtime, handler_handlers, .{value}) catch |err| return providerProgramMapHandlerError(err),
                            .mapped_request_value = value,
                        };
                    }

                    fn providerProgramMapHandlerError(err: anyerror) Error {
                        return switch (err) {
                            error.OutOfMemory => error.OutOfMemory,
                            error.CrossThread => error.CrossThread,
                            error.ExecutionBudgetExceeded => error.ExecutionBudgetExceeded,
                            error.RuntimeBusy => error.RuntimeBusy,
                            error.RuntimeDestroyed => error.RuntimeDestroyed,
                            error.MissingPrompt => error.MissingPrompt,
                            error.NonDiagonalComplete => error.NonDiagonalComplete,
                            error.FrontendSuspend => error.FrontendSuspend,
                            error.ProgramContractViolation => error.ProgramContractViolation,
                            else => error.ProgramContractViolation,
                        };
                    }

                    fn providerProgramRequestValueType(comptime Entry: type) type {
                        return switch (Entry.kind) {
                            .operation => Entry.Site.Payload,
                            .after => if (Entry.Site.has_static_input_ref) Entry.Site.Input else void,
                            else => void,
                        };
                    }

                    fn finishProviderProgramDone(
                        comptime Entry: type,
                        allocator: std.mem.Allocator,
                        request: RequestEnvelope,
                        certificate: Treaty.Certificate,
                        offer: ProviderOffer,
                        options_value: HandleOptions,
                        use_value: ResponseUse,
                        value: anytype,
                    ) Error!HandleResult {
                        var response = switch (Entry.program_result_to_provider_outcome) {
                            .result_to_resume => ResponseEnvelope.@"resume"(allocator, request, value),
                            .result_to_return_now => ResponseEnvelope.returnNow(allocator, request, value),
                            .result_to_resume_after => ResponseEnvelope.resumeAfter(allocator, request, value),
                            .result_to_outcome_union => return .{ .rejected = blocker(.handler_program_result_mapping_invalid, request, certificate, offer.fingerprint, "provider Program outcome-union mapping is not implemented for this result") },
                        } catch |err| switch (err) {
                            error.ProgramContractViolation => {
                                return .{ .rejected = blocker(.response_build_failed, request, certificate, offer.fingerprint, "failed to build provider Program response envelope") };
                            },
                            else => return err,
                        };
                        errdefer response.deinit();
                        return finishProviderResponse(options_value, request, certificate, offer, &response, use_value);
                    }

                    fn handleEntry(comptime Entry: type, ctx: anytype, allocator: std.mem.Allocator, request: RequestEnvelope, certificate: Treaty.Certificate, offer: ProviderOffer, options_value: HandleOptions) Error!HandleResult {
                        if (validateForEntry(Entry, request, certificate, offer, options_value)) |failed| {
                            try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                            return .{ .rejected = failed };
                        }
                        const use_value = options_value.response_use orelse certificate.response_use;
                        if (use_value != certificate.response_use) {
                            const failed = blocker(.response_use_not_supported, request, certificate, offer.fingerprint, "provider response-use override differs from treaty certificate");
                            try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                            return .{ .rejected = failed };
                        }
                        if (rejectInvalidReplaySource(request, certificate, offer, use_value, options_value)) |failed| {
                            try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                            return .{ .rejected = failed };
                        }
                        try appendProviderEvent(options_value.journal, .provider_request_validated, request, certificate, null, null, null);
                        if (comptime @hasDecl(Entry, "program_backed") and Entry.program_backed) {
                            const failed = blocker(.handler_program_requires_step_api, request, certificate, offer.fingerprint, "program-backed provider handlers require ProviderHarness provider-program step APIs");
                            try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                            return .{ .rejected = failed };
                        }
                        const view = requestView(Entry, request, certificate, offer);
                        try appendProviderEvent(options_value.journal, .provider_handler_invoked, request, certificate, null, null, null);
                        const outcome = Entry.handler(ctx, view) catch |err| return mapProgramRunError(Error, err);
                        switch (outcome) {
                            .@"resume" => |value| {
                                if (Entry.kind != .operation or !offer.allowed_response_kinds.@"resume" or !Entry.Site.may_resume) {
                                    const failed = blocker(.invalid_provider_outcome, request, certificate, offer.fingerprint, "resume outcome is not permitted for this provider offer");
                                    try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                                    return .{ .rejected = failed };
                                }
                                if (rejectInvalidReplaySource(request, certificate, offer, use_value, options_value)) |failed| {
                                    try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                                    return .{ .rejected = failed };
                                }
                                var response = ResponseEnvelope.@"resume"(allocator, request, value) catch |err| switch (err) {
                                    error.ProgramContractViolation => {
                                        const failed = blocker(.response_build_failed, request, certificate, offer.fingerprint, "failed to build resume response envelope");
                                        try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                                        return .{ .rejected = failed };
                                    },
                                    else => return err,
                                };
                                errdefer response.deinit();
                                return finishProviderResponse(options_value, request, certificate, offer, &response, use_value);
                            },
                            .return_now => |value| {
                                if (Entry.kind != .operation or !offer.allowed_response_kinds.return_now or !Entry.Site.may_return_now) {
                                    const failed = blocker(.invalid_provider_outcome, request, certificate, offer.fingerprint, "returnNow outcome is not permitted for this provider offer");
                                    try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                                    return .{ .rejected = failed };
                                }
                                if (rejectInvalidReplaySource(request, certificate, offer, use_value, options_value)) |failed| {
                                    try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                                    return .{ .rejected = failed };
                                }
                                var response = ResponseEnvelope.returnNow(allocator, request, value) catch |err| switch (err) {
                                    error.ProgramContractViolation => {
                                        const failed = blocker(.response_build_failed, request, certificate, offer.fingerprint, "failed to build returnNow response envelope");
                                        try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                                        return .{ .rejected = failed };
                                    },
                                    else => return err,
                                };
                                errdefer response.deinit();
                                return finishProviderResponse(options_value, request, certificate, offer, &response, use_value);
                            },
                            .resume_after => |value| {
                                if (Entry.kind != .after or !offer.allowed_response_kinds.resume_after) {
                                    const failed = blocker(.invalid_provider_outcome, request, certificate, offer.fingerprint, "resumeAfter outcome is not permitted for this provider offer");
                                    try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                                    return .{ .rejected = failed };
                                }
                                if (rejectInvalidReplaySource(request, certificate, offer, use_value, options_value)) |failed| {
                                    try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                                    return .{ .rejected = failed };
                                }
                                var response = ResponseEnvelope.resumeAfter(allocator, request, value) catch |err| switch (err) {
                                    error.ProgramContractViolation => {
                                        const failed = blocker(.response_build_failed, request, certificate, offer.fingerprint, "failed to build resumeAfter response envelope");
                                        try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                                        return .{ .rejected = failed };
                                    },
                                    else => return err,
                                };
                                errdefer response.deinit();
                                return finishProviderResponse(options_value, request, certificate, offer, &response, use_value);
                            },
                            .replay => |value| {
                                if (Entry.kind != .operation or !offer.allowed_response_kinds.@"resume" or !Entry.Site.may_resume or !(use_value == .replayed or use_value == .deterministic_replay)) {
                                    const failed = blocker(.invalid_provider_outcome, request, certificate, offer.fingerprint, "replay outcome is not permitted for this provider offer");
                                    try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                                    return .{ .rejected = failed };
                                }
                                if (rejectInvalidReplaySource(request, certificate, offer, use_value, options_value)) |failed| {
                                    try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                                    return .{ .rejected = failed };
                                }
                                var response = ResponseEnvelope.@"resume"(allocator, request, value) catch |err| switch (err) {
                                    error.ProgramContractViolation => {
                                        const failed = blocker(.response_build_failed, request, certificate, offer.fingerprint, "failed to build replay response envelope");
                                        try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                                        return .{ .rejected = failed };
                                    },
                                    else => return err,
                                };
                                errdefer response.deinit();
                                return finishProviderResponse(options_value, request, certificate, offer, &response, use_value);
                            },
                            .reject => |reason| {
                                const failed = blocker(.handler_rejected, request, certificate, offer.fingerprint, reason);
                                try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                                return .{ .rejected = failed };
                            },
                            .forward => {
                                const failed = blocker(.handler_forwarded, request, certificate, offer.fingerprint, "provider handler forwarded request");
                                try appendProviderEvent(options_value.journal, .provider_response_forwarded, request, certificate, null, null, failed.tag);
                                return .{ .forwarded = failed };
                            },
                            .pending => {
                                const failed = blocker(.pending_response, request, certificate, offer.fingerprint, "provider handler left request pending");
                                try appendProviderEvent(options_value.journal, .provider_pending, request, certificate, null, null, failed.tag);
                                return .{ .pending = failed };
                            },
                        }
                    }

                    /// Validate and handle one treaty-bound provider request.
                    pub fn handle(ctx: anytype, allocator: std.mem.Allocator, request: RequestEnvelope, certificate: Treaty.Certificate, options_value: HandleOptions) Error!HandleResult {
                        try appendProviderEvent(options_value.journal, .provider_request_received, request, certificate, null, null, null);
                        var manifest = try Manifest.encode(allocator);
                        defer manifest.deinit();
                        if (request.manifest_fingerprint != manifest.fingerprint or certificate.manifest_fingerprint != manifest.fingerprint) {
                            const failed = blocker(.manifest_mismatch, request, certificate, null, "request or certificate manifest does not match this Program");
                            try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                            return .{ .rejected = failed };
                        }
                        inline for (entries, 0..) |Entry, index| {
                            var offer = try ProviderOffer.encode(allocator, offerOptions(index, manifest.fingerprint));
                            defer offer.deinit();
                            if (offer.fingerprint == certificate.provider_offer_fingerprint) {
                                return handleEntry(Entry, ctx, allocator, request, certificate, offer, options_value);
                            }
                        }
                        const failed = blocker(.offer_not_in_harness, request, certificate, certificate.provider_offer_fingerprint, "certificate selected an offer not derived by this harness");
                        try appendProviderEvent(options_value.journal, .provider_request_rejected, request, certificate, null, null, failed.tag);
                        return .{ .rejected = failed };
                    }

                    /// Host-owned in-memory request packet helper shape.
                    pub const RequestPacket = struct {
                        request: RequestEnvelope,
                        certificate: Treaty.Certificate,
                        treaty: ?Treaty = null,
                    };

                    /// Handle one packet value.
                    pub fn handlePacket(ctx: anytype, allocator: std.mem.Allocator, packet: RequestPacket, options_value: HandleOptions) Error!HandleResult {
                        var packet_options = options_value;
                        if (packet.treaty) |treaty| packet_options.treaty = treaty;
                        return handle(ctx, allocator, packet.request, packet.certificate, packet_options);
                    }

                    /// Pop one host-owned treaty packet and push a produced response through host-owned methods.
                    pub fn handleNext(inbox: anytype, outbox: anytype, ctx: anytype, allocator: std.mem.Allocator, options_value: HandleOptions) Error!HandleResult {
                        const InboxType = @TypeOf(inbox.*);
                        const maybe_packet = if (comptime @hasDecl(InboxType, "nextTreaty"))
                            try inbox.nextTreaty()
                        else
                            try inbox.next();
                        const packet = maybe_packet orelse return .{ .pending = .{
                            .tag = .pending_response,
                            .summary = "provider inbox is empty",
                        } };
                        var result = try handlePacket(ctx, allocator, packet, options_value);
                        switch (result) {
                            .response => |*response_packet| {
                                errdefer response_packet.deinit();
                                const OutboxType = @TypeOf(outbox.*);
                                if (comptime @hasDecl(OutboxType, "appendProviderResponse")) {
                                    var outbox_packet = try response_packet.clone(allocator);
                                    var transferred = false;
                                    errdefer if (!transferred) outbox_packet.deinit();
                                    try outbox.appendProviderResponse(outbox_packet);
                                    transferred = true;
                                } else if (comptime @hasDecl(OutboxType, "appendResponse")) {
                                    var outbox_packet = try response_packet.clone(allocator);
                                    var transferred = false;
                                    errdefer if (!transferred) outbox_packet.deinit();
                                    try outbox.appendResponse(outbox_packet.response, outbox_packet.treaty_authorization);
                                    transferred = true;
                                } else if (comptime @hasDecl(OutboxType, "append")) {
                                    var outbox_packet = try response_packet.clone(allocator);
                                    var transferred = false;
                                    errdefer if (!transferred) outbox_packet.deinit();
                                    try outbox.append(outbox_packet.response);
                                    transferred = true;
                                } else {
                                    return error.ProgramContractViolation;
                                }
                            },
                            else => {},
                        }
                        return result;
                    }

                    /// Drain host-owned in-memory packets until the inbox reports empty.
                    pub fn drain(inbox: anytype, outbox: anytype, ctx: anytype, allocator: std.mem.Allocator, options_value: HandleOptions) Error!usize {
                        var count: usize = 0;
                        while (true) {
                            var result = try handleNext(inbox, outbox, ctx, allocator, options_value);
                            switch (result) {
                                .pending => |pending| {
                                    if (pending.request_envelope_fingerprint == null) break;
                                    count += 1;
                                },
                                .response => |*packet| {
                                    packet.deinit();
                                    count += 1;
                                },
                                else => count += 1,
                            }
                        }
                        return count;
                    }
                };
            }

            fn providerHarnessHasField(comptime Options: type, comptime field_name: []const u8) bool {
                const info = @typeInfo(Options);
                if (info != .@"struct") return false;
                inline for (info.@"struct".fields) |field| {
                    if (std.mem.eql(u8, field.name, field_name)) return true;
                }
                return false;
            }

            fn providerHarnessField(comptime options: anytype, comptime field_name: []const u8, comptime default: anytype) @TypeOf(default) {
                if (comptime providerHarnessHasField(@TypeOf(options), field_name)) {
                    return @field(options, field_name);
                }
                return default;
            }

            fn providerProgramOfferOptions(comptime options: anytype) ProviderHandlerOptions {
                return .{
                    .label = providerHarnessField(options, "label", @as(?[]const u8, null)),
                    .allowed_response_kinds = providerProgramResponseKinds(options),
                    .supported_usage_modes = providerProgramUsageSet(options),
                    .supported_response_uses = providerProgramResponseUseSet(options),
                    .supported_replay_policies = providerProgramReplayUseSet(options),
                    .supported_branch_policies = providerProgramBranchPolicySet(options),
                    .capsule_policy = providerHarnessField(options, "capsule_policy", CapsulePolicy.allowed),
                    .opens_obligation = providerHarnessField(options, "opens_obligation", @as(bool, false)),
                    .max_request_bytes = providerHarnessField(options, "max_request_bytes", @as(usize, std.math.maxInt(usize))),
                    .max_response_bytes = providerHarnessField(options, "max_response_bytes", @as(usize, std.math.maxInt(usize))),
                    .max_capsule_bytes = providerHarnessField(options, "max_capsule_bytes", @as(usize, std.math.maxInt(usize))),
                    .protocol_label = providerHarnessField(options, "protocol_label", @as(?[]const u8, null)),
                    .protocol_op_fingerprint = providerHarnessField(options, "protocol_op_fingerprint", @as(?u64, null)),
                    .tags = providerHarnessField(options, "tags", @as([]const []const u8, &.{})),
                    .metadata = providerHarnessField(options, "metadata", @as([]const u8, &.{})),
                };
            }

            fn providerProgramResponseKinds(comptime options: anytype) ?Policy.ResponseKindSet {
                const mapped = comptime providerProgramMappedResponseKinds(options);
                if (comptime providerHarnessHasField(@TypeOf(options), "allowed_response_kinds")) {
                    comptime validateProviderProgramResponseKinds(options.allowed_response_kinds, mapped);
                    return options.allowed_response_kinds;
                }
                if (comptime providerHarnessHasField(@TypeOf(options), "response_kinds")) {
                    comptime validateProviderProgramResponseKinds(options.response_kinds, mapped);
                    return options.response_kinds;
                }
                return mapped;
            }

            fn providerProgramMappedResponseKinds(comptime options: anytype) Policy.ResponseKindSet {
                const has_after_site = comptime providerHarnessHasField(@TypeOf(options), "after");
                const result_mapping = providerHarnessField(options, "map_result", if (has_after_site) ProgramResultToProviderOutcome.result_to_resume_after else ProgramResultToProviderOutcome.result_to_resume);
                return switch (result_mapping) {
                    .result_to_resume => .{ .@"resume" = true, .return_now = false, .resume_after = false },
                    .result_to_return_now => .{ .@"resume" = false, .return_now = true, .resume_after = false },
                    .result_to_resume_after => .{ .@"resume" = false, .return_now = false, .resume_after = true },
                    .result_to_outcome_union => @compileError("provider Program result_to_outcome_union is reserved until provider-program outcome-union execution is implemented"),
                };
            }

            fn validateProviderProgramResponseKinds(comptime declared: Policy.ResponseKindSet, comptime mapped: Policy.ResponseKindSet) void {
                if (declared.@"resume" != mapped.@"resume" or
                    declared.return_now != mapped.return_now or
                    declared.resume_after != mapped.resume_after)
                {
                    @compileError("provider Program response_kinds must exactly match map_result response kind");
                }
            }

            fn providerProgramUsageSet(comptime options: anytype) UsageSet {
                if (comptime providerHarnessHasField(@TypeOf(options), "supported_usage_modes")) return options.supported_usage_modes;
                if (comptime providerHarnessHasField(@TypeOf(options), "usage")) return singletonUsageSet(options.usage);
                return .{};
            }

            fn providerProgramResponseUseSet(comptime options: anytype) ResponseUseSet {
                if (comptime providerHarnessHasField(@TypeOf(options), "supported_response_uses")) return options.supported_response_uses;
                if (comptime providerHarnessHasField(@TypeOf(options), "response_use")) return coerceResponseUseSet(options.response_use);
                return .{};
            }

            fn providerProgramReplayUseSet(comptime options: anytype) ResponseUseSet {
                if (comptime providerHarnessHasField(@TypeOf(options), "supported_replay_policies")) return options.supported_replay_policies;
                if (comptime providerHarnessHasField(@TypeOf(options), "replay_policy")) return coerceResponseUseSet(options.replay_policy);
                return .{};
            }

            fn providerProgramBranchPolicySet(comptime options: anytype) BranchPolicySet {
                if (comptime providerHarnessHasField(@TypeOf(options), "supported_branch_policies")) return options.supported_branch_policies;
                if (comptime providerHarnessHasField(@TypeOf(options), "branch_policy")) return singletonBranchPolicySet(options.branch_policy);
                return .{};
            }

            fn singletonUsageSet(comptime usage: anytype) UsageSet {
                return switch (usage) {
                    .copyable => .{ .copyable = true, .replayable = false, .affine = false, .linear = false, .ephemeral = false },
                    .replayable => .{ .copyable = false, .replayable = true, .affine = false, .linear = false, .ephemeral = false },
                    .affine => .{ .copyable = false, .replayable = false, .affine = true, .linear = false, .ephemeral = false },
                    .linear => .{ .copyable = false, .replayable = false, .affine = false, .linear = true, .ephemeral = false },
                    .ephemeral => .{ .copyable = false, .replayable = false, .affine = false, .linear = false, .ephemeral = true },
                    else => @compileError("unsupported provider-program usage option"),
                };
            }

            fn coerceResponseUseSet(comptime value: anytype) ResponseUseSet {
                if (@TypeOf(value) == ResponseUseSet) return value;
                return switch (value) {
                    .fresh => .{ .fresh = true, .replayed = false, .deterministic_replay = false, .override = false },
                    .replayed => .{ .fresh = false, .replayed = true, .deterministic_replay = false, .override = false },
                    .deterministic_replay => .{ .fresh = false, .replayed = false, .deterministic_replay = true, .override = false },
                    .override => .{ .fresh = false, .replayed = false, .deterministic_replay = false, .override = true },
                    else => @compileError("unsupported provider-program response-use option"),
                };
            }

            fn singletonBranchPolicySet(comptime policy_value: anytype) BranchPolicySet {
                return switch (policy_value) {
                    .unrestricted => .{ .unrestricted = true, .replay_only = false, .single_live_branch = false, .split_required = false, .no_branch = false, .host_owned = false },
                    .replay_only => .{ .unrestricted = false, .replay_only = true, .single_live_branch = false, .split_required = false, .no_branch = false, .host_owned = false },
                    .single_live_branch => .{ .unrestricted = false, .replay_only = false, .single_live_branch = true, .split_required = false, .no_branch = false, .host_owned = false },
                    .split_required => .{ .unrestricted = false, .replay_only = false, .single_live_branch = false, .split_required = true, .no_branch = false, .host_owned = false },
                    .no_branch => .{ .unrestricted = false, .replay_only = false, .single_live_branch = false, .split_required = false, .no_branch = true, .host_owned = false },
                    .host_owned => .{ .unrestricted = false, .replay_only = false, .single_live_branch = false, .split_required = false, .no_branch = false, .host_owned = true },
                    else => @compileError("unsupported provider-program branch policy option"),
                };
            }

            fn providerProgramMappingFingerprint(
                comptime kind_value: anytype,
                comptime Site: type,
                comptime HandlerProgram: type,
                comptime request_mapping: RequestToProgramArgs,
                comptime result_mapping: ProgramResultToProviderOutcome,
                comptime custom_mapper_fingerprint: ?u64,
            ) u64 {
                validateProviderProgramResultMapping(kind_value, Site, HandlerProgram, result_mapping);
                var builder = Evidence.FingerprintBuilder.init(Evidence.domains.provider_program_mapping);
                builder.fieldBytes("kind", switch (kind_value) {
                    .operation => "operation",
                    .after => "after",
                    else => @compileError("unsupported provider-program handler kind"),
                });
                builder.fieldUsize("site.index", Site.index);
                builder.fieldU64("site.fingerprint", Site.fingerprint);
                builder.fieldBytes("program.label", HandlerProgram.contract.label);
                builder.fieldU64("program.plan_hash", HandlerProgram.compiled_plan.hash());
                builder.fieldBytes("request_mapping", @tagName(request_mapping));
                builder.fieldBytes("result_mapping", @tagName(result_mapping));
                builder.fieldOptionalU64("custom_mapper", custom_mapper_fingerprint);
                fingerprintProviderProgramValueRef(&builder, "program.result", HandlerProgram.contract.result_ref);
                return builder.finish();
            }

            fn validateProviderProgramRequestMapping(
                comptime kind_value: anytype,
                comptime Site: type,
                comptime HandlerProgram: type,
                comptime request_mapping: RequestToProgramArgs,
                comptime custom_mapper_fingerprint: ?u64,
            ) void {
                const parameters = HandlerProgram.contract.entry_parameters;
                const request_ref = providerProgramRequestValueRef(kind_value, Site);
                switch (request_mapping) {
                    .payload_to_args => {
                        if (parameters.len != 1) @compileError("provider Program payload_to_args requires exactly one handler Program argument");
                        if (!providerProgramValueRefsCompatible(body_compiled_plan, body_value_schema_types, request_ref, HandlerProgram.compiled_plan, HandlerProgram.value_schema_types, parameters[0].ref)) {
                            @compileError("provider Program payload_to_args argument schema does not match request payload/current-value schema");
                        }
                    },
                    .payload_and_metadata_to_args => {
                        if (parameters.len != 2) @compileError("provider Program payload_and_metadata_to_args requires payload/current-value plus metadata arguments");
                        if (!providerProgramValueRefsCompatible(body_compiled_plan, body_value_schema_types, request_ref, HandlerProgram.compiled_plan, HandlerProgram.value_schema_types, parameters[0].ref)) {
                            @compileError("provider Program payload_and_metadata_to_args first argument schema does not match request payload/current-value schema");
                        }
                        if (parameters[1].ref.schema_index == null and parameters[1].ref.codec == .unit) {
                            @compileError("provider Program metadata argument must be represented by a non-unit value ref");
                        }
                    },
                    .unit_args => {
                        if (parameters.len != 0) @compileError("provider Program unit_args requires a handler Program with no entry arguments");
                        if (!providerProgramRequestValueRef(kind_value, Site).eql(.{ .codec = .unit })) {
                            @compileError("provider Program unit_args requires a unit request payload/current value");
                        }
                    },
                    .custom_comptime_mapper => {
                        if (custom_mapper_fingerprint == null) {
                            @compileError("provider Program custom_comptime_mapper requires mapper_fingerprint");
                        }
                    },
                }
            }

            fn validateProviderProgramResultMapping(comptime kind_value: anytype, comptime Site: type, comptime HandlerProgram: type, comptime result_mapping: ProgramResultToProviderOutcome) void {
                const result_ref = HandlerProgram.contract.result_ref;
                switch (result_mapping) {
                    .result_to_resume => {
                        if (kind_value != .operation or !Site.may_resume) {
                            @compileError("provider Program result_to_resume requires a resumable operation offer");
                        }
                        if (!providerProgramValueRefsCompatible(HandlerProgram.compiled_plan, HandlerProgram.value_schema_types, result_ref, body_compiled_plan, body_value_schema_types, Site.resume_ref)) {
                            @compileError("provider Program result_to_resume result schema does not match operation resume schema");
                        }
                    },
                    .result_to_return_now => {
                        if (kind_value != .operation or !Site.may_return_now) {
                            @compileError("provider Program result_to_return_now requires a return-now operation offer");
                        }
                        if (!providerProgramValueRefsCompatible(HandlerProgram.compiled_plan, HandlerProgram.value_schema_types, result_ref, body_compiled_plan, body_value_schema_types, Site.result_ref)) {
                            @compileError("provider Program result_to_return_now result schema does not match operation result schema");
                        }
                    },
                    .result_to_resume_after => {
                        if (kind_value != .after) {
                            @compileError("provider Program result_to_resume_after requires an after handler");
                        }
                        if (!providerProgramValueRefsCompatible(HandlerProgram.compiled_plan, HandlerProgram.value_schema_types, result_ref, body_compiled_plan, body_value_schema_types, Site.output_ref)) {
                            @compileError("provider Program result_to_resume_after result schema does not match after output schema");
                        }
                    },
                    .result_to_outcome_union => {
                        if (result_ref.schema_index == null) @compileError("provider Program result_to_outcome_union requires a typed union/product result schema");
                    },
                }
            }

            fn providerProgramRequestValueRef(comptime kind_value: anytype, comptime Site: type) lowering_api.ValueRef {
                return switch (kind_value) {
                    .operation => Site.payload_ref,
                    .after => Site.current_value_ref orelse .{ .codec = .unit },
                    else => @compileError("unsupported provider-program handler kind"),
                };
            }

            fn fingerprintProviderProgramValueRef(builder: *Evidence.FingerprintBuilder, comptime prefix: []const u8, comptime ref: lowering_api.ValueRef) void {
                builder.fieldBytes(prefix ++ ".codec", @tagName(ref.codec));
                builder.fieldBool(prefix ++ ".schema.present", ref.schema_index != null);
                if (ref.schema_index) |schema_index| builder.fieldUsize(prefix ++ ".schema", schema_index);
            }

            fn providerProgramValueRefsCompatible(
                comptime left_plan: lowering_api.ProgramPlan,
                comptime left_schema_types: anytype,
                comptime left_ref: lowering_api.ValueRef,
                comptime right_plan: lowering_api.ProgramPlan,
                comptime right_schema_types: anytype,
                comptime right_ref: lowering_api.ValueRef,
            ) bool {
                if (left_ref.codec != right_ref.codec) return false;
                switch (left_ref.codec) {
                    .product, .sum => {
                        if (left_ref.schema_index == null or right_ref.schema_index == null) return false;
                        if (left_ref.schema_index.? >= left_plan.value_schemas.len or right_ref.schema_index.? >= right_plan.value_schemas.len) return false;
                    },
                    else => {
                        if (left_ref.schema_index != null or right_ref.schema_index != null) return false;
                    },
                }
                const LeftType = ProgramValueTypeForRef(left_plan, left_schema_types, left_ref);
                const RightType = ProgramValueTypeForRef(right_plan, right_schema_types, right_ref);
                return LeftType == RightType;
            }

            fn validateProviderHarnessOptions(comptime options: anytype) void {
                const Options = @TypeOf(options);
                if (!providerHarnessHasField(Options, "label")) @compileError("Program.Exchange.ProviderHarness requires label");
                const has_entries = providerHarnessHasField(Options, "entries");
                const has_handlers = providerHarnessHasField(Options, "handlers");
                if (!has_entries and !has_handlers) @compileError("Program.Exchange.ProviderHarness requires entries or handlers");
                const entries = if (has_entries) options.entries else options.handlers;
                if (options.label.len == 0) @compileError("Program.Exchange.ProviderHarness label must be non-empty");
                if (entries.len == 0) @compileError("Program.Exchange.ProviderHarness requires at least one handler declaration");
                inline for (entries) |Entry| validateProviderHarnessEntry(Entry);
                comptime assertProviderHarnessNoDuplicates(entries);
            }

            fn validateProviderHarnessEntry(comptime Entry: type) void {
                if (!hasDeclSafe(Entry, "kind") or !hasDeclSafe(Entry, "Site") or !hasDeclSafe(Entry, "offer_options")) {
                    @compileError("Program.Exchange.ProviderHarness listed non-provider handler declaration");
                }
                const Site = Entry.Site;
                if (!hasDeclSafe(Site, "Owner") or
                    !hasDeclSafe(Site, "owner_label") or
                    !std.mem.eql(u8, Site.owner_label, label) or
                    !hasDeclSafe(Site, "owner_plan_hash") or
                    Site.owner_plan_hash != body_compiled_plan_hash or
                    !hasDeclSafe(Site, "OwnerHandlers") or
                    Site.OwnerHandlers != HandlersType or
                    Site.Owner != Body)
                {
                    @compileError("Program.Exchange.ProviderHarness descriptor belongs to another program");
                }
                switch (Entry.kind) {
                    .operation => if (!hasDeclSafe(Site, "kind") or Site.kind != .operation) {
                        @compileError("Program.Exchange.ProviderHarness listed non-operation site for operation handler");
                    },
                    .after => if (!hasDeclSafe(Site, "kind") or Site.kind != .after) {
                        @compileError("Program.Exchange.ProviderHarness listed non-after site for after handler");
                    },
                    else => @compileError("Program.Exchange.ProviderHarness listed non-provider handler declaration"),
                }
            }

            fn assertProviderHarnessNoDuplicates(comptime entries: anytype) void {
                var operation_covered: [protocol.operation_site_count]bool = [_]bool{false} ** protocol.operation_site_count;
                var after_covered: [protocol.after_site_count]bool = [_]bool{false} ** protocol.after_site_count;
                inline for (entries) |Entry| switch (Entry.kind) {
                    .operation => {
                        if (operation_covered[Entry.Site.index]) @compileError("Program.Exchange.ProviderHarness listed duplicate operation handler");
                        operation_covered[Entry.Site.index] = true;
                    },
                    .after => {
                        if (after_covered[Entry.Site.index]) @compileError("Program.Exchange.ProviderHarness listed duplicate after handler");
                        after_covered[Entry.Site.index] = true;
                    },
                    else => unreachable,
                };
            }

            fn assertProviderHarnessCoversAll(comptime entries: anytype) void {
                var operation_covered: [protocol.operation_site_count]bool = [_]bool{false} ** protocol.operation_site_count;
                var after_covered: [protocol.after_site_count]bool = [_]bool{false} ** protocol.after_site_count;
                inline for (entries) |Entry| switch (Entry.kind) {
                    .operation => operation_covered[Entry.Site.index] = true,
                    .after => after_covered[Entry.Site.index] = true,
                    else => unreachable,
                };
                inline for (operation_covered) |is_covered| {
                    if (!is_covered) @compileError("Program.Exchange.ProviderHarness coverage omitted reachable operation site");
                }
                inline for (after_covered) |is_covered| {
                    if (!is_covered) @compileError("Program.Exchange.ProviderHarness coverage omitted reachable after site");
                }
            }

            fn providerHarnessOperationSiteCount(comptime entries: anytype) usize {
                comptime var count: usize = 0;
                inline for (entries) |Entry| {
                    if (Entry.kind == .operation) count += 1;
                }
                return count;
            }

            fn providerHarnessAfterSiteCount(comptime entries: anytype) usize {
                comptime var count: usize = 0;
                inline for (entries) |Entry| {
                    if (Entry.kind == .after) count += 1;
                }
                return count;
            }

            fn providerHarnessOperationSites(comptime entries: anytype) [providerHarnessOperationSiteCount(entries)]usize {
                comptime var sites: [providerHarnessOperationSiteCount(entries)]usize = undefined;
                comptime var index: usize = 0;
                inline for (entries) |Entry| if (Entry.kind == .operation) {
                    sites[index] = Entry.Site.index;
                    index += 1;
                };
                return sites;
            }

            fn providerHarnessAfterSites(comptime entries: anytype) [providerHarnessAfterSiteCount(entries)]usize {
                comptime var sites: [providerHarnessAfterSiteCount(entries)]usize = undefined;
                comptime var index: usize = 0;
                inline for (entries) |Entry| if (Entry.kind == .after) {
                    sites[index] = Entry.Site.index;
                    index += 1;
                };
                return sites;
            }

            fn providerHarnessProtocolLabels(comptime entries: anytype) [entries.len][]const u8 {
                comptime var labels: [entries.len][]const u8 = undefined;
                inline for (entries, 0..) |Entry, index| {
                    labels[index] = providerHarnessEntryProtocolLabel(Entry);
                }
                return labels;
            }

            fn providerHarnessProtocolOps(comptime entries: anytype) [entries.len]u64 {
                comptime var ops: [entries.len]u64 = undefined;
                inline for (entries, 0..) |Entry, index| {
                    ops[index] = providerHarnessEntryProtocolOpFingerprint(Entry);
                }
                return ops;
            }

            fn providerHarnessEntryProtocolLabel(comptime Entry: type) []const u8 {
                return Entry.offer_options.protocol_label orelse switch (Entry.kind) {
                    .operation => Entry.Site.requirement_label,
                    .after => Entry.Site.original_requirement_label,
                    else => unreachable,
                };
            }

            fn providerHarnessEntryProtocolOpFingerprint(comptime Entry: type) u64 {
                return Entry.offer_options.protocol_op_fingerprint orelse switch (Entry.kind) {
                    .operation => Entry.Site.fingerprint,
                    .after => Entry.Site.source_operation_site_fingerprint,
                    else => unreachable,
                };
            }

            fn providerHarnessDefaultOfferLabel(comptime Entry: type) []const u8 {
                return switch (Entry.kind) {
                    .operation => Entry.Site.op_name,
                    .after => Entry.Site.original_op_name,
                    else => unreachable,
                };
            }

            fn providerHarnessDefaultResponseKinds(comptime Entry: type) Policy.ResponseKindSet {
                return switch (Entry.kind) {
                    .operation => .{
                        .@"resume" = Entry.Site.may_resume,
                        .return_now = Entry.Site.may_return_now,
                        .resume_after = false,
                    },
                    .after => .{
                        .@"resume" = false,
                        .return_now = false,
                        .resume_after = true,
                    },
                    else => unreachable,
                };
            }

            fn providerHarnessEntryResponseKinds(comptime Entry: type) Policy.ResponseKindSet {
                return Entry.offer_options.allowed_response_kinds orelse providerHarnessDefaultResponseKinds(Entry);
            }

            fn providerHarnessAllowedResponseKinds(comptime entries: anytype) Policy.ResponseKindSet {
                comptime var result: Policy.ResponseKindSet = .{
                    .@"resume" = false,
                    .return_now = false,
                    .resume_after = false,
                };
                inline for (entries) |Entry| {
                    const entry_kinds = comptime providerHarnessEntryResponseKinds(Entry);
                    result.@"resume" = result.@"resume" or entry_kinds.@"resume";
                    result.return_now = result.return_now or entry_kinds.return_now;
                    result.resume_after = result.resume_after or entry_kinds.resume_after;
                }
                return result;
            }

            fn providerHarnessManifestResponseKinds(comptime options: anytype, comptime entries: anytype) Policy.ResponseKindSet {
                const derived = providerHarnessAllowedResponseKinds(entries);
                if (comptime providerHarnessHasField(@TypeOf(options), "allowed_response_kinds")) {
                    return .{
                        .@"resume" = options.allowed_response_kinds.@"resume" and derived.@"resume",
                        .return_now = options.allowed_response_kinds.return_now and derived.return_now,
                        .resume_after = options.allowed_response_kinds.resume_after and derived.resume_after,
                    };
                }
                return derived;
            }

            fn providerHarnessMaxRequestBytes(comptime entries: anytype) usize {
                comptime var result: usize = 0;
                inline for (entries) |Entry| result = @max(result, Entry.offer_options.max_request_bytes);
                return result;
            }

            fn providerHarnessMaxResponseBytes(comptime entries: anytype) usize {
                comptime var result: usize = 0;
                inline for (entries) |Entry| result = @max(result, Entry.offer_options.max_response_bytes);
                return result;
            }

            fn providerHarnessManifestMaxRequestBytes(comptime options: anytype, comptime entries: anytype) usize {
                const derived = providerHarnessMaxRequestBytes(entries);
                if (comptime providerHarnessHasField(@TypeOf(options), "max_request_envelope_bytes")) {
                    return @min(options.max_request_envelope_bytes, derived);
                }
                return derived;
            }

            fn providerHarnessManifestMaxResponseBytes(comptime options: anytype, comptime entries: anytype) usize {
                const derived = providerHarnessMaxResponseBytes(entries);
                if (comptime providerHarnessHasField(@TypeOf(options), "max_response_envelope_bytes")) {
                    return @min(options.max_response_envelope_bytes, derived);
                }
                return derived;
            }

            fn providerHarnessProducedResponseRefs(comptime Entry: type, comptime response_kinds: Policy.ResponseKindSet) []const lowering_api.ValueRef {
                return switch (Entry.kind) {
                    .operation => switch (Entry.Site.op_mode) {
                        .transform => if (response_kinds.@"resume") &.{Entry.Site.resume_ref} else &.{},
                        .choice => if (response_kinds.@"resume" and response_kinds.return_now)
                            &.{ Entry.Site.resume_ref, Entry.Site.result_ref }
                        else if (response_kinds.@"resume")
                            &.{Entry.Site.resume_ref}
                        else if (response_kinds.return_now)
                            &.{Entry.Site.result_ref}
                        else
                            &.{},
                        .abort => if (response_kinds.return_now) &.{Entry.Site.result_ref} else &.{},
                    },
                    .after => if (response_kinds.resume_after) &.{Entry.Site.output_ref} else &.{},
                    else => unreachable,
                };
            }

            fn providerHarnessOfferOptions(comptime Entry: type, manifest_fingerprint: u64, provider_fingerprint: u64) ProviderOffer.Options {
                const offer_label = Entry.offer_options.label orelse providerHarnessDefaultOfferLabel(Entry);
                const response_kinds = comptime providerHarnessEntryResponseKinds(Entry);
                return .{
                    .label = offer_label,
                    .provider_fingerprint = provider_fingerprint,
                    .manifest_fingerprint = manifest_fingerprint,
                    .supported_operation_sites = switch (Entry.kind) {
                        .operation => &.{Entry.Site.index},
                        .after => &.{},
                        else => unreachable,
                    },
                    .supported_after_sites = switch (Entry.kind) {
                        .operation => &.{},
                        .after => &.{Entry.Site.index},
                        else => unreachable,
                    },
                    .supported_protocol_op_fingerprints = &.{providerHarnessEntryProtocolOpFingerprint(Entry)},
                    .supported_protocol_labels = &.{providerHarnessEntryProtocolLabel(Entry)},
                    .accepted_payload_refs = switch (Entry.kind) {
                        .operation => &.{Entry.Site.payload_ref},
                        .after => &.{},
                        else => unreachable,
                    },
                    .accepted_current_value_refs = switch (Entry.kind) {
                        .operation => &.{},
                        .after => if (Entry.Site.current_value_ref) |ref| &.{ref} else &.{},
                        else => unreachable,
                    },
                    .produced_response_refs = providerHarnessProducedResponseRefs(Entry, response_kinds),
                    .allowed_response_kinds = response_kinds,
                    .supported_usage_modes = Entry.offer_options.supported_usage_modes,
                    .supported_response_uses = Entry.offer_options.supported_response_uses,
                    .supported_replay_policies = Entry.offer_options.supported_replay_policies,
                    .supported_branch_policies = Entry.offer_options.supported_branch_policies,
                    .capsule_policy = Entry.offer_options.capsule_policy,
                    .opens_obligation = Entry.offer_options.opens_obligation,
                    .max_request_bytes = Entry.offer_options.max_request_bytes,
                    .max_response_bytes = Entry.offer_options.max_response_bytes,
                    .max_capsule_bytes = Entry.offer_options.max_capsule_bytes,
                    .tags = Entry.offer_options.tags,
                    .metadata = Entry.offer_options.metadata,
                    .provider_program_mapping_fingerprint = if (comptime @hasDecl(Entry, "provider_program_mapping_fingerprint")) Entry.provider_program_mapping_fingerprint else null,
                };
            }

            /// Exchange-facing metadata for one protocol adaptation offer.
            pub const MorphismOffer = struct {
                label: []const u8,
                source_site_fingerprint: ?u64 = null,
                source_protocol_op_fingerprint: ?u64 = null,
                target_protocol_op_fingerprint: u64,
                dynamic_morphism_fingerprint: ?u64 = null,
                residual_morphism_fingerprint: ?u64 = null,
                pipeline_fingerprint: ?u64 = null,
                source_usage: Usage = .copyable,
                target_usage: Usage = .copyable,
                source_response_refs: []const lowering_api.ValueRef = &.{},
                target_response_refs: []const lowering_api.ValueRef = &.{},
                blockers: []const Treaty.Blocker = &.{},

                /// Return the deterministic morphism-offer fingerprint.
                pub fn fingerprint(self: @This()) u64 {
                    return fingerprintMorphismOffer(self);
                }

                /// Canonical evidence reference for this morphism offer.
                pub fn evidenceRef(self: @This()) Evidence.Ref {
                    return Evidence.refFor(Evidence.domains.morphism_offer, self.fingerprint(), .{ .label = self.label });
                }

                /// Return true when this offer can adapt the request source.
                pub fn supportsSource(self: @This(), request: RequestEnvelope) bool {
                    if (self.blockers.len != 0) return false;
                    request.validate() catch return false;
                    if (self.source_site_fingerprint) |site| {
                        if (site != request.site_fingerprint) return false;
                    }
                    if (self.source_protocol_op_fingerprint) |op| {
                        if ((requestProtocolOperationFingerprint(request) orelse return false) != op) return false;
                    }
                    const source_usage = if (request.usage_metadata) |metadata| metadata.usage else Usage.copyable;
                    if (source_usage != self.source_usage) return false;
                    var refs: [3]lowering_api.ValueRef = undefined;
                    const refs_len = responseRefsForRequest(request, &refs);
                    if (self.target_response_refs.len != 0 and self.source_response_refs.len == 0) return false;
                    if (self.source_response_refs.len != 0) {
                        var source_ref_supported = false;
                        for (refs[0..refs_len]) |ref| {
                            if (listAllowsValueRef(self.source_response_refs, ref)) source_ref_supported = true;
                        }
                        if (!source_ref_supported) return false;
                    }
                    return true;
                }

                /// Return true when this offer cites a static residual or pipeline adapter.
                pub fn hasStaticAdapter(self: @This()) bool {
                    return self.residual_morphism_fingerprint != null or self.pipeline_fingerprint != null;
                }
            };

            /// Resolver policy-rich input derived from a request envelope.
            pub const TreatyRequest = struct {
                request_envelope_fingerprint: u64,
                request_kind: RequestKind,
                request_site_fingerprint: u64,
                protocol_op_fingerprint: ?u64,
                exchange_manifest_fingerprint: u64,
                desired_response_kinds: Policy.ResponseKindSet = .{},
                desired_response_refs: []const lowering_api.ValueRef = &.{},
                requested_usage_mode: ?Usage = null,
                requested_response_use: ?ResponseUse = null,
                requested_branch_policy: ?BranchPolicy = null,
                requested_replay_policy: ?ResponseUse = null,
                required_provider_tags: []const []const u8 = &.{},
                allowed_provider_tags: []const []const u8 = &.{},
                max_request_bytes: usize = std.math.maxInt(usize),
                max_response_bytes: usize = std.math.maxInt(usize),
                capsule_policy: CapsulePolicy = .allowed,
                prefer_residualization: bool = false,
                allow_dynamic_morphism: bool = true,
                allow_provider_fallback: bool = true,
                require_least_authority: bool = false,
                require_treaty_bound_response_authorization: bool = true,
                require_journal_recording: bool = false,

                /// Build a treaty request from a concrete request envelope.
                pub fn fromRequest(request: RequestEnvelope) @This() {
                    return .{
                        .request_envelope_fingerprint = request.fingerprint,
                        .request_kind = request.kind,
                        .request_site_fingerprint = request.site_fingerprint,
                        .protocol_op_fingerprint = requestProtocolOperationFingerprint(request),
                        .exchange_manifest_fingerprint = request.manifest_fingerprint,
                        .desired_response_kinds = responseKindSetForRequest(request),
                        .desired_response_refs = &.{},
                        .requested_usage_mode = if (request.usage_metadata) |metadata| metadata.usage else null,
                        .requested_branch_policy = if (request.usage_metadata) |metadata| metadata.branch_policy else null,
                        .requested_replay_policy = if (request.usage_metadata) |metadata| metadata.replay_policy else null,
                        .capsule_policy = if (request.capsule_image != null) .allowed else .allowed,
                    };
                }
            };

            const ExchangeResponseKindSet = Policy.ResponseKindSet;

            /// Selected Effect Treaty agreement and its proof certificate.
            pub const Treaty = struct {
                allocator: ?std.mem.Allocator = null,
                fingerprint: u64,
                request_envelope_fingerprint: u64,
                request_envelope_format_version: u32 = exchange_request_format_version,
                request_fingerprint: u64,
                manifest_fingerprint: u64,
                provider_fingerprint: u64,
                provider_offer_fingerprint: u64,
                provider_offer_tags: []const []const u8 = &.{},
                capability_fingerprint: u64,
                attenuated_capability: ?Capability = null,
                capability_path_fingerprint: u64,
                capability_instance_fingerprint: ?u64 = null,
                obligation_fingerprint: ?u64 = null,
                route: Route,
                handling: HandlingKind = .direct,
                morphism_offer_fingerprints: []const u64 = &.{},
                effect_session_spec_fingerprint: ?u64 = null,
                dynamic_morphism_fingerprints: []const u64 = &.{},
                residualization_fingerprints: []const u64 = &.{},
                pipeline_fingerprint: ?u64 = null,
                source_protocol_op_fingerprint: ?u64 = null,
                target_protocol_op_fingerprint: ?u64 = null,
                usage: Usage = .copyable,
                provider_usage: Usage = .copyable,
                response_use: ResponseUse = .fresh,
                replay_policy: ResponseUse = .fresh,
                branch_policy: BranchPolicy = .unrestricted,
                expected_response_kinds: ExchangeResponseKindSet = .{},
                expected_response_refs: []const lowering_api.ValueRef = &.{},
                provider_response_refs: []const lowering_api.ValueRef = &.{},
                journal_policy_fingerprint: ?u64 = null,
                require_treaty_bound_response_authorization: bool = true,
                certificate: Certificate,

                /// Canonical evidence reference for this treaty.
                pub fn evidenceRef(self: @This()) Evidence.Ref {
                    return Evidence.refForTreaty(self);
                }

                /// Treaty handling implementation mode.
                pub const HandlingKind = enum {
                    direct,
                    dynamic_morphism,
                    residualized,
                    pipeline_adapted,
                };

                /// Resolver ambiguity policy.
                pub const AmbiguityPolicy = enum {
                    reject_ambiguous,
                    prefer_least_authority,
                    prefer_direct,
                    prefer_residualized,
                    prefer_dynamic,
                    host_ordered,
                };

                /// Rule for adapting policy metadata across a morphism offer.
                pub const MappingRule = enum {
                    preserve,
                    narrow_to_target,
                };

                /// Structured treaty blocker tag.
                pub const BlockerTag = enum {
                    no_provider_offer,
                    no_capability,
                    capability_not_monotone,
                    capability_too_broad_when_attenuation_required,
                    provider_does_not_support_site,
                    provider_does_not_support_protocol_op,
                    morphism_missing,
                    morphism_type_mismatch,
                    morphism_usage_mode_mismatch,
                    residualization_unsupported,
                    dynamic_morphism_disallowed,
                    capsule_export_disallowed,
                    replay_policy_incompatible,
                    branch_policy_incompatible,
                    response_use_incompatible,
                    usage_mode_not_allowed,
                    obligation_open_failed,
                    obligation_state_incompatible,
                    capability_instance_consumed,
                    capability_instance_wrong_branch,
                    ambiguous_provider,
                    ambiguous_morphism_path,
                    max_morphism_hops_exceeded,
                    envelope_too_large,
                    foreign_manifest,
                    malformed_request,
                    malformed_offer,
                    malformed_treaty_request,
                    wrong_treaty,
                    wrong_certificate,
                    wrong_provider,
                    wrong_capability,
                    wrong_route,
                    wrong_morphism,
                    wrong_response_kind,
                };

                /// Structured treaty blocker with optional candidate fingerprints.
                pub const Blocker = struct {
                    tag: Treaty.BlockerTag,
                    request_fingerprint: u64 = 0,
                    request_format_version: ?u32 = null,
                    provider_fingerprint: ?u64 = null,
                    offer_fingerprint: ?u64 = null,
                    capability_fingerprint: ?u64 = null,
                    capability_instance_fingerprint: ?u64 = null,
                    obligation_fingerprint: ?u64 = null,
                    morphism_fingerprint: ?u64 = null,
                    summary: []const u8 = "",

                    /// Lower treaty-specific blocker metadata into the shared Evidence blocker shape.
                    pub fn toEvidenceBlocker(self: @This()) Evidence.Blocker {
                        var related_storage = [_]Evidence.Ref{Evidence.refForProviderIdentity(0)} ** 6;
                        var related_len: usize = 0;
                        if (self.provider_fingerprint) |fingerprint| {
                            related_storage[related_len] = Evidence.refForProviderIdentity(fingerprint);
                            related_len += 1;
                        }
                        if (self.offer_fingerprint) |fingerprint| {
                            related_storage[related_len] = Evidence.refFor(Evidence.domains.provider_offer, fingerprint, .{});
                            related_len += 1;
                        }
                        if (self.capability_fingerprint) |fingerprint| {
                            related_storage[related_len] = Evidence.refFor(Evidence.domains.capability, fingerprint, .{});
                            related_len += 1;
                        }
                        if (self.capability_instance_fingerprint) |fingerprint| {
                            related_storage[related_len] = Evidence.refFor(Evidence.domains.capability_instance, fingerprint, .{});
                            related_len += 1;
                        }
                        if (self.obligation_fingerprint) |fingerprint| {
                            related_storage[related_len] = Evidence.refFor(Evidence.domains.obligation, fingerprint, .{});
                            related_len += 1;
                        }
                        if (self.morphism_fingerprint) |fingerprint| {
                            related_storage[related_len] = Evidence.refFor(Evidence.domains.morphism_offer, fingerprint, .{});
                            related_len += 1;
                        }
                        var evidence_blocker = self.toEvidenceBlockerWithRelated(null);
                        evidence_blocker.related_ref_storage = related_storage;
                        evidence_blocker.related_ref_count = related_len;
                        return evidence_blocker;
                    }

                    /// Lower treaty-specific blocker metadata with caller-owned related-ref storage.
                    pub fn toEvidenceBlockerWithRelated(self: @This(), storage: ?*[6]Evidence.Ref) Evidence.Blocker {
                        var related_len: usize = 0;
                        const related_refs = if (storage) |related_storage| blk: {
                            if (self.provider_fingerprint) |fingerprint| {
                                related_storage[related_len] = Evidence.refForProviderIdentity(fingerprint);
                                related_len += 1;
                            }
                            if (self.offer_fingerprint) |fingerprint| {
                                related_storage[related_len] = Evidence.refFor(Evidence.domains.provider_offer, fingerprint, .{});
                                related_len += 1;
                            }
                            if (self.capability_fingerprint) |fingerprint| {
                                related_storage[related_len] = Evidence.refFor(Evidence.domains.capability, fingerprint, .{});
                                related_len += 1;
                            }
                            if (self.capability_instance_fingerprint) |fingerprint| {
                                related_storage[related_len] = Evidence.refFor(Evidence.domains.capability_instance, fingerprint, .{});
                                related_len += 1;
                            }
                            if (self.obligation_fingerprint) |fingerprint| {
                                related_storage[related_len] = Evidence.refFor(Evidence.domains.obligation, fingerprint, .{});
                                related_len += 1;
                            }
                            if (self.morphism_fingerprint) |fingerprint| {
                                related_storage[related_len] = Evidence.refFor(Evidence.domains.morphism_offer, fingerprint, .{});
                                related_len += 1;
                            }
                            break :blk related_storage[0..related_len];
                        } else &.{};
                        const request_ref = if (self.request_fingerprint != 0) Evidence.refFor(Evidence.domains.exchange_request_envelope, self.request_fingerprint, .{ .format_version = self.request_format_version }) else null;
                        const primary = if (self.offer_fingerprint) |fingerprint|
                            Evidence.refFor(Evidence.domains.provider_offer, fingerprint, .{})
                        else if (self.capability_fingerprint) |fingerprint|
                            Evidence.refFor(Evidence.domains.capability, fingerprint, .{})
                        else if (self.capability_instance_fingerprint) |fingerprint|
                            Evidence.refFor(Evidence.domains.capability_instance, fingerprint, .{})
                        else if (self.obligation_fingerprint) |fingerprint|
                            Evidence.refFor(Evidence.domains.obligation, fingerprint, .{})
                        else if (self.morphism_fingerprint) |fingerprint|
                            Evidence.refFor(Evidence.domains.morphism_offer, fingerprint, .{})
                        else if (self.provider_fingerprint) |fingerprint|
                            Evidence.refForProviderIdentity(fingerprint)
                        else
                            request_ref;
                        return .{
                            .domain = Evidence.domains.treaty_resolver.id,
                            .tag = @tagName(self.tag),
                            .subject = request_ref,
                            .primary = primary,
                            .related_refs = related_refs,
                            .short_code = @tagName(self.tag),
                            .summary = if (self.summary.len == 0) @tagName(self.tag) else self.summary,
                            .source = .treaty,
                        };
                    }
                };

                /// Fixed-capacity blocker list used by the resolver and certificate checker.
                pub const BlockerList = struct {
                    blockers: [16]Blocker = undefined,
                    count: usize = 0,
                    saturated: bool = false,
                    request_format_version: u32 = exchange_request_format_version,

                    /// Return true when the list has no blockers.
                    pub fn allowed(self: @This()) bool {
                        return self.count == 0 and !self.saturated;
                    }

                    /// Add a blocker to the list.
                    pub fn add(self: *@This(), blocker: Blocker) void {
                        if (self.count < self.blockers.len) {
                            var stored = blocker;
                            if (stored.request_fingerprint != 0 and stored.request_format_version == null) {
                                stored.request_format_version = self.request_format_version;
                            }
                            self.blockers[self.count] = stored;
                            self.count += 1;
                        } else {
                            self.saturated = true;
                        }
                    }

                    /// Add a tag-only blocker.
                    pub fn addTag(self: *@This(), tag: Treaty.BlockerTag, request_fingerprint: u64, summary: []const u8) void {
                        self.add(.{ .tag = tag, .request_fingerprint = request_fingerprint, .summary = summary });
                    }

                    /// Merge all blockers from another list.
                    pub fn merge(self: *@This(), other: @This()) void {
                        for (other.blockers[0..other.count]) |blocker| self.add(blocker);
                        if (other.saturated) self.saturated = true;
                    }

                    /// Return the first blocker tag name.
                    pub fn firstTagName(self: @This()) ?[]const u8 {
                        if (self.count == 0) return null;
                        return @tagName(self.blockers[0].tag);
                    }

                    /// Lower retained treaty blockers into caller-owned shared Evidence blockers.
                    pub fn toEvidenceBlockers(self: @This(), storage: []Evidence.Blocker, related_storage: [][6]Evidence.Ref) []const Evidence.Blocker {
                        const limit = @min(storage.len, self.count);
                        for (self.blockers[0..limit], 0..) |blocker, index| {
                            const related = if (index < related_storage.len) &related_storage[index] else null;
                            storage[index] = blocker.toEvidenceBlockerWithRelated(related);
                        }
                        return storage[0..limit];
                    }

                    fn evidenceOmittedFingerprint(self: @This(), report_domain: Evidence.Domain.Id, lowered_count: usize, related_count: usize) ?u64 {
                        if (!self.saturated and lowered_count >= self.count and related_count >= lowered_count) return null;
                        var builder = Evidence.FingerprintBuilder.init(Evidence.domainById(report_domain) orelse Evidence.domains.program_plan);
                        builder.fieldBytes("kind", "treaty_blocker_omitted_evidence");
                        builder.fieldBool("saturated", self.saturated);
                        builder.fieldUsize("retained_count", self.count);
                        builder.fieldUsize("lowered_count", lowered_count);
                        builder.fieldUsize("related_count", related_count);
                        for (self.blockers[0..self.count], 0..) |blocker, index| {
                            var full_related: [6]Evidence.Ref = undefined;
                            const full_blocker = blocker.toEvidenceBlockerWithRelated(&full_related);
                            builder.fieldUsize("blocker.index", index);
                            builder.fieldU64("blocker.fingerprint", full_blocker.fingerprint());
                            builder.fieldBool("blocker.omitted", index >= lowered_count);
                            builder.fieldBool("blocker.related_omitted", index < lowered_count and index >= related_count);
                        }
                        return builder.finish();
                    }

                    /// Lower this treaty blocker list into a shared Evidence report.
                    pub fn toEvidenceReport(
                        self: @This(),
                        subject: Evidence.Ref,
                        dependencies: []const Evidence.Dependency,
                        blocker_storage: []Evidence.Blocker,
                        related_storage: [][6]Evidence.Ref,
                    ) Evidence.Report {
                        const blockers = self.toEvidenceBlockers(blocker_storage, related_storage);
                        if (self.allowed()) return Evidence.Report.ok(subject, Evidence.domains.treaty_resolver.id, dependencies);
                        if (self.evidenceOmittedFingerprint(Evidence.domains.treaty_resolver.id, blockers.len, related_storage.len)) |omitted_fingerprint| {
                            return Evidence.Report.withIncompleteFailure(subject, Evidence.domains.treaty_resolver.id, dependencies, blockers, &.{}, omitted_fingerprint, null, "treaty resolver report");
                        }
                        return Evidence.Report.withFailure(subject, Evidence.domains.treaty_resolver.id, dependencies, blockers, &.{}, null, "treaty resolver report");
                    }
                };

                /// Host treaty resolution policy.
                pub const Policy = struct {
                    allow_direct_handling: bool = true,
                    allow_morphism_adaptation: bool = true,
                    allow_residualization: bool = true,
                    allow_dynamic_interpretation: bool = true,
                    require_least_authority: bool = true,
                    require_capability_attenuation: bool = false,
                    required_provider_tags: []const []const u8 = &.{},
                    disallowed_provider_tags: []const []const u8 = &.{},
                    disallow_capsule_export: bool = false,
                    require_capsule_embedding: bool = false,
                    disallow_fresh_response: bool = false,
                    require_replay_only_response: bool = false,
                    require_obligation_opening: bool = false,
                    require_journal_recording: bool = false,
                    require_treaty_bound_response_authorization: bool = true,
                    allowed_usage_modes: UsageSet = .{},
                    allowed_response_uses: ResponseUseSet = .{},
                    allowed_branch_policies: BranchPolicySet = .{},
                    max_morphism_hops: usize = 1,
                    max_envelope_bytes: usize = std.math.maxInt(usize),
                    max_capsule_bytes: usize = std.math.maxInt(usize),
                    ambiguity_policy: AmbiguityPolicy = .reject_ambiguous,
                    provider_priority: ?[]const u64 = null,

                    /// Convert treaty policy into the lower Exchange envelope policy.
                    pub fn exchangePolicy(self: @This()) Exchange.Policy {
                        return .{
                            .allow_capsules = !self.disallow_capsule_export,
                            .max_envelope_bytes = self.max_envelope_bytes,
                            .max_capsule_image_bytes = self.max_capsule_bytes,
                        };
                    }
                };

                /// Proof-carrying treaty certificate.
                pub const Certificate = struct {
                    treaty_format_version: u32 = exchange_treaty_format_version,
                    treaty_fingerprint: u64,
                    request_envelope_fingerprint: u64,
                    request_envelope_format_version: u32 = exchange_request_format_version,
                    request_fingerprint: u64,
                    manifest_fingerprint: u64,
                    provider_fingerprint: u64,
                    provider_offer_fingerprint: u64,
                    provider_offer_tags: []const []const u8 = &.{},
                    capability_fingerprint: u64,
                    attenuated_capability_fingerprint: ?u64 = null,
                    capability_path_fingerprint: u64,
                    capability_instance_fingerprint: ?u64 = null,
                    obligation_fingerprint: ?u64 = null,
                    effect_session_spec_fingerprint: ?u64 = null,
                    route_fingerprint: u64,
                    morphism_offer_fingerprints: []const u64 = &.{},
                    dynamic_morphism_fingerprints: []const u64 = &.{},
                    residualization_fingerprints: []const u64 = &.{},
                    pipeline_fingerprint: ?u64 = null,
                    source_protocol_op_fingerprint: ?u64 = null,
                    target_protocol_op_fingerprint: ?u64 = null,
                    handling: HandlingKind = .direct,
                    usage: Usage = .copyable,
                    provider_usage: Usage = .copyable,
                    response_use: ResponseUse = .fresh,
                    replay_policy: ResponseUse = .fresh,
                    branch_policy: BranchPolicy = .unrestricted,
                    expected_response_kinds: ExchangeResponseKindSet = .{},
                    expected_response_refs: []const lowering_api.ValueRef = &.{},
                    provider_response_refs: []const lowering_api.ValueRef = &.{},
                    journal_policy_fingerprint: ?u64 = null,
                    require_treaty_bound_response_authorization: bool = true,
                    blockers: BlockerList = .{},
                    certificate_fingerprint: u64 = 0,

                    /// Check internal certificate consistency.
                    pub fn check(self: @This()) Error!void {
                        if (self.treaty_format_version != exchange_treaty_format_version) return error.ProgramContractViolation;
                        if (self.treaty_fingerprint == 0 or self.request_envelope_fingerprint == 0) return error.ProgramContractViolation;
                        if (self.provider_fingerprint == 0 or self.provider_offer_fingerprint == 0) return error.ProgramContractViolation;
                        if (self.capability_fingerprint == 0 or self.capability_path_fingerprint == 0) return error.ProgramContractViolation;
                        if (self.route_fingerprint == 0) return error.ProgramContractViolation;
                        if (!self.blockers.allowed()) return error.ProgramContractViolation;
                        if (self.certificate_fingerprint != fingerprintTreatyCertificate(self)) return error.ProgramContractViolation;
                    }

                    /// Canonical evidence reference for this treaty certificate.
                    pub fn evidenceRef(self: @This()) Evidence.Ref {
                        return Evidence.refForTreatyCertificate(self);
                    }

                    /// Shared certificate snapshot view with caller-owned dependency storage.
                    pub fn evidenceView(self: @This(), storage: ?*[6]Evidence.Dependency) Evidence.CertificateView {
                        return Evidence.certificateViewForTreatyCertificateWithDependencies(storage, self);
                    }

                    /// Clone certificate-owned slices before transferring it outside the runner.
                    pub fn clone(self: @This(), allocator: std.mem.Allocator) Error!@This() {
                        const morphism_fps = try cloneU64s(allocator, self.morphism_offer_fingerprints);
                        errdefer allocator.free(morphism_fps);
                        const dynamic_fps = try cloneU64s(allocator, self.dynamic_morphism_fingerprints);
                        errdefer allocator.free(dynamic_fps);
                        const residual_fps = try cloneU64s(allocator, self.residualization_fingerprints);
                        errdefer allocator.free(residual_fps);
                        const response_refs = try cloneValueRefs(allocator, self.expected_response_refs);
                        errdefer allocator.free(response_refs);
                        const provider_refs = try cloneValueRefs(allocator, self.provider_response_refs);
                        errdefer allocator.free(provider_refs);
                        const provider_tags = try cloneStringList(allocator, self.provider_offer_tags);
                        errdefer freeStringList(allocator, provider_tags);
                        var cloned = self;
                        cloned.morphism_offer_fingerprints = morphism_fps;
                        cloned.dynamic_morphism_fingerprints = dynamic_fps;
                        cloned.residualization_fingerprints = residual_fps;
                        cloned.expected_response_refs = response_refs;
                        cloned.provider_response_refs = provider_refs;
                        cloned.provider_offer_tags = provider_tags;
                        return cloned;
                    }

                    /// Release storage owned by a cloned certificate.
                    pub fn deinit(self: *@This(), allocator: std.mem.Allocator) void {
                        allocator.free(self.morphism_offer_fingerprints);
                        allocator.free(self.dynamic_morphism_fingerprints);
                        allocator.free(self.residualization_fingerprints);
                        allocator.free(self.expected_response_refs);
                        allocator.free(self.provider_response_refs);
                        freeStringList(allocator, self.provider_offer_tags);
                        self.morphism_offer_fingerprints = &.{};
                        self.dynamic_morphism_fingerprints = &.{};
                        self.residualization_fingerprints = &.{};
                        self.expected_response_refs = &.{};
                        self.provider_response_refs = &.{};
                        self.provider_offer_tags = &.{};
                    }
                };

                /// Treaty-bound response authorization sidecar.
                pub const Authorization = struct {
                    treaty_fingerprint: u64,
                    treaty_certificate_fingerprint: u64,
                    provider_fingerprint: u64,
                    provider_offer_fingerprint: u64,
                    capability_fingerprint: u64,
                    attenuated_capability_fingerprint: ?u64 = null,
                    capability_path_fingerprint: u64,
                    capability_instance_fingerprint: ?u64 = null,
                    obligation_fingerprint: ?u64 = null,
                    route_fingerprint: u64,
                    request_envelope_fingerprint: u64,
                    request_envelope_format_version: u32 = exchange_request_format_version,
                    response_envelope_fingerprint: u64,
                    usage: Usage = .copyable,
                    response_use: ResponseUse = .fresh,
                    replay_policy: ResponseUse = .fresh,
                    branch_policy: BranchPolicy = .unrestricted,
                    replay_source_response_fingerprint: ?u64 = null,
                    replay_source_response_value_fingerprint: ?u64 = null,
                    expected_obligation_transition_fingerprint: ?u64 = null,
                    format_version: u32 = exchange_treaty_authorization_fingerprint_version,
                    authorization_fingerprint: u64 = 0,

                    /// Canonical evidence reference for this treaty authorization.
                    pub fn evidenceRef(self: @This()) Evidence.Ref {
                        return Evidence.refForTreatyAuthorization(self);
                    }

                    /// Shared authorization snapshot view.
                    pub fn evidenceView(self: @This()) Evidence.AuthorizationView {
                        return Evidence.authorizationViewForTreatyAuthorization(self);
                    }

                    /// Construct a treaty-bound authorization for a response.
                    pub fn forResponse(treaty: Treaty, response: ResponseEnvelope, response_use: ResponseUse) Error!@This() {
                        try validateResponseEnvelopeFieldsBoundToBytes(response);
                        var value = @This(){
                            .treaty_fingerprint = treaty.fingerprint,
                            .treaty_certificate_fingerprint = treaty.certificate.certificate_fingerprint,
                            .provider_fingerprint = treaty.provider_fingerprint,
                            .provider_offer_fingerprint = treaty.provider_offer_fingerprint,
                            .capability_fingerprint = treaty.capability_fingerprint,
                            .attenuated_capability_fingerprint = if (treaty.attenuated_capability) |capability| capability.fingerprint else null,
                            .capability_path_fingerprint = treaty.capability_path_fingerprint,
                            .capability_instance_fingerprint = treaty.capability_instance_fingerprint,
                            .obligation_fingerprint = treaty.obligation_fingerprint,
                            .route_fingerprint = treaty.route.fingerprint,
                            .request_envelope_fingerprint = treaty.request_envelope_fingerprint,
                            .request_envelope_format_version = treaty.request_envelope_format_version,
                            .response_envelope_fingerprint = response.fingerprint,
                            .usage = treaty.usage,
                            .response_use = response_use,
                            .replay_policy = treaty.replay_policy,
                            .branch_policy = treaty.branch_policy,
                        };
                        value.authorization_fingerprint = fingerprintTreatyAuthorization(value);
                        return value;
                    }

                    /// Construct a treaty-bound authorization from a provider-visible certificate.
                    pub fn forCertificate(certificate: Treaty.Certificate, response: ResponseEnvelope, response_use: ResponseUse) Error!@This() {
                        try certificate.check();
                        try validateResponseEnvelopeFieldsBoundToBytes(response);
                        if (certificate.request_envelope_fingerprint != response.request_envelope_fingerprint) return error.ProgramContractViolation;
                        var value = @This(){
                            .treaty_fingerprint = certificate.treaty_fingerprint,
                            .treaty_certificate_fingerprint = certificate.certificate_fingerprint,
                            .provider_fingerprint = certificate.provider_fingerprint,
                            .provider_offer_fingerprint = certificate.provider_offer_fingerprint,
                            .capability_fingerprint = certificate.capability_fingerprint,
                            .attenuated_capability_fingerprint = certificate.attenuated_capability_fingerprint,
                            .capability_path_fingerprint = certificate.capability_path_fingerprint,
                            .capability_instance_fingerprint = certificate.capability_instance_fingerprint,
                            .obligation_fingerprint = certificate.obligation_fingerprint,
                            .route_fingerprint = certificate.route_fingerprint,
                            .request_envelope_fingerprint = certificate.request_envelope_fingerprint,
                            .request_envelope_format_version = certificate.request_envelope_format_version,
                            .response_envelope_fingerprint = response.fingerprint,
                            .usage = certificate.usage,
                            .response_use = response_use,
                            .replay_policy = certificate.replay_policy,
                            .branch_policy = certificate.branch_policy,
                        };
                        value.authorization_fingerprint = fingerprintTreatyAuthorization(value);
                        return value;
                    }

                    /// Construct a treaty authorization that binds the expected obligation transition.
                    pub fn forResponseWithObligationTransition(treaty: Treaty, response: ResponseEnvelope, response_use: ResponseUse, transition_fingerprint: u64) Error!@This() {
                        if (treaty.obligation_fingerprint == null or transition_fingerprint == 0) return error.ProgramContractViolation;
                        var value = try forResponse(treaty, response, response_use);
                        value.expected_obligation_transition_fingerprint = transition_fingerprint;
                        value.authorization_fingerprint = fingerprintTreatyAuthorization(value);
                        return value;
                    }

                    /// Construct a replay treaty authorization that cites a recorded source response.
                    pub fn forResponseWithReplaySource(treaty: Treaty, response: ResponseEnvelope, response_use: ResponseUse, source_response_fingerprint: u64, source_response_value_fingerprint: u64) Error!@This() {
                        if (response_use != .replayed and response_use != .deterministic_replay) return error.ProgramContractViolation;
                        if (source_response_fingerprint == 0) return error.ProgramContractViolation;
                        if (treaty.obligation_fingerprint == null and source_response_fingerprint == response.fingerprint) return error.ProgramContractViolation;
                        if (source_response_value_fingerprint == 0 or source_response_value_fingerprint != response.response_value_fingerprint) return error.ProgramContractViolation;
                        var value = try forResponse(treaty, response, response_use);
                        value.replay_source_response_fingerprint = source_response_fingerprint;
                        value.replay_source_response_value_fingerprint = source_response_value_fingerprint;
                        value.authorization_fingerprint = fingerprintTreatyAuthorization(value);
                        return value;
                    }

                    /// Construct a replay treaty authorization from a certificate and recorded source response.
                    pub fn forCertificateWithReplaySource(certificate: Treaty.Certificate, response: ResponseEnvelope, response_use: ResponseUse, source_response_fingerprint: u64, source_response_value_fingerprint: u64) Error!@This() {
                        if (response_use != .replayed and response_use != .deterministic_replay) return error.ProgramContractViolation;
                        if (source_response_fingerprint == 0) return error.ProgramContractViolation;
                        if (certificate.obligation_fingerprint == null and source_response_fingerprint == response.fingerprint) return error.ProgramContractViolation;
                        if (source_response_value_fingerprint == 0 or source_response_value_fingerprint != response.response_value_fingerprint) return error.ProgramContractViolation;
                        var value = try forCertificate(certificate, response, response_use);
                        value.replay_source_response_fingerprint = source_response_fingerprint;
                        value.replay_source_response_value_fingerprint = source_response_value_fingerprint;
                        value.authorization_fingerprint = fingerprintTreatyAuthorization(value);
                        return value;
                    }

                    /// Encode this treaty authorization into deterministic bytes.
                    pub fn encode(self: @This(), allocator: std.mem.Allocator) Error![]u8 {
                        return switch (self.format_version) {
                            2 => encodeV2(self, allocator),
                            3 => encodeV3(self, allocator),
                            exchange_treaty_authorization_fingerprint_version => encodeV4(self, allocator),
                            else => error.ProgramContractViolation,
                        };
                    }

                    fn encodeV4(self: @This(), allocator: std.mem.Allocator) Error![]u8 {
                        var writer = Writer.init(allocator);
                        errdefer writer.deinit();
                        try writer.writeBytes(treaty_authorization_magic);
                        try writer.writeU32(exchange_treaty_authorization_fingerprint_version);
                        try writer.writeU64(self.treaty_fingerprint);
                        try writer.writeU64(self.treaty_certificate_fingerprint);
                        try writer.writeU64(self.provider_fingerprint);
                        try writer.writeU64(self.provider_offer_fingerprint);
                        try writer.writeU64(self.capability_fingerprint);
                        try writeOptionalU64(&writer, self.attenuated_capability_fingerprint);
                        try writer.writeU64(self.capability_path_fingerprint);
                        try writeOptionalU64(&writer, self.capability_instance_fingerprint);
                        try writeOptionalU64(&writer, self.obligation_fingerprint);
                        try writer.writeU64(self.route_fingerprint);
                        try writer.writeU64(self.request_envelope_fingerprint);
                        try writer.writeU32(self.request_envelope_format_version);
                        try writer.writeU64(self.response_envelope_fingerprint);
                        try writeUsage(&writer, self.usage);
                        try writeResponseUse(&writer, self.response_use);
                        try writeResponseUse(&writer, self.replay_policy);
                        try writeBranchPolicy(&writer, self.branch_policy);
                        try writeOptionalU64(&writer, self.replay_source_response_fingerprint);
                        try writeOptionalU64(&writer, self.replay_source_response_value_fingerprint);
                        try writeOptionalU64(&writer, self.expected_obligation_transition_fingerprint);
                        try writer.writeU64(fingerprintTreatyAuthorization(self));
                        return writer.toOwnedSlice();
                    }

                    fn encodeV3(self: @This(), allocator: std.mem.Allocator) Error![]u8 {
                        if (self.request_envelope_format_version != exchange_request_format_version) return error.ProgramContractViolation;
                        var writer = Writer.init(allocator);
                        errdefer writer.deinit();
                        try writer.writeBytes(treaty_authorization_magic);
                        try writer.writeU32(3);
                        try writer.writeU64(self.treaty_fingerprint);
                        try writer.writeU64(self.treaty_certificate_fingerprint);
                        try writer.writeU64(self.provider_fingerprint);
                        try writer.writeU64(self.provider_offer_fingerprint);
                        try writer.writeU64(self.capability_fingerprint);
                        try writeOptionalU64(&writer, self.attenuated_capability_fingerprint);
                        try writer.writeU64(self.capability_path_fingerprint);
                        try writeOptionalU64(&writer, self.capability_instance_fingerprint);
                        try writeOptionalU64(&writer, self.obligation_fingerprint);
                        try writer.writeU64(self.route_fingerprint);
                        try writer.writeU64(self.request_envelope_fingerprint);
                        try writer.writeU64(self.response_envelope_fingerprint);
                        try writeUsage(&writer, self.usage);
                        try writeResponseUse(&writer, self.response_use);
                        try writeResponseUse(&writer, self.replay_policy);
                        try writeBranchPolicy(&writer, self.branch_policy);
                        try writeOptionalU64(&writer, self.replay_source_response_fingerprint);
                        try writeOptionalU64(&writer, self.replay_source_response_value_fingerprint);
                        try writeOptionalU64(&writer, self.expected_obligation_transition_fingerprint);
                        try writer.writeU64(fingerprintTreatyAuthorizationV3(self));
                        return writer.toOwnedSlice();
                    }

                    fn encodeV2(self: @This(), allocator: std.mem.Allocator) Error![]u8 {
                        if (self.provider_fingerprint != 0 or
                            self.capability_fingerprint != 0 or
                            self.capability_path_fingerprint != 0 or
                            self.request_envelope_fingerprint != 0)
                        {
                            return error.ProgramContractViolation;
                        }
                        var writer = Writer.init(allocator);
                        errdefer writer.deinit();
                        try writer.writeBytes(treaty_authorization_magic);
                        try writer.writeU32(2);
                        try writer.writeU64(self.treaty_fingerprint);
                        try writer.writeU64(self.treaty_certificate_fingerprint);
                        try writer.writeU64(self.provider_offer_fingerprint);
                        try writeOptionalU64(&writer, self.attenuated_capability_fingerprint);
                        try writeOptionalU64(&writer, self.capability_instance_fingerprint);
                        try writeOptionalU64(&writer, self.obligation_fingerprint);
                        try writer.writeU64(self.route_fingerprint);
                        try writer.writeU64(self.response_envelope_fingerprint);
                        try writeUsage(&writer, self.usage);
                        try writeResponseUse(&writer, self.response_use);
                        try writeResponseUse(&writer, self.replay_policy);
                        try writeBranchPolicy(&writer, self.branch_policy);
                        try writeOptionalU64(&writer, self.replay_source_response_fingerprint);
                        try writeOptionalU64(&writer, self.replay_source_response_value_fingerprint);
                        try writeOptionalU64(&writer, self.expected_obligation_transition_fingerprint);
                        try writer.writeU64(fingerprintTreatyAuthorizationV2(self));
                        return writer.toOwnedSlice();
                    }

                    /// Decode and validate treaty authorization bytes.
                    pub fn decode(bytes: []const u8) Error!@This() {
                        var reader = Reader.init(bytes);
                        try reader.expectBytes(treaty_authorization_magic);
                        const format_version = try reader.readU32();
                        if (format_version == 2) return decodeV2(&reader);
                        if (format_version == 3) return decodeV3(&reader);
                        if (format_version != exchange_treaty_authorization_fingerprint_version) return error.ProgramContractViolation;
                        return decodeV4(&reader);
                    }

                    fn decodeV4(reader: *Reader) Error!@This() {
                        const value = @This(){
                            .treaty_fingerprint = try reader.readU64(),
                            .treaty_certificate_fingerprint = try reader.readU64(),
                            .provider_fingerprint = try reader.readU64(),
                            .provider_offer_fingerprint = try reader.readU64(),
                            .capability_fingerprint = try reader.readU64(),
                            .attenuated_capability_fingerprint = try readOptionalU64(reader),
                            .capability_path_fingerprint = try reader.readU64(),
                            .capability_instance_fingerprint = try readOptionalU64(reader),
                            .obligation_fingerprint = try readOptionalU64(reader),
                            .route_fingerprint = try reader.readU64(),
                            .request_envelope_fingerprint = try reader.readU64(),
                            .request_envelope_format_version = try reader.readU32(),
                            .response_envelope_fingerprint = try reader.readU64(),
                            .usage = try readUsage(reader),
                            .response_use = try readResponseUse(reader),
                            .replay_policy = try readResponseUse(reader),
                            .branch_policy = try readBranchPolicy(reader),
                            .replay_source_response_fingerprint = try readOptionalU64(reader),
                            .replay_source_response_value_fingerprint = try readOptionalU64(reader),
                            .expected_obligation_transition_fingerprint = try readOptionalU64(reader),
                            .authorization_fingerprint = try reader.readU64(),
                        };
                        if (!reader.eof()) return error.ProgramContractViolation;
                        if (value.authorization_fingerprint != fingerprintTreatyAuthorization(value)) return error.ProgramContractViolation;
                        return value;
                    }

                    fn decodeV3(reader: *Reader) Error!@This() {
                        const value = @This(){
                            .treaty_fingerprint = try reader.readU64(),
                            .treaty_certificate_fingerprint = try reader.readU64(),
                            .provider_fingerprint = try reader.readU64(),
                            .provider_offer_fingerprint = try reader.readU64(),
                            .capability_fingerprint = try reader.readU64(),
                            .attenuated_capability_fingerprint = try readOptionalU64(reader),
                            .capability_path_fingerprint = try reader.readU64(),
                            .capability_instance_fingerprint = try readOptionalU64(reader),
                            .obligation_fingerprint = try readOptionalU64(reader),
                            .route_fingerprint = try reader.readU64(),
                            .request_envelope_fingerprint = try reader.readU64(),
                            .response_envelope_fingerprint = try reader.readU64(),
                            .usage = try readUsage(reader),
                            .response_use = try readResponseUse(reader),
                            .replay_policy = try readResponseUse(reader),
                            .branch_policy = try readBranchPolicy(reader),
                            .replay_source_response_fingerprint = try readOptionalU64(reader),
                            .replay_source_response_value_fingerprint = try readOptionalU64(reader),
                            .expected_obligation_transition_fingerprint = try readOptionalU64(reader),
                            .format_version = 3,
                            .authorization_fingerprint = try reader.readU64(),
                        };
                        if (!reader.eof()) return error.ProgramContractViolation;
                        if (value.authorization_fingerprint != fingerprintTreatyAuthorizationV3(value)) return error.ProgramContractViolation;
                        return value;
                    }

                    fn decodeV2(reader: *Reader) Error!@This() {
                        const value = @This(){
                            .treaty_fingerprint = try reader.readU64(),
                            .treaty_certificate_fingerprint = try reader.readU64(),
                            .provider_fingerprint = 0,
                            .provider_offer_fingerprint = try reader.readU64(),
                            .capability_fingerprint = 0,
                            .attenuated_capability_fingerprint = try readOptionalU64(reader),
                            .capability_path_fingerprint = 0,
                            .capability_instance_fingerprint = try readOptionalU64(reader),
                            .obligation_fingerprint = try readOptionalU64(reader),
                            .route_fingerprint = try reader.readU64(),
                            .request_envelope_fingerprint = 0,
                            .response_envelope_fingerprint = try reader.readU64(),
                            .usage = try readUsage(reader),
                            .response_use = try readResponseUse(reader),
                            .replay_policy = try readResponseUse(reader),
                            .branch_policy = try readBranchPolicy(reader),
                            .replay_source_response_fingerprint = try readOptionalU64(reader),
                            .replay_source_response_value_fingerprint = try readOptionalU64(reader),
                            .expected_obligation_transition_fingerprint = try readOptionalU64(reader),
                            .format_version = 2,
                            .authorization_fingerprint = try reader.readU64(),
                        };
                        if (!reader.eof()) return error.ProgramContractViolation;
                        if (value.authorization_fingerprint != fingerprintTreatyAuthorizationV2(value)) return error.ProgramContractViolation;
                        return value;
                    }
                };

                /// Release treaty-owned attenuation storage.
                pub fn deinit(self: *@This()) void {
                    if (self.attenuated_capability) |*capability| capability.deinit();
                    if (self.allocator) |allocator| {
                        allocator.free(self.morphism_offer_fingerprints);
                        freeStringList(allocator, self.provider_offer_tags);
                        allocator.free(self.expected_response_refs);
                        allocator.free(self.provider_response_refs);
                        allocator.free(self.certificate.dynamic_morphism_fingerprints);
                        allocator.free(self.certificate.residualization_fingerprints);
                    }
                    self.morphism_offer_fingerprints = &.{};
                    self.provider_offer_tags = &.{};
                    self.dynamic_morphism_fingerprints = &.{};
                    self.residualization_fingerprints = &.{};
                    self.expected_response_refs = &.{};
                    self.provider_response_refs = &.{};
                }

                /// Check the treaty certificate against the selected treaty.
                pub fn checkCertificate(self: @This()) Error!void {
                    try self.certificate.check();
                    if (self.fingerprint != fingerprintTreatyCore(self)) return error.ProgramContractViolation;
                    if (self.certificate.treaty_fingerprint != self.fingerprint) return error.ProgramContractViolation;
                    if (self.certificate.provider_fingerprint != self.provider_fingerprint) return error.ProgramContractViolation;
                    if (self.certificate.provider_offer_fingerprint != self.provider_offer_fingerprint) return error.ProgramContractViolation;
                    if (!stringListEqual(self.certificate.provider_offer_tags, self.provider_offer_tags)) return error.ProgramContractViolation;
                    if (self.certificate.capability_fingerprint != self.capability_fingerprint) return error.ProgramContractViolation;
                    if (self.certificate.request_envelope_fingerprint != self.request_envelope_fingerprint) return error.ProgramContractViolation;
                    if (self.certificate.request_envelope_format_version != self.request_envelope_format_version) return error.ProgramContractViolation;
                    if (self.certificate.request_fingerprint != self.request_fingerprint) return error.ProgramContractViolation;
                    if (self.certificate.manifest_fingerprint != self.manifest_fingerprint) return error.ProgramContractViolation;
                    if (self.certificate.attenuated_capability_fingerprint != if (self.attenuated_capability) |capability| capability.fingerprint else null) return error.ProgramContractViolation;
                    if (self.certificate.capability_path_fingerprint != self.capability_path_fingerprint) return error.ProgramContractViolation;
                    if (self.certificate.capability_instance_fingerprint != self.capability_instance_fingerprint) return error.ProgramContractViolation;
                    if (self.certificate.obligation_fingerprint != self.obligation_fingerprint) return error.ProgramContractViolation;
                    if (self.route.fingerprint != fingerprintRoute(self.route)) return error.ProgramContractViolation;
                    if (self.certificate.route_fingerprint != self.route.fingerprint) return error.ProgramContractViolation;
                    if (self.route.request_envelope_fingerprint != self.request_envelope_fingerprint) return error.ProgramContractViolation;
                    if (self.route.provider_fingerprint != self.provider_fingerprint) return error.ProgramContractViolation;
                    if (self.route.manifest_fingerprint != self.manifest_fingerprint) return error.ProgramContractViolation;
                    const expected_route_capability_fingerprint = if (self.attenuated_capability) |capability| capability.fingerprint else self.capability_fingerprint;
                    if (self.route.capability_fingerprint != expected_route_capability_fingerprint) return error.ProgramContractViolation;
                    if (self.route.capability_path_fingerprint != self.capability_path_fingerprint) return error.ProgramContractViolation;
                    if (!self.route.valid()) return error.ProgramContractViolation;
                    if (!u64ListEqual(self.certificate.morphism_offer_fingerprints, self.morphism_offer_fingerprints)) return error.ProgramContractViolation;
                    if (self.certificate.effect_session_spec_fingerprint != self.effect_session_spec_fingerprint) return error.ProgramContractViolation;
                    if (!u64ListEqual(self.certificate.dynamic_morphism_fingerprints, self.dynamic_morphism_fingerprints)) return error.ProgramContractViolation;
                    if (!u64ListEqual(self.certificate.residualization_fingerprints, self.residualization_fingerprints)) return error.ProgramContractViolation;
                    if (self.certificate.pipeline_fingerprint != self.pipeline_fingerprint) return error.ProgramContractViolation;
                    if (self.certificate.source_protocol_op_fingerprint != self.source_protocol_op_fingerprint) return error.ProgramContractViolation;
                    if (self.certificate.target_protocol_op_fingerprint != self.target_protocol_op_fingerprint) return error.ProgramContractViolation;
                    if (self.certificate.handling != self.handling) return error.ProgramContractViolation;
                    if (self.certificate.usage != self.usage) return error.ProgramContractViolation;
                    if (self.certificate.provider_usage != self.provider_usage) return error.ProgramContractViolation;
                    if (self.certificate.response_use != self.response_use) return error.ProgramContractViolation;
                    if (self.certificate.replay_policy != self.replay_policy) return error.ProgramContractViolation;
                    if (self.certificate.branch_policy != self.branch_policy) return error.ProgramContractViolation;
                    if (!responseKindSetsEqual(self.certificate.expected_response_kinds, self.expected_response_kinds)) return error.ProgramContractViolation;
                    if (!valueRefListEqual(self.certificate.expected_response_refs, self.expected_response_refs)) return error.ProgramContractViolation;
                    if (!valueRefListEqual(self.certificate.provider_response_refs, self.provider_response_refs)) return error.ProgramContractViolation;
                    if (self.certificate.journal_policy_fingerprint != self.journal_policy_fingerprint) return error.ProgramContractViolation;
                    if (self.certificate.require_treaty_bound_response_authorization != self.require_treaty_bound_response_authorization) return error.ProgramContractViolation;
                }
            };

            /// Deterministic capability grant authorizing a provider to answer request subsets.
            pub const Capability = struct {
                allocator: std.mem.Allocator,
                bytes: []u8,
                version: u32,
                fingerprint: u64,
                issuer_label: []u8,
                provider_fingerprint: u64,
                manifest_fingerprint: u64,
                allowed_request_kinds: RequestKindSet,
                allowed_program_labels: []const []const u8,
                allowed_plan_hashes: []const u64,
                allowed_operation_sites: []const usize,
                allowed_after_sites: []const usize,
                allowed_protocol_op_fingerprints: []const u64,
                allowed_requirement_labels: []const []const u8,
                allowed_op_names: []const []const u8,
                allowed_response_kinds: Policy.ResponseKindSet,
                allowed_response_refs: []lowering_api.ValueRef,
                allow_embedded_capsule_response_handling: bool,
                allow_capsule_restore: bool,
                max_request_bytes: usize,
                max_response_bytes: usize,
                max_payload_bytes: usize,
                max_capsule_image_bytes: usize,
                journal_policy_fingerprint: ?u64,
                expires_at_generation: ?u64,
                parent_capability_fingerprint: ?u64,
                attenuation_path_fingerprint: u64,

                /// Options used to encode a capability grant.
                pub const Options = struct {
                    issuer_label: []const u8,
                    provider_fingerprint: u64,
                    manifest_fingerprint: u64,
                    allowed_request_kinds: ?RequestKindSet = null,
                    allowed_program_labels: []const []const u8 = &.{},
                    allowed_plan_hashes: []const u64 = &.{},
                    allowed_operation_sites: []const usize = &.{},
                    allowed_after_sites: []const usize = &.{},
                    allowed_protocol_op_fingerprints: []const u64 = &.{},
                    allowed_requirement_labels: []const []const u8 = &.{},
                    allowed_op_names: []const []const u8 = &.{},
                    allowed_response_kinds: Policy.ResponseKindSet = .{},
                    allowed_response_refs: []const lowering_api.ValueRef = &.{},
                    allow_embedded_capsule_response_handling: bool = true,
                    allow_capsule_restore: bool = true,
                    max_request_bytes: usize = std.math.maxInt(usize),
                    max_response_bytes: usize = std.math.maxInt(usize),
                    max_payload_bytes: usize = std.math.maxInt(usize),
                    max_capsule_image_bytes: usize = std.math.maxInt(usize),
                    journal_policy_fingerprint: ?u64 = null,
                    expires_at_generation: ?u64 = null,
                    parent_capability_fingerprint: ?u64 = null,
                    attenuation_path_fingerprint: ?u64 = null,
                };

                /// Optional narrowing arguments for deterministic attenuation.
                pub const Attenuation = struct {
                    allowed_request_kinds: ?RequestKindSet = null,
                    allowed_program_labels: ?[]const []const u8 = null,
                    allowed_plan_hashes: ?[]const u64 = null,
                    allowed_operation_sites: ?[]const usize = null,
                    allowed_after_sites: ?[]const usize = null,
                    allowed_protocol_op_fingerprints: ?[]const u64 = null,
                    allowed_requirement_labels: ?[]const []const u8 = null,
                    allowed_op_names: ?[]const []const u8 = null,
                    allowed_response_kinds: ?Policy.ResponseKindSet = null,
                    allowed_response_refs: ?[]const lowering_api.ValueRef = null,
                    allow_embedded_capsule_response_handling: ?bool = null,
                    allow_capsule_restore: ?bool = null,
                    max_request_bytes: ?usize = null,
                    max_response_bytes: ?usize = null,
                    max_payload_bytes: ?usize = null,
                    max_capsule_image_bytes: ?usize = null,
                    journal_policy_fingerprint: ?u64 = null,
                    expires_at_generation: ?u64 = null,
                };

                /// Encode a capability grant into deterministic owned bytes.
                pub fn encode(allocator: std.mem.Allocator, options: Options) Error!@This() {
                    const grant = capabilityGrantFingerprint(options);
                    const path = options.attenuation_path_fingerprint orelse capabilityPathFingerprint(options.parent_capability_fingerprint, options.provider_fingerprint, 0, grant);
                    var writer = Writer.init(allocator);
                    errdefer writer.deinit();
                    try writeCapabilityPayload(&writer, options, path);
                    const payload = writer.bytes.items;
                    const fingerprint = exchangeFingerprint("ability.exchange.capability", exchange_capability_fingerprint_version, payload);
                    try writer.writeU64(fingerprint);
                    return capabilityFromOptions(allocator, try writer.toOwnedSlice(), fingerprint, options, path);
                }

                /// Decode and validate a capability grant image.
                pub fn decode(allocator: std.mem.Allocator, bytes: []const u8) Error!@This() {
                    const payload = try checkedPayload(bytes, "ability.exchange.capability", exchange_capability_fingerprint_version);
                    var reader = Reader.init(payload);
                    try reader.expectBytes(capability_magic);
                    const format = try reader.readU32();
                    if (format != exchange_capability_format_version) return error.ProgramContractViolation;
                    if (try reader.readU32() != exchange_capability_fingerprint_version) return error.ProgramContractViolation;
                    const version = try reader.readU32();
                    if (version != 1) return error.ProgramContractViolation;
                    const issuer = try allocator.dupe(u8, try reader.readLenBytes());
                    errdefer allocator.free(issuer);
                    const provider_fp = try reader.readU64();
                    const manifest_fp = try reader.readU64();
                    const request_kinds = try readRequestKindSet(&reader);
                    const program_labels = try readStringList(allocator, &reader);
                    errdefer freeStringList(allocator, program_labels);
                    const plan_hashes = try readU64List(allocator, &reader);
                    errdefer allocator.free(plan_hashes);
                    const operation_sites = try readUsizeList(allocator, &reader);
                    errdefer allocator.free(operation_sites);
                    const after_sites = try readUsizeList(allocator, &reader);
                    errdefer allocator.free(after_sites);
                    const protocol_ops = try readU64List(allocator, &reader);
                    errdefer allocator.free(protocol_ops);
                    const requirement_labels = try readStringList(allocator, &reader);
                    errdefer freeStringList(allocator, requirement_labels);
                    const op_names = try readStringList(allocator, &reader);
                    errdefer freeStringList(allocator, op_names);
                    const response_kinds = try readResponseKindSet(&reader);
                    const response_refs = try readValueRefList(allocator, &reader);
                    errdefer allocator.free(response_refs);
                    const allow_capsule_response = try reader.readBool();
                    const allow_restore = try reader.readBool();
                    const max_request = try reader.readUsize();
                    const max_response = try reader.readUsize();
                    const max_payload = try reader.readUsize();
                    const max_capsule = try reader.readUsize();
                    const journal_policy = try readOptionalU64(&reader);
                    const expires_at = try readOptionalU64(&reader);
                    const parent = try readOptionalU64(&reader);
                    const path = try reader.readU64();
                    if (!reader.eof()) return error.ProgramContractViolation;
                    const owned = try allocator.dupe(u8, bytes);
                    errdefer allocator.free(owned);
                    return .{
                        .allocator = allocator,
                        .bytes = owned,
                        .version = version,
                        .fingerprint = try checkedBytesFingerprint(bytes, "ability.exchange.capability", exchange_capability_fingerprint_version),
                        .issuer_label = issuer,
                        .provider_fingerprint = provider_fp,
                        .manifest_fingerprint = manifest_fp,
                        .allowed_request_kinds = request_kinds,
                        .allowed_program_labels = program_labels,
                        .allowed_plan_hashes = plan_hashes,
                        .allowed_operation_sites = operation_sites,
                        .allowed_after_sites = after_sites,
                        .allowed_protocol_op_fingerprints = protocol_ops,
                        .allowed_requirement_labels = requirement_labels,
                        .allowed_op_names = op_names,
                        .allowed_response_kinds = response_kinds,
                        .allowed_response_refs = response_refs,
                        .allow_embedded_capsule_response_handling = allow_capsule_response,
                        .allow_capsule_restore = allow_restore,
                        .max_request_bytes = max_request,
                        .max_response_bytes = max_response,
                        .max_payload_bytes = max_payload,
                        .max_capsule_image_bytes = max_capsule,
                        .journal_policy_fingerprint = journal_policy,
                        .expires_at_generation = expires_at,
                        .parent_capability_fingerprint = parent,
                        .attenuation_path_fingerprint = path,
                    };
                }

                /// Release capability-owned storage.
                pub fn deinit(self: *@This()) void {
                    self.allocator.free(self.bytes);
                    self.allocator.free(self.issuer_label);
                    freeStringList(self.allocator, self.allowed_program_labels);
                    self.allocator.free(self.allowed_plan_hashes);
                    self.allocator.free(self.allowed_operation_sites);
                    self.allocator.free(self.allowed_after_sites);
                    self.allocator.free(self.allowed_protocol_op_fingerprints);
                    freeStringList(self.allocator, self.allowed_requirement_labels);
                    freeStringList(self.allocator, self.allowed_op_names);
                    self.allocator.free(self.allowed_response_refs);
                    self.bytes = &.{};
                }

                /// Canonical evidence reference for this capability grant.
                pub fn evidenceRef(self: @This()) Evidence.Ref {
                    return Evidence.refForCapability(self);
                }

                /// Return a child capability whose authority is a subset of this capability.
                pub fn attenuate(self: @This(), allocator: std.mem.Allocator, args: Attenuation) Error!@This() {
                    if (!capabilityFieldsBoundToBytes(self)) return error.ProgramContractViolation;
                    const request_kinds = args.allowed_request_kinds orelse if (args.allowed_operation_sites != null or args.allowed_after_sites != null) RequestKindSet{
                        .operation = args.allowed_operation_sites != null,
                        .after = args.allowed_after_sites != null,
                    } else self.allowed_request_kinds;
                    if (!request_kinds.subsetOf(self.allowed_request_kinds)) return error.ProgramContractViolation;
                    if (args.allowed_response_kinds) |value| if (!responseKindSetSubset(value, self.allowed_response_kinds)) return error.ProgramContractViolation;
                    if (args.allowed_program_labels) |value| if (!stringListSubset(value, self.allowed_program_labels)) return error.ProgramContractViolation;
                    if (args.allowed_plan_hashes) |value| if (!u64ListSubset(value, self.allowed_plan_hashes)) return error.ProgramContractViolation;
                    if (args.allowed_operation_sites) |value| if (!usizeListSubset(value, self.allowed_operation_sites)) return error.ProgramContractViolation;
                    if (args.allowed_after_sites) |value| if (!usizeListSubset(value, self.allowed_after_sites)) return error.ProgramContractViolation;
                    if (args.allowed_protocol_op_fingerprints) |value| if (!u64ListSubset(value, self.allowed_protocol_op_fingerprints)) return error.ProgramContractViolation;
                    if (args.allowed_requirement_labels) |value| if (!stringListSubset(value, self.allowed_requirement_labels)) return error.ProgramContractViolation;
                    if (args.allowed_op_names) |value| if (!stringListSubset(value, self.allowed_op_names)) return error.ProgramContractViolation;
                    if (args.allowed_response_refs) |value| if (!valueRefListSubset(value, self.allowed_response_refs)) return error.ProgramContractViolation;
                    if ((args.allow_embedded_capsule_response_handling orelse self.allow_embedded_capsule_response_handling) and !self.allow_embedded_capsule_response_handling) return error.ProgramContractViolation;
                    if ((args.allow_capsule_restore orelse self.allow_capsule_restore) and !self.allow_capsule_restore) return error.ProgramContractViolation;
                    const journal_policy = args.journal_policy_fingerprint orelse self.journal_policy_fingerprint;
                    if (args.journal_policy_fingerprint) |child_policy| {
                        if (self.journal_policy_fingerprint) |parent_policy| {
                            if (child_policy != parent_policy) return error.ProgramContractViolation;
                        }
                    }
                    if (args.expires_at_generation) |child_expiry| {
                        if (self.expires_at_generation) |parent_expiry| {
                            if (child_expiry > parent_expiry) return error.ProgramContractViolation;
                        }
                    }
                    const max_request = args.max_request_bytes orelse self.max_request_bytes;
                    const max_response = args.max_response_bytes orelse self.max_response_bytes;
                    const max_payload = args.max_payload_bytes orelse self.max_payload_bytes;
                    const max_capsule = args.max_capsule_image_bytes orelse self.max_capsule_image_bytes;
                    if (max_request > self.max_request_bytes or max_response > self.max_response_bytes or max_payload > self.max_payload_bytes or max_capsule > self.max_capsule_image_bytes) return error.ProgramContractViolation;
                    var options: Options = .{
                        .issuer_label = self.issuer_label,
                        .provider_fingerprint = self.provider_fingerprint,
                        .manifest_fingerprint = self.manifest_fingerprint,
                        .allowed_request_kinds = request_kinds,
                        .allowed_program_labels = args.allowed_program_labels orelse self.allowed_program_labels,
                        .allowed_plan_hashes = args.allowed_plan_hashes orelse self.allowed_plan_hashes,
                        .allowed_operation_sites = args.allowed_operation_sites orelse self.allowed_operation_sites,
                        .allowed_after_sites = args.allowed_after_sites orelse self.allowed_after_sites,
                        .allowed_protocol_op_fingerprints = args.allowed_protocol_op_fingerprints orelse self.allowed_protocol_op_fingerprints,
                        .allowed_requirement_labels = args.allowed_requirement_labels orelse self.allowed_requirement_labels,
                        .allowed_op_names = args.allowed_op_names orelse self.allowed_op_names,
                        .allowed_response_kinds = args.allowed_response_kinds orelse self.allowed_response_kinds,
                        .allowed_response_refs = args.allowed_response_refs orelse self.allowed_response_refs,
                        .allow_embedded_capsule_response_handling = args.allow_embedded_capsule_response_handling orelse self.allow_embedded_capsule_response_handling,
                        .allow_capsule_restore = args.allow_capsule_restore orelse self.allow_capsule_restore,
                        .max_request_bytes = max_request,
                        .max_response_bytes = max_response,
                        .max_payload_bytes = max_payload,
                        .max_capsule_image_bytes = max_capsule,
                        .journal_policy_fingerprint = journal_policy,
                        .expires_at_generation = args.expires_at_generation orelse self.expires_at_generation,
                        .parent_capability_fingerprint = self.fingerprint,
                    };
                    options.attenuation_path_fingerprint = capabilityPathFingerprint(
                        self.fingerprint,
                        self.provider_fingerprint,
                        self.attenuation_path_fingerprint,
                        capabilityGrantFingerprint(options),
                    );
                    return Capability.encode(allocator, options);
                }

                /// Validate this capability against a request/provider pair.
                pub fn allowsRequest(self: @This(), request: RequestEnvelope, provider: ProviderManifest) ValidationReport {
                    return validateRequestCapability(self, provider, request);
                }
            };

            /// Capability authorization sidecar. It is deliberately outside response bytes/fingerprints.
            pub const Authorization = struct {
                provider_fingerprint: u64,
                capability_fingerprint: u64,
                capability_path_fingerprint: u64,
                route_fingerprint: u64,
                request_envelope_fingerprint: u64,
                response_envelope_fingerprint: u64,
                authorization_fingerprint: u64,

                /// Canonical evidence reference for this authorization sidecar.
                pub fn evidenceRef(self: @This()) Evidence.Ref {
                    return Evidence.refForAuthorization(self);
                }

                /// Construct an authorization witness for a routed response.
                pub fn forResponse(route: Route, response: ResponseEnvelope) Error!@This() {
                    if (route.request_envelope_fingerprint != response.request_envelope_fingerprint) return error.ProgramContractViolation;
                    var value = Authorization{
                        .provider_fingerprint = route.provider_fingerprint,
                        .capability_fingerprint = route.capability_fingerprint,
                        .capability_path_fingerprint = route.capability_path_fingerprint,
                        .route_fingerprint = route.fingerprint,
                        .request_envelope_fingerprint = route.request_envelope_fingerprint,
                        .response_envelope_fingerprint = response.fingerprint,
                        .authorization_fingerprint = 0,
                    };
                    value.authorization_fingerprint = fingerprintAuthorization(value);
                    return value;
                }

                /// Encode this authorization witness into deterministic bytes.
                pub fn encode(self: @This(), allocator: std.mem.Allocator) Error![]u8 {
                    var writer = Writer.init(allocator);
                    errdefer writer.deinit();
                    try writer.writeBytes(authorization_magic);
                    try writer.writeU32(exchange_authorization_fingerprint_version);
                    try writer.writeU64(self.provider_fingerprint);
                    try writer.writeU64(self.capability_fingerprint);
                    try writer.writeU64(self.capability_path_fingerprint);
                    try writer.writeU64(self.route_fingerprint);
                    try writer.writeU64(self.request_envelope_fingerprint);
                    try writer.writeU64(self.response_envelope_fingerprint);
                    try writer.writeU64(fingerprintAuthorization(self));
                    return writer.toOwnedSlice();
                }

                /// Decode and validate deterministic authorization bytes.
                pub fn decode(bytes: []const u8) Error!@This() {
                    var reader = Reader.init(bytes);
                    try reader.expectBytes(authorization_magic);
                    if (try reader.readU32() != exchange_authorization_fingerprint_version) return error.ProgramContractViolation;
                    const value = Authorization{
                        .provider_fingerprint = try reader.readU64(),
                        .capability_fingerprint = try reader.readU64(),
                        .capability_path_fingerprint = try reader.readU64(),
                        .route_fingerprint = try reader.readU64(),
                        .request_envelope_fingerprint = try reader.readU64(),
                        .response_envelope_fingerprint = try reader.readU64(),
                        .authorization_fingerprint = try reader.readU64(),
                    };
                    if (!reader.eof()) return error.ProgramContractViolation;
                    if (value.authorization_fingerprint != fingerprintAuthorization(value)) return error.ProgramContractViolation;
                    return value;
                }
            };

            /// Deterministic result of matching a request to provider plus capability.
            pub const Route = struct {
                fingerprint: u64,
                request_envelope_fingerprint: u64,
                provider_fingerprint: u64,
                capability_fingerprint: u64,
                capability_path_fingerprint: u64,
                manifest_fingerprint: u64,
                request_kind: RequestKind,
                site_index: usize,
                site_fingerprint: u64,
                allowed_response_kinds: Policy.ResponseKindSet,
                max_response_bytes: usize,
                max_payload_bytes: usize,
                capsule_restore_allowed: bool,
                blockers: ValidationReport,

                /// Build a route witness from request, provider, capability, and policy.
                pub fn from(request: RequestEnvelope, provider: ProviderManifest, capability: Capability, policy: Policy) @This() {
                    var blockers = validateRequestCapability(capability, provider, request);
                    blockers.merge(validatePolicyRequestScope(policy, request));
                    const allowed_response_kinds = allowedResponseKindsForRequest(request, provider, capability, policy);
                    addResponseViabilityBlockers(&blockers, request, allowed_response_kinds, capability.allowed_response_refs);
                    if (!policyProviderAllowed(policy, provider.provider_fingerprint)) blockers.add(.provider_not_allowed);
                    if (!policyCapabilityAllowed(policy, capability.fingerprint)) blockers.add(.capability_not_allowed);
                    var route = Route{
                        .fingerprint = 0,
                        .request_envelope_fingerprint = request.fingerprint,
                        .provider_fingerprint = provider.provider_fingerprint,
                        .capability_fingerprint = capability.fingerprint,
                        .capability_path_fingerprint = capability.attenuation_path_fingerprint,
                        .manifest_fingerprint = request.manifest_fingerprint,
                        .request_kind = request.kind,
                        .site_index = request.site_index,
                        .site_fingerprint = request.site_fingerprint,
                        .allowed_response_kinds = allowed_response_kinds,
                        .max_response_bytes = @min(@min(provider.max_response_envelope_bytes, capability.max_response_bytes), policy.max_envelope_bytes),
                        .max_payload_bytes = if (policy.allow_response_value_images) @min(capability.max_payload_bytes, policy.max_payload_bytes) else 0,
                        .capsule_restore_allowed = capability.allow_capsule_restore and provider.accepts_capsule_restore and policy.allow_capsule_restore,
                        .blockers = blockers,
                    };
                    route.fingerprint = fingerprintRoute(route);
                    return route;
                }

                /// Return true when this route has no blockers.
                pub fn valid(self: @This()) bool {
                    return self.blockers.allowed();
                }

                /// Canonical evidence reference for this route witness.
                pub fn evidenceRef(self: @This()) Evidence.Ref {
                    return Evidence.refForRoute(self);
                }
            };

            /// Host-owned deterministic route planner over provider/capability catalogs.
            pub const Router = struct {
                providers: []const ProviderManifest,
                capabilities: []const Capability,
                policy: Policy = .{},

                /// Router planning outcome.
                pub const Status = enum {
                    no_route,
                    one_route,
                    ambiguous_routes,
                    blocked_routes,
                };

                /// Route planning report.
                pub const Plan = struct {
                    status: Status,
                    route: ?Route = null,
                    blocked: ValidationReport = .{},
                    candidate_count: usize = 0,
                    blocked_count: usize = 0,
                };

                /// Plan a deterministic route for the request.
                pub fn plan(self: @This(), request: RequestEnvelope) Plan {
                    return self.planWithPolicy(request, self.policy);
                }

                /// Plan a deterministic route while also applying caller-supplied policy restrictions.
                pub fn planWithPolicy(self: @This(), request: RequestEnvelope, policy: Policy) Plan {
                    var first_valid: ?Route = null;
                    var first_blocked: ?Route = null;
                    var blocked_report: ValidationReport = .{};
                    var valid_count: usize = 0;
                    var blocked_count: usize = 0;
                    for (self.providers) |provider| {
                        capabilities_loop: for (self.capabilities) |capability| {
                            if (capability.provider_fingerprint != provider.provider_fingerprint) continue :capabilities_loop;
                            var route = Route.from(request, provider, capability, self.policy);
                            const caller_route = Route.from(request, provider, capability, policy);
                            route.blockers.merge(caller_route.blockers);
                            route.allowed_response_kinds = responseKindSetIntersection(route.allowed_response_kinds, caller_route.allowed_response_kinds);
                            route.max_response_bytes = @min(route.max_response_bytes, caller_route.max_response_bytes);
                            route.max_payload_bytes = @min(route.max_payload_bytes, caller_route.max_payload_bytes);
                            route.capsule_restore_allowed = route.capsule_restore_allowed and caller_route.capsule_restore_allowed;
                            if (!requestAcceptsAnyResponseKind(request, route.allowed_response_kinds)) route.blockers.add(.response_kind);
                            route.fingerprint = fingerprintRoute(route);
                            if (route.valid()) {
                                valid_count += 1;
                                if (first_valid == null) first_valid = route;
                            } else {
                                blocked_count += 1;
                                blocked_report.merge(route.blockers);
                                if (first_blocked == null) first_blocked = route;
                            }
                        }
                    }
                    if (valid_count == 1) return .{ .status = .one_route, .route = first_valid, .candidate_count = valid_count, .blocked_count = blocked_count };
                    if (valid_count > 1) {
                        var blocked: ValidationReport = .{};
                        blocked.add(.ambiguous_route);
                        return .{ .status = .ambiguous_routes, .route = first_valid, .blocked = blocked, .candidate_count = valid_count, .blocked_count = blocked_count };
                    }
                    if (blocked_count > 0) return .{ .status = .blocked_routes, .route = first_blocked, .blocked = blocked_report, .blocked_count = blocked_count };
                    var blocked: ValidationReport = .{};
                    blocked.add(.no_route);
                    return .{ .status = .no_route, .blocked = blocked };
                }

                /// Look up a capability by fingerprint.
                pub fn capabilityByFingerprint(self: @This(), fingerprint: u64) ?*const Capability {
                    for (self.capabilities) |*capability| if (capability.fingerprint == fingerprint) return capability;
                    return null;
                }
            };

            /// Pure Effect Treaty resolver over host-owned catalogs.
            pub const TreatyResolver = struct {
                /// Resolver inputs. The resolver never performs IO or calls providers.
                pub const Inputs = struct {
                    allocator: std.mem.Allocator,
                    request: RequestEnvelope,
                    manifest: Manifest,
                    provider_manifests: []const ProviderManifest = &.{},
                    provider_offers: []const ProviderOffer = &.{},
                    capabilities: []const Capability = &.{},
                    capability_instances: []const CapabilityInstance = &.{},
                    morphism_offers: []const MorphismOffer = &.{},
                    treaty_request: ?TreatyRequest = null,
                    treaty_policy: Treaty.Policy = .{},
                    route_policy: Policy = .{},
                    effect_session_spec: ?EffectSessionSpec = null,
                    obligation: ?Obligation = null,
                    live_capability_instance_fingerprint: ?u64 = null,
                };

                /// Treaty resolver status.
                pub const Status = enum {
                    treaty,
                    no_treaty,
                    ambiguous_treaties,
                    blocked,
                };

                /// Treaty resolver output.
                pub const Result = struct {
                    status: Status,
                    treaty: ?Treaty = null,
                    blockers: Treaty.BlockerList = .{},
                    candidate_count: usize = 0,
                    blocked_count: usize = 0,

                    /// Release owned treaty storage, if any.
                    pub fn deinit(self: *@This()) void {
                        if (self.treaty) |*value| value.deinit();
                    }
                };

                /// Resolve a treaty from request/catalog/policy inputs.
                pub fn resolve(inputs: Inputs) Error!TreatyResolver.Result {
                    inputs.request.validate() catch |err| switch (err) {
                        error.ProgramContractViolation => {
                            var blockers: Treaty.BlockerList = .{ .request_format_version = inputs.request.request_format_version };
                            blockers.addTag(.malformed_request, inputs.request.fingerprint, "request envelope fields are not bound to request bytes");
                            return .{ .status = .blocked, .blockers = blockers, .blocked_count = 1 };
                        },
                        else => return err,
                    };
                    const request_value = inputs.treaty_request orelse TreatyRequest.fromRequest(inputs.request);
                    if (request_value.request_envelope_fingerprint != inputs.request.fingerprint or
                        request_value.exchange_manifest_fingerprint != inputs.request.manifest_fingerprint or
                        request_value.request_kind != inputs.request.kind or
                        request_value.request_site_fingerprint != inputs.request.site_fingerprint or
                        request_value.protocol_op_fingerprint != requestProtocolOperationFingerprint(inputs.request))
                    {
                        var blockers: Treaty.BlockerList = .{ .request_format_version = inputs.request.request_format_version };
                        blockers.addTag(.malformed_treaty_request, inputs.request.fingerprint, "treaty request does not match request envelope");
                        return .{ .status = .blocked, .blockers = blockers };
                    }
                    if (inputs.manifest.fingerprint != inputs.request.manifest_fingerprint) {
                        var blockers: Treaty.BlockerList = .{ .request_format_version = inputs.request.request_format_version };
                        blockers.addTag(.foreign_manifest, inputs.request.fingerprint, "request envelope cites a different exchange manifest");
                        return .{ .status = .blocked, .blockers = blockers };
                    }
                    if (inputs.request.bytes.len > inputs.treaty_policy.max_envelope_bytes or
                        inputs.request.bytes.len > request_value.max_request_bytes)
                    {
                        var blockers: Treaty.BlockerList = .{ .request_format_version = inputs.request.request_format_version };
                        blockers.addTag(.envelope_too_large, inputs.request.fingerprint, "request envelope exceeds treaty byte policy");
                        return .{ .status = .blocked, .blockers = blockers };
                    }
                    if (inputs.request.capsule_image) |image| {
                        if (inputs.treaty_policy.disallow_capsule_export or image.len > inputs.treaty_policy.max_capsule_bytes or request_value.capsule_policy == .forbidden) {
                            var blockers: Treaty.BlockerList = .{ .request_format_version = inputs.request.request_format_version };
                            blockers.addTag(.capsule_export_disallowed, inputs.request.fingerprint, "capsule export is disallowed by treaty policy");
                            return .{ .status = .blocked, .blockers = blockers };
                        }
                    } else if (inputs.treaty_policy.require_capsule_embedding or request_value.capsule_policy == .required) {
                        var blockers: Treaty.BlockerList = .{ .request_format_version = inputs.request.request_format_version };
                        blockers.addTag(.capsule_export_disallowed, inputs.request.fingerprint, "treaty policy requires an embedded capsule");
                        return .{ .status = .blocked, .blockers = blockers };
                    }

                    var first_treaty: ?Treaty = null;
                    errdefer if (first_treaty) |*treaty| treaty.deinit();
                    var valid_count: usize = 0;
                    var blocked_count: usize = 0;
                    var ambiguous_best = false;
                    var blockers: Treaty.BlockerList = .{ .request_format_version = inputs.request.request_format_version };
                    if (inputs.treaty_policy.allow_direct_handling and request_value.allow_provider_fallback) {
                        try scanDirectTreaties(inputs, request_value, &first_treaty, &valid_count, &blocked_count, &ambiguous_best, &blockers);
                    }
                    if (inputs.treaty_policy.allow_morphism_adaptation) {
                        try scanMorphismTreaties(inputs, request_value, &first_treaty, &valid_count, &blocked_count, &ambiguous_best, &blockers);
                    }
                    if (valid_count == 1 and first_treaty != null) return .{ .status = .treaty, .treaty = first_treaty, .candidate_count = valid_count, .blocked_count = blocked_count };
                    if (valid_count > 1) {
                        if (treatyEffectiveAmbiguityPolicy(inputs.treaty_policy, request_value) != .reject_ambiguous and !ambiguous_best and first_treaty != null) {
                            return .{ .status = .treaty, .treaty = first_treaty, .candidate_count = valid_count, .blocked_count = blocked_count };
                        }
                        if (first_treaty) |*value| value.deinit();
                        blockers.addTag(.ambiguous_provider, inputs.request.fingerprint, "multiple treaty candidates remain under the ambiguity policy");
                        return .{ .status = .ambiguous_treaties, .blockers = blockers, .candidate_count = valid_count, .blocked_count = blocked_count };
                    }
                    if (blocked_count != 0) return .{ .status = .blocked, .blockers = blockers, .blocked_count = blocked_count };
                    blockers.addTag(.no_provider_offer, inputs.request.fingerprint, "no provider offer supports the request");
                    return .{ .status = .no_treaty, .blockers = blockers };
                }
            };

            /// Optional linear-session metadata carried by durable request envelopes.
            pub const RequestUsageMetadata = struct {
                effect_session_spec_fingerprint: ?u64 = null,
                capability_instance_fingerprint: ?u64 = null,
                obligation_fingerprint: ?u64 = null,
                usage: Usage = .copyable,
                branch_id: u64 = 0,
                branch_policy: BranchPolicy = .unrestricted,
                replay_policy: ResponseUse = .fresh,
                ephemeral: bool = false,
                cancelable: bool = false,
            };

            /// Options used while producing request envelopes.
            pub const RequestOptions = struct {
                capsule: ?Session.Capsule.Image = null,
                journal: ?*Session.Journal = null,
                journal_branch_id: ?[]const u8 = null,
                usage_metadata: ?RequestUsageMetadata = null,
            };

            /// Canonical typed request envelope for a yielded operation or after hook.
            pub const RequestEnvelope = struct {
                allocator: std.mem.Allocator,
                bytes: []u8,
                fingerprint: u64,
                request_format_version: u32 = exchange_request_format_version,
                request_fingerprint_version: u32 = exchange_request_fingerprint_version,
                manifest_fingerprint: u64,
                program_label: []const u8,
                plan_label: []const u8,
                plan_hash: u64,
                kind: RequestKind,
                request_fingerprint: u64,
                trace_fingerprint: u64,
                turn_index: usize,
                site_index: usize,
                site_fingerprint: u64,
                semantic_label: ?[]const u8,
                name: []const u8,
                mode: plan_types.ControlMode,
                value_ref: lowering_api.ValueRef,
                value_image: []u8,
                value_fingerprint: u64,
                expected_resume_ref: ?lowering_api.ValueRef,
                expected_return_ref: ?lowering_api.ValueRef,
                expected_after_ref: ?lowering_api.ValueRef,
                result_ref: lowering_api.ValueRef,
                capsule_image: ?[]u8 = null,
                capsule_image_fingerprint: ?u64 = null,
                journal_branch_id: ?[]const u8 = null,
                usage_metadata: ?RequestUsageMetadata = null,

                /// Encode an operation request yielded by Program.Session.
                pub fn fromRequest(allocator: std.mem.Allocator, request: Session.Request, options: RequestOptions) Error!@This() {
                    const trace = request.trace();
                    const value_image = try encodeRequestValueImage(allocator, request);
                    defer allocator.free(value_image);
                    const manifest_image = try manifestFingerprintForCurrentProgram(allocator);
                    var envelope = try encodeRequestEnvelope(allocator, .{
                        .kind = .operation,
                        .manifest_fingerprint = manifest_image,
                        .request_fingerprint = trace.fingerprint,
                        .trace_fingerprint = trace.fingerprint,
                        .turn_index = trace.turn_index,
                        .site_index = trace.operation_site_index,
                        .site_fingerprint = trace.operation_site_fingerprint,
                        .semantic_label = trace.semantic_label,
                        .name = trace.op_name,
                        .mode = trace.mode,
                        .value_ref = trace.payload_ref,
                        .value_image = value_image,
                        .value_fingerprint = trace.payload_value_fingerprint,
                        .expected_resume_ref = if (trace.mode == .abort) null else trace.resume_ref,
                        .expected_return_ref = if (trace.mode == .transform) null else trace.result_ref,
                        .expected_after_ref = null,
                        .result_ref = trace.result_ref,
                        .capsule = options.capsule,
                        .journal_branch_id = options.journal_branch_id,
                        .usage_metadata = options.usage_metadata,
                    });
                    errdefer envelope.deinit();
                    try envelope.validate();
                    if (options.journal) |journal| {
                        const start_len = journal.entries.items.len;
                        errdefer journal.truncateEntries(start_len);
                        try journal.appendRequest(.{ .operation = trace });
                        if (options.capsule) |capsule| try journal.appendCapsuleImage(capsule);
                    }
                    return envelope;
                }

                /// Encode an after-continuation request yielded by Program.Session.
                pub fn fromAfter(allocator: std.mem.Allocator, request: Session.AfterRequest, options: RequestOptions) Error!@This() {
                    const trace = request.trace();
                    const value_image = try encodeAfterValueImage(allocator, request);
                    defer allocator.free(value_image);
                    const manifest_image = try manifestFingerprintForCurrentProgram(allocator);
                    var envelope = try encodeRequestEnvelope(allocator, .{
                        .kind = .after,
                        .manifest_fingerprint = manifest_image,
                        .request_fingerprint = trace.fingerprint,
                        .trace_fingerprint = trace.fingerprint,
                        .turn_index = trace.turn_index,
                        .site_index = trace.after_site_index,
                        .site_fingerprint = trace.after_site_fingerprint,
                        .semantic_label = trace.semantic_label,
                        .name = trace.original_op_name,
                        .mode = .transform,
                        .value_ref = trace.current_value_ref,
                        .value_image = value_image,
                        .value_fingerprint = trace.current_value_fingerprint,
                        .expected_resume_ref = null,
                        .expected_return_ref = null,
                        .expected_after_ref = trace.expected_output_ref,
                        .result_ref = trace.result_ref,
                        .capsule = options.capsule,
                        .journal_branch_id = options.journal_branch_id,
                        .usage_metadata = options.usage_metadata,
                    });
                    errdefer envelope.deinit();
                    try envelope.validate();
                    if (options.journal) |journal| {
                        const start_len = journal.entries.items.len;
                        errdefer journal.truncateEntries(start_len);
                        try journal.appendRequest(.{ .after = trace });
                        if (options.capsule) |capsule| try journal.appendCapsuleImage(capsule);
                    }
                    return envelope;
                }

                /// Decode and validate a request envelope for this Program.
                pub fn decode(allocator: std.mem.Allocator, bytes: []const u8) Error!@This() {
                    return decodeWithPolicy(allocator, bytes, .{});
                }

                /// Decode and validate a request envelope after applying policy limits before payload copies.
                pub fn decodeWithPolicy(allocator: std.mem.Allocator, bytes: []const u8, policy: Policy) Error!@This() {
                    if (bytes.len > policy.max_envelope_bytes) return error.ProgramContractViolation;
                    const payload = try checkedRequestPayload(bytes);
                    var reader = Reader.init(payload);
                    try reader.expectBytes(request_magic);
                    const decoded_request_format_version = try reader.readU32();
                    const decoded_request_fingerprint_version = try reader.readU32();
                    if (!supportedRequestEnvelopeVersions(decoded_request_format_version, decoded_request_fingerprint_version)) return error.ProgramContractViolation;
                    const manifest_fingerprint = try reader.readU64();
                    var envelope_owned = false;
                    const program_label_owned = try dupeExpectedString(allocator, &reader, label);
                    errdefer if (!envelope_owned) allocator.free(program_label_owned);
                    const plan = try dupeExpectedString(allocator, &reader, body_compiled_plan.label);
                    errdefer if (!envelope_owned) allocator.free(plan);
                    const decoded_plan_hash = try reader.readU64();
                    if (decoded_plan_hash != body_compiled_plan_hash) return error.ProgramContractViolation;
                    const kind_value = try readRequestKind(&reader);
                    const request_fingerprint = try reader.readU64();
                    const trace_fingerprint = try reader.readU64();
                    const turn_index = try reader.readUsize();
                    const site_index = try reader.readUsize();
                    const site_fingerprint = try reader.readU64();
                    switch (kind_value) {
                        .operation => if (!Policy.policyAllowsSite(policy.allowed_operation_sites, site_index)) return error.ProgramContractViolation,
                        .after => if (!Policy.policyAllowsSite(policy.allowed_after_sites, site_index)) return error.ProgramContractViolation,
                    }
                    const semantic_label = try readOptionalOwnedBytes(allocator, &reader);
                    errdefer if (!envelope_owned) if (semantic_label) |value| allocator.free(value);
                    const name_value = try allocator.dupe(u8, try reader.readLenBytes());
                    errdefer if (!envelope_owned) allocator.free(name_value);
                    const mode = try readExchangeControlMode(&reader);
                    const value_ref = try readExchangeValueRef(&reader);
                    const value_fingerprint = try reader.readU64();
                    const value_image_slice = try reader.readLenBytes();
                    if (value_image_slice.len > policy.max_payload_bytes) return error.ProgramContractViolation;
                    const value_image = try allocator.dupe(u8, value_image_slice);
                    errdefer if (!envelope_owned) allocator.free(value_image);
                    const expected_resume_ref = try readOptionalValueRef(&reader);
                    const expected_return_ref = try readOptionalValueRef(&reader);
                    const expected_after_ref = try readOptionalValueRef(&reader);
                    const result_ref = try readExchangeValueRef(&reader);
                    const capsule_image = if (try reader.readBool()) blk: {
                        if (!policy.allow_capsules) return error.ProgramContractViolation;
                        const capsule_slice = try reader.readLenBytes();
                        const capsule_limit = policy.max_capsule_image_bytes orelse policy.max_payload_bytes;
                        if (capsule_slice.len > capsule_limit) return error.ProgramContractViolation;
                        const capsule_bytes = try allocator.dupe(u8, capsule_slice);
                        errdefer if (!envelope_owned) allocator.free(capsule_bytes);
                        const fingerprint = Session.capsuleImageFingerprint(capsule_bytes);
                        const encoded_fingerprint = try reader.readU64();
                        if (fingerprint != encoded_fingerprint) return error.ProgramContractViolation;
                        break :blk capsule_bytes;
                    } else null;
                    errdefer if (!envelope_owned) if (capsule_image) |image| allocator.free(image);
                    const capsule_fingerprint = if (capsule_image != null) Session.capsuleImageFingerprint(capsule_image.?) else null;
                    const branch_id = if (decoded_request_format_version == 1 and reader.eof())
                        null
                    else
                        try readOptionalOwnedBytes(allocator, &reader);
                    errdefer if (!envelope_owned) if (branch_id) |value| allocator.free(value);
                    const usage_metadata = if (decoded_request_format_version >= 3)
                        try readRequestUsageMetadata(&reader)
                    else
                        null;
                    if (!reader.eof()) return error.ProgramContractViolation;
                    const owned = allocator.dupe(u8, bytes) catch |err| return mapProgramRunError(Error, err);
                    errdefer if (!envelope_owned) allocator.free(owned);
                    var envelope = RequestEnvelope{
                        .allocator = allocator,
                        .bytes = owned,
                        .fingerprint = try checkedRequestBytesFingerprint(bytes),
                        .request_format_version = decoded_request_format_version,
                        .request_fingerprint_version = decoded_request_fingerprint_version,
                        .manifest_fingerprint = manifest_fingerprint,
                        .program_label = program_label_owned,
                        .plan_label = plan,
                        .plan_hash = decoded_plan_hash,
                        .kind = kind_value,
                        .request_fingerprint = request_fingerprint,
                        .trace_fingerprint = trace_fingerprint,
                        .turn_index = turn_index,
                        .site_index = site_index,
                        .site_fingerprint = site_fingerprint,
                        .semantic_label = semantic_label,
                        .name = name_value,
                        .mode = mode,
                        .value_ref = value_ref,
                        .value_image = value_image,
                        .value_fingerprint = value_fingerprint,
                        .expected_resume_ref = expected_resume_ref,
                        .expected_return_ref = expected_return_ref,
                        .expected_after_ref = expected_after_ref,
                        .result_ref = result_ref,
                        .capsule_image = capsule_image,
                        .capsule_image_fingerprint = capsule_fingerprint,
                        .journal_branch_id = branch_id,
                        .usage_metadata = usage_metadata,
                    };
                    envelope_owned = true;
                    validateRequestEnvelopeFields(envelope) catch |err| {
                        envelope.deinit();
                        return err;
                    };
                    policy.validateRequest(envelope) catch |err| {
                        envelope.deinit();
                        return err;
                    };
                    return envelope;
                }

                /// Validate manifest, plan, site, value image, and capsule compatibility.
                pub fn validate(self: @This()) Error!void {
                    try validateRequestEnvelopeFields(self);
                    try validateRequestEnvelopeFieldsBoundToBytes(self);
                }

                /// Canonical evidence reference for this request envelope.
                pub fn evidenceRef(self: @This()) Evidence.Ref {
                    return Evidence.refForRequestEnvelope(self);
                }

                /// Release request envelope storage.
                pub fn deinit(self: *@This()) void {
                    self.allocator.free(self.bytes);
                    self.allocator.free(self.program_label);
                    self.allocator.free(self.plan_label);
                    if (self.semantic_label) |value| self.allocator.free(value);
                    self.allocator.free(self.name);
                    self.allocator.free(self.value_image);
                    if (self.capsule_image) |image| self.allocator.free(image);
                    if (self.journal_branch_id) |branch| self.allocator.free(branch);
                    self.bytes = &.{};
                }
            };

            /// Options used while applying response envelopes.
            pub const ResponseOptions = struct {
                journal: ?*Session.Journal = null,
                request_envelope_fingerprint: ?u64 = null,
                request_manifest_fingerprint: ?u64 = null,
            };

            /// Canonical typed response envelope for host-supplied answers.
            pub const ResponseEnvelope = struct {
                allocator: std.mem.Allocator,
                bytes: []u8,
                fingerprint: u64,
                manifest_fingerprint: u64,
                request_envelope_fingerprint: u64,
                request_fingerprint: u64,
                kind: ResponseKind,
                response_ref: lowering_api.ValueRef,
                value_image: []u8,
                response_value_fingerprint: u64,
                response_trace_fingerprint: u64,
                authorization: ?Authorization = null,
                treaty_authorization: ?Treaty.Authorization = null,

                /// Encode a resume response for an operation request envelope.
                pub fn @"resume"(allocator: std.mem.Allocator, request: RequestEnvelope, value: anytype) Error!@This() {
                    return encodeResponseEnvelope(allocator, request, .@"resume", value);
                }

                /// Encode a return-now response for an operation request envelope.
                pub fn returnNow(allocator: std.mem.Allocator, request: RequestEnvelope, value: anytype) Error!@This() {
                    return encodeResponseEnvelope(allocator, request, .return_now, value);
                }

                /// Encode a resume-after response for an after request envelope.
                pub fn resumeAfter(allocator: std.mem.Allocator, request: RequestEnvelope, value: anytype) Error!@This() {
                    return encodeResponseEnvelope(allocator, request, .resume_after, value);
                }

                /// Decode and validate response bytes that are self-contained in the envelope.
                pub fn decode(allocator: std.mem.Allocator, bytes: []const u8) Error!@This() {
                    return decodeWithPolicy(allocator, bytes, .{});
                }

                /// Decode and validate response bytes after applying policy limits before payload copies.
                pub fn decodeWithPolicy(allocator: std.mem.Allocator, bytes: []const u8, policy: Policy) Error!@This() {
                    if (bytes.len > policy.max_envelope_bytes) return error.ProgramContractViolation;
                    const payload = try checkedPayload(bytes, "ability.exchange.response", exchange_response_fingerprint_version);
                    var reader = Reader.init(payload);
                    try reader.expectBytes(response_magic);
                    if (try reader.readU32() != exchange_response_format_version) return error.ProgramContractViolation;
                    if (try reader.readU32() != exchange_response_fingerprint_version) return error.ProgramContractViolation;
                    const manifest_fingerprint = try reader.readU64();
                    const request_envelope_fingerprint = try reader.readU64();
                    const request_fingerprint = try reader.readU64();
                    const kind_value = try readExchangeResponseKind(&reader);
                    if (!policy.allowed_response_kinds.allows(kind_value)) return error.ProgramContractViolation;
                    const response_ref = try readExchangeValueRef(&reader);
                    const value_fingerprint = try reader.readU64();
                    const response_trace_fingerprint = try reader.readU64();
                    const value_image_slice = try reader.readLenBytes();
                    if (value_image_slice.len > policy.max_payload_bytes) return error.ProgramContractViolation;
                    if (!policy.allow_response_value_images and value_image_slice.len != 0) return error.ProgramContractViolation;
                    const value_image = try allocator.dupe(u8, value_image_slice);
                    errdefer allocator.free(value_image);
                    if (!reader.eof()) return error.ProgramContractViolation;
                    if (!try manifestFingerprintMatchesSupportedRequestVersion(allocator, manifest_fingerprint)) return error.ProgramContractViolation;
                    const trace = responseTraceFromEnvelope(request_fingerprint, kind_value, response_ref, value_fingerprint);
                    if (trace.fingerprint != response_trace_fingerprint) return error.ProgramContractViolation;
                    try validateExchangeValueImage(allocator, response_ref, value_fingerprint, value_image);
                    const owned = allocator.dupe(u8, bytes) catch |err| return mapProgramRunError(Error, err);
                    errdefer allocator.free(owned);
                    return .{
                        .allocator = allocator,
                        .bytes = owned,
                        .fingerprint = try checkedBytesFingerprint(bytes, "ability.exchange.response", exchange_response_fingerprint_version),
                        .manifest_fingerprint = manifest_fingerprint,
                        .request_envelope_fingerprint = request_envelope_fingerprint,
                        .request_fingerprint = request_fingerprint,
                        .kind = kind_value,
                        .response_ref = response_ref,
                        .value_image = value_image,
                        .response_value_fingerprint = value_fingerprint,
                        .response_trace_fingerprint = response_trace_fingerprint,
                    };
                }

                /// Validate this response against the exact request envelope it answers.
                pub fn validateForRequest(self: @This(), request: RequestEnvelope) Error!void {
                    try request.validate();
                    if (self.manifest_fingerprint != request.manifest_fingerprint) return error.ProgramContractViolation;
                    if (self.request_envelope_fingerprint != request.fingerprint) return error.ProgramContractViolation;
                    if (self.request_fingerprint != request.request_fingerprint) return error.ProgramContractViolation;
                    try validateResponseEnvelopeFieldsBoundToBytes(self);
                    const expected_ref = try expectedResponseRef(request, self.kind);
                    if (!self.response_ref.eql(expected_ref)) return error.ProgramContractViolation;
                    const trace = responseTraceFromEnvelope(request.request_fingerprint, self.kind, self.response_ref, self.response_value_fingerprint);
                    if (trace.fingerprint != self.response_trace_fingerprint) return error.ProgramContractViolation;
                    try validateExchangeValueImage(self.allocator, self.response_ref, self.response_value_fingerprint, self.value_image);
                }

                /// Canonical evidence reference for this response envelope.
                pub fn evidenceRef(self: @This()) Evidence.Ref {
                    return Evidence.refForResponseEnvelope(self);
                }

                /// Attach a deterministic authorization witness without changing response bytes.
                pub fn authorize(self: *@This(), route: Route) Error!void {
                    self.authorization = try Authorization.forResponse(route, self.*);
                }

                /// Attach a treaty-bound authorization witness without changing response bytes.
                pub fn authorizeTreaty(self: *@This(), treaty: Treaty, response_use: ResponseUse) Error!void {
                    self.treaty_authorization = try Treaty.Authorization.forResponse(treaty, self.*, response_use);
                }

                /// Attach a treaty-bound authorization witness that cites an obligation transition.
                pub fn authorizeTreatyWithObligationTransition(self: *@This(), treaty: Treaty, response_use: ResponseUse, transition_fingerprint: u64) Error!void {
                    self.treaty_authorization = try Treaty.Authorization.forResponseWithObligationTransition(treaty, self.*, response_use, transition_fingerprint);
                }

                /// Attach a replay treaty authorization witness that cites a recorded source response.
                pub fn authorizeTreatyWithReplaySource(self: *@This(), treaty: Treaty, response_use: ResponseUse, source_response_fingerprint: u64, source_response_value_fingerprint: u64) Error!void {
                    self.treaty_authorization = try Treaty.Authorization.forResponseWithReplaySource(treaty, self.*, response_use, source_response_fingerprint, source_response_value_fingerprint);
                }

                /// Release response envelope storage.
                pub fn deinit(self: *@This()) void {
                    self.allocator.free(self.bytes);
                    self.allocator.free(self.value_image);
                    self.bytes = &.{};
                }
            };

            fn instanceMatchesObligationOpenedInstance(instance: CapabilityInstance, obligation: Obligation) bool {
                if (obligation.capability_instance_fingerprint == null) return false;
                if (instance.instance_fingerprint == obligation.effect_session_instance_fingerprint and
                    instance.instance_fingerprint == obligation.capability_instance_fingerprint.?)
                {
                    return true;
                }
                var opened = instance;
                opened.current_state = obligation.state_at_open;
                opened.opened_request_fingerprint = obligation.request_fingerprint;
                opened.consumed_response_fingerprint = null;
                opened.instance_fingerprint = 0;
                const opened_fingerprint = fingerprintCapabilityInstance(opened);
                return opened_fingerprint == obligation.effect_session_instance_fingerprint and
                    opened_fingerprint == obligation.capability_instance_fingerprint.?;
            }

            fn instanceCanAnswerObligation(instance: CapabilityInstance, obligation: Obligation, response_uses_replay: bool) bool {
                if (instance.instance_fingerprint == obligation.effect_session_instance_fingerprint) return true;
                if (response_uses_replay or obligation.usage == .copyable or obligation.usage == .replayable) {
                    return instanceMatchesObligationOpenedInstance(instance, obligation);
                }
                return false;
            }

            fn obligationAuthorityFingerprint(obligation: Obligation) u64 {
                return obligation.authority_instance_fingerprint orelse obligation.effect_session_instance_fingerprint;
            }

            /// Nonblocking transport-neutral runner over host-owned inbox/outbox storage.
            pub const MailboxRunner = struct {
                last_request_fingerprint: ?u64 = null,
                last_request_envelope_fingerprint: ?u64 = null,
                last_request_manifest_fingerprint: ?u64 = null,
                last_request_included_capsule: ?bool = null,
                last_request_journal_branch_id: ?[]u8 = null,
                last_request_journal_branch_allocator: ?std.mem.Allocator = null,
                last_request_usage_metadata: ?RequestUsageMetadata = null,
                last_route: ?Route = null,
                last_treaty: ?Treaty = null,
                last_treaty_requires_journal: bool = false,
                last_treaty_journaled: bool = false,
                last_response_capability_required: bool = false,

                /// One nonblocking mailbox runner outcome.
                pub const Step = union(enum) {
                    parked: RequestEnvelope,
                    done: Result,
                    running,
                };

                /// Release runner-owned pending request state.
                pub fn deinit(self: *@This()) void {
                    self.clearLastRequestJournalBranch();
                    self.clearLastTreaty();
                }

                fn clearLastTreaty(self: *@This()) void {
                    if (self.last_treaty) |*treaty| treaty.deinit();
                    self.last_treaty = null;
                    self.last_treaty_requires_journal = false;
                    self.last_treaty_journaled = false;
                }

                fn clearLastRequestJournalBranch(self: *@This()) void {
                    if (self.last_request_journal_branch_id) |branch| {
                        self.last_request_journal_branch_allocator.?.free(branch);
                    }
                    self.last_request_journal_branch_id = null;
                    self.last_request_journal_branch_allocator = null;
                }

                fn cloneJournalBranch(allocator: std.mem.Allocator, branch: ?[]const u8) Error!?[]u8 {
                    const value = branch orelse return null;
                    return allocator.dupe(u8, value) catch |err| return mapProgramRunError(Error, err);
                }

                fn adoptLastRequestJournalBranch(self: *@This(), allocator: std.mem.Allocator, branch: ?[]u8) void {
                    self.clearLastRequestJournalBranch();
                    self.last_request_journal_branch_id = branch;
                    self.last_request_journal_branch_allocator = if (branch != null) allocator else null;
                }

                fn activeRequestJournalBranchId(self: *const @This(), option_branch: ?[]const u8) ?[]const u8 {
                    return if (self.last_request_envelope_fingerprint != null)
                        self.last_request_journal_branch_id
                    else
                        option_branch;
                }

                fn activeRequestUsageMetadata(self: *const @This(), option_metadata: ?RequestUsageMetadata) ?RequestUsageMetadata {
                    return if (self.last_request_envelope_fingerprint != null)
                        self.last_request_usage_metadata
                    else
                        option_metadata;
                }

                fn appendOutboxEnvelope(allocator: std.mem.Allocator, outbox: anytype, envelope: RequestEnvelope) Error!void {
                    var outbox_envelope = RequestEnvelope.decode(allocator, envelope.bytes) catch |err| return mapProgramRunError(Error, err);
                    errdefer outbox_envelope.deinit();
                    outbox.append(outbox_envelope) catch |err| return mapProgramRunError(Error, err);
                }

                fn appendRoutedOutboxEnvelope(allocator: std.mem.Allocator, outbox: anytype, envelope: RequestEnvelope, route: Route) Error!void {
                    var outbox_envelope = RequestEnvelope.decode(allocator, envelope.bytes) catch |err| return mapProgramRunError(Error, err);
                    errdefer outbox_envelope.deinit();
                    const OutboxType = @TypeOf(outbox.*);
                    if (comptime @hasDecl(OutboxType, "appendRouted")) {
                        // appendRouted mirrors append: it takes envelope ownership only
                        // after success, so failures leave cleanup with the runner.
                        outbox.appendRouted(outbox_envelope, route) catch |err| return mapProgramRunError(Error, err);
                    } else {
                        outbox.append(outbox_envelope) catch |err| return mapProgramRunError(Error, err);
                    }
                }

                const JournalCheckpoint = struct {
                    ledger: *Session.Journal,
                    start_len: usize,
                };

                const ConfiguredObligationOpen = struct {
                    instance: *CapabilityInstance,
                    obligation: *Obligation,
                    previous_instance: CapabilityInstance,
                    previous_obligation: Obligation,
                    journal_checkpoint: ?JournalCheckpoint = null,
                };

                fn rollbackConfiguredObligationOpen(opened: ConfiguredObligationOpen) void {
                    opened.instance.deinit();
                    opened.instance.* = opened.previous_instance;
                    opened.obligation.deinit();
                    opened.obligation.* = opened.previous_obligation;
                    if (opened.journal_checkpoint) |checkpoint| checkpoint.ledger.truncateEntries(checkpoint.start_len);
                }

                fn commitConfiguredObligationOpen(opened: ConfiguredObligationOpen) void {
                    var previous_instance = opened.previous_instance;
                    previous_instance.deinit();
                    var previous = opened.previous_obligation;
                    previous.deinit();
                }

                fn appendRouteSelectedJournal(journal: ?*Session.Journal, route: Route) Error!?JournalCheckpoint {
                    const ledger = journal orelse return null;
                    const start_len = ledger.entries.items.len;
                    try ledger.appendExchangeEvent(.{
                        .kind = .route_selected,
                        .provider_fingerprint = route.provider_fingerprint,
                        .capability_fingerprint = route.capability_fingerprint,
                        .route_fingerprint = route.fingerprint,
                        .request_envelope_fingerprint = route.request_envelope_fingerprint,
                    });
                    return .{ .ledger = ledger, .start_len = start_len };
                }

                fn appendRouteAwareOutboxEnvelope(
                    allocator: std.mem.Allocator,
                    outbox: anytype,
                    envelope: RequestEnvelope,
                    router: ?Router,
                    policy: Policy,
                    journal: ?*Session.Journal,
                    require_routed_result: bool,
                    capability_instance: ?*CapabilityInstance,
                    obligation: ?*Obligation,
                    allowed_response_refs: []const lowering_api.ValueRef,
                ) Error!?Route {
                    if (router) |catalog| {
                        const route_plan = catalog.planWithPolicy(envelope, policy);
                        const route_required = policyRequiresRoute(policy) or policyRequiresRoute(catalog.policy);
                        const reject_ambiguous_routes = policy.reject_ambiguous_routes or catalog.policy.reject_ambiguous_routes;
                        const router_request_policy = validatePolicyRequestScope(catalog.policy, envelope);
                        if (!router_request_policy.allowed()) {
                            if (journal) |ledger| try ledger.appendExchangeEvent(.{
                                .kind = .route_blocked,
                                .request_envelope_fingerprint = envelope.fingerprint,
                                .blocker_tag = router_request_policy.firstTagName(),
                            });
                            return error.ProgramContractViolation;
                        }
                        switch (route_plan.status) {
                            .one_route => {
                                const route = route_plan.route.?;
                                const journal_checkpoint = try appendRouteSelectedJournal(journal, route);
                                errdefer if (journal_checkpoint) |checkpoint| checkpoint.ledger.truncateEntries(checkpoint.start_len);
                                const opened_obligation = try openConfiguredObligation(capability_instance, obligation, envelope, policy, route, allowed_response_refs, journal);
                                errdefer if (opened_obligation) |opened| rollbackConfiguredObligationOpen(opened);
                                try appendRoutedOutboxEnvelope(allocator, outbox, envelope, route);
                                if (opened_obligation) |opened| commitConfiguredObligationOpen(opened);
                                return route;
                            },
                            .ambiguous_routes => {
                                if (!reject_ambiguous_routes and route_plan.route != null) {
                                    const route = route_plan.route.?;
                                    const journal_checkpoint = try appendRouteSelectedJournal(journal, route);
                                    errdefer if (journal_checkpoint) |checkpoint| checkpoint.ledger.truncateEntries(checkpoint.start_len);
                                    const opened_obligation = try openConfiguredObligation(capability_instance, obligation, envelope, policy, route, allowed_response_refs, journal);
                                    errdefer if (opened_obligation) |opened| rollbackConfiguredObligationOpen(opened);
                                    try appendRoutedOutboxEnvelope(allocator, outbox, envelope, route);
                                    if (opened_obligation) |opened| commitConfiguredObligationOpen(opened);
                                    return route;
                                }
                                if (journal) |ledger| try ledger.appendExchangeEvent(.{
                                    .kind = .route_blocked,
                                    .request_envelope_fingerprint = envelope.fingerprint,
                                    .blocker_tag = route_plan.blocked.firstTagName(),
                                });
                                return error.ProgramContractViolation;
                            },
                            .blocked_routes => {
                                if (!route_required and blockedRoutesAllowOptionalFallback(route_plan.blocked)) {} else {
                                    if (journal) |ledger| try ledger.appendExchangeEvent(.{
                                        .kind = .route_blocked,
                                        .request_envelope_fingerprint = envelope.fingerprint,
                                        .blocker_tag = route_plan.blocked.firstTagName(),
                                    });
                                    return error.ProgramContractViolation;
                                }
                            },
                            .no_route => {},
                        }
                        if (route_required or require_routed_result) {
                            if (journal) |ledger| try ledger.appendExchangeEvent(.{
                                .kind = .route_blocked,
                                .request_envelope_fingerprint = envelope.fingerprint,
                                .blocker_tag = route_plan.blocked.firstTagName(),
                            });
                            return error.ProgramContractViolation;
                        }
                    } else if (policyRequiresRoute(policy) or require_routed_result) {
                        if (journal) |ledger| try ledger.appendExchangeEvent(.{
                            .kind = .route_blocked,
                            .request_envelope_fingerprint = envelope.fingerprint,
                            .blocker_tag = @tagName(BlockerTag.no_route),
                        });
                        return error.ProgramContractViolation;
                    }
                    const opened_obligation = try openConfiguredObligation(capability_instance, obligation, envelope, policy, null, allowed_response_refs, journal);
                    errdefer if (opened_obligation) |opened| rollbackConfiguredObligationOpen(opened);
                    try appendOutboxEnvelope(allocator, outbox, envelope);
                    if (opened_obligation) |opened| commitConfiguredObligationOpen(opened);
                    return null;
                }

                fn configuredObligationResponseKinds(policy: Policy, route: ?Route) Policy.ResponseKindSet {
                    return if (route) |selected_route| selected_route.allowed_response_kinds else policy.allowed_response_kinds;
                }

                fn configuredObligationNeedsOpen(obligation: Obligation, envelope: RequestEnvelope, instance: CapabilityInstance, route: ?Route) Error!bool {
                    if (obligation.obligation_fingerprint == 0) return true;
                    const mismatched_request = obligation.request_envelope_fingerprint != envelope.fingerprint or
                        obligation.request_fingerprint != envelope.request_fingerprint;
                    const mismatched_instance = !instanceMatchesObligationOpenedInstance(instance, obligation);
                    const mismatched_route = if (route) |selected_route|
                        obligation.provider_fingerprint == null or
                            obligation.provider_fingerprint.? != selected_route.provider_fingerprint or
                            instance.parent_capability_fingerprint != selected_route.capability_fingerprint
                    else
                        false;
                    if (!mismatched_request and !mismatched_instance and !mismatched_route) return false;
                    if (obligation.status == .open) return error.ProgramContractViolation;
                    return true;
                }

                fn validateConfiguredOpenObligation(obligation: Obligation, envelope: RequestEnvelope, instance: CapabilityInstance, route: ?Route) Error!void {
                    if (obligation.status != .open) return error.ProgramContractViolation;
                    if (obligation.request_envelope_fingerprint != envelope.fingerprint) return error.ProgramContractViolation;
                    if (obligation.request_fingerprint != envelope.request_fingerprint) return error.ProgramContractViolation;
                    if (obligation.site_fingerprint != envelope.site_fingerprint) return error.ProgramContractViolation;
                    if (!instanceMatchesObligationOpenedInstance(instance, obligation)) return error.ProgramContractViolation;
                    if (route) |selected_route| {
                        if (obligation.provider_fingerprint == null or obligation.provider_fingerprint.? != selected_route.provider_fingerprint) return error.ProgramContractViolation;
                    }
                    try validateConfiguredRouteInstance(instance, route);
                }

                fn validateConfiguredReplayableObligation(obligation: Obligation, envelope: RequestEnvelope, instance: CapabilityInstance, route: ?Route) Error!void {
                    if (obligation.status != .consumed and obligation.status != .replayed) return error.ProgramContractViolation;
                    if (obligation.usage == .ephemeral) return error.ProgramContractViolation;
                    if (obligation.request_envelope_fingerprint != envelope.fingerprint) return error.ProgramContractViolation;
                    if (obligation.request_fingerprint != envelope.request_fingerprint) return error.ProgramContractViolation;
                    if (obligation.site_fingerprint != envelope.site_fingerprint) return error.ProgramContractViolation;
                    if (!instanceMatchesObligationOpenedInstance(instance, obligation)) return error.ProgramContractViolation;
                    if (route) |selected_route| {
                        if (obligation.provider_fingerprint == null or obligation.provider_fingerprint.? != selected_route.provider_fingerprint) return error.ProgramContractViolation;
                    }
                    try validateConfiguredRouteInstance(instance, route);
                }

                fn validateConfiguredRouteInstance(instance: CapabilityInstance, route: ?Route) Error!void {
                    if (route) |selected_route| {
                        if (instance.parent_capability_fingerprint != selected_route.capability_fingerprint) return error.ProgramContractViolation;
                        if (instance.provider_fingerprint != selected_route.provider_fingerprint) return error.ProgramContractViolation;
                    }
                }

                fn openConfiguredObligation(
                    instance: ?*CapabilityInstance,
                    obligation: ?*Obligation,
                    envelope: RequestEnvelope,
                    policy: Policy,
                    route: ?Route,
                    allowed_response_refs: []const lowering_api.ValueRef,
                    journal: ?*Session.Journal,
                ) Error!?ConfiguredObligationOpen {
                    const instance_ptr = instance orelse return null;
                    const obligation_ptr = obligation orelse return null;
                    if (try configuredObligationNeedsOpen(obligation_ptr.*, envelope, instance_ptr.*, route)) {
                        try validateConfiguredRouteInstance(instance_ptr.*, route);
                        var previous_instance = try instance_ptr.*.clone();
                        var previous_instance_owned = true;
                        errdefer if (previous_instance_owned) previous_instance.deinit();
                        const previous_obligation = obligation_ptr.*;
                        const response_kinds = configuredObligationResponseKinds(policy, route);
                        var opened_obligation = try Obligation.open(instance_ptr, envelope, response_kinds, allowed_response_refs);
                        errdefer opened_obligation.deinit();
                        errdefer {
                            instance_ptr.deinit();
                            instance_ptr.* = previous_instance;
                            previous_instance_owned = false;
                        }
                        const opened_instance = instance_ptr.*;
                        const journal_checkpoint = if (journal) |ledger| checkpoint: {
                            const start_len = ledger.entries.items.len;
                            try ledger.appendExchangeEvent(.{
                                .kind = .obligation_opened,
                                .request_envelope_fingerprint = envelope.fingerprint,
                                .capability_instance_fingerprint = opened_instance.instance_fingerprint,
                                .obligation_fingerprint = opened_obligation.obligation_fingerprint,
                                .branch_id = opened_obligation.branch_id,
                                .previous_state_fingerprint = stateLabelFingerprint(opened_obligation.state_at_open),
                                .next_state_fingerprint = stateLabelFingerprint(opened_obligation.state_at_open),
                            });
                            break :checkpoint JournalCheckpoint{ .ledger = ledger, .start_len = start_len };
                        } else null;
                        obligation_ptr.* = opened_obligation;
                        previous_instance_owned = false;
                        return .{
                            .instance = instance_ptr,
                            .obligation = obligation_ptr,
                            .previous_instance = previous_instance,
                            .previous_obligation = previous_obligation,
                            .journal_checkpoint = journal_checkpoint,
                        };
                    } else {
                        if (obligation_ptr.*.status == .open) {
                            try validateConfiguredOpenObligation(obligation_ptr.*, envelope, instance_ptr.*, route);
                        } else {
                            try validateConfiguredReplayableObligation(obligation_ptr.*, envelope, instance_ptr.*, route);
                        }
                        return null;
                    }
                }

                fn validateCurrentRequestPolicy(
                    allocator: std.mem.Allocator,
                    session: *Session,
                    current_value: Session.Current,
                    policy: Policy,
                    include_capsule: bool,
                    journal_branch_id: ?[]const u8,
                    usage_metadata: ?RequestUsageMetadata,
                ) Error!void {
                    switch (current_value) {
                        .request => |request| {
                            var envelope = try requestEnvelopeForCurrent(allocator, session, .{ .request = request }, include_capsule, journal_branch_id, usage_metadata);
                            defer envelope.deinit();
                            try policy.validateRequest(envelope);
                        },
                        .after => |after| {
                            var envelope = try requestEnvelopeForCurrent(allocator, session, .{ .after = after }, include_capsule, journal_branch_id, usage_metadata);
                            defer envelope.deinit();
                            try policy.validateRequest(envelope);
                        },
                        .none => {},
                    }
                }

                fn appendTreatyOutboxEnvelope(allocator: std.mem.Allocator, outbox: anytype, envelope: RequestEnvelope, treaty: Treaty) Error!void {
                    var outbox_envelope = RequestEnvelope.decode(allocator, envelope.bytes) catch |err| return mapProgramRunError(Error, err);
                    errdefer outbox_envelope.deinit();
                    const OutboxType = @TypeOf(outbox.*);
                    if (comptime @hasDecl(OutboxType, "appendTreaty")) {
                        var outbox_certificate = try treaty.certificate.clone(allocator);
                        errdefer outbox_certificate.deinit(allocator);
                        outbox.appendTreaty(outbox_envelope, outbox_certificate) catch |err| return mapProgramRunError(Error, err);
                    } else if (comptime @hasDecl(OutboxType, "appendRouted")) {
                        if (treaty.handling != .direct) return error.ProgramContractViolation;
                        if (treaty.require_treaty_bound_response_authorization) return error.ProgramContractViolation;
                        outbox.appendRouted(outbox_envelope, treaty.route) catch |err| return mapProgramRunError(Error, err);
                    } else {
                        if (treaty.handling != .direct) return error.ProgramContractViolation;
                        if (treaty.require_treaty_bound_response_authorization) return error.ProgramContractViolation;
                        outbox.append(outbox_envelope) catch |err| return mapProgramRunError(Error, err);
                    }
                }

                const ResolverCapabilityInstances = struct {
                    items: []const CapabilityInstance,
                    owned: ?[]CapabilityInstance = null,

                    fn deinit(self: @This(), allocator: std.mem.Allocator) void {
                        if (self.owned) |owned| allocator.free(owned);
                    }
                };

                fn resolverCapabilityInstances(
                    allocator: std.mem.Allocator,
                    catalog: []const CapabilityInstance,
                    live_state: ?*CapabilityInstance,
                ) Error!ResolverCapabilityInstances {
                    const state = live_state orelse return .{ .items = catalog };
                    if (!state.*.validFingerprint()) return error.ProgramContractViolation;
                    const owned = allocator.alloc(CapabilityInstance, catalog.len + 1) catch |err| return mapProgramRunError(Error, err);
                    owned[0] = state.*;
                    for (catalog, 0..) |instance, index| owned[index + 1] = instance;
                    return .{ .items = owned, .owned = owned };
                }

                /// Treaty mode: resolve a treaty before writing to the provider outbox.
                pub fn runTreatyStep(
                    self: *@This(),
                    session: *Session,
                    outbox: anytype,
                    inbox: anytype,
                    options: struct {
                        allocator: std.mem.Allocator,
                        manifest: Manifest,
                        provider_manifests: []const ProviderManifest = &.{},
                        provider_offers: []const ProviderOffer = &.{},
                        capabilities: []const Capability = &.{},
                        capability_instances: []const CapabilityInstance = &.{},
                        morphism_offers: []const MorphismOffer = &.{},
                        treaty_request: ?TreatyRequest = null,
                        treaty_policy: Treaty.Policy = .{},
                        route_policy: Policy = .{},
                        effect_session_spec: ?EffectSessionSpec = null,
                        obligation: ?Obligation = null,
                        capability_instance_state: ?*CapabilityInstance = null,
                        obligation_state: ?*Obligation = null,
                        replay_source_response_fingerprint: ?u64 = null,
                        replay_source_response_value_fingerprint: ?u64 = null,
                        capsule: bool = false,
                        journal_branch_id: ?[]const u8 = null,
                        journal: ?*Session.Journal = null,
                        usage_metadata: ?RequestUsageMetadata = null,
                    },
                ) Error!Step {
                    if (self.last_request_envelope_fingerprint != null and self.last_treaty == null) return error.ProgramContractViolation;
                    const current_value = try session.current();
                    if (options.journal == null) {
                        if (self.last_treaty_requires_journal) return error.ProgramContractViolation;
                        if (options.treaty_policy.require_journal_recording) return error.ProgramContractViolation;
                        if (options.treaty_request) |request_value| {
                            if (request_value.require_journal_recording) return error.ProgramContractViolation;
                        }
                    }
                    if (try inbox.nextResponse()) |response_value| {
                        var response = response_value;
                        defer response.deinit();
                        const treaty = self.last_treaty orelse return error.ProgramContractViolation;
                        const treaty_requires_journal = options.treaty_policy.require_journal_recording or
                            if (options.treaty_request) |request_value| request_value.require_journal_recording else false;
                        if (self.last_treaty_requires_journal and options.journal == null) return error.ProgramContractViolation;
                        if (treaty_requires_journal and !self.last_treaty_journaled) return error.ProgramContractViolation;
                        var owned_current = try requestEnvelopeForCurrent(
                            options.allocator,
                            session,
                            current_value,
                            self.last_request_included_capsule orelse options.capsule,
                            self.activeRequestJournalBranchId(options.journal_branch_id),
                            self.activeRequestUsageMetadata(options.usage_metadata),
                        );
                        defer owned_current.deinit();
                        const resolver_instances = try resolverCapabilityInstances(options.allocator, options.capability_instances, options.capability_instance_state);
                        defer resolver_instances.deinit(options.allocator);
                        var current_result = try TreatyResolver.resolve(.{
                            .allocator = options.allocator,
                            .request = owned_current,
                            .manifest = options.manifest,
                            .provider_manifests = options.provider_manifests,
                            .provider_offers = options.provider_offers,
                            .capabilities = options.capabilities,
                            .capability_instances = resolver_instances.items,
                            .morphism_offers = options.morphism_offers,
                            .treaty_request = options.treaty_request,
                            .treaty_policy = options.treaty_policy,
                            .route_policy = options.route_policy,
                            .effect_session_spec = options.effect_session_spec,
                            .obligation = if (options.obligation_state) |state| state.* else options.obligation,
                            .live_capability_instance_fingerprint = if (options.capability_instance_state) |state| state.instance_fingerprint else null,
                        });
                        defer current_result.deinit();
                        const current_treaty = current_result.treaty orelse {
                            if (options.journal) |ledger| try ledger.appendExchangeEvent(.{
                                .kind = .treaty_response_rejected,
                                .provider_fingerprint = treaty.provider_fingerprint,
                                .capability_fingerprint = treaty.capability_fingerprint,
                                .route_fingerprint = treaty.route.fingerprint,
                                .request_envelope_fingerprint = treaty.request_envelope_fingerprint,
                                .response_envelope_fingerprint = response.fingerprint,
                                .treaty_fingerprint = treaty.fingerprint,
                                .treaty_certificate_fingerprint = treaty.certificate.certificate_fingerprint,
                                .provider_offer_fingerprint = treaty.provider_offer_fingerprint,
                                .blocker_tag = current_result.blockers.firstTagName(),
                            });
                            return error.ProgramContractViolation;
                        };
                        if (current_treaty.fingerprint != treaty.fingerprint or
                            current_treaty.certificate.certificate_fingerprint != treaty.certificate.certificate_fingerprint)
                        {
                            if (options.journal) |ledger| try ledger.appendExchangeEvent(.{
                                .kind = .treaty_response_rejected,
                                .provider_fingerprint = treaty.provider_fingerprint,
                                .capability_fingerprint = treaty.capability_fingerprint,
                                .route_fingerprint = treaty.route.fingerprint,
                                .request_envelope_fingerprint = treaty.request_envelope_fingerprint,
                                .response_envelope_fingerprint = response.fingerprint,
                                .treaty_fingerprint = treaty.fingerprint,
                                .treaty_certificate_fingerprint = treaty.certificate.certificate_fingerprint,
                                .provider_offer_fingerprint = treaty.provider_offer_fingerprint,
                                .blocker_tag = @tagName(if (current_treaty.fingerprint != treaty.fingerprint) Treaty.BlockerTag.wrong_treaty else Treaty.BlockerTag.wrong_certificate),
                            });
                            return error.ProgramContractViolation;
                        }
                        const treaty_report = validateTreatyResponseWithPolicy(treaty, owned_current, response, options.treaty_policy);
                        if (!treaty_report.allowed()) {
                            if (options.journal) |ledger| try ledger.appendExchangeEvent(.{
                                .kind = .treaty_response_rejected,
                                .provider_fingerprint = treaty.provider_fingerprint,
                                .capability_fingerprint = treaty.capability_fingerprint,
                                .route_fingerprint = treaty.route.fingerprint,
                                .request_envelope_fingerprint = treaty.request_envelope_fingerprint,
                                .response_envelope_fingerprint = response.fingerprint,
                                .treaty_fingerprint = treaty.fingerprint,
                                .treaty_certificate_fingerprint = treaty.certificate.certificate_fingerprint,
                                .provider_offer_fingerprint = treaty.provider_offer_fingerprint,
                                .blocker_tag = treaty_report.firstTagName(),
                            });
                            return error.ProgramContractViolation;
                        }
                        const treaty_response_use = if (response.treaty_authorization) |authorization| authorization.response_use else treaty.response_use;
                        var pending_obligation: ?Obligation = null;
                        var pending_instance: ?CapabilityInstance = null;
                        errdefer if (pending_obligation) |*updated| updated.deinit();
                        errdefer if (pending_instance) |*updated| updated.deinit();
                        var pending_obligation_event: ?Session.Journal.ExchangeEvent = null;
                        if (treaty.obligation_fingerprint) |expected_obligation_fingerprint| {
                            const obligation_ptr = options.obligation_state orelse return error.ProgramContractViolation;
                            if (!obligation_ptr.*.validFingerprint()) return error.ProgramContractViolation;
                            if (obligation_ptr.*.obligation_fingerprint != expected_obligation_fingerprint) return error.ProgramContractViolation;
                            try validateObligationResponseMetadata(obligation_ptr.*, owned_current.usage_metadata, treaty_response_use);
                            if (obligation_ptr.*.capability_instance_fingerprint != null and options.capability_instance_state == null) return error.ProgramContractViolation;
                            if (treaty.capability_instance_fingerprint != null and options.capability_instance_state == null) return error.ProgramContractViolation;
                            if (options.capability_instance_state) |instance| {
                                if (!instance.*.validFingerprint()) return error.ProgramContractViolation;
                                if (treaty.capability_instance_fingerprint) |fingerprint| {
                                    if (instance.*.instance_fingerprint != fingerprint) return error.ProgramContractViolation;
                                }
                                const response_uses_replay = treaty_response_use == .replayed or treaty_response_use == .deterministic_replay;
                                if (!instanceCanAnswerObligation(instance.*, obligation_ptr.*, response_uses_replay)) return error.ProgramContractViolation;
                                if (instance.*.provider_fingerprint != treaty.provider_fingerprint) return error.ProgramContractViolation;
                                if (!capabilityInstanceParentMatchesTreatyCapability(instance.*, treaty)) return error.ProgramContractViolation;
                                if (instance.*.usage != obligation_ptr.*.usage) return error.ProgramContractViolation;
                                if (instance.*.branch_id != obligation_ptr.*.branch_id) return error.ProgramContractViolation;
                                if (obligation_ptr.*.capability_instance_fingerprint) |fingerprint| {
                                    if (fingerprint != obligation_ptr.*.effect_session_instance_fingerprint) return error.ProgramContractViolation;
                                }
                            }
                            const response_has_open_obligation = false;
                            const branch_report = validateBranchPolicy(obligation_ptr.*.branch_policy, obligation_ptr.*.usage, treaty_response_use, response_has_open_obligation, self.last_request_included_capsule orelse options.capsule);
                            if (!branch_report.allowed()) return error.ProgramContractViolation;
                            var transition = switch (treaty_response_use) {
                                .fresh, .override => try obligation_ptr.*.consume(response, treaty_response_use),
                                .replayed, .deterministic_replay => replay: {
                                    const authorization_source = if (response.treaty_authorization) |authorization|
                                        authorization.replay_source_response_fingerprint
                                    else
                                        null;
                                    const source_fingerprint = authorization_source orelse options.replay_source_response_fingerprint orelse return error.ProgramContractViolation;
                                    const source_value_fingerprint = if (authorization_source != null)
                                        response.treaty_authorization.?.replay_source_response_value_fingerprint
                                    else
                                        options.replay_source_response_value_fingerprint;
                                    break :replay try obligation_ptr.*.replayWithSourceValue(
                                        response,
                                        source_fingerprint,
                                        source_value_fingerprint,
                                        treaty_response_use,
                                    );
                                },
                            };
                            if (options.effect_session_spec) |spec| {
                                transition = try advanceObligationTransitionWithSpec(spec, obligation_ptr.*, transition, response);
                                if (options.capability_instance_state) |instance| {
                                    if (instance.*.effect_session_spec_fingerprint != spec.fingerprint()) return error.ProgramContractViolation;
                                }
                            } else if (transition.capability_instance_consumed) {
                                return error.ProgramContractViolation;
                            }
                            if (response.treaty_authorization) |authorization| {
                                if (authorization.expected_obligation_transition_fingerprint) |fingerprint| {
                                    if (fingerprint != transition.transition_fingerprint) return error.ProgramContractViolation;
                                }
                            }
                            const updated_obligation = try obligation_ptr.*.applyTransition(transition);
                            if (options.capability_instance_state) |instance| {
                                if (transition.capability_instance_consumed) {
                                    pending_instance = try instance.*.consumeWithState(response.fingerprint, transition.next_session_state);
                                } else if (options.effect_session_spec != null) {
                                    pending_instance = try instance.*.advanceState(transition.next_session_state);
                                }
                            }
                            const event_instance_fingerprint = if (pending_instance) |instance|
                                instance.instance_fingerprint
                            else if (options.capability_instance_state) |instance|
                                instance.instance_fingerprint
                            else
                                null;
                            pending_obligation = updated_obligation;
                            pending_obligation_event = .{
                                .kind = if (transition.next_obligation_status == .replayed) .obligation_replayed else .obligation_consumed,
                                .request_envelope_fingerprint = response.request_envelope_fingerprint,
                                .response_envelope_fingerprint = response.fingerprint,
                                .capability_instance_fingerprint = event_instance_fingerprint,
                                .obligation_fingerprint = transition.obligation_fingerprint,
                                .obligation_transition_fingerprint = transition.transition_fingerprint,
                                .treaty_fingerprint = treaty.fingerprint,
                                .treaty_certificate_fingerprint = treaty.certificate.certificate_fingerprint,
                                .provider_offer_fingerprint = treaty.provider_offer_fingerprint,
                                .branch_id = transition.branch_id,
                            };
                        }
                        var treaty_response_checkpoint: ?JournalCheckpoint = null;
                        errdefer if (treaty_response_checkpoint) |checkpoint| checkpoint.ledger.truncateEntries(checkpoint.start_len);
                        if (options.journal) |ledger| {
                            const start_len = ledger.entries.items.len;
                            treaty_response_checkpoint = .{ .ledger = ledger, .start_len = start_len };
                            if (pending_obligation_event) |event| try ledger.appendExchangeEvent(event);
                            try ledger.appendExchangeEvent(.{
                                .kind = .treaty_authorization_recorded,
                                .provider_fingerprint = treaty.provider_fingerprint,
                                .capability_fingerprint = treaty.capability_fingerprint,
                                .route_fingerprint = treaty.route.fingerprint,
                                .request_envelope_fingerprint = treaty.request_envelope_fingerprint,
                                .response_envelope_fingerprint = response.fingerprint,
                                .treaty_fingerprint = treaty.fingerprint,
                                .treaty_certificate_fingerprint = treaty.certificate.certificate_fingerprint,
                                .provider_offer_fingerprint = treaty.provider_offer_fingerprint,
                                .authorization_fingerprint = if (response.treaty_authorization) |authorization| authorization.authorization_fingerprint else null,
                            });
                            try ledger.appendExchangeEvent(.{
                                .kind = .treaty_response_accepted,
                                .provider_fingerprint = treaty.provider_fingerprint,
                                .capability_fingerprint = treaty.capability_fingerprint,
                                .route_fingerprint = treaty.route.fingerprint,
                                .request_envelope_fingerprint = treaty.request_envelope_fingerprint,
                                .response_envelope_fingerprint = response.fingerprint,
                                .treaty_fingerprint = treaty.fingerprint,
                                .treaty_certificate_fingerprint = treaty.certificate.certificate_fingerprint,
                                .provider_offer_fingerprint = treaty.provider_offer_fingerprint,
                                .authorization_fingerprint = if (response.treaty_authorization) |authorization| authorization.authorization_fingerprint else null,
                            });
                        }
                        try applyResponse(session, response, .{
                            .journal = options.journal,
                            .request_envelope_fingerprint = self.last_request_envelope_fingerprint,
                            .request_manifest_fingerprint = self.last_request_manifest_fingerprint,
                        });
                        if (options.obligation_state) |obligation_ptr| {
                            if (pending_obligation) |updated| {
                                obligation_ptr.deinit();
                                obligation_ptr.* = updated;
                                pending_obligation = null;
                            }
                        }
                        if (options.capability_instance_state) |instance| {
                            if (pending_instance) |updated| {
                                instance.deinit();
                                instance.* = updated;
                                pending_instance = null;
                            }
                        }
                        treaty_response_checkpoint = null;
                        self.last_request_fingerprint = null;
                        self.last_request_envelope_fingerprint = null;
                        self.last_request_manifest_fingerprint = null;
                        self.last_request_included_capsule = null;
                        self.last_request_usage_metadata = null;
                        self.clearLastRequestJournalBranch();
                        self.last_route = null;
                        self.clearLastTreaty();
                        self.last_response_capability_required = false;
                        return .running;
                    }
                    const current = switch (current_value) {
                        .request, .after => current_value,
                        .none => switch (try session.next()) {
                            .request => |request| Session.Current{ .request = request },
                            .after => |after| Session.Current{ .after = after },
                            .done => |result| return .{ .done = result },
                        },
                    };
                    const request_included_capsule = self.last_request_included_capsule orelse options.capsule;
                    const request_journal_branch_id = self.activeRequestJournalBranchId(options.journal_branch_id);
                    const request_usage_metadata = self.activeRequestUsageMetadata(options.usage_metadata);
                    var envelope = try requestEnvelopeForCurrent(options.allocator, session, current, request_included_capsule, request_journal_branch_id, request_usage_metadata);
                    errdefer envelope.deinit();
                    const resolver_instances = try resolverCapabilityInstances(options.allocator, options.capability_instances, options.capability_instance_state);
                    defer resolver_instances.deinit(options.allocator);
                    var result = try TreatyResolver.resolve(.{
                        .allocator = options.allocator,
                        .request = envelope,
                        .manifest = options.manifest,
                        .provider_manifests = options.provider_manifests,
                        .provider_offers = options.provider_offers,
                        .capabilities = options.capabilities,
                        .capability_instances = resolver_instances.items,
                        .morphism_offers = options.morphism_offers,
                        .treaty_request = options.treaty_request,
                        .treaty_policy = options.treaty_policy,
                        .route_policy = options.route_policy,
                        .effect_session_spec = options.effect_session_spec,
                        .obligation = if (options.obligation_state) |state| state.* else options.obligation,
                        .live_capability_instance_fingerprint = if (options.capability_instance_state) |state| state.instance_fingerprint else null,
                    });
                    defer result.deinit();
                    const treaty = result.treaty orelse {
                        if (options.journal) |ledger| try ledger.appendExchangeEvent(.{
                            .kind = .treaty_blocked,
                            .request_envelope_fingerprint = envelope.fingerprint,
                            .blocker_tag = result.blockers.firstTagName(),
                        });
                        return error.ProgramContractViolation;
                    };
                    const envelope_changed = self.last_request_envelope_fingerprint != envelope.fingerprint;
                    const treaty_changed = self.last_treaty == null or
                        self.last_treaty.?.fingerprint != treaty.fingerprint or
                        self.last_treaty.?.certificate.certificate_fingerprint != treaty.certificate.certificate_fingerprint;
                    const treaty_requires_journal = options.treaty_policy.require_journal_recording or
                        if (options.treaty_request) |request_value| request_value.require_journal_recording else false;
                    if (envelope_changed or treaty_changed) {
                        var treaty_journal_checkpoint: ?JournalCheckpoint = null;
                        errdefer if (treaty_journal_checkpoint) |checkpoint| checkpoint.ledger.truncateEntries(checkpoint.start_len);
                        if (options.journal) |ledger| {
                            const start_len = ledger.entries.items.len;
                            treaty_journal_checkpoint = .{ .ledger = ledger, .start_len = start_len };
                            try ledger.appendExchangeEvent(.{
                                .kind = .treaty_requested,
                                .request_envelope_fingerprint = envelope.fingerprint,
                            });
                            try ledger.appendExchangeEvent(.{
                                .kind = .treaty_selected,
                                .provider_fingerprint = treaty.provider_fingerprint,
                                .capability_fingerprint = treaty.capability_fingerprint,
                                .route_fingerprint = treaty.route.fingerprint,
                                .request_envelope_fingerprint = treaty.request_envelope_fingerprint,
                                .treaty_fingerprint = treaty.fingerprint,
                                .treaty_certificate_fingerprint = treaty.certificate.certificate_fingerprint,
                                .provider_offer_fingerprint = treaty.provider_offer_fingerprint,
                            });
                            if (treaty.attenuated_capability) |attenuated| try ledger.appendExchangeEvent(.{
                                .kind = .treaty_capability_attenuated,
                                .provider_fingerprint = treaty.provider_fingerprint,
                                .capability_fingerprint = attenuated.fingerprint,
                                .route_fingerprint = treaty.route.fingerprint,
                                .request_envelope_fingerprint = treaty.request_envelope_fingerprint,
                                .treaty_fingerprint = treaty.fingerprint,
                                .treaty_certificate_fingerprint = treaty.certificate.certificate_fingerprint,
                                .provider_offer_fingerprint = treaty.provider_offer_fingerprint,
                            });
                            try ledger.appendExchangeEvent(.{
                                .kind = .treaty_replay_policy_checked,
                                .provider_fingerprint = treaty.provider_fingerprint,
                                .capability_fingerprint = treaty.capability_fingerprint,
                                .route_fingerprint = treaty.route.fingerprint,
                                .request_envelope_fingerprint = treaty.request_envelope_fingerprint,
                                .treaty_fingerprint = treaty.fingerprint,
                                .treaty_certificate_fingerprint = treaty.certificate.certificate_fingerprint,
                                .provider_offer_fingerprint = treaty.provider_offer_fingerprint,
                            });
                            try ledger.appendExchangeEvent(.{
                                .kind = .treaty_branch_policy_checked,
                                .provider_fingerprint = treaty.provider_fingerprint,
                                .capability_fingerprint = treaty.capability_fingerprint,
                                .route_fingerprint = treaty.route.fingerprint,
                                .request_envelope_fingerprint = treaty.request_envelope_fingerprint,
                                .treaty_fingerprint = treaty.fingerprint,
                                .treaty_certificate_fingerprint = treaty.certificate.certificate_fingerprint,
                                .provider_offer_fingerprint = treaty.provider_offer_fingerprint,
                            });
                            try ledger.appendExchangeEvent(.{
                                .kind = .treaty_certificate_recorded,
                                .request_envelope_fingerprint = treaty.request_envelope_fingerprint,
                                .treaty_fingerprint = treaty.fingerprint,
                                .treaty_certificate_fingerprint = treaty.certificate.certificate_fingerprint,
                                .provider_offer_fingerprint = treaty.provider_offer_fingerprint,
                            });
                        }
                        var owned_branch = try cloneJournalBranch(options.allocator, request_journal_branch_id);
                        errdefer if (owned_branch) |branch| options.allocator.free(branch);
                        try appendTreatyOutboxEnvelope(options.allocator, outbox, envelope, treaty);
                        self.clearLastTreaty();
                        self.last_treaty = treaty;
                        self.last_treaty_requires_journal = treaty_requires_journal;
                        self.last_treaty_journaled = options.journal != null;
                        result.treaty = null;
                        self.last_route = treaty.route;
                        self.last_request_fingerprint = envelope.request_fingerprint;
                        self.last_request_envelope_fingerprint = envelope.fingerprint;
                        self.last_request_manifest_fingerprint = envelope.manifest_fingerprint;
                        self.last_request_included_capsule = request_included_capsule;
                        self.last_request_usage_metadata = request_usage_metadata;
                        self.adoptLastRequestJournalBranch(options.allocator, owned_branch);
                        owned_branch = null;
                    } else {
                        if (treaty_requires_journal and !self.last_treaty_journaled) return error.ProgramContractViolation;
                        self.last_treaty_requires_journal = self.last_treaty_requires_journal or treaty_requires_journal;
                    }
                    return .{ .parked = envelope };
                }

                /// Advance one host turn, appending yielded requests and consuming one response if present.
                pub fn runStep(
                    self: *@This(),
                    session: *Session,
                    outbox: anytype,
                    inbox: anytype,
                    options: struct {
                        allocator: std.mem.Allocator,
                        policy: Policy = .{},
                        capsule: bool = false,
                        journal_branch_id: ?[]const u8 = null,
                        router: ?Router = null,
                        journal: ?*Session.Journal = null,
                        usage_metadata: ?RequestUsageMetadata = null,
                        capability_instance: ?*CapabilityInstance = null,
                        obligation: ?*Obligation = null,
                        effect_session_spec: ?EffectSessionSpec = null,
                        response_use: ResponseUse = .fresh,
                        replay_source_response_fingerprint: ?u64 = null,
                        replay_source_response_value_fingerprint: ?u64 = null,
                        allowed_response_refs: []const lowering_api.ValueRef = &.{},
                    },
                ) Error!Step {
                    if (self.last_treaty != null) return error.ProgramContractViolation;
                    const current_value = try session.current();
                    if (try inbox.nextResponse()) |response_value| {
                        var response = response_value;
                        defer response.deinit();
                        const request_included_capsule = self.last_request_included_capsule orelse options.capsule;
                        const request_journal_branch_id = self.activeRequestJournalBranchId(options.journal_branch_id);
                        const request_usage_metadata = self.activeRequestUsageMetadata(options.usage_metadata);
                        try validateCurrentRequestPolicy(options.allocator, session, current_value, options.policy, request_included_capsule, request_journal_branch_id, request_usage_metadata);
                        if (options.router) |router| try validateCurrentRequestPolicy(options.allocator, session, current_value, router.policy, request_included_capsule, request_journal_branch_id, request_usage_metadata);
                        try options.policy.validateResponse(response);
                        if (options.router) |router| try router.policy.validateResponse(response);
                        var response_authorized_checkpoint: ?JournalCheckpoint = null;
                        errdefer if (response_authorized_checkpoint) |checkpoint| checkpoint.ledger.truncateEntries(checkpoint.start_len);
                        var obligation_event_checkpoint: ?JournalCheckpoint = null;
                        errdefer if (obligation_event_checkpoint) |checkpoint| checkpoint.ledger.truncateEntries(checkpoint.start_len);
                        if (self.last_route) |route| {
                            var route_policy_report = validateRouteResponse(route, response);
                            route_policy_report.merge(validateRoutePolicies(route, options.router, options.policy));
                            var owned_current = try requestEnvelopeForCurrent(options.allocator, session, current_value, request_included_capsule, request_journal_branch_id, request_usage_metadata);
                            defer owned_current.deinit();
                            route_policy_report.merge(validateRouteCurrentPlan(route, options.router, options.policy, owned_current));
                            if (!route_policy_report.allowed()) {
                                if (options.journal) |ledger| try ledger.appendExchangeEvent(.{
                                    .kind = .response_rejected,
                                    .provider_fingerprint = route.provider_fingerprint,
                                    .capability_fingerprint = route.capability_fingerprint,
                                    .route_fingerprint = route.fingerprint,
                                    .request_envelope_fingerprint = route.request_envelope_fingerprint,
                                    .response_envelope_fingerprint = response.fingerprint,
                                    .blocker_tag = route_policy_report.firstTagName(),
                                });
                                return error.ProgramContractViolation;
                            }
                        } else {
                            var owned_current = try requestEnvelopeForCurrent(options.allocator, session, current_value, request_included_capsule, request_journal_branch_id, request_usage_metadata);
                            defer owned_current.deinit();
                            const unrouted_report = validateUnroutedResponsePlan(options.router, options.policy, owned_current);
                            if (!unrouted_report.allowed()) {
                                if (options.journal) |ledger| try ledger.appendExchangeEvent(.{
                                    .kind = .response_rejected,
                                    .request_envelope_fingerprint = owned_current.fingerprint,
                                    .response_envelope_fingerprint = response.fingerprint,
                                    .blocker_tag = unrouted_report.firstTagName(),
                                });
                                return error.ProgramContractViolation;
                            }
                        }
                        if (self.last_response_capability_required or responseCapabilityRequiredFor(options.router, options.policy)) {
                            const route = self.last_route orelse return error.ProgramContractViolation;
                            const router = options.router orelse return error.ProgramContractViolation;
                            const capability = router.capabilityByFingerprint(route.capability_fingerprint) orelse return error.ProgramContractViolation;
                            var owned_current = try requestEnvelopeForCurrent(options.allocator, session, current_value, request_included_capsule, request_journal_branch_id, request_usage_metadata);
                            defer owned_current.deinit();
                            var report = validateRoutedResponseCapability(route, capability.*, owned_current, response);
                            report.merge(validateRoutePolicies(route, options.router, options.policy));
                            if (!report.allowed()) {
                                if (options.journal) |ledger| try ledger.appendExchangeEvent(.{
                                    .kind = .response_rejected,
                                    .provider_fingerprint = route.provider_fingerprint,
                                    .capability_fingerprint = route.capability_fingerprint,
                                    .route_fingerprint = route.fingerprint,
                                    .request_envelope_fingerprint = route.request_envelope_fingerprint,
                                    .response_envelope_fingerprint = response.fingerprint,
                                    .blocker_tag = report.firstTagName(),
                                });
                                return error.ProgramContractViolation;
                            }
                            if (options.journal) |ledger| {
                                const start_len = ledger.entries.items.len;
                                try ledger.appendExchangeEvent(.{
                                    .kind = .response_authorized,
                                    .provider_fingerprint = route.provider_fingerprint,
                                    .capability_fingerprint = route.capability_fingerprint,
                                    .route_fingerprint = route.fingerprint,
                                    .authorization_fingerprint = response.authorization.?.authorization_fingerprint,
                                    .request_envelope_fingerprint = route.request_envelope_fingerprint,
                                    .response_envelope_fingerprint = response.fingerprint,
                                });
                                response_authorized_checkpoint = .{ .ledger = ledger, .start_len = start_len };
                            }
                        }
                        var pending_obligation: ?Obligation = null;
                        var pending_instance: ?CapabilityInstance = null;
                        errdefer if (pending_obligation) |*updated| updated.deinit();
                        errdefer if (pending_instance) |*updated| updated.deinit();
                        var pending_obligation_event: ?Session.Journal.ExchangeEvent = null;
                        if (options.obligation) |obligation_ptr| {
                            if (!obligation_ptr.*.validFingerprint()) return error.ProgramContractViolation;
                            try validateObligationResponseMetadata(obligation_ptr.*, request_usage_metadata, options.response_use);
                            if (obligation_ptr.*.capability_instance_fingerprint != null and options.capability_instance == null) return error.ProgramContractViolation;
                            if (options.capability_instance) |instance| {
                                if (!instance.*.validFingerprint()) return error.ProgramContractViolation;
                                const response_uses_replay = options.response_use == .replayed or options.response_use == .deterministic_replay;
                                if (!instanceCanAnswerObligation(instance.*, obligation_ptr.*, response_uses_replay)) return error.ProgramContractViolation;
                                if (instance.*.usage != obligation_ptr.*.usage) return error.ProgramContractViolation;
                                if (instance.*.branch_id != obligation_ptr.*.branch_id) return error.ProgramContractViolation;
                                if (obligation_ptr.*.provider_fingerprint) |fingerprint| {
                                    if (fingerprint != instance.*.provider_fingerprint) return error.ProgramContractViolation;
                                }
                                if (obligation_ptr.*.capability_instance_fingerprint) |fingerprint| {
                                    if (fingerprint != obligation_ptr.*.effect_session_instance_fingerprint) return error.ProgramContractViolation;
                                }
                            }
                            const response_has_open_obligation = false;
                            const branch_report = validateBranchPolicy(obligation_ptr.*.branch_policy, obligation_ptr.*.usage, options.response_use, response_has_open_obligation, request_included_capsule);
                            if (!branch_report.allowed()) return error.ProgramContractViolation;
                            var transition = switch (options.response_use) {
                                .fresh, .override => try obligation_ptr.*.consume(response, options.response_use),
                                .replayed, .deterministic_replay => try obligation_ptr.*.replayWithSourceValue(
                                    response,
                                    options.replay_source_response_fingerprint orelse return error.ProgramContractViolation,
                                    options.replay_source_response_value_fingerprint,
                                    options.response_use,
                                ),
                            };
                            if (options.effect_session_spec) |spec| {
                                transition = try advanceObligationTransitionWithSpec(spec, obligation_ptr.*, transition, response);
                                if (options.capability_instance) |instance| {
                                    if (instance.*.effect_session_spec_fingerprint != spec.fingerprint()) return error.ProgramContractViolation;
                                }
                            } else if (transition.capability_instance_consumed) {
                                return error.ProgramContractViolation;
                            }
                            const updated_obligation = try obligation_ptr.*.applyTransition(transition);
                            if (options.capability_instance) |instance| {
                                if (transition.capability_instance_consumed) {
                                    pending_instance = try instance.*.consumeWithState(response.fingerprint, transition.next_session_state);
                                } else if (options.effect_session_spec != null) {
                                    pending_instance = try instance.*.advanceState(transition.next_session_state);
                                }
                            }
                            const event_instance_fingerprint = if (pending_instance) |instance|
                                instance.instance_fingerprint
                            else if (options.capability_instance) |instance|
                                instance.instance_fingerprint
                            else
                                null;
                            pending_obligation = updated_obligation;
                            pending_obligation_event = .{
                                .kind = if (transition.next_obligation_status == .replayed) .obligation_replayed else .obligation_consumed,
                                .request_envelope_fingerprint = response.request_envelope_fingerprint,
                                .response_envelope_fingerprint = response.fingerprint,
                                .capability_instance_fingerprint = event_instance_fingerprint,
                                .obligation_fingerprint = transition.obligation_fingerprint,
                                .obligation_transition_fingerprint = transition.transition_fingerprint,
                                .branch_id = transition.branch_id,
                            };
                        }
                        if (options.journal) |ledger| {
                            if (pending_obligation_event) |event| {
                                const start_len = ledger.entries.items.len;
                                try ledger.appendExchangeEvent(event);
                                obligation_event_checkpoint = .{ .ledger = ledger, .start_len = start_len };
                            }
                        }
                        try applyResponse(session, response, .{
                            .request_envelope_fingerprint = self.last_request_envelope_fingerprint,
                            .request_manifest_fingerprint = self.last_request_manifest_fingerprint,
                        });
                        if (options.obligation) |obligation_ptr| {
                            if (pending_obligation) |updated| {
                                obligation_ptr.deinit();
                                obligation_ptr.* = updated;
                                pending_obligation = null;
                            }
                        }
                        if (options.capability_instance) |instance| {
                            if (pending_instance) |updated| {
                                instance.deinit();
                                instance.* = updated;
                                pending_instance = null;
                            }
                        }
                        self.last_request_fingerprint = null;
                        self.last_request_envelope_fingerprint = null;
                        self.last_request_manifest_fingerprint = null;
                        self.last_request_included_capsule = null;
                        self.last_request_usage_metadata = null;
                        self.clearLastRequestJournalBranch();
                        self.last_route = null;
                        self.clearLastTreaty();
                        self.last_response_capability_required = false;
                        return .running;
                    }
                    return switch (current_value) {
                        .request => |request| blk: {
                            const request_journal_branch_id = self.activeRequestJournalBranchId(options.journal_branch_id);
                            const request_usage_metadata = self.activeRequestUsageMetadata(options.usage_metadata);
                            var envelope = try requestEnvelopeForCurrent(options.allocator, session, .{ .request = request }, options.capsule, request_journal_branch_id, request_usage_metadata);
                            errdefer envelope.deinit();
                            try options.policy.validateRequest(envelope);
                            const response_capability_required = self.last_response_capability_required or
                                responseCapabilityRequiredFor(options.router, options.policy);
                            const route_refresh_required = routeRefreshRequiredFor(self.last_route, options.router, options.policy, envelope, self.last_response_capability_required, response_capability_required);
                            if (self.last_request_envelope_fingerprint != envelope.fingerprint or route_refresh_required) {
                                var owned_branch = try cloneJournalBranch(options.allocator, request_journal_branch_id);
                                errdefer if (owned_branch) |branch| options.allocator.free(branch);
                                self.last_route = try appendRouteAwareOutboxEnvelope(options.allocator, outbox, envelope, options.router, options.policy, options.journal, self.last_route != null, options.capability_instance, options.obligation, options.allowed_response_refs);
                                self.last_request_fingerprint = envelope.request_fingerprint;
                                self.last_request_envelope_fingerprint = envelope.fingerprint;
                                self.last_request_manifest_fingerprint = envelope.manifest_fingerprint;
                                self.last_request_included_capsule = options.capsule;
                                self.last_request_usage_metadata = request_usage_metadata;
                                self.adoptLastRequestJournalBranch(options.allocator, owned_branch);
                                owned_branch = null;
                                self.last_response_capability_required = response_capability_required;
                            } else {
                                self.last_response_capability_required = response_capability_required;
                            }
                            break :blk .{ .parked = envelope };
                        },
                        .after => |after| blk: {
                            const request_journal_branch_id = self.activeRequestJournalBranchId(options.journal_branch_id);
                            const request_usage_metadata = self.activeRequestUsageMetadata(options.usage_metadata);
                            var envelope = try requestEnvelopeForCurrent(options.allocator, session, .{ .after = after }, options.capsule, request_journal_branch_id, request_usage_metadata);
                            errdefer envelope.deinit();
                            try options.policy.validateRequest(envelope);
                            const response_capability_required = self.last_response_capability_required or
                                responseCapabilityRequiredFor(options.router, options.policy);
                            const route_refresh_required = routeRefreshRequiredFor(self.last_route, options.router, options.policy, envelope, self.last_response_capability_required, response_capability_required);
                            if (self.last_request_envelope_fingerprint != envelope.fingerprint or route_refresh_required) {
                                var owned_branch = try cloneJournalBranch(options.allocator, request_journal_branch_id);
                                errdefer if (owned_branch) |branch| options.allocator.free(branch);
                                self.last_route = try appendRouteAwareOutboxEnvelope(options.allocator, outbox, envelope, options.router, options.policy, options.journal, self.last_route != null, options.capability_instance, options.obligation, options.allowed_response_refs);
                                self.last_request_fingerprint = envelope.request_fingerprint;
                                self.last_request_envelope_fingerprint = envelope.fingerprint;
                                self.last_request_manifest_fingerprint = envelope.manifest_fingerprint;
                                self.last_request_included_capsule = options.capsule;
                                self.last_request_usage_metadata = request_usage_metadata;
                                self.adoptLastRequestJournalBranch(options.allocator, owned_branch);
                                owned_branch = null;
                                self.last_response_capability_required = response_capability_required;
                            } else {
                                self.last_response_capability_required = response_capability_required;
                            }
                            break :blk .{ .parked = envelope };
                        },
                        .none => switch (try session.next()) {
                            .request => |request| blk: {
                                var envelope = try requestEnvelopeForCurrent(options.allocator, session, .{ .request = request }, options.capsule, options.journal_branch_id, options.usage_metadata);
                                errdefer envelope.deinit();
                                try options.policy.validateRequest(envelope);
                                var owned_branch = try cloneJournalBranch(options.allocator, options.journal_branch_id);
                                errdefer if (owned_branch) |branch| options.allocator.free(branch);
                                const require_routed_result = self.last_route != null;
                                self.last_route = try appendRouteAwareOutboxEnvelope(options.allocator, outbox, envelope, options.router, options.policy, options.journal, require_routed_result, options.capability_instance, options.obligation, options.allowed_response_refs);
                                self.last_request_fingerprint = envelope.request_fingerprint;
                                self.last_request_envelope_fingerprint = envelope.fingerprint;
                                self.last_request_manifest_fingerprint = envelope.manifest_fingerprint;
                                self.last_request_included_capsule = options.capsule;
                                self.last_request_usage_metadata = options.usage_metadata;
                                self.adoptLastRequestJournalBranch(options.allocator, owned_branch);
                                owned_branch = null;
                                self.last_response_capability_required = responseCapabilityRequiredFor(options.router, options.policy);
                                break :blk .{ .parked = envelope };
                            },
                            .after => |after| blk: {
                                var envelope = try requestEnvelopeForCurrent(options.allocator, session, .{ .after = after }, options.capsule, options.journal_branch_id, options.usage_metadata);
                                errdefer envelope.deinit();
                                try options.policy.validateRequest(envelope);
                                var owned_branch = try cloneJournalBranch(options.allocator, options.journal_branch_id);
                                errdefer if (owned_branch) |branch| options.allocator.free(branch);
                                const require_routed_result = self.last_route != null;
                                self.last_route = try appendRouteAwareOutboxEnvelope(options.allocator, outbox, envelope, options.router, options.policy, options.journal, require_routed_result, options.capability_instance, options.obligation, options.allowed_response_refs);
                                self.last_request_fingerprint = envelope.request_fingerprint;
                                self.last_request_envelope_fingerprint = envelope.fingerprint;
                                self.last_request_manifest_fingerprint = envelope.manifest_fingerprint;
                                self.last_request_included_capsule = options.capsule;
                                self.last_request_usage_metadata = options.usage_metadata;
                                self.adoptLastRequestJournalBranch(options.allocator, owned_branch);
                                owned_branch = null;
                                self.last_response_capability_required = responseCapabilityRequiredFor(options.router, options.policy);
                                break :blk .{ .parked = envelope };
                            },
                            .done => |result| .{ .done = result },
                        },
                    };
                }
            };

            /// Apply a validated response envelope to the current parked session request.
            pub fn applyResponse(session: *Session, response: ResponseEnvelope, options: ResponseOptions) Error!void {
                const current_value = try session.current();
                const request_envelope = switch (current_value) {
                    .request => |request| try RequestEnvelope.fromRequest(response.allocator, request, .{}),
                    .after => |after| try RequestEnvelope.fromAfter(response.allocator, after, .{}),
                    .none => return error.ProgramContractViolation,
                };
                var owned_request = request_envelope;
                defer owned_request.deinit();
                try validateResponseForCurrentRequest(response, owned_request, options.request_envelope_fingerprint, options.request_manifest_fingerprint);
                const response_trace: Session.Trace.Response = .{
                    .request_fingerprint = response.request_fingerprint,
                    .kind = response.kind,
                    .response_ref = response.response_ref,
                    .response_value_fingerprint = response.response_value_fingerprint,
                    .fingerprint = response.response_trace_fingerprint,
                };
                const journal_checkpoint = if (options.journal) |journal| checkpoint: {
                    const start_len = journal.entries.items.len;
                    try journal.appendValidatedResponseValueImage(response_trace, response.value_image);
                    break :checkpoint .{ .journal = journal, .start_len = start_len };
                } else null;
                errdefer if (journal_checkpoint) |checkpoint| checkpoint.journal.truncateEntries(checkpoint.start_len);
                try applyResponseValue(session, current_value, response);
            }

            fn validateResponseForCurrentRequest(response: ResponseEnvelope, request: RequestEnvelope, request_envelope_fingerprint: ?u64, request_manifest_fingerprint: ?u64) Error!void {
                try request.validate();
                if (response.request_envelope_fingerprint != (request_envelope_fingerprint orelse request.fingerprint)) return error.ProgramContractViolation;
                if (response.manifest_fingerprint != (request_manifest_fingerprint orelse request.manifest_fingerprint)) return error.ProgramContractViolation;
                if (response.request_fingerprint != request.request_fingerprint) return error.ProgramContractViolation;
                try validateResponseEnvelopeFieldsBoundToBytes(response);
                const expected_ref = try expectedResponseRef(request, response.kind);
                if (!response.response_ref.eql(expected_ref)) return error.ProgramContractViolation;
                const trace = responseTraceFromEnvelope(request.request_fingerprint, response.kind, response.response_ref, response.response_value_fingerprint);
                if (trace.fingerprint != response.response_trace_fingerprint) return error.ProgramContractViolation;
                try validateExchangeValueImage(response.allocator, response.response_ref, response.response_value_fingerprint, response.value_image);
            }

            /// Validate a capability grant against a request envelope and provider manifest.
            pub fn validateRequestCapability(capability: Capability, provider: ProviderManifest, request: RequestEnvelope) ValidationReport {
                request.validate() catch {
                    var invalid: ValidationReport = .{};
                    invalid.add(.invalid_envelope);
                    return invalid;
                };
                var report = validateCapabilityRequestScope(capability, request);
                if (!providerFieldsBoundToBytes(provider)) report.add(.wrong_provider);
                if (provider.provider_fingerprint != capability.provider_fingerprint) report.add(.wrong_provider);
                if (!provider.supportsRequest(request)) report.add(switch (request.kind) {
                    .operation => .operation_site,
                    .after => .after_site,
                });
                if (request.bytes.len > provider.max_request_envelope_bytes) report.add(.request_too_large);
                if (request.capsule_image != null and !provider.accepts_embedded_capsules) report.add(.embedded_capsule);
                const allowed_response_kinds = allowedResponseKindsForRequest(request, provider, capability, .{});
                addResponseViabilityBlockers(&report, request, allowed_response_kinds, capability.allowed_response_refs);
                return report;
            }

            fn validateCapabilityRequestScope(capability: Capability, request: RequestEnvelope) ValidationReport {
                const protocol_op_fingerprint = requestProtocolOperationFingerprint(request) orelse {
                    var report: ValidationReport = .{};
                    report.add(.invalid_envelope);
                    return report;
                };
                return validateCapabilityRequestScopeForProtocol(capability, request, protocol_op_fingerprint);
            }

            fn validateCapabilityRequestScopeForProtocol(capability: Capability, request: RequestEnvelope, protocol_op_fingerprint: u64) ValidationReport {
                var report: ValidationReport = .{};
                request.validate() catch {
                    report.add(.invalid_envelope);
                    return report;
                };
                if (!capabilityFieldsBoundToBytes(capability)) report.add(.wrong_capability);
                const requirement_label = requestRequirementLabel(request) orelse {
                    report.add(.invalid_envelope);
                    return report;
                };
                if (request.manifest_fingerprint != capability.manifest_fingerprint) report.add(.wrong_manifest);
                if (!capability.allowed_request_kinds.allows(request.kind)) report.add(.request_kind);
                if (capability.expires_at_generation) |expires_at| {
                    if (request.turn_index >= expires_at) report.add(.expired_capability);
                }
                if (!listAllowsString(capability.allowed_program_labels, request.program_label)) report.add(.wrong_program_label);
                if (!listAllowsU64(capability.allowed_plan_hashes, request.plan_hash)) report.add(.wrong_plan_hash);
                if (capability.journal_policy_fingerprint) |expected_policy| {
                    const branch_id = request.journal_branch_id orelse {
                        report.add(.wrong_journal_policy);
                        return report;
                    };
                    if (journalBranchPolicyFingerprint(branch_id) != expected_policy) report.add(.wrong_journal_policy);
                }
                switch (request.kind) {
                    .operation => if (!listAllowsUsize(capability.allowed_operation_sites, request.site_index)) report.add(.operation_site),
                    .after => if (!listAllowsUsize(capability.allowed_after_sites, request.site_index)) report.add(.after_site),
                }
                if (!listAllowsU64(capability.allowed_protocol_op_fingerprints, protocol_op_fingerprint)) report.add(.protocol_operation);
                if (!listAllowsString(capability.allowed_requirement_labels, requirement_label)) report.add(.protocol_operation);
                if (!listAllowsString(capability.allowed_op_names, request.name)) report.add(.protocol_operation);
                if (request.bytes.len > capability.max_request_bytes) report.add(.request_too_large);
                if (request.value_image.len > capability.max_payload_bytes) report.add(.payload_too_large);
                if (request.capsule_image) |image| {
                    if (!capability.allow_embedded_capsule_response_handling) report.add(.embedded_capsule);
                    if (image.len > capability.max_capsule_image_bytes) report.add(.capsule_too_large);
                }
                return report;
            }

            fn validateCapabilityMorphismTargetScope(capability: Capability, request: RequestEnvelope, target_protocol_op_fingerprint: u64) ValidationReport {
                var report: ValidationReport = .{};
                request.validate() catch {
                    report.add(.invalid_envelope);
                    return report;
                };
                if (!capabilityFieldsBoundToBytes(capability)) report.add(.wrong_capability);
                if (request.manifest_fingerprint != capability.manifest_fingerprint) report.add(.wrong_manifest);
                if (!capability.allowed_request_kinds.allows(request.kind)) report.add(.request_kind);
                if (capability.expires_at_generation) |expires_at| {
                    if (request.turn_index >= expires_at) report.add(.expired_capability);
                }
                if (!listAllowsString(capability.allowed_program_labels, request.program_label)) report.add(.wrong_program_label);
                if (!listAllowsU64(capability.allowed_plan_hashes, request.plan_hash)) report.add(.wrong_plan_hash);
                if (capability.journal_policy_fingerprint) |expected_policy| {
                    const branch_id = request.journal_branch_id orelse {
                        report.add(.wrong_journal_policy);
                        return report;
                    };
                    if (journalBranchPolicyFingerprint(branch_id) != expected_policy) report.add(.wrong_journal_policy);
                }
                if (capability.allowed_protocol_op_fingerprints.len == 0 and
                    (capability.allowed_requirement_labels.len != 0 or capability.allowed_op_names.len != 0))
                {
                    report.add(.protocol_operation);
                }
                switch (request.kind) {
                    .operation => if (!listAllowsUsize(capability.allowed_operation_sites, request.site_index)) report.add(.operation_site),
                    .after => if (!listAllowsUsize(capability.allowed_after_sites, request.site_index)) report.add(.after_site),
                }
                if (!listAllowsU64(capability.allowed_protocol_op_fingerprints, target_protocol_op_fingerprint)) report.add(.protocol_operation);
                if (request.bytes.len > capability.max_request_bytes) report.add(.request_too_large);
                if (request.value_image.len > capability.max_payload_bytes) report.add(.payload_too_large);
                if (request.capsule_image) |image| {
                    if (!capability.allow_embedded_capsule_response_handling) report.add(.embedded_capsule);
                    if (image.len > capability.max_capsule_image_bytes) report.add(.capsule_too_large);
                }
                return report;
            }

            fn validateProviderMorphismTargetScope(provider: ProviderManifest, request: RequestEnvelope, target_protocol_op_fingerprint: u64) ValidationReport {
                var report: ValidationReport = .{};
                request.validate() catch {
                    report.add(.invalid_envelope);
                    return report;
                };
                if (!providerFieldsBoundToBytes(provider)) report.add(.wrong_provider);
                if (!listAllowsU64(provider.supported_program_manifest_fingerprints, request.manifest_fingerprint)) report.add(.wrong_manifest);
                const operation_sites_constrained = provider.supported_operation_sites.len != 0;
                const after_sites_constrained = provider.supported_after_sites.len != 0;
                switch (request.kind) {
                    .operation => {
                        if (!operation_sites_constrained and after_sites_constrained) report.add(.operation_site);
                        if (operation_sites_constrained and !listAllowsUsize(provider.supported_operation_sites, request.site_index)) report.add(.operation_site);
                    },
                    .after => {
                        if (!after_sites_constrained and operation_sites_constrained) report.add(.after_site);
                        if (after_sites_constrained and !listAllowsUsize(provider.supported_after_sites, request.site_index)) report.add(.after_site);
                    },
                }
                if (provider.supported_protocol_op_fingerprints.len == 0 and provider.supported_protocol_labels.len != 0) report.add(.protocol_operation);
                if (!listAllowsU64(provider.supported_protocol_op_fingerprints, target_protocol_op_fingerprint)) report.add(.protocol_operation);
                if (request.bytes.len > provider.max_request_envelope_bytes) report.add(.request_too_large);
                if (request.capsule_image != null and !provider.accepts_embedded_capsules) report.add(.embedded_capsule);
                return report;
            }

            fn validatePolicyRequestScope(policy: Policy, request: RequestEnvelope) ValidationReport {
                var report: ValidationReport = .{};
                if (request.bytes.len > policy.max_envelope_bytes) report.add(.request_too_large);
                if (request.value_image.len > policy.max_payload_bytes) report.add(.payload_too_large);
                if (request.capsule_image != null and !policy.allow_capsules) report.add(.embedded_capsule);
                if (request.capsule_image) |image| {
                    if (image.len > (policy.max_capsule_image_bytes orelse policy.max_payload_bytes)) report.add(.capsule_too_large);
                }
                if (policy.usage) |usage_value| {
                    if (request.usage_metadata == null or request.usage_metadata.?.usage != usage_value) report.add(.usage_mode);
                }
                if (request.usage_metadata) |metadata| {
                    if ((metadata.ephemeral or metadata.usage == .ephemeral) and request.capsule_image != null) report.add(.embedded_capsule);
                    if (metadata.branch_policy == .no_branch and request.capsule_image != null) report.add(.branch_policy);
                    if (policy.branch_policy) |policy_value| {
                        if (metadata.branch_policy != policy_value) report.add(.branch_policy);
                    }
                    if (policy.replay_policy) |policy_value| {
                        if (metadata.replay_policy != policy_value) report.add(.replay_policy);
                    }
                } else {
                    if (policy.branch_policy != null) report.add(.branch_policy);
                    if (policy.replay_policy != null) report.add(.replay_policy);
                }
                switch (request.kind) {
                    .operation => if (!Policy.policyAllowsSite(policy.allowed_operation_sites, request.site_index)) report.add(.operation_site),
                    .after => if (!Policy.policyAllowsSite(policy.allowed_after_sites, request.site_index)) report.add(.after_site),
                }
                return report;
            }

            /// Validate a response envelope's sidecar authorization against a capability and request.
            pub fn validateResponseCapability(capability: Capability, request: RequestEnvelope, response: ResponseEnvelope) ValidationReport {
                var report = validateCapabilityRequestScope(capability, request);
                request.validate() catch {
                    report.add(.invalid_envelope);
                    return report;
                };
                response.validateForRequest(request) catch {
                    report.add(.invalid_envelope);
                    return report;
                };
                const authorization = response.authorization orelse {
                    report.add(.missing_capability_fingerprint);
                    return report;
                };
                if (authorization.capability_fingerprint != capability.fingerprint) report.add(.wrong_capability);
                if (authorization.provider_fingerprint != capability.provider_fingerprint) report.add(.wrong_provider);
                if (authorization.capability_path_fingerprint != capability.attenuation_path_fingerprint) report.add(.wrong_capability_path);
                if (authorization.request_envelope_fingerprint != request.fingerprint) report.add(.wrong_request);
                if (authorization.response_envelope_fingerprint != response.fingerprint) report.add(.wrong_request);
                if (authorization.authorization_fingerprint != fingerprintAuthorization(authorization)) report.add(.wrong_capability);
                if (response.manifest_fingerprint != capability.manifest_fingerprint) report.add(.wrong_manifest);
                if (!capability.allowed_response_kinds.allows(response.kind)) report.add(.response_kind);
                if (!listAllowsValueRef(capability.allowed_response_refs, response.response_ref)) report.add(.response_ref);
                if (response.bytes.len > capability.max_response_bytes) report.add(.response_too_large);
                if (response.value_image.len > capability.max_payload_bytes) report.add(.payload_too_large);
                return report;
            }

            /// Validate a response envelope against a selected treaty and treaty authorization sidecar.
            pub fn validateTreatyResponse(treaty: Treaty, request: RequestEnvelope, response: ResponseEnvelope) Treaty.BlockerList {
                return validateTreatyResponseWithPolicy(treaty, request, response, .{
                    .require_least_authority = false,
                    .require_treaty_bound_response_authorization = false,
                });
            }

            /// Validate a response envelope against a selected treaty with explicit treaty policy.
            pub fn validateTreatyResponseWithPolicy(treaty: Treaty, request: RequestEnvelope, response: ResponseEnvelope, policy: Treaty.Policy) Treaty.BlockerList {
                var blockers: Treaty.BlockerList = .{ .request_format_version = request.request_format_version };
                if (treaty.route.fingerprint != fingerprintRoute(treaty.route)) {
                    blockers.addTag(.wrong_route, request.fingerprint, "route fingerprint does not match route fields");
                    return blockers;
                }
                if (treaty.fingerprint != fingerprintTreatyCore(treaty)) {
                    blockers.addTag(.wrong_treaty, request.fingerprint, "treaty fingerprint does not match treaty fields");
                    return blockers;
                }
                if (treaty.request_envelope_format_version != request.request_format_version) {
                    blockers.addTag(.wrong_treaty, request.fingerprint, "treaty cites a different request envelope format");
                    return blockers;
                }
                treaty.checkCertificate() catch {
                    blockers.addTag(.wrong_certificate, request.fingerprint, "treaty certificate is invalid");
                    return blockers;
                };
                response.validateForRequest(request) catch {
                    blockers.addTag(.wrong_treaty, request.fingerprint, "response does not match treaty request envelope");
                    return blockers;
                };
                if (treaty.request_envelope_fingerprint != request.fingerprint) blockers.addTag(.wrong_treaty, request.fingerprint, "request envelope fingerprint differs from treaty");
                if (treaty.route.request_envelope_fingerprint != request.fingerprint) blockers.addTag(.wrong_route, request.fingerprint, "route does not match treaty request");
                if (response.bytes.len > treaty.route.max_response_bytes) blockers.addTag(.wrong_treaty, request.fingerprint, "response exceeds treaty route byte limit");
                if (response.value_image.len > treaty.route.max_payload_bytes) blockers.addTag(.wrong_treaty, request.fingerprint, "response payload exceeds treaty route payload limit");
                if (!treaty.expected_response_kinds.allows(response.kind)) blockers.addTag(.wrong_response_kind, request.fingerprint, "response kind not admitted by treaty");
                if (!listAllowsValueRef(treaty.expected_response_refs, response.response_ref)) blockers.addTag(.wrong_response_kind, request.fingerprint, "response ref not admitted by treaty");
                if (request.bytes.len > policy.max_envelope_bytes or response.bytes.len > policy.max_envelope_bytes) blockers.addTag(.wrong_treaty, request.fingerprint, "request or response exceeds current treaty byte policy");
                if (request.capsule_image) |image| {
                    if (policy.disallow_capsule_export or image.len > policy.max_capsule_bytes) blockers.addTag(.capsule_export_disallowed, request.fingerprint, "request capsule violates current treaty policy");
                } else if (policy.require_capsule_embedding) {
                    blockers.addTag(.capsule_export_disallowed, request.fingerprint, "current treaty policy requires an embedded capsule");
                }
                if (!policy.allowed_usage_modes.allows(treaty.usage)) blockers.addTag(.usage_mode_not_allowed, request.fingerprint, "treaty usage mode violates current policy");
                if (!policy.allowed_response_uses.allows(treaty.response_use)) blockers.addTag(.response_use_incompatible, request.fingerprint, "treaty response-use violates current policy");
                if (!policy.allowed_branch_policies.allows(treaty.branch_policy)) blockers.addTag(.branch_policy_incompatible, request.fingerprint, "treaty branch policy violates current policy");
                if (!providerOfferTagsAllowPolicy(policy, treaty.certificate.provider_offer_tags)) blockers.addTag(.wrong_provider, request.fingerprint, "current treaty tag policy rejects provider offer tags");
                if (policy.disallow_fresh_response and treaty.response_use == .fresh) blockers.addTag(.replay_policy_incompatible, request.fingerprint, "current treaty policy disallows fresh responses");
                if (policy.require_replay_only_response and treaty.response_use != .replayed and treaty.response_use != .deterministic_replay) blockers.addTag(.replay_policy_incompatible, request.fingerprint, "current treaty policy requires replay-only responses");
                if (policy.require_obligation_opening and treaty.obligation_fingerprint == null) blockers.addTag(.obligation_open_failed, request.fingerprint, "current treaty policy requires an opened obligation");
                if ((policy.require_capability_attenuation or policy.require_least_authority) and treaty.attenuated_capability == null) blockers.addTag(.capability_too_broad_when_attenuation_required, request.fingerprint, "current treaty policy requires capability attenuation");
                switch (treaty.handling) {
                    .direct => if (!policy.allow_direct_handling) blockers.addTag(.no_provider_offer, request.fingerprint, "current treaty policy disallows direct handling"),
                    .dynamic_morphism => {
                        if (!policy.allow_morphism_adaptation) blockers.addTag(.morphism_missing, request.fingerprint, "current treaty policy disallows morphism adaptation");
                        if (policy.max_morphism_hops == 0) blockers.addTag(.max_morphism_hops_exceeded, request.fingerprint, "current treaty policy disallows morphism hops");
                        if (!policy.allow_dynamic_interpretation) blockers.addTag(.dynamic_morphism_disallowed, request.fingerprint, "current treaty policy disallows dynamic morphism handling");
                    },
                    .residualized, .pipeline_adapted => {
                        if (!policy.allow_morphism_adaptation) blockers.addTag(.morphism_missing, request.fingerprint, "current treaty policy disallows morphism adaptation");
                        if (policy.max_morphism_hops == 0) blockers.addTag(.max_morphism_hops_exceeded, request.fingerprint, "current treaty policy disallows morphism hops");
                        if (!policy.allow_residualization) blockers.addTag(.residualization_unsupported, request.fingerprint, "current treaty policy disallows residualized handling");
                    },
                }
                const treaty_response_is_replay = treaty.response_use == .replayed or treaty.response_use == .deterministic_replay;
                const authorization = response.treaty_authorization orelse {
                    if (treaty.require_treaty_bound_response_authorization or policy.require_treaty_bound_response_authorization) {
                        blockers.addTag(.wrong_treaty, request.fingerprint, "missing treaty authorization sidecar");
                    }
                    if (treaty_response_is_replay and treaty.obligation_fingerprint == null) {
                        blockers.addTag(.replay_policy_incompatible, request.fingerprint, "non-obligation replay treaty response requires a distinct recorded source response witness");
                    }
                    return blockers;
                };
                switch (authorization.format_version) {
                    2 => {
                        if (authorization.authorization_fingerprint != fingerprintTreatyAuthorizationV2(authorization)) blockers.addTag(.wrong_treaty, request.fingerprint, "treaty authorization fingerprint mismatch");
                    },
                    3 => {
                        if (authorization.authorization_fingerprint != fingerprintTreatyAuthorizationV3(authorization)) blockers.addTag(.wrong_treaty, request.fingerprint, "treaty authorization fingerprint mismatch");
                        if (authorization.provider_fingerprint != treaty.provider_fingerprint) blockers.addTag(.wrong_provider, request.fingerprint, "authorization cites a different provider");
                        if (authorization.capability_fingerprint != treaty.capability_fingerprint) blockers.addTag(.wrong_capability, request.fingerprint, "authorization cites a different capability");
                        if (authorization.capability_path_fingerprint != treaty.capability_path_fingerprint) blockers.addTag(.wrong_capability, request.fingerprint, "authorization cites a different capability path");
                        if (authorization.request_envelope_fingerprint != request.fingerprint) blockers.addTag(.wrong_treaty, request.fingerprint, "authorization cites a different request envelope");
                    },
                    exchange_treaty_authorization_fingerprint_version => {
                        if (authorization.authorization_fingerprint != fingerprintTreatyAuthorization(authorization)) blockers.addTag(.wrong_treaty, request.fingerprint, "treaty authorization fingerprint mismatch");
                        if (authorization.provider_fingerprint != treaty.provider_fingerprint) blockers.addTag(.wrong_provider, request.fingerprint, "authorization cites a different provider");
                        if (authorization.capability_fingerprint != treaty.capability_fingerprint) blockers.addTag(.wrong_capability, request.fingerprint, "authorization cites a different capability");
                        if (authorization.capability_path_fingerprint != treaty.capability_path_fingerprint) blockers.addTag(.wrong_capability, request.fingerprint, "authorization cites a different capability path");
                        if (authorization.request_envelope_fingerprint != request.fingerprint) blockers.addTag(.wrong_treaty, request.fingerprint, "authorization cites a different request envelope");
                        if (authorization.request_envelope_format_version != request.request_format_version) blockers.addTag(.wrong_treaty, request.fingerprint, "authorization cites a different request envelope format");
                    },
                    else => blockers.addTag(.wrong_treaty, request.fingerprint, "unknown treaty authorization format"),
                }
                if (!authorizationTreatyFingerprintMatches(authorization, treaty)) blockers.addTag(.wrong_treaty, request.fingerprint, "authorization cites a different treaty");
                if (!authorizationCertificateFingerprintMatches(authorization, treaty.certificate)) blockers.addTag(.wrong_certificate, request.fingerprint, "authorization cites a different treaty certificate");
                if (authorization.provider_offer_fingerprint != treaty.provider_offer_fingerprint) blockers.addTag(.wrong_provider, request.fingerprint, "authorization cites a different provider offer");
                if (authorization.attenuated_capability_fingerprint != treaty.certificate.attenuated_capability_fingerprint) blockers.addTag(.wrong_capability, request.fingerprint, "authorization cites a different attenuated capability");
                if (authorization.capability_instance_fingerprint != treaty.capability_instance_fingerprint) blockers.addTag(.capability_instance_wrong_branch, request.fingerprint, "authorization cites a different capability instance");
                if (authorization.obligation_fingerprint != treaty.obligation_fingerprint) blockers.addTag(.obligation_state_incompatible, request.fingerprint, "authorization cites a different obligation");
                if (authorization.expected_obligation_transition_fingerprint != null and treaty.obligation_fingerprint == null) blockers.addTag(.obligation_state_incompatible, request.fingerprint, "authorization cites an obligation transition for a non-obligation treaty");
                const replay_response = authorization.response_use == .replayed or authorization.response_use == .deterministic_replay;
                if (replay_response and treaty.obligation_fingerprint == null) {
                    const source_response = authorization.replay_source_response_fingerprint orelse 0;
                    const source_value = authorization.replay_source_response_value_fingerprint orelse 0;
                    if (source_response == 0 or source_response == response.fingerprint or source_value != response.response_value_fingerprint) {
                        blockers.addTag(.replay_policy_incompatible, request.fingerprint, "non-obligation replay treaty response requires a distinct recorded source response witness");
                    }
                } else if (!replay_response and (authorization.replay_source_response_fingerprint != null or authorization.replay_source_response_value_fingerprint != null)) {
                    blockers.addTag(.replay_policy_incompatible, request.fingerprint, "fresh treaty response cites a replay source");
                }
                if (authorization.route_fingerprint != treaty.route.fingerprint) blockers.addTag(.wrong_route, request.fingerprint, "authorization cites a different route");
                if (authorization.response_envelope_fingerprint != response.fingerprint) blockers.addTag(.wrong_treaty, request.fingerprint, "authorization cites a different response envelope");
                if (authorization.usage != treaty.usage) blockers.addTag(.usage_mode_not_allowed, request.fingerprint, "authorization usage mode differs from treaty");
                if (authorization.response_use != treaty.response_use) blockers.addTag(.response_use_incompatible, request.fingerprint, "authorization response-use differs from treaty");
                if (authorization.replay_policy != treaty.replay_policy) blockers.addTag(.replay_policy_incompatible, request.fingerprint, "authorization replay policy differs from treaty");
                if (authorization.branch_policy != treaty.branch_policy) blockers.addTag(.branch_policy_incompatible, request.fingerprint, "authorization branch policy differs from treaty");
                return blockers;
            }

            /// Validate a response sidecar against the exact selected route and request authority.
            pub fn validateRoutedResponseCapability(route: Route, capability: Capability, request: RequestEnvelope, response: ResponseEnvelope) ValidationReport {
                var report = validateResponseCapability(capability, request, response);
                if (route.fingerprint != fingerprintRoute(route)) report.add(.wrong_route);
                for (route.blockers.blockers[0..route.blockers.count]) |blocker| report.add(blocker);
                const authorization = response.authorization orelse return report;
                if (route.capability_fingerprint != capability.fingerprint) report.add(.wrong_capability);
                if (route.request_envelope_fingerprint != request.fingerprint) report.add(.wrong_request);
                if (authorization.route_fingerprint != route.fingerprint) report.add(.wrong_route);
                if (!route.allowed_response_kinds.allows(response.kind)) report.add(.response_kind);
                if (response.bytes.len > route.max_response_bytes) report.add(.response_too_large);
                if (response.value_image.len > route.max_payload_bytes) report.add(.payload_too_large);
                return report;
            }

            /// Validate response capability and consume/replay an obligation in one deterministic result.
            pub fn authorizeObligationResponse(
                route: Route,
                capability: Capability,
                instance: CapabilityInstance,
                obligation: Obligation,
                spec: EffectSessionSpec,
                request: RequestEnvelope,
                response: ResponseEnvelope,
                use_value: ResponseUse,
            ) Error!AuthorizationResult {
                return authorizeObligationResponseWithReplaySource(route, capability, instance, obligation, spec, request, response, use_value, null);
            }

            /// Validate response capability and consume/replay an obligation, requiring a recorded source for replay.
            pub fn authorizeObligationResponseWithReplaySource(
                route: Route,
                capability: Capability,
                instance: CapabilityInstance,
                obligation: Obligation,
                spec: EffectSessionSpec,
                request: RequestEnvelope,
                response: ResponseEnvelope,
                use_value: ResponseUse,
                replay_source_response_fingerprint: ?u64,
            ) Error!AuthorizationResult {
                return authorizeObligationResponseWithReplaySourceValue(route, capability, instance, obligation, spec, request, response, use_value, replay_source_response_fingerprint, null);
            }

            /// Validate response capability and consume/replay an obligation, allowing branch-local replay with a source value witness.
            pub fn authorizeObligationResponseWithReplaySourceValue(
                route: Route,
                capability: Capability,
                instance: CapabilityInstance,
                obligation: Obligation,
                spec: EffectSessionSpec,
                request: RequestEnvelope,
                response: ResponseEnvelope,
                use_value: ResponseUse,
                replay_source_response_fingerprint: ?u64,
                replay_source_response_value_fingerprint: ?u64,
            ) Error!AuthorizationResult {
                try spec.validate();
                if (!instance.validFingerprint()) return error.ProgramContractViolation;
                if (!obligation.validFingerprint()) return error.ProgramContractViolation;
                const spec_fingerprint = spec.fingerprint();
                if (instance.parent_capability_fingerprint != capability.fingerprint) return error.ProgramContractViolation;
                if (instance.effect_session_spec_fingerprint != spec_fingerprint) return error.ProgramContractViolation;
                const response_uses_replay = use_value == .replayed or use_value == .deterministic_replay;
                if (!instanceCanAnswerObligation(instance, obligation, response_uses_replay)) return error.ProgramContractViolation;
                if (instance.provider_fingerprint != capability.provider_fingerprint) return error.ProgramContractViolation;
                if (instance.usage != obligation.usage) return error.ProgramContractViolation;
                if (instance.branch_id != obligation.branch_id) return error.ProgramContractViolation;
                if (instance.replay_policy != obligation.replay_policy) return error.ProgramContractViolation;
                if (obligation.provider_fingerprint) |provider_fingerprint| {
                    if (provider_fingerprint != instance.provider_fingerprint) return error.ProgramContractViolation;
                }
                if (obligation.capability_instance_fingerprint) |instance_fingerprint| {
                    if (instance_fingerprint != obligation.effect_session_instance_fingerprint) return error.ProgramContractViolation;
                }
                if (request.fingerprint != obligation.request_envelope_fingerprint) return error.ProgramContractViolation;
                if (response.request_envelope_fingerprint != request.fingerprint) return error.ProgramContractViolation;
                if (!obligationReplayPolicyAllows(obligation.status, obligation.branch_policy, spec.replay_policy, use_value)) return error.ProgramContractViolation;
                if (request.usage_metadata) |metadata| {
                    if (metadata.effect_session_spec_fingerprint) |fingerprint| {
                        if (fingerprint != spec_fingerprint) return error.ProgramContractViolation;
                    }
                    if (metadata.capability_instance_fingerprint) |fingerprint| {
                        if (fingerprint != instance.requestMetadataInstanceFingerprint(request.request_fingerprint, obligation.state_at_open)) return error.ProgramContractViolation;
                    }
                    if (metadata.obligation_fingerprint) |fingerprint| {
                        if (fingerprint != obligation.obligation_fingerprint) return error.ProgramContractViolation;
                    }
                    if (metadata.usage != obligation.usage or metadata.branch_id != obligation.branch_id) return error.ProgramContractViolation;
                    if (metadata.branch_policy != obligation.branch_policy) return error.ProgramContractViolation;
                    if (!obligationReplayPolicyAllows(obligation.status, obligation.branch_policy, obligation.replay_policy, metadata.replay_policy)) return error.ProgramContractViolation;
                    if (!obligationReplayPolicyAllows(obligation.status, obligation.branch_policy, metadata.replay_policy, use_value)) return error.ProgramContractViolation;
                }
                var report = validateRoutedResponseCapability(route, capability, request, response);
                const response_has_open_obligation = false;
                const branch_report = validateBranchPolicy(instance.branch_policy, obligation.usage, use_value, response_has_open_obligation, request.capsule_image != null);
                for (branch_report.blockers[0..branch_report.count]) |blocker| report.add(blocker);
                if (!report.allowed()) return error.ProgramContractViolation;
                var transition = switch (use_value) {
                    .fresh, .override => try obligation.consume(response, use_value),
                    .replayed, .deterministic_replay => try obligation.replayWithSourceValue(
                        response,
                        replay_source_response_fingerprint orelse return error.ProgramContractViolation,
                        replay_source_response_value_fingerprint,
                        use_value,
                    ),
                };
                transition = try advanceObligationTransitionWithSpec(spec, obligation, transition, response);
                const authorization = response.authorization orelse return error.ProgramContractViolation;
                var result = AuthorizationResult{
                    .authorization_fingerprint = authorization.authorization_fingerprint,
                    .obligation_transition_fingerprint = transition.transition_fingerprint,
                    .capability_instance_fingerprint = instance.instance_fingerprint,
                    .previous_obligation_status = transition.previous_obligation_status,
                    .next_obligation_status = transition.next_obligation_status,
                    .previous_session_state = transition.previous_session_state,
                    .next_session_state = transition.next_session_state,
                    .response_use = transition.response_use,
                    .response_fingerprint = transition.response_fingerprint orelse return error.ProgramContractViolation,
                    .replay_source_response_fingerprint = transition.replay_source_response_fingerprint,
                    .capability_instance_consumed = transition.capability_instance_consumed,
                    .branch_remains_open = transition.branch_remains_open,
                };
                result.result_fingerprint = fingerprintAuthorizationResult(result);
                return result;
            }

            fn advanceObligationTransitionWithSpec(
                spec: EffectSessionSpec,
                obligation: Obligation,
                transition: ObligationTransition,
                response: ResponseEnvelope,
            ) Error!ObligationTransition {
                try spec.validate();
                var advanced = transition;
                const response_start_state = (try spec.requestTarget(obligation.state_at_open, obligation.site_fingerprint)) orelse obligation.state_at_open;
                advanced.previous_session_state = response_start_state;
                advanced.next_session_state = try spec.responseTarget(response_start_state, response.kind, response.response_ref, obligation.site_fingerprint);
                advanced.transition_fingerprint = 0;
                advanced.transition_fingerprint = fingerprintObligationTransition(advanced);
                return advanced;
            }

            /// Validate whether a branch action is allowed for an obligation policy.
            pub fn validateBranchPolicy(policy_value: BranchPolicy, usage: Usage, response_use: ResponseUse, has_open_obligation: bool, has_capsule_image: bool) ValidationReport {
                var report: ValidationReport = .{};
                switch (policy_value) {
                    .unrestricted => {},
                    .replay_only => if (response_use == .fresh or response_use == .override) report.add(.replay_policy),
                    .single_live_branch => {},
                    .split_required => if (has_open_obligation) report.add(.branch_policy),
                    .no_branch => if (has_open_obligation or has_capsule_image) report.add(.branch_policy),
                    .host_owned => {},
                }
                if (usage == .ephemeral and has_capsule_image) report.add(.embedded_capsule);
                return report;
            }

            fn validateObligationResponseMetadata(obligation: Obligation, metadata: ?RequestUsageMetadata, response_use: ResponseUse) Error!void {
                if (metadata) |value| {
                    if (value.obligation_fingerprint) |fingerprint| {
                        if (fingerprint != obligation.obligation_fingerprint) return error.ProgramContractViolation;
                    }
                    if (value.usage != obligation.usage) return error.ProgramContractViolation;
                    if (value.branch_id != obligation.branch_id) return error.ProgramContractViolation;
                    if (value.branch_policy != obligation.branch_policy) return error.ProgramContractViolation;
                    if (!obligationReplayPolicyAllows(obligation.status, obligation.branch_policy, obligation.replay_policy, value.replay_policy)) return error.ProgramContractViolation;
                    if (!obligationReplayPolicyAllows(obligation.status, obligation.branch_policy, value.replay_policy, response_use)) return error.ProgramContractViolation;
                }
            }

            fn obligationReplayPolicyAllows(obligation_status: ObligationStatus, branch_policy: BranchPolicy, metadata_policy: ResponseUse, response_use: ResponseUse) bool {
                if (metadataReplayPolicyAllows(obligation_status, metadata_policy, response_use)) return true;
                const response_is_replay = response_use == .replayed or response_use == .deterministic_replay;
                return obligation_status == .open and branch_policy == .replay_only and metadata_policy == .fresh and response_is_replay;
            }

            fn metadataReplayPolicyAllows(obligation_status: ObligationStatus, metadata_policy: ResponseUse, response_use: ResponseUse) bool {
                if (metadata_policy == response_use) return true;
                const response_is_replay = response_use == .replayed or response_use == .deterministic_replay;
                const obligation_already_answered = obligation_status == .consumed or obligation_status == .replayed;
                return response_is_replay and obligation_already_answered and metadata_policy == .fresh;
            }

            /// Validate a deterministic obligation transition ledger.
            pub fn validateObligations(ledger: ObligationLedger) ValidationReport {
                return ledger.validate();
            }

            /// Restore from a request capsule only when the route/capability permits restoration.
            pub fn restoreFromRequestEnvelopeWithCapability(
                runtime: *lowered_machine.Runtime,
                handlers: HandlersType,
                request: RequestEnvelope,
                route: Route,
                provider: ProviderManifest,
                capability: Capability,
                policy: Policy,
            ) Error!Session {
                if (route.fingerprint != fingerprintRoute(route)) return error.ProgramContractViolation;
                const expected_route = Route.from(request, provider, capability, policy);
                if (expected_route.fingerprint != route.fingerprint) return error.ProgramContractViolation;
                if (!expected_route.valid()) return error.ProgramContractViolation;
                if (!expected_route.capsule_restore_allowed) return error.ProgramContractViolation;
                if (route.request_envelope_fingerprint != request.fingerprint) return error.ProgramContractViolation;
                if (route.capability_fingerprint != capability.fingerprint) return error.ProgramContractViolation;
                if (!capability.allow_capsule_restore) return error.ProgramContractViolation;
                try request.validate();
                const report = validateCapabilityRequestScope(capability, request);
                if (!report.allowed()) return error.ProgramContractViolation;
                if (request.capsule_image) |image| {
                    if (image.len > capability.max_capsule_image_bytes) return error.ProgramContractViolation;
                }
                return restoreFromRequestEnvelope(runtime, handlers, request);
            }

            fn validateRequestEnvelopeFields(envelope: RequestEnvelope) Error!void {
                if (!try manifestFingerprintMatchesRequestVersion(envelope.allocator, envelope.manifest_fingerprint, envelope.request_format_version, envelope.request_fingerprint_version)) return error.ProgramContractViolation;
                if (!std.mem.eql(u8, envelope.program_label, label)) return error.ProgramContractViolation;
                if (!std.mem.eql(u8, envelope.plan_label, body_compiled_plan.label)) return error.ProgramContractViolation;
                if (envelope.plan_hash != body_compiled_plan_hash) return error.ProgramContractViolation;
                if (envelope.fingerprint != try checkedRequestBytesFingerprint(envelope.bytes)) return error.ProgramContractViolation;
                switch (envelope.kind) {
                    .operation => try validateOperationEnvelopeSite(envelope),
                    .after => try validateAfterEnvelopeSite(envelope),
                }
                try validateExchangeValueImage(envelope.allocator, envelope.value_ref, envelope.value_fingerprint, envelope.value_image);
                try validateCapsuleImageForEnvelope(envelope);
                if (envelope.usage_metadata) |metadata| {
                    if ((metadata.ephemeral or metadata.usage == .ephemeral) and envelope.capsule_image != null) return error.ProgramContractViolation;
                    if (metadata.branch_policy == .no_branch and envelope.capsule_image != null) return error.ProgramContractViolation;
                    if (metadata.obligation_fingerprint != null and metadata.capability_instance_fingerprint == null) return error.ProgramContractViolation;
                }
            }

            fn validateRequestEnvelopeFieldsBoundToBytes(envelope: RequestEnvelope) Error!void {
                var decoded = try RequestEnvelope.decode(envelope.allocator, envelope.bytes);
                defer decoded.deinit();
                if (envelope.fingerprint != decoded.fingerprint) return error.ProgramContractViolation;
                if (envelope.request_format_version != decoded.request_format_version) return error.ProgramContractViolation;
                if (envelope.request_fingerprint_version != decoded.request_fingerprint_version) return error.ProgramContractViolation;
                if (envelope.manifest_fingerprint != decoded.manifest_fingerprint) return error.ProgramContractViolation;
                if (!std.mem.eql(u8, envelope.program_label, decoded.program_label)) return error.ProgramContractViolation;
                if (!std.mem.eql(u8, envelope.plan_label, decoded.plan_label)) return error.ProgramContractViolation;
                if (envelope.plan_hash != decoded.plan_hash) return error.ProgramContractViolation;
                if (envelope.kind != decoded.kind) return error.ProgramContractViolation;
                if (envelope.request_fingerprint != decoded.request_fingerprint) return error.ProgramContractViolation;
                if (envelope.trace_fingerprint != decoded.trace_fingerprint) return error.ProgramContractViolation;
                if (envelope.turn_index != decoded.turn_index) return error.ProgramContractViolation;
                if (envelope.site_index != decoded.site_index) return error.ProgramContractViolation;
                if (envelope.site_fingerprint != decoded.site_fingerprint) return error.ProgramContractViolation;
                if (!optionalBytesEql(envelope.semantic_label, decoded.semantic_label)) return error.ProgramContractViolation;
                if (!std.mem.eql(u8, envelope.name, decoded.name)) return error.ProgramContractViolation;
                if (envelope.mode != decoded.mode) return error.ProgramContractViolation;
                if (!envelope.value_ref.eql(decoded.value_ref)) return error.ProgramContractViolation;
                if (envelope.value_fingerprint != decoded.value_fingerprint) return error.ProgramContractViolation;
                if (!std.mem.eql(u8, envelope.value_image, decoded.value_image)) return error.ProgramContractViolation;
                if (!optionalValueRefEql(envelope.expected_resume_ref, decoded.expected_resume_ref)) return error.ProgramContractViolation;
                if (!optionalValueRefEql(envelope.expected_return_ref, decoded.expected_return_ref)) return error.ProgramContractViolation;
                if (!optionalValueRefEql(envelope.expected_after_ref, decoded.expected_after_ref)) return error.ProgramContractViolation;
                if (!envelope.result_ref.eql(decoded.result_ref)) return error.ProgramContractViolation;
                if (!optionalBytesEql(envelope.capsule_image, decoded.capsule_image)) return error.ProgramContractViolation;
                if (envelope.capsule_image_fingerprint != decoded.capsule_image_fingerprint) return error.ProgramContractViolation;
                if (!optionalBytesEql(envelope.journal_branch_id, decoded.journal_branch_id)) return error.ProgramContractViolation;
                if (!requestUsageMetadataEql(envelope.usage_metadata, decoded.usage_metadata)) return error.ProgramContractViolation;
            }

            fn validateResponseEnvelopeFieldsBoundToBytes(response: ResponseEnvelope) Error!void {
                var decoded = try ResponseEnvelope.decode(response.allocator, response.bytes);
                defer decoded.deinit();
                if (response.fingerprint != decoded.fingerprint) return error.ProgramContractViolation;
                if (response.manifest_fingerprint != decoded.manifest_fingerprint) return error.ProgramContractViolation;
                if (response.request_envelope_fingerprint != decoded.request_envelope_fingerprint) return error.ProgramContractViolation;
                if (response.request_fingerprint != decoded.request_fingerprint) return error.ProgramContractViolation;
                if (response.kind != decoded.kind) return error.ProgramContractViolation;
                if (!response.response_ref.eql(decoded.response_ref)) return error.ProgramContractViolation;
                if (response.response_value_fingerprint != decoded.response_value_fingerprint) return error.ProgramContractViolation;
                if (response.response_trace_fingerprint != decoded.response_trace_fingerprint) return error.ProgramContractViolation;
                if (!std.mem.eql(u8, response.value_image, decoded.value_image)) return error.ProgramContractViolation;
            }

            /// Restore a session from an embedded request capsule image.
            pub fn restoreFromRequestEnvelope(
                runtime: *lowered_machine.Runtime,
                handlers: HandlersType,
                request: RequestEnvelope,
            ) Error!Session {
                try request.validate();
                const image_bytes = request.capsule_image orelse return error.ProgramContractViolation;
                var capsule = try Session.Capsule.decode(request.allocator, image_bytes);
                defer capsule.deinit();
                var session = try Session.restore(runtime, handlers, &capsule);
                errdefer session.deinit();
                const current_value = try session.current();
                const current_fingerprint = switch (current_value) {
                    .request => |current_request| current_request.fingerprint(),
                    .after => |after_request| after_request.fingerprint(),
                    .none => return error.ProgramContractViolation,
                };
                if (current_fingerprint != request.request_fingerprint) return error.ProgramContractViolation;
                return session;
            }

            fn requestEnvelopeForCurrent(
                allocator: std.mem.Allocator,
                session: *Session,
                current_value: Session.Current,
                include_capsule: bool,
                journal_branch_id: ?[]const u8,
                usage_metadata: ?RequestUsageMetadata,
            ) Error!RequestEnvelope {
                var capsule_image: ?Session.Capsule.Image = null;
                if (include_capsule) {
                    var capsule = try session.capture(allocator);
                    defer capsule.deinit();
                    capsule_image = try capsule.encode(allocator);
                }
                defer if (capsule_image) |*image| image.deinit();
                return switch (current_value) {
                    .request => |request| RequestEnvelope.fromRequest(allocator, request, .{ .capsule = capsule_image, .journal_branch_id = journal_branch_id, .usage_metadata = usage_metadata }),
                    .after => |after| RequestEnvelope.fromAfter(allocator, after, .{ .capsule = capsule_image, .journal_branch_id = journal_branch_id, .usage_metadata = usage_metadata }),
                    .none => error.ProgramContractViolation,
                };
            }

            const Writer = Session.ExchangeByteWriter;
            const Reader = Session.ExchangeByteReader;

            fn writeCapsulePolicy(writer: *Writer, policy_value: CapsulePolicy) std.mem.Allocator.Error!void {
                try writer.writeU8(switch (policy_value) {
                    .required => 0,
                    .allowed => 1,
                    .forbidden => 2,
                });
            }

            fn readCapsulePolicy(reader: *Reader) Error!CapsulePolicy {
                return switch (try reader.readU8()) {
                    0 => .required,
                    1 => .allowed,
                    2 => .forbidden,
                    else => error.ProgramContractViolation,
                };
            }

            fn writeUsageSet(writer: *Writer, set: UsageSet) std.mem.Allocator.Error!void {
                try writer.writeBool(set.copyable);
                try writer.writeBool(set.replayable);
                try writer.writeBool(set.affine);
                try writer.writeBool(set.linear);
                try writer.writeBool(set.ephemeral);
            }

            fn readUsageSet(reader: *Reader) Error!UsageSet {
                return .{
                    .copyable = try reader.readBool(),
                    .replayable = try reader.readBool(),
                    .affine = try reader.readBool(),
                    .linear = try reader.readBool(),
                    .ephemeral = try reader.readBool(),
                };
            }

            fn writeResponseUseSet(writer: *Writer, set: ResponseUseSet) std.mem.Allocator.Error!void {
                try writer.writeBool(set.fresh);
                try writer.writeBool(set.replayed);
                try writer.writeBool(set.deterministic_replay);
                try writer.writeBool(set.override);
            }

            fn readResponseUseSet(reader: *Reader) Error!ResponseUseSet {
                return .{
                    .fresh = try reader.readBool(),
                    .replayed = try reader.readBool(),
                    .deterministic_replay = try reader.readBool(),
                    .override = try reader.readBool(),
                };
            }

            fn writeBranchPolicySet(writer: *Writer, set: BranchPolicySet) std.mem.Allocator.Error!void {
                try writer.writeBool(set.unrestricted);
                try writer.writeBool(set.replay_only);
                try writer.writeBool(set.single_live_branch);
                try writer.writeBool(set.split_required);
                try writer.writeBool(set.no_branch);
                try writer.writeBool(set.host_owned);
            }

            fn readBranchPolicySet(reader: *Reader) Error!BranchPolicySet {
                return .{
                    .unrestricted = try reader.readBool(),
                    .replay_only = try reader.readBool(),
                    .single_live_branch = try reader.readBool(),
                    .split_required = try reader.readBool(),
                    .no_branch = try reader.readBool(),
                    .host_owned = try reader.readBool(),
                };
            }

            fn validateProviderOfferOptions(options: ProviderOffer.Options) Error!void {
                if (options.label.len == 0) return error.ProgramContractViolation;
                if (options.max_response_bytes == 0 or options.max_request_bytes == 0) return error.ProgramContractViolation;
                if (options.provider_program_mapping_fingerprint) |fingerprint| {
                    if (fingerprint == 0) return error.ProgramContractViolation;
                }
            }

            fn writeProviderOfferPayload(writer: *Writer, options: ProviderOffer.Options) std.mem.Allocator.Error!void {
                try writer.writeBytes(provider_offer_magic);
                try writer.writeU32(if (options.provider_program_mapping_fingerprint != null) provider_offer_program_format_version else exchange_provider_offer_format_version);
                try writer.writeU32(exchange_provider_offer_fingerprint_version);
                try writer.writeLenBytes(options.label);
                try writer.writeU64(options.provider_fingerprint);
                try writer.writeU64(options.manifest_fingerprint);
                try writeUsizeList(writer, options.supported_operation_sites);
                try writeUsizeList(writer, options.supported_after_sites);
                try writeU64List(writer, options.supported_protocol_op_fingerprints);
                try writeStringList(writer, options.supported_protocol_labels);
                try writeValueRefList(writer, options.accepted_payload_refs);
                try writeValueRefList(writer, options.accepted_current_value_refs);
                try writeValueRefList(writer, options.produced_response_refs);
                try writeResponseKindSet(writer, options.allowed_response_kinds);
                try writeUsageSet(writer, options.supported_usage_modes);
                try writeResponseUseSet(writer, options.supported_response_uses);
                try writeResponseUseSet(writer, options.supported_replay_policies);
                try writeBranchPolicySet(writer, options.supported_branch_policies);
                try writeCapsulePolicy(writer, options.capsule_policy);
                try writer.writeBool(options.opens_obligation);
                try writer.writeUsize(options.max_request_bytes);
                try writer.writeUsize(options.max_response_bytes);
                try writer.writeUsize(options.max_capsule_bytes);
                try writeStringList(writer, options.tags);
                try writer.writeLenBytes(options.metadata);
                if (options.provider_program_mapping_fingerprint) |fingerprint| try writer.writeU64(fingerprint);
            }

            fn providerOfferFromOptions(
                allocator: std.mem.Allocator,
                bytes: []u8,
                fingerprint: u64,
                options: ProviderOffer.Options,
            ) Error!ProviderOffer {
                errdefer allocator.free(bytes);
                const label_value = try allocator.dupe(u8, options.label);
                errdefer allocator.free(label_value);
                const operation_sites = try cloneUsizes(allocator, options.supported_operation_sites);
                errdefer allocator.free(operation_sites);
                const after_sites = try cloneUsizes(allocator, options.supported_after_sites);
                errdefer allocator.free(after_sites);
                const protocol_ops = try cloneU64s(allocator, options.supported_protocol_op_fingerprints);
                errdefer allocator.free(protocol_ops);
                const protocol_labels = try cloneStringList(allocator, options.supported_protocol_labels);
                errdefer freeStringList(allocator, protocol_labels);
                const payload_refs = try cloneValueRefs(allocator, options.accepted_payload_refs);
                errdefer allocator.free(payload_refs);
                const current_refs = try cloneValueRefs(allocator, options.accepted_current_value_refs);
                errdefer allocator.free(current_refs);
                const response_refs = try cloneValueRefs(allocator, options.produced_response_refs);
                errdefer allocator.free(response_refs);
                const tags_value = try cloneStringList(allocator, options.tags);
                errdefer freeStringList(allocator, tags_value);
                const metadata_value = try allocator.dupe(u8, options.metadata);
                errdefer allocator.free(metadata_value);
                return .{
                    .allocator = allocator,
                    .bytes = bytes,
                    .format_version = if (options.provider_program_mapping_fingerprint != null) provider_offer_program_format_version else exchange_provider_offer_format_version,
                    .fingerprint = fingerprint,
                    .label = label_value,
                    .provider_fingerprint = options.provider_fingerprint,
                    .manifest_fingerprint = options.manifest_fingerprint,
                    .supported_operation_sites = operation_sites,
                    .supported_after_sites = after_sites,
                    .supported_protocol_op_fingerprints = protocol_ops,
                    .supported_protocol_labels = protocol_labels,
                    .accepted_payload_refs = payload_refs,
                    .accepted_current_value_refs = current_refs,
                    .produced_response_refs = response_refs,
                    .allowed_response_kinds = options.allowed_response_kinds,
                    .supported_usage_modes = options.supported_usage_modes,
                    .supported_response_uses = options.supported_response_uses,
                    .supported_replay_policies = options.supported_replay_policies,
                    .supported_branch_policies = options.supported_branch_policies,
                    .capsule_policy = options.capsule_policy,
                    .opens_obligation = options.opens_obligation,
                    .max_request_bytes = options.max_request_bytes,
                    .max_response_bytes = options.max_response_bytes,
                    .max_capsule_bytes = options.max_capsule_bytes,
                    .tags = tags_value,
                    .metadata = metadata_value,
                    .provider_program_mapping_fingerprint = options.provider_program_mapping_fingerprint,
                };
            }

            fn providerOfferFieldsBoundToBytes(offer: ProviderOffer) bool {
                const payload = checkedPayload(offer.bytes, "ability.exchange.provider_offer", exchange_provider_offer_fingerprint_version) catch return false;
                const fingerprint = checkedBytesFingerprint(offer.bytes, "ability.exchange.provider_offer", exchange_provider_offer_fingerprint_version) catch return false;
                if (fingerprint != offer.fingerprint) return false;
                var reader = Reader.init(payload);
                reader.expectBytes(provider_offer_magic) catch return false;
                const format_version = reader.readU32() catch return false;
                if (format_version != exchange_provider_offer_format_version and format_version != provider_offer_program_format_version) return false;
                if (format_version != offer.format_version) return false;
                if ((reader.readU32() catch return false) != exchange_provider_offer_fingerprint_version) return false;
                if (!std.mem.eql(u8, reader.readLenBytes() catch return false, offer.label)) return false;
                if ((reader.readU64() catch return false) != offer.provider_fingerprint) return false;
                if ((reader.readU64() catch return false) != offer.manifest_fingerprint) return false;
                expectUsizeList(&reader, offer.supported_operation_sites) catch return false;
                expectUsizeList(&reader, offer.supported_after_sites) catch return false;
                expectU64List(&reader, offer.supported_protocol_op_fingerprints) catch return false;
                expectStringList(&reader, offer.supported_protocol_labels) catch return false;
                expectValueRefList(&reader, offer.accepted_payload_refs) catch return false;
                expectValueRefList(&reader, offer.accepted_current_value_refs) catch return false;
                expectValueRefList(&reader, offer.produced_response_refs) catch return false;
                const response_kinds = readResponseKindSet(&reader) catch return false;
                if (!responseKindSetsEqual(response_kinds, offer.allowed_response_kinds)) return false;
                if (!usageSetsEqual(readUsageSet(&reader) catch return false, offer.supported_usage_modes)) return false;
                if (!responseUseSetsEqual(readResponseUseSet(&reader) catch return false, offer.supported_response_uses)) return false;
                if (!responseUseSetsEqual(readResponseUseSet(&reader) catch return false, offer.supported_replay_policies)) return false;
                if (!branchPolicySetsEqual(readBranchPolicySet(&reader) catch return false, offer.supported_branch_policies)) return false;
                if ((readCapsulePolicy(&reader) catch return false) != offer.capsule_policy) return false;
                if ((reader.readBool() catch return false) != offer.opens_obligation) return false;
                if ((reader.readUsize() catch return false) != offer.max_request_bytes) return false;
                if ((reader.readUsize() catch return false) != offer.max_response_bytes) return false;
                if ((reader.readUsize() catch return false) != offer.max_capsule_bytes) return false;
                expectStringList(&reader, offer.tags) catch return false;
                if (!std.mem.eql(u8, reader.readLenBytes() catch return false, offer.metadata)) return false;
                const program_mapping_fingerprint: ?u64 = if (format_version == provider_offer_program_format_version) reader.readU64() catch return false else null;
                if (program_mapping_fingerprint != offer.provider_program_mapping_fingerprint) return false;
                return reader.eof();
            }

            fn writeManifestPayload(writer: *Writer) anyerror!void {
                try writeManifestPayloadWithVersions(writer, exchange_request_format_version, exchange_request_fingerprint_version, exchange_manifest_journal_format_version);
            }

            fn writeManifestPayloadWithVersions(
                writer: *Writer,
                encoded_request_format_version: u32,
                encoded_request_fingerprint_version: u32,
                encoded_journal_format_version: u32,
            ) anyerror!void {
                try writer.writeBytes(manifest_magic);
                try writer.writeU32(exchange_manifest_format_version);
                try writer.writeU32(exchange_manifest_fingerprint_version);
                try writer.writeU32(encoded_request_format_version);
                try writer.writeU32(encoded_request_fingerprint_version);
                try writer.writeU32(exchange_response_format_version);
                try writer.writeU32(exchange_response_fingerprint_version);
                try writer.writeLenBytes(label);
                try writer.writeLenBytes(body_compiled_plan.label);
                try writer.writeU64(body_compiled_plan_hash);
                try writer.writeU32(lowering_api.trace_fingerprint_version);
                try writer.writeU32(capsule_image_format_version);
                try writer.writeU32(capsule_image_fingerprint_version);
                try writer.writeU32(encoded_journal_format_version);
                try writer.writeU32(journal_fingerprint_version);
                try writer.writeUsize(compiled_plan.value_schemas.len);
                for (compiled_plan.value_schemas, 0..) |schema, schema_index| {
                    try writer.writeLenBytes(schema.label);
                    try writeExchangeValueRef(writer, .{ .codec = schema.codec, .schema_index = @intCast(schema_index) });
                    try writer.writeU16(schema.first_field);
                    try writer.writeU16(schema.field_count);
                    try writer.writeU16(schema.first_variant);
                    try writer.writeU16(schema.variant_count);
                }
                try writer.writeUsize(compiled_plan.value_fields.len);
                for (compiled_plan.value_fields) |field| {
                    try writer.writeLenBytes(field.name);
                    try writeExchangeValueRef(writer, .{ .codec = field.codec, .schema_index = field.schema_index });
                }
                try writer.writeUsize(compiled_plan.value_variants.len);
                for (compiled_plan.value_variants) |variant| {
                    try writer.writeLenBytes(variant.name);
                    try writeExchangeValueRef(writer, .{ .codec = variant.codec, .schema_index = variant.schema_index });
                }
                try writer.writeUsize(protocol.operation_site_count);
                inline for (protocol.operation_site_metadata) |site| {
                    try writer.writeUsize(site.index);
                    try writer.writeU64(site.fingerprint);
                    try writeOptionalBytes(writer, site.semantic_label);
                    try writer.writeLenBytes(site.requirement_label);
                    try writer.writeLenBytes(site.op_name);
                    try writeExchangeControlMode(writer, site.op_mode);
                    try writeExchangeValueRef(writer, site.payload_ref);
                    try writeExchangeValueRef(writer, site.resume_ref);
                    try writeExchangeValueRef(writer, site.result_ref);
                    try writer.writeBool(site.has_after);
                }
                try writer.writeUsize(protocol.after_site_count);
                inline for (protocol.after_site_metadata) |site| {
                    try writer.writeUsize(site.index);
                    try writer.writeU64(site.fingerprint);
                    try writeOptionalBytes(writer, site.semantic_label);
                    try writer.writeUsize(site.source_operation_site_index);
                    try writer.writeU64(site.source_operation_site_fingerprint);
                    try writer.writeLenBytes(site.original_requirement_label);
                    try writer.writeLenBytes(site.original_op_name);
                    try writeExchangeValueRef(writer, site.result_ref);
                }
            }

            fn readManifestValueSchemas(reader: *Reader) Error!void {
                const count = try reader.readUsize();
                if (count != compiled_plan.value_schemas.len) return error.ProgramContractViolation;
                for (compiled_plan.value_schemas, 0..) |schema, schema_index| {
                    if (!std.mem.eql(u8, try reader.readLenBytes(), schema.label)) return error.ProgramContractViolation;
                    const ref = try readExchangeValueRef(reader);
                    if (!ref.eql(.{ .codec = schema.codec, .schema_index = @intCast(schema_index) })) return error.ProgramContractViolation;
                    if (try reader.readU16() != schema.first_field) return error.ProgramContractViolation;
                    if (try reader.readU16() != schema.field_count) return error.ProgramContractViolation;
                    if (try reader.readU16() != schema.first_variant) return error.ProgramContractViolation;
                    if (try reader.readU16() != schema.variant_count) return error.ProgramContractViolation;
                }
                const field_count = try reader.readUsize();
                if (field_count != compiled_plan.value_fields.len) return error.ProgramContractViolation;
                for (compiled_plan.value_fields) |field| {
                    if (!std.mem.eql(u8, try reader.readLenBytes(), field.name)) return error.ProgramContractViolation;
                    const ref = try readExchangeValueRef(reader);
                    if (!ref.eql(.{ .codec = field.codec, .schema_index = field.schema_index })) return error.ProgramContractViolation;
                }
                const variant_count = try reader.readUsize();
                if (variant_count != compiled_plan.value_variants.len) return error.ProgramContractViolation;
                for (compiled_plan.value_variants) |variant| {
                    if (!std.mem.eql(u8, try reader.readLenBytes(), variant.name)) return error.ProgramContractViolation;
                    const ref = try readExchangeValueRef(reader);
                    if (!ref.eql(.{ .codec = variant.codec, .schema_index = variant.schema_index })) return error.ProgramContractViolation;
                }
            }

            fn readManifestOperationSites(reader: *Reader) Error!void {
                const count = try reader.readUsize();
                if (count != protocol.operation_site_count) return error.ProgramContractViolation;
                inline for (protocol.operation_site_metadata) |site| {
                    if (try reader.readUsize() != site.index) return error.ProgramContractViolation;
                    if (try reader.readU64() != site.fingerprint) return error.ProgramContractViolation;
                    try expectOptionalBytes(reader, site.semantic_label);
                    if (!std.mem.eql(u8, try reader.readLenBytes(), site.requirement_label)) return error.ProgramContractViolation;
                    if (!std.mem.eql(u8, try reader.readLenBytes(), site.op_name)) return error.ProgramContractViolation;
                    if (try readExchangeControlMode(reader) != site.op_mode) return error.ProgramContractViolation;
                    if (!(try readExchangeValueRef(reader)).eql(site.payload_ref)) return error.ProgramContractViolation;
                    if (!(try readExchangeValueRef(reader)).eql(site.resume_ref)) return error.ProgramContractViolation;
                    if (!(try readExchangeValueRef(reader)).eql(site.result_ref)) return error.ProgramContractViolation;
                    if (try reader.readBool() != site.has_after) return error.ProgramContractViolation;
                }
            }

            fn readManifestAfterSites(reader: *Reader) Error!void {
                const count = try reader.readUsize();
                if (count != protocol.after_site_count) return error.ProgramContractViolation;
                inline for (protocol.after_site_metadata) |site| {
                    if (try reader.readUsize() != site.index) return error.ProgramContractViolation;
                    if (try reader.readU64() != site.fingerprint) return error.ProgramContractViolation;
                    try expectOptionalBytes(reader, site.semantic_label);
                    if (try reader.readUsize() != site.source_operation_site_index) return error.ProgramContractViolation;
                    if (try reader.readU64() != site.source_operation_site_fingerprint) return error.ProgramContractViolation;
                    if (!std.mem.eql(u8, try reader.readLenBytes(), site.original_requirement_label)) return error.ProgramContractViolation;
                    if (!std.mem.eql(u8, try reader.readLenBytes(), site.original_op_name)) return error.ProgramContractViolation;
                    if (!(try readExchangeValueRef(reader)).eql(site.result_ref)) return error.ProgramContractViolation;
                }
            }

            fn manifestFingerprintForCurrentProgram(allocator: std.mem.Allocator) Error!u64 {
                var manifest = try Manifest.encode(allocator);
                defer manifest.deinit();
                return manifest.fingerprint;
            }

            fn manifestFingerprintForVersions(allocator: std.mem.Allocator, encoded_request_format_version: u32, encoded_request_fingerprint_version: u32, encoded_journal_format_version: u32) Error!u64 {
                var writer = Writer.init(allocator);
                defer writer.deinit();
                writeManifestPayloadWithVersions(&writer, encoded_request_format_version, encoded_request_fingerprint_version, encoded_journal_format_version) catch |err| return mapProgramRunError(Error, err);
                return exchangeFingerprint("ability.exchange.manifest", exchange_manifest_fingerprint_version, writer.bytes.items);
            }

            const ManifestVersionTuple = struct {
                request_format: u32,
                request_fingerprint: u32,
                journal_format: u32,
            };

            const emitted_manifest_version_tuples = [_]ManifestVersionTuple{
                .{ .request_format = exchange_request_format_version, .request_fingerprint = exchange_request_fingerprint_version, .journal_format = journal_format_version },
                .{ .request_format = 3, .request_fingerprint = 3, .journal_format = 5 },
                .{ .request_format = 3, .request_fingerprint = 3, .journal_format = 4 },
                .{ .request_format = 3, .request_fingerprint = 3, .journal_format = 3 },
                .{ .request_format = 2, .request_fingerprint = 2, .journal_format = 2 },
                .{ .request_format = 2, .request_fingerprint = 2, .journal_format = 1 },
                .{ .request_format = 1, .request_fingerprint = 1, .journal_format = 2 },
                .{ .request_format = 1, .request_fingerprint = 1, .journal_format = 1 },
            };

            fn emittedManifestVersionTuple(request_format: u32, request_fingerprint: u32, journal_format: u32) bool {
                if (!supportedRequestEnvelopeVersions(request_format, request_fingerprint)) return false;
                for (emitted_manifest_version_tuples) |pair| {
                    if (pair.request_format == request_format and pair.request_fingerprint == request_fingerprint and pair.journal_format == journal_format) return true;
                }
                return false;
            }

            fn manifestFingerprintMatchesRequestVersion(allocator: std.mem.Allocator, fingerprint: u64, request_format: u32, request_fingerprint: u32) Error!bool {
                if (!supportedRequestEnvelopeVersions(request_format, request_fingerprint)) return false;
                for (emitted_manifest_version_tuples) |pair| {
                    if (pair.request_format != request_format or pair.request_fingerprint != request_fingerprint) continue;
                    if (fingerprint == try manifestFingerprintForVersions(allocator, request_format, request_fingerprint, pair.journal_format)) return true;
                }
                return false;
            }

            fn manifestFingerprintMatchesSupportedRequestVersion(allocator: std.mem.Allocator, fingerprint: u64) Error!bool {
                if (try manifestFingerprintMatchesRequestVersion(allocator, fingerprint, exchange_request_format_version, exchange_request_fingerprint_version)) return true;
                if (try manifestFingerprintMatchesRequestVersion(allocator, fingerprint, 2, 2)) return true;
                if (try manifestFingerprintMatchesRequestVersion(allocator, fingerprint, 1, 1)) return true;
                return false;
            }

            fn encodeRequestEnvelope(allocator: std.mem.Allocator, args: anytype) Error!RequestEnvelope {
                var writer = Writer.init(allocator);
                errdefer writer.deinit();
                try writer.writeBytes(request_magic);
                try writer.writeU32(exchange_request_format_version);
                try writer.writeU32(exchange_request_fingerprint_version);
                try writer.writeU64(args.manifest_fingerprint);
                try writer.writeLenBytes(label);
                try writer.writeLenBytes(body_compiled_plan.label);
                try writer.writeU64(body_compiled_plan_hash);
                try writeRequestKind(&writer, args.kind);
                try writer.writeU64(args.request_fingerprint);
                try writer.writeU64(args.trace_fingerprint);
                try writer.writeUsize(args.turn_index);
                try writer.writeUsize(args.site_index);
                try writer.writeU64(args.site_fingerprint);
                try writeOptionalBytes(&writer, args.semantic_label);
                try writer.writeLenBytes(args.name);
                try writeExchangeControlMode(&writer, args.mode);
                try writeExchangeValueRef(&writer, args.value_ref);
                try writer.writeU64(args.value_fingerprint);
                try writer.writeLenBytes(args.value_image);
                try writeOptionalValueRef(&writer, args.expected_resume_ref);
                try writeOptionalValueRef(&writer, args.expected_return_ref);
                try writeOptionalValueRef(&writer, args.expected_after_ref);
                try writeExchangeValueRef(&writer, args.result_ref);
                try writer.writeBool(args.capsule != null);
                if (args.capsule) |capsule| {
                    try writer.writeLenBytes(capsule.bytes);
                    try writer.writeU64(capsule.image_fingerprint);
                }
                try writeOptionalBytes(&writer, args.journal_branch_id);
                try writeRequestUsageMetadata(&writer, args.usage_metadata);
                const payload = writer.bytes.items;
                const fingerprint = exchangeFingerprint("ability.exchange.request", exchange_request_fingerprint_version, payload);
                try writer.writeU64(fingerprint);
                const owned = try writer.toOwnedSlice();
                errdefer allocator.free(owned);
                const value_image = try allocator.dupe(u8, args.value_image);
                errdefer allocator.free(value_image);
                const capsule_image = if (args.capsule) |capsule| try allocator.dupe(u8, capsule.bytes) else null;
                errdefer if (capsule_image) |image| allocator.free(image);
                const branch_id = if (args.journal_branch_id) |branch| try allocator.dupe(u8, branch) else null;
                errdefer if (branch_id) |branch| allocator.free(branch);
                const name_value = try allocator.dupe(u8, args.name);
                errdefer allocator.free(name_value);
                const semantic_label = if (args.semantic_label) |semantic| try allocator.dupe(u8, semantic) else null;
                errdefer if (semantic_label) |semantic| allocator.free(semantic);
                const program_label = try allocator.dupe(u8, label);
                errdefer allocator.free(program_label);
                const plan_label = try allocator.dupe(u8, body_compiled_plan.label);
                errdefer allocator.free(plan_label);
                return .{
                    .allocator = allocator,
                    .bytes = owned,
                    .fingerprint = fingerprint,
                    .request_format_version = exchange_request_format_version,
                    .request_fingerprint_version = exchange_request_fingerprint_version,
                    .manifest_fingerprint = args.manifest_fingerprint,
                    .program_label = program_label,
                    .plan_label = plan_label,
                    .plan_hash = body_compiled_plan_hash,
                    .kind = args.kind,
                    .request_fingerprint = args.request_fingerprint,
                    .trace_fingerprint = args.trace_fingerprint,
                    .turn_index = args.turn_index,
                    .site_index = args.site_index,
                    .site_fingerprint = args.site_fingerprint,
                    .semantic_label = semantic_label,
                    .name = name_value,
                    .mode = args.mode,
                    .value_ref = args.value_ref,
                    .value_image = value_image,
                    .value_fingerprint = args.value_fingerprint,
                    .expected_resume_ref = args.expected_resume_ref,
                    .expected_return_ref = args.expected_return_ref,
                    .expected_after_ref = args.expected_after_ref,
                    .result_ref = args.result_ref,
                    .capsule_image = capsule_image,
                    .capsule_image_fingerprint = if (args.capsule) |capsule| capsule.image_fingerprint else null,
                    .journal_branch_id = branch_id,
                    .usage_metadata = args.usage_metadata,
                };
            }

            fn encodeResponseEnvelope(allocator: std.mem.Allocator, request: RequestEnvelope, kind_value: ResponseKind, value: anytype) Error!ResponseEnvelope {
                try request.validate();
                const response_ref = try expectedResponseRef(request, kind_value);
                const response_value_fingerprint = try fingerprintExchangeValueImage(response_ref, value);
                const response_trace = responseTraceFromEnvelope(request.request_fingerprint, kind_value, response_ref, response_value_fingerprint);
                const value_image = try encodeExchangeValueImage(allocator, response_ref, response_value_fingerprint, value);
                errdefer allocator.free(value_image);
                var writer = Writer.init(allocator);
                errdefer writer.deinit();
                try writer.writeBytes(response_magic);
                try writer.writeU32(exchange_response_format_version);
                try writer.writeU32(exchange_response_fingerprint_version);
                try writer.writeU64(request.manifest_fingerprint);
                try writer.writeU64(request.fingerprint);
                try writer.writeU64(request.request_fingerprint);
                try writeExchangeResponseKind(&writer, kind_value);
                try writeExchangeValueRef(&writer, response_ref);
                try writer.writeU64(response_value_fingerprint);
                try writer.writeU64(response_trace.fingerprint);
                try writer.writeLenBytes(value_image);
                const payload = writer.bytes.items;
                const fingerprint = exchangeFingerprint("ability.exchange.response", exchange_response_fingerprint_version, payload);
                try writer.writeU64(fingerprint);
                return .{
                    .allocator = allocator,
                    .bytes = try writer.toOwnedSlice(),
                    .fingerprint = fingerprint,
                    .manifest_fingerprint = request.manifest_fingerprint,
                    .request_envelope_fingerprint = request.fingerprint,
                    .request_fingerprint = request.request_fingerprint,
                    .kind = kind_value,
                    .response_ref = response_ref,
                    .value_image = value_image,
                    .response_value_fingerprint = response_value_fingerprint,
                    .response_trace_fingerprint = response_trace.fingerprint,
                };
            }

            fn applyResponseValue(session: *Session, current_value: Session.Current, response: ResponseEnvelope) Error!void {
                return switch (response.response_ref.codec) {
                    .unit => try applyDecodedExchangeValueImage(session, current_value, response, void),
                    .bool => try applyDecodedExchangeValueImage(session, current_value, response, bool),
                    .i32 => try applyDecodedExchangeValueImage(session, current_value, response, i32),
                    .usize => try applyDecodedExchangeValueImage(session, current_value, response, usize),
                    .string => try applyDecodedExchangeValueImage(session, current_value, response, []const u8),
                    .string_list => try applyDecodedExchangeValueImage(session, current_value, response, []const []const u8),
                    .product, .sum => blk: {
                        const schema_index = response.response_ref.schema_index orelse return error.ProgramContractViolation;
                        inline for (body_value_schema_types, 0..) |SchemaType, index| {
                            if (schema_index == index) {
                                break :blk try applyDecodedExchangeValueImage(session, current_value, response, SchemaType);
                            }
                        }
                        return error.ProgramContractViolation;
                    },
                };
            }

            fn applyDecodedExchangeValueImageWithRef(
                session: *Session,
                current_value: Session.Current,
                response: ResponseEnvelope,
                comptime ref: lowering_api.ValueRef,
                comptime ValueType: type,
            ) Error!void {
                var journal = Session.Journal.init(response.allocator);
                defer journal.deinit();
                var replayer = journal.replayer();
                defer replayer.deinit();
                var reader = Reader.init(response.value_image);
                const encoded_ref = try readExchangeValueRef(&reader);
                if (!encoded_ref.eql(ref)) return error.ProgramContractViolation;
                var context = Session.ValueImageContext.init(response.allocator);
                defer context.deinit();
                const value = Session.readTypedValueImage(&reader, &replayer, &context, ref, ValueType) catch |err| return mapProgramRunError(Error, err);
                if (!reader.eof()) return error.ProgramContractViolation;
                if (try Session.fingerprintTypedValueImage(ref, value) != response.response_value_fingerprint) return error.ProgramContractViolation;
                const canonical = try encodeExchangeValueImage(response.allocator, response.response_ref, response.response_value_fingerprint, value);
                defer response.allocator.free(canonical);
                if (!std.mem.eql(u8, response.value_image, canonical)) return error.ProgramContractViolation;
                try applyTypedResponse(session, current_value, response, value);
            }

            fn applyDecodedExchangeValueImage(
                session: *Session,
                current_value: Session.Current,
                response: ResponseEnvelope,
                comptime ValueType: type,
            ) Error!void {
                switch (response.response_ref.codec) {
                    .unit, .bool, .i32, .usize, .string, .string_list => {
                        const expected_ref = comptime ProgramValueRefForType(body_value_schema_types, ValueType);
                        if (!response.response_ref.eql(expected_ref)) return error.ProgramContractViolation;
                        return applyDecodedExchangeValueImageWithRef(session, current_value, response, expected_ref, ValueType);
                    },
                    .product => {
                        const schema_index = response.response_ref.schema_index orelse return error.ProgramContractViolation;
                        inline for (body_value_schema_types, 0..) |SchemaType, index| {
                            if (schema_index == index) {
                                if (SchemaType != ValueType) return error.ProgramContractViolation;
                                return applyDecodedExchangeValueImageWithRef(session, current_value, response, .{ .codec = .product, .schema_index = @intCast(index) }, ValueType);
                            }
                        }
                        return error.ProgramContractViolation;
                    },
                    .sum => {
                        const schema_index = response.response_ref.schema_index orelse return error.ProgramContractViolation;
                        inline for (body_value_schema_types, 0..) |SchemaType, index| {
                            if (schema_index == index) {
                                if (SchemaType != ValueType) return error.ProgramContractViolation;
                                return applyDecodedExchangeValueImageWithRef(session, current_value, response, .{ .codec = .sum, .schema_index = @intCast(index) }, ValueType);
                            }
                        }
                        return error.ProgramContractViolation;
                    },
                }
            }

            fn applyTypedResponse(session: *Session, current_value: Session.Current, response: ResponseEnvelope, value: anytype) Error!void {
                const stable_value = try session.storeExchangeResponseValue(value);
                return switch (current_value) {
                    .request => |request| switch (response.kind) {
                        .@"resume" => try session.@"resume"(request, stable_value),
                        .return_now => try session.returnNow(request, stable_value),
                        .resume_after => error.ProgramContractViolation,
                    },
                    .after => |after| switch (response.kind) {
                        .resume_after => try session.resumeAfter(after, stable_value),
                        else => error.ProgramContractViolation,
                    },
                    .none => error.ProgramContractViolation,
                };
            }

            fn encodeRequestValueImage(allocator: std.mem.Allocator, request: Session.Request) Error![]u8 {
                return switch (request.payload_ref.codec) {
                    .unit => encodeExchangeValueImage(allocator, request.payload_ref, request.trace().payload_value_fingerprint, try request.payload(void)),
                    .bool => encodeExchangeValueImage(allocator, request.payload_ref, request.trace().payload_value_fingerprint, try request.payload(bool)),
                    .i32 => encodeExchangeValueImage(allocator, request.payload_ref, request.trace().payload_value_fingerprint, try request.payload(i32)),
                    .usize => encodeExchangeValueImage(allocator, request.payload_ref, request.trace().payload_value_fingerprint, try request.payload(usize)),
                    .string => encodeExchangeValueImage(allocator, request.payload_ref, request.trace().payload_value_fingerprint, try request.payload([]const u8)),
                    .string_list => encodeExchangeValueImage(allocator, request.payload_ref, request.trace().payload_value_fingerprint, try request.payload([]const []const u8)),
                    .product, .sum => blk: {
                        const schema_index = request.payload_ref.schema_index orelse return error.ProgramContractViolation;
                        inline for (body_value_schema_types, 0..) |SchemaType, index| {
                            if (schema_index == index) break :blk encodeExchangeValueImage(allocator, request.payload_ref, request.trace().payload_value_fingerprint, try request.payload(SchemaType));
                        }
                        return error.ProgramContractViolation;
                    },
                };
            }

            fn encodeAfterValueImage(allocator: std.mem.Allocator, request: Session.AfterRequest) Error![]u8 {
                return switch (request.value_ref.codec) {
                    .unit => encodeExchangeValueImage(allocator, request.value_ref, request.trace().current_value_fingerprint, try request.value(void)),
                    .bool => encodeExchangeValueImage(allocator, request.value_ref, request.trace().current_value_fingerprint, try request.value(bool)),
                    .i32 => encodeExchangeValueImage(allocator, request.value_ref, request.trace().current_value_fingerprint, try request.value(i32)),
                    .usize => encodeExchangeValueImage(allocator, request.value_ref, request.trace().current_value_fingerprint, try request.value(usize)),
                    .string => encodeExchangeValueImage(allocator, request.value_ref, request.trace().current_value_fingerprint, try request.value([]const u8)),
                    .string_list => encodeExchangeValueImage(allocator, request.value_ref, request.trace().current_value_fingerprint, try request.value([]const []const u8)),
                    .product, .sum => blk: {
                        const schema_index = request.value_ref.schema_index orelse return error.ProgramContractViolation;
                        inline for (body_value_schema_types, 0..) |SchemaType, index| {
                            if (schema_index == index) break :blk encodeExchangeValueImage(allocator, request.value_ref, request.trace().current_value_fingerprint, try request.value(SchemaType));
                        }
                        return error.ProgramContractViolation;
                    },
                };
            }

            fn encodeExchangeValueImageWithRef(allocator: std.mem.Allocator, comptime ref: lowering_api.ValueRef, expected_fingerprint: u64, value: anytype) Error![]u8 {
                if (try Session.fingerprintTypedValueImage(ref, value) != expected_fingerprint) return error.ProgramContractViolation;
                var writer = Writer.init(allocator);
                errdefer writer.deinit();
                var context = Session.ValueImageContext.initCanonical(allocator);
                defer context.deinit();
                try writeExchangeValueRef(&writer, ref);
                Session.writeTypedValueImage(&writer, &context, ref, value) catch |err| return mapProgramRunError(Error, err);
                return writer.toOwnedSlice() catch |err| return mapProgramRunError(Error, err);
            }

            fn fingerprintExchangeValueImage(ref: lowering_api.ValueRef, value: anytype) Error!u64 {
                const ValueType = @TypeOf(value);
                switch (ref.codec) {
                    .unit, .bool, .i32, .usize, .string, .string_list => {
                        const expected_ref = comptime ProgramValueRefForType(body_value_schema_types, ValueType);
                        if (!ref.eql(expected_ref)) return error.ProgramContractViolation;
                        return Session.fingerprintTypedValueImage(expected_ref, value);
                    },
                    .product => {
                        const schema_index = ref.schema_index orelse return error.ProgramContractViolation;
                        inline for (body_value_schema_types, 0..) |SchemaType, index| {
                            if (schema_index == index) {
                                if (SchemaType != ValueType) return error.ProgramContractViolation;
                                return Session.fingerprintTypedValueImage(.{ .codec = .product, .schema_index = @intCast(index) }, value);
                            }
                        }
                        return error.ProgramContractViolation;
                    },
                    .sum => {
                        const schema_index = ref.schema_index orelse return error.ProgramContractViolation;
                        inline for (body_value_schema_types, 0..) |SchemaType, index| {
                            if (schema_index == index) {
                                if (SchemaType != ValueType) return error.ProgramContractViolation;
                                return Session.fingerprintTypedValueImage(.{ .codec = .sum, .schema_index = @intCast(index) }, value);
                            }
                        }
                        return error.ProgramContractViolation;
                    },
                }
            }

            fn encodeExchangeValueImage(allocator: std.mem.Allocator, ref: lowering_api.ValueRef, expected_fingerprint: u64, value: anytype) Error![]u8 {
                const ValueType = @TypeOf(value);
                switch (ref.codec) {
                    .unit, .bool, .i32, .usize, .string, .string_list => {
                        const expected_ref = comptime ProgramValueRefForType(body_value_schema_types, ValueType);
                        if (!ref.eql(expected_ref)) return error.ProgramContractViolation;
                        return encodeExchangeValueImageWithRef(allocator, expected_ref, expected_fingerprint, value);
                    },
                    .product => {
                        const schema_index = ref.schema_index orelse return error.ProgramContractViolation;
                        inline for (body_value_schema_types, 0..) |SchemaType, index| {
                            if (schema_index == index) {
                                if (SchemaType != ValueType) return error.ProgramContractViolation;
                                return encodeExchangeValueImageWithRef(allocator, .{ .codec = .product, .schema_index = @intCast(index) }, expected_fingerprint, value);
                            }
                        }
                        return error.ProgramContractViolation;
                    },
                    .sum => {
                        const schema_index = ref.schema_index orelse return error.ProgramContractViolation;
                        inline for (body_value_schema_types, 0..) |SchemaType, index| {
                            if (schema_index == index) {
                                if (SchemaType != ValueType) return error.ProgramContractViolation;
                                return encodeExchangeValueImageWithRef(allocator, .{ .codec = .sum, .schema_index = @intCast(index) }, expected_fingerprint, value);
                            }
                        }
                        return error.ProgramContractViolation;
                    },
                }
            }

            fn decodeExchangeValueImageWithRef(
                allocator: std.mem.Allocator,
                comptime ref: lowering_api.ValueRef,
                expected_fingerprint: u64,
                image: []const u8,
                comptime ValueType: type,
            ) Error!void {
                var journal = Session.Journal.init(allocator);
                defer journal.deinit();
                var replayer = journal.replayer();
                defer replayer.deinit();
                var reader = Reader.init(image);
                const encoded_ref = try readExchangeValueRef(&reader);
                if (!encoded_ref.eql(ref)) return error.ProgramContractViolation;
                var context = Session.ValueImageContext.init(allocator);
                defer context.deinit();
                const value = Session.readTypedValueImage(&reader, &replayer, &context, ref, ValueType) catch |err| return mapProgramRunError(Error, err);
                if (!reader.eof()) return error.ProgramContractViolation;
                if (try Session.fingerprintTypedValueImage(ref, value) != expected_fingerprint) return error.ProgramContractViolation;
                const canonical = try encodeExchangeValueImage(allocator, ref, expected_fingerprint, value);
                defer allocator.free(canonical);
                if (!std.mem.eql(u8, image, canonical)) return error.ProgramContractViolation;
            }

            fn decodeExchangeValueImageValueWithRef(
                allocator: std.mem.Allocator,
                comptime ref: lowering_api.ValueRef,
                expected_fingerprint: u64,
                image: []const u8,
                comptime ValueType: type,
            ) Error!ValueType {
                var journal = Session.Journal.init(allocator);
                defer journal.deinit();
                var replayer = journal.replayer();
                defer replayer.deinit();
                var reader = Reader.init(image);
                const encoded_ref = try readExchangeValueRef(&reader);
                if (!encoded_ref.eql(ref)) return error.ProgramContractViolation;
                var context = Session.ValueImageContext.init(allocator);
                defer context.deinit();
                const decoded = Session.readTypedValueImage(&reader, &replayer, &context, ref, ValueType) catch |err| return mapProgramRunError(Error, err);
                if (!reader.eof()) return error.ProgramContractViolation;
                if (try Session.fingerprintTypedValueImage(ref, decoded) != expected_fingerprint) return error.ProgramContractViolation;
                const canonical = try encodeExchangeValueImage(allocator, ref, expected_fingerprint, decoded);
                defer allocator.free(canonical);
                if (!std.mem.eql(u8, image, canonical)) return error.ProgramContractViolation;
                return cloneBodyOwnedResultValue(allocator, decoded) catch |err| return mapProgramRunError(Error, err);
            }

            fn decodeExchangeValueImage(
