            fn validateExchangeValueImage(allocator: std.mem.Allocator, ref: lowering_api.ValueRef, expected_fingerprint: u64, image: []const u8) Error!void {
                switch (ref.codec) {
                    .unit => try decodeExchangeValueImage(allocator, ref, expected_fingerprint, image, void),
                    .bool => try decodeExchangeValueImage(allocator, ref, expected_fingerprint, image, bool),
                    .i32 => try decodeExchangeValueImage(allocator, ref, expected_fingerprint, image, i32),
                    .usize => try decodeExchangeValueImage(allocator, ref, expected_fingerprint, image, usize),
                    .string => try decodeExchangeValueImage(allocator, ref, expected_fingerprint, image, []const u8),
                    .string_list => try decodeExchangeValueImage(allocator, ref, expected_fingerprint, image, []const []const u8),
                    .product, .sum => {
                        const schema_index = ref.schema_index orelse return error.ProgramContractViolation;
                        inline for (body_value_schema_types, 0..) |SchemaType, index| {
                            if (schema_index == index) {
                                try decodeExchangeValueImage(allocator, ref, expected_fingerprint, image, SchemaType);
                                return;
                            }
                        }
                        return error.ProgramContractViolation;
                    },
                }
            }

            fn expectedResponseRef(request: RequestEnvelope, kind_value: ResponseKind) Error!lowering_api.ValueRef {
                return switch (kind_value) {
                    .@"resume" => request.expected_resume_ref orelse error.ProgramContractViolation,
                    .return_now => request.expected_return_ref orelse error.ProgramContractViolation,
                    .resume_after => request.expected_after_ref orelse error.ProgramContractViolation,
                };
            }

            fn responseTraceFromEnvelope(request_fingerprint: u64, kind_value: ResponseKind, ref: lowering_api.ValueRef, value_fingerprint: u64) Session.Trace.Response {
                var hasher = std.hash.Wyhash.init(0);
                hashBytes(&hasher, "ability.session.response");
                hashU32(&hasher, Session.Trace.fingerprint_version);
                hashU64(&hasher, request_fingerprint);
                hashBytes(&hasher, @tagName(kind_value));
                Session.hashJournalTraceValueRef(&hasher, ref);
                hashU64(&hasher, value_fingerprint);
                return .{
                    .request_fingerprint = request_fingerprint,
                    .kind = kind_value,
                    .response_ref = ref,
                    .response_value_fingerprint = value_fingerprint,
                    .fingerprint = hasher.final(),
                };
            }

            fn validateOperationEnvelopeSite(envelope: RequestEnvelope) Error!void {
                inline for (protocol.operation_site_metadata) |site| {
                    if (site.index == envelope.site_index) {
                        if (site.fingerprint != envelope.site_fingerprint) return error.ProgramContractViolation;
                        if (!optionalBytesEql(envelope.semantic_label, site.semantic_label)) return error.ProgramContractViolation;
                        if (!std.mem.eql(u8, envelope.name, site.op_name)) return error.ProgramContractViolation;
                        if (envelope.mode != site.op_mode) return error.ProgramContractViolation;
                        if (!site.payload_ref.eql(envelope.value_ref)) return error.ProgramContractViolation;
                        if (!site.result_ref.eql(envelope.result_ref)) return error.ProgramContractViolation;
                        if (!optionalValueRefEql(envelope.expected_resume_ref, if (site.op_mode == .abort) null else site.resume_ref)) return error.ProgramContractViolation;
                        if (!optionalValueRefEql(envelope.expected_return_ref, if (site.op_mode == .transform) null else site.result_ref)) return error.ProgramContractViolation;
                        if (envelope.expected_after_ref != null) return error.ProgramContractViolation;
                        const trace: Session.Trace.OperationRequest = .{
                            .program_label = label,
                            .plan_label = body_compiled_plan.label,
                            .plan_hash = body_compiled_plan_hash,
                            .turn_index = envelope.turn_index,
                            .operation_site_index = site.index,
                            .operation_site_fingerprint = site.fingerprint,
                            .semantic_label = site.semantic_label,
                            .function_index = site.function_index,
                            .block_index = site.block_index,
                            .instruction_index = site.instruction_index,
                            .requirement_index = site.requirement_index,
                            .requirement_label = site.requirement_label,
                            .op_index = site.op_index,
                            .op_name = site.op_name,
                            .mode = site.op_mode,
                            .payload_ref = site.payload_ref,
                            .has_payload = site.payload_ref.codec != .unit,
                            .payload_value_fingerprint = envelope.value_fingerprint,
                            .resume_ref = site.resume_ref,
                            .result_ref = site.result_ref,
                            .has_after = site.has_after,
                            .fingerprint = 0,
                        };
                        const expected_fingerprint = Session.fingerprintJournalOperationRequestTrace(trace);
                        if (envelope.request_fingerprint != expected_fingerprint or envelope.trace_fingerprint != expected_fingerprint) return error.ProgramContractViolation;
                        return;
                    }
                }
                return error.ProgramContractViolation;
            }

            fn validateAfterEnvelopeSite(envelope: RequestEnvelope) Error!void {
                inline for (protocol.after_site_metadata) |site| {
                    if (site.index == envelope.site_index) {
                        if (site.fingerprint != envelope.site_fingerprint) return error.ProgramContractViolation;
                        if (!optionalBytesEql(envelope.semantic_label, site.semantic_label)) return error.ProgramContractViolation;
                        if (!std.mem.eql(u8, envelope.name, site.original_op_name)) return error.ProgramContractViolation;
                        if (envelope.mode != .transform) return error.ProgramContractViolation;
                        if (!site.result_ref.eql(envelope.result_ref)) return error.ProgramContractViolation;
                        if (envelope.expected_resume_ref != null or envelope.expected_return_ref != null) return error.ProgramContractViolation;
                        if (envelope.expected_after_ref == null) return error.ProgramContractViolation;
                        inline for (protocol.operation_site_metadata) |operation_site| {
                            if (operation_site.index == site.source_operation_site_index) {
                                if (operation_site.fingerprint != site.source_operation_site_fingerprint) return error.ProgramContractViolation;
                                const expected_input_ref = comptime lowering_api.sessionAfterProtocolInputRefForOperationSite(body_compiled_plan, body_value_schema_types, HandlersType, operation_site);
                                if (expected_input_ref) |input_ref| {
                                    if (!envelope.value_ref.eql(input_ref)) return error.ProgramContractViolation;
                                }
                                const expected_output_ref = comptime lowering_api.sessionAfterProtocolOutputRefForOperationSite(body_compiled_plan, body_value_schema_types, HandlersType, operation_site);
                                if (!envelope.expected_after_ref.?.eql(expected_output_ref)) return error.ProgramContractViolation;
                                const trace: Session.Trace.AfterRequest = .{
                                    .program_label = label,
                                    .plan_label = body_compiled_plan.label,
                                    .plan_hash = body_compiled_plan_hash,
                                    .turn_index = envelope.turn_index,
                                    .after_site_index = site.index,
                                    .after_site_fingerprint = site.fingerprint,
                                    .semantic_label = site.semantic_label,
                                    .source_operation_site_index = site.source_operation_site_index,
                                    .source_operation_site_fingerprint = site.source_operation_site_fingerprint,
                                    .function_index = site.source_function_index,
                                    .block_index = site.source_block_index,
                                    .instruction_index = site.source_instruction_index,
                                    .original_requirement_index = site.original_requirement_index,
                                    .original_requirement_label = site.original_requirement_label,
                                    .original_op_index = site.original_op_index,
                                    .original_op_name = site.original_op_name,
                                    .current_value_ref = envelope.value_ref,
                                    .current_value_fingerprint = envelope.value_fingerprint,
                                    .expected_output_ref = expected_output_ref,
                                    .result_ref = site.result_ref,
                                    .fingerprint = 0,
                                };
                                const expected_fingerprint = Session.fingerprintJournalAfterRequestTrace(trace);
                                if (envelope.request_fingerprint != expected_fingerprint or envelope.trace_fingerprint != expected_fingerprint) return error.ProgramContractViolation;
                                return;
                            }
                        }
                        return error.ProgramContractViolation;
                    }
                }
                return error.ProgramContractViolation;
            }

            fn requestRequirementLabel(request: RequestEnvelope) ?[]const u8 {
                return switch (request.kind) {
                    .operation => blk: {
                        inline for (protocol.operation_site_metadata) |site| {
                            if (site.index == request.site_index and site.fingerprint == request.site_fingerprint) break :blk site.requirement_label;
                        }
                        break :blk null;
                    },
                    .after => blk: {
                        inline for (protocol.after_site_metadata) |site| {
                            if (site.index == request.site_index and site.fingerprint == request.site_fingerprint) break :blk site.original_requirement_label;
                        }
                        break :blk null;
                    },
                };
            }

            fn requestProtocolOperationFingerprint(request: RequestEnvelope) ?u64 {
                return switch (request.kind) {
                    .operation => request.site_fingerprint,
                    .after => blk: {
                        inline for (protocol.after_site_metadata) |site| {
                            if (site.index == request.site_index and site.fingerprint == request.site_fingerprint) break :blk site.source_operation_site_fingerprint;
                        }
                        break :blk null;
                    },
                };
            }

            fn optionalValueRefEql(actual: ?lowering_api.ValueRef, expected: ?lowering_api.ValueRef) bool {
                if (actual == null and expected == null) return true;
                if (actual == null or expected == null) return false;
                return actual.?.eql(expected.?);
            }

            fn optionalBytesEql(actual: ?[]const u8, expected: ?[]const u8) bool {
                if (actual == null and expected == null) return true;
                if (actual == null or expected == null) return false;
                return std.mem.eql(u8, actual.?, expected.?);
            }

            fn requestUsageMetadataEql(actual: ?RequestUsageMetadata, expected: ?RequestUsageMetadata) bool {
                if (actual == null and expected == null) return true;
                if (actual == null or expected == null) return false;
                const left = actual.?;
                const right = expected.?;
                return left.effect_session_spec_fingerprint == right.effect_session_spec_fingerprint and
                    left.capability_instance_fingerprint == right.capability_instance_fingerprint and
                    left.obligation_fingerprint == right.obligation_fingerprint and
                    left.usage == right.usage and
                    left.branch_id == right.branch_id and
                    left.branch_policy == right.branch_policy and
                    left.replay_policy == right.replay_policy and
                    left.ephemeral == right.ephemeral and
                    left.cancelable == right.cancelable;
            }

            fn validateCapsuleImageForEnvelope(envelope: RequestEnvelope) Error!void {
                const image_bytes = envelope.capsule_image orelse return;
                const image_fingerprint = envelope.capsule_image_fingerprint orelse return error.ProgramContractViolation;
                if (image_fingerprint != Session.capsuleImageFingerprint(image_bytes)) return error.ProgramContractViolation;
                var capsule = try Session.Capsule.decode(envelope.allocator, image_bytes);
                defer capsule.deinit();
                const metadata = capsule.metadata();
                if (metadata.current_request_fingerprint != envelope.request_fingerprint) return error.ProgramContractViolation;
                switch (envelope.kind) {
                    .operation => {
                        if (metadata.parked_kind != .operation) return error.ProgramContractViolation;
                        if (metadata.current_operation_site_index == null or metadata.current_operation_site_index.? != envelope.site_index) return error.ProgramContractViolation;
                    },
                    .after => {
                        if (metadata.parked_kind != .after) return error.ProgramContractViolation;
                        if (metadata.current_after_site_index == null or metadata.current_after_site_index.? != envelope.site_index) return error.ProgramContractViolation;
                    },
                }
            }

            fn exchangeFingerprint(domain: []const u8, version: u32, bytes: []const u8) u64 {
                var hasher = std.hash.Wyhash.init(0);
                hashBytes(&hasher, domain);
                hashU32(&hasher, version);
                hashBytes(&hasher, bytes);
                return hasher.final();
            }

            fn journalBranchPolicyFingerprint(journal_branch_id: []const u8) u64 {
                return exchangeFingerprint("ability.exchange.journal.policy", exchange_capability_fingerprint_version, journal_branch_id);
            }

            fn checkedPayload(bytes: []const u8, domain: []const u8, version: u32) Error![]const u8 {
                if (bytes.len < 8) return error.ProgramContractViolation;
                const payload = bytes[0 .. bytes.len - 8];
                const actual = std.mem.readInt(u64, bytes[bytes.len - 8 ..][0..8], .little);
                if (actual != exchangeFingerprint(domain, version, payload)) return error.ProgramContractViolation;
                return payload;
            }

            fn checkedBytesFingerprint(bytes: []const u8, domain: []const u8, version: u32) Error!u64 {
                const payload = try checkedPayload(bytes, domain, version);
                return exchangeFingerprint(domain, version, payload);
            }

            fn supportedRequestEnvelopeVersions(format_version: u32, fingerprint_version: u32) bool {
                return (format_version == 1 and fingerprint_version == 1) or
                    (format_version == 2 and fingerprint_version == 2) or
                    (format_version == exchange_request_format_version and fingerprint_version == exchange_request_fingerprint_version);
            }

            fn checkedRequestPayload(bytes: []const u8) Error![]const u8 {
                if (bytes.len < 8) return error.ProgramContractViolation;
                const payload = bytes[0 .. bytes.len - 8];
                const actual = std.mem.readInt(u64, bytes[bytes.len - 8 ..][0..8], .little);
                var reader = Reader.init(payload);
                try reader.expectBytes(request_magic);
                const format_version = try reader.readU32();
                const fingerprint_version = try reader.readU32();
                if (!supportedRequestEnvelopeVersions(format_version, fingerprint_version)) return error.ProgramContractViolation;
                if (actual != exchangeFingerprint("ability.exchange.request", fingerprint_version, payload)) return error.ProgramContractViolation;
                return payload;
            }

            fn checkedRequestBytesFingerprint(bytes: []const u8) Error!u64 {
                const payload = try checkedRequestPayload(bytes);
                return std.mem.readInt(u64, bytes[payload.len..][0..8], .little);
            }

            fn writeExchangeValueRef(writer: *Writer, ref: lowering_api.ValueRef) std.mem.Allocator.Error!void {
                try writer.writeU8(@intFromEnum(ref.codec));
                try writer.writeBool(ref.schema_index != null);
                if (ref.schema_index) |schema_index| try writer.writeU16(schema_index);
            }

            fn readExchangeValueRef(reader: *Reader) Error!lowering_api.ValueRef {
                return Session.readExchangeValueRef(reader);
            }

            fn writeOptionalValueRef(writer: *Writer, ref: ?lowering_api.ValueRef) std.mem.Allocator.Error!void {
                try writer.writeBool(ref != null);
                if (ref) |actual| try writeExchangeValueRef(writer, actual);
            }

            fn readOptionalValueRef(reader: *Reader) Error!?lowering_api.ValueRef {
                if (!try reader.readBool()) return null;
                return try readExchangeValueRef(reader);
            }

            fn writeOptionalBytes(writer: *Writer, value: ?[]const u8) std.mem.Allocator.Error!void {
                try writer.writeBool(value != null);
                if (value) |actual| try writer.writeLenBytes(actual);
            }

            fn readOptionalOwnedBytes(allocator: std.mem.Allocator, reader: *Reader) Error!?[]u8 {
                if (!try reader.readBool()) return null;
                return allocator.dupe(u8, try reader.readLenBytes()) catch |err| return mapProgramRunError(Error, err);
            }

            fn writeUsage(writer: *Writer, usage: Usage) std.mem.Allocator.Error!void {
                try writer.writeU8(switch (usage) {
                    .copyable => 0,
                    .replayable => 1,
                    .affine => 2,
                    .linear => 3,
                    .ephemeral => 4,
                });
            }

            fn readUsage(reader: *Reader) Error!Usage {
                return switch (try reader.readU8()) {
                    0 => .copyable,
                    1 => .replayable,
                    2 => .affine,
                    3 => .linear,
                    4 => .ephemeral,
                    else => error.ProgramContractViolation,
                };
            }

            fn writeResponseUse(writer: *Writer, use_value: ResponseUse) std.mem.Allocator.Error!void {
                try writer.writeU8(switch (use_value) {
                    .fresh => 0,
                    .replayed => 1,
                    .deterministic_replay => 2,
                    .override => 3,
                });
            }

            fn readResponseUse(reader: *Reader) Error!ResponseUse {
                return switch (try reader.readU8()) {
                    0 => .fresh,
                    1 => .replayed,
                    2 => .deterministic_replay,
                    3 => .override,
                    else => error.ProgramContractViolation,
                };
            }

            fn writeBranchPolicy(writer: *Writer, policy_value: BranchPolicy) std.mem.Allocator.Error!void {
                try writer.writeU8(switch (policy_value) {
                    .unrestricted => 0,
                    .replay_only => 1,
                    .single_live_branch => 2,
                    .split_required => 3,
                    .no_branch => 4,
                    .host_owned => 5,
                });
            }

            fn readBranchPolicy(reader: *Reader) Error!BranchPolicy {
                return switch (try reader.readU8()) {
                    0 => .unrestricted,
                    1 => .replay_only,
                    2 => .single_live_branch,
                    3 => .split_required,
                    4 => .no_branch,
                    5 => .host_owned,
                    else => error.ProgramContractViolation,
                };
            }

            fn writeRequestUsageMetadata(writer: *Writer, metadata: ?RequestUsageMetadata) std.mem.Allocator.Error!void {
                try writer.writeBool(metadata != null);
                if (metadata) |value| {
                    try writeOptionalU64(writer, value.effect_session_spec_fingerprint);
                    try writeOptionalU64(writer, value.capability_instance_fingerprint);
                    try writeOptionalU64(writer, value.obligation_fingerprint);
                    try writeUsage(writer, value.usage);
                    try writer.writeU64(value.branch_id);
                    try writeBranchPolicy(writer, value.branch_policy);
                    try writeResponseUse(writer, value.replay_policy);
                    try writer.writeBool(value.ephemeral);
                    try writer.writeBool(value.cancelable);
                }
            }

            fn readRequestUsageMetadata(reader: *Reader) Error!?RequestUsageMetadata {
                if (!try reader.readBool()) return null;
                return .{
                    .effect_session_spec_fingerprint = try readOptionalU64(reader),
                    .capability_instance_fingerprint = try readOptionalU64(reader),
                    .obligation_fingerprint = try readOptionalU64(reader),
                    .usage = try readUsage(reader),
                    .branch_id = try reader.readU64(),
                    .branch_policy = try readBranchPolicy(reader),
                    .replay_policy = try readResponseUse(reader),
                    .ephemeral = try reader.readBool(),
                    .cancelable = try reader.readBool(),
                };
            }

            fn expectOptionalBytes(reader: *Reader, expected: ?[]const u8) Error!void {
                if (try reader.readBool()) {
                    const actual = try reader.readLenBytes();
                    if (expected == null or !std.mem.eql(u8, actual, expected.?)) return error.ProgramContractViolation;
                } else if (expected != null) return error.ProgramContractViolation;
            }

            fn dupeExpectedString(allocator: std.mem.Allocator, reader: *Reader, expected: []const u8) Error![]u8 {
                const actual = try reader.readLenBytes();
                if (!std.mem.eql(u8, actual, expected)) return error.ProgramContractViolation;
                return allocator.dupe(u8, actual) catch |err| return mapProgramRunError(Error, err);
            }

            fn cloneU64s(allocator: std.mem.Allocator, values: []const u64) Error![]u64 {
                return allocator.dupe(u64, values) catch |err| return mapProgramRunError(Error, err);
            }

            fn cloneUsizes(allocator: std.mem.Allocator, values: []const usize) Error![]usize {
                return allocator.dupe(usize, values) catch |err| return mapProgramRunError(Error, err);
            }

            fn cloneValueRefs(allocator: std.mem.Allocator, values: []const lowering_api.ValueRef) Error![]lowering_api.ValueRef {
                return allocator.dupe(lowering_api.ValueRef, values) catch |err| return mapProgramRunError(Error, err);
            }

            fn cloneStringList(allocator: std.mem.Allocator, values: []const []const u8) Error![]const []const u8 {
                const owned = allocator.alloc([]u8, values.len) catch |err| return mapProgramRunError(Error, err);
                var filled: usize = 0;
                errdefer {
                    for (owned[0..filled]) |item| allocator.free(item);
                    allocator.free(owned);
                }
                for (values, 0..) |value, index| {
                    owned[index] = allocator.dupe(u8, value) catch |err| return mapProgramRunError(Error, err);
                    filled += 1;
                }
                return owned;
            }

            fn freeStringList(allocator: std.mem.Allocator, values: []const []const u8) void {
                for (values) |value| allocator.free(value);
                allocator.free(values);
            }

            fn writeStringList(writer: *Writer, values: []const []const u8) std.mem.Allocator.Error!void {
                try writer.writeUsize(values.len);
                for (values) |value| try writer.writeLenBytes(value);
            }

            fn readStringList(allocator: std.mem.Allocator, reader: *Reader) Error![]const []const u8 {
                const count = try reader.readUsize();
                if (count > reader.remaining() / 8) return error.ProgramContractViolation;
                const values = allocator.alloc([]u8, count) catch |err| return mapProgramRunError(Error, err);
                var filled: usize = 0;
                errdefer {
                    for (values[0..filled]) |item| allocator.free(item);
                    allocator.free(values);
                }
                for (0..count) |index| {
                    values[index] = allocator.dupe(u8, try reader.readLenBytes()) catch |err| return mapProgramRunError(Error, err);
                    filled += 1;
                }
                return values;
            }

            fn writeU64List(writer: *Writer, values: []const u64) std.mem.Allocator.Error!void {
                try writer.writeUsize(values.len);
                for (values) |value| try writer.writeU64(value);
            }

            fn readU64List(allocator: std.mem.Allocator, reader: *Reader) Error![]u64 {
                const count = try reader.readUsize();
                if (count > reader.remaining() / 8) return error.ProgramContractViolation;
                const values = allocator.alloc(u64, count) catch |err| return mapProgramRunError(Error, err);
                errdefer allocator.free(values);
                for (values) |*value| value.* = try reader.readU64();
                return values;
            }

            fn writeUsizeList(writer: *Writer, values: []const usize) std.mem.Allocator.Error!void {
                try writer.writeUsize(values.len);
                for (values) |value| try writer.writeUsize(value);
            }

            fn readUsizeList(allocator: std.mem.Allocator, reader: *Reader) Error![]usize {
                const count = try reader.readUsize();
                if (count > reader.remaining() / 8) return error.ProgramContractViolation;
                const values = allocator.alloc(usize, count) catch |err| return mapProgramRunError(Error, err);
                errdefer allocator.free(values);
                for (values) |*value| value.* = try reader.readUsize();
                return values;
            }

            fn writeValueRefList(writer: *Writer, values: []const lowering_api.ValueRef) std.mem.Allocator.Error!void {
                try writer.writeUsize(values.len);
                for (values) |value| try writeExchangeValueRef(writer, value);
            }

            fn readValueRefList(allocator: std.mem.Allocator, reader: *Reader) Error![]lowering_api.ValueRef {
                const count = try reader.readUsize();
                if (count > reader.remaining() / 2) return error.ProgramContractViolation;
                const values = allocator.alloc(lowering_api.ValueRef, count) catch |err| return mapProgramRunError(Error, err);
                errdefer allocator.free(values);
                for (values) |*value| value.* = try readExchangeValueRef(reader);
                return values;
            }

            fn expectStringList(reader: *Reader, expected: []const []const u8) Error!void {
                const count = try reader.readUsize();
                if (count != expected.len) return error.ProgramContractViolation;
                for (expected) |value| {
                    if (!std.mem.eql(u8, try reader.readLenBytes(), value)) return error.ProgramContractViolation;
                }
            }

            fn expectU64List(reader: *Reader, expected: []const u64) Error!void {
                const count = try reader.readUsize();
                if (count != expected.len) return error.ProgramContractViolation;
                for (expected) |value| {
                    if (try reader.readU64() != value) return error.ProgramContractViolation;
                }
            }

            fn expectUsizeList(reader: *Reader, expected: []const usize) Error!void {
                const count = try reader.readUsize();
                if (count != expected.len) return error.ProgramContractViolation;
                for (expected) |value| {
                    if (try reader.readUsize() != value) return error.ProgramContractViolation;
                }
            }

            fn expectValueRefList(reader: *Reader, expected: []const lowering_api.ValueRef) Error!void {
                const count = try reader.readUsize();
                if (count != expected.len) return error.ProgramContractViolation;
                for (expected) |value| {
                    const actual = try readExchangeValueRef(reader);
                    if (!actual.eql(value)) return error.ProgramContractViolation;
                }
            }

            fn writeOptionalU64(writer: *Writer, value: ?u64) std.mem.Allocator.Error!void {
                try writer.writeBool(value != null);
                if (value) |actual| try writer.writeU64(actual);
            }

            fn readOptionalU64(reader: *Reader) Error!?u64 {
                if (!try reader.readBool()) return null;
                return try reader.readU64();
            }

            fn writeResponseKindSet(writer: *Writer, set: Policy.ResponseKindSet) std.mem.Allocator.Error!void {
                try writer.writeBool(set.@"resume");
                try writer.writeBool(set.return_now);
                try writer.writeBool(set.resume_after);
            }

            fn readResponseKindSet(reader: *Reader) Error!Policy.ResponseKindSet {
                return .{
                    .@"resume" = try reader.readBool(),
                    .return_now = try reader.readBool(),
                    .resume_after = try reader.readBool(),
                };
            }

            fn responseKindSetsEqual(left: Policy.ResponseKindSet, right: Policy.ResponseKindSet) bool {
                return left.@"resume" == right.@"resume" and
                    left.return_now == right.return_now and
                    left.resume_after == right.resume_after;
            }

            fn usageSetsEqual(left: UsageSet, right: UsageSet) bool {
                return left.copyable == right.copyable and
                    left.replayable == right.replayable and
                    left.affine == right.affine and
                    left.linear == right.linear and
                    left.ephemeral == right.ephemeral;
            }

            fn responseUseSetsEqual(left: ResponseUseSet, right: ResponseUseSet) bool {
                return left.fresh == right.fresh and
                    left.replayed == right.replayed and
                    left.deterministic_replay == right.deterministic_replay and
                    left.override == right.override;
            }

            fn branchPolicySetsEqual(left: BranchPolicySet, right: BranchPolicySet) bool {
                return left.unrestricted == right.unrestricted and
                    left.replay_only == right.replay_only and
                    left.single_live_branch == right.single_live_branch and
                    left.split_required == right.split_required and
                    left.no_branch == right.no_branch and
                    left.host_owned == right.host_owned;
            }

            fn responseKindSetForRequest(request: RequestEnvelope) Policy.ResponseKindSet {
                return .{
                    .@"resume" = request.expected_resume_ref != null,
                    .return_now = request.expected_return_ref != null,
                    .resume_after = request.expected_after_ref != null,
                };
            }

            fn responseRefsForRequest(request: RequestEnvelope, refs: *[3]lowering_api.ValueRef) usize {
                var count: usize = 0;
                if (request.expected_resume_ref) |ref| {
                    refs[count] = ref;
                    count += 1;
                }
                if (request.expected_return_ref) |ref| {
                    refs[count] = ref;
                    count += 1;
                }
                if (request.expected_after_ref) |ref| {
                    refs[count] = ref;
                    count += 1;
                }
                return count;
            }

            fn responseRefsForKinds(request: RequestEnvelope, kinds: Policy.ResponseKindSet, refs: *[3]lowering_api.ValueRef) usize {
                var count: usize = 0;
                if (kinds.@"resume") {
                    if (request.expected_resume_ref) |ref| {
                        refs[count] = ref;
                        count += 1;
                    }
                }
                if (kinds.return_now) {
                    if (request.expected_return_ref) |ref| {
                        refs[count] = ref;
                        count += 1;
                    }
                }
                if (kinds.resume_after) {
                    if (request.expected_after_ref) |ref| {
                        refs[count] = ref;
                        count += 1;
                    }
                }
                return count;
            }

            fn expectedResponseRefsForTreaty(request: RequestEnvelope, request_value: TreatyRequest, kinds: Policy.ResponseKindSet, refs: *[3]lowering_api.ValueRef) usize {
                var count: usize = 0;
                if (request.expected_resume_ref) |ref| {
                    if (kinds.@"resume" and listAllowsValueRef(request_value.desired_response_refs, ref)) {
                        refs[count] = ref;
                        count += 1;
                    }
                }
                if (request.expected_return_ref) |ref| {
                    if (kinds.return_now and listAllowsValueRef(request_value.desired_response_refs, ref)) {
                        refs[count] = ref;
                        count += 1;
                    }
                }
                if (request.expected_after_ref) |ref| {
                    if (kinds.resume_after and listAllowsValueRef(request_value.desired_response_refs, ref)) {
                        refs[count] = ref;
                        count += 1;
                    }
                }
                return count;
            }

            fn filterResponseRefsForOffer(offer: ProviderOffer, refs: *[3]lowering_api.ValueRef, refs_len: usize) usize {
                var count: usize = 0;
                for (refs[0..refs_len]) |ref| {
                    const offer_allows_ref = offer.produced_response_refs.len == 0 or listAllowsValueRef(offer.produced_response_refs, ref);
                    if (offer_allows_ref and !valueRefListContains(refs[0..count], ref)) {
                        refs[count] = ref;
                        count += 1;
                    }
                }
                return count;
            }

            fn filterResponseRefsForTreaty(offer: ProviderOffer, morphism: ?MorphismOffer, refs: *[3]lowering_api.ValueRef, refs_len: usize) usize {
                if (morphism) |morphism_offer| {
                    var count: usize = 0;
                    for (refs[0..refs_len]) |ref| {
                        const morphism_allows_source_ref = if (morphism_offer.target_response_refs.len == 0)
                            morphism_offer.source_response_refs.len == 0 or listAllowsValueRef(morphism_offer.source_response_refs, ref)
                        else
                            valueRefListContains(morphism_offer.source_response_refs, ref);
                        const offer_allows_target_ref = if (morphism_offer.target_response_refs.len == 0)
                            listAllowsValueRef(offer.produced_response_refs, ref)
                        else
                            offer.supportsProtocolOperation(morphism_offer.target_protocol_op_fingerprint, morphism_offer.target_response_refs);
                        if (morphism_allows_source_ref and offer_allows_target_ref and !valueRefListContains(refs[0..count], ref)) {
                            refs[count] = ref;
                            count += 1;
                        }
                    }
                    return count;
                }
                return filterResponseRefsForOffer(offer, refs, refs_len);
            }

            fn responseKindsForRefs(request: RequestEnvelope, kinds: Policy.ResponseKindSet, refs: []const lowering_api.ValueRef) Policy.ResponseKindSet {
                var result: Policy.ResponseKindSet = .{
                    .@"resume" = false,
                    .return_now = false,
                    .resume_after = false,
                };
                if (kinds.@"resume") {
                    if (request.expected_resume_ref) |ref| {
                        result.@"resume" = valueRefListContains(refs, ref);
                    }
                }
                if (kinds.return_now) {
                    if (request.expected_return_ref) |ref| {
                        result.return_now = valueRefListContains(refs, ref);
                    }
                }
                if (kinds.resume_after) {
                    if (request.expected_after_ref) |ref| {
                        result.resume_after = valueRefListContains(refs, ref);
                    }
                }
                return result;
            }

            fn offerUsageCompatible(offer: ProviderOffer, request: RequestEnvelope) bool {
                const metadata = request.usage_metadata orelse return offer.supported_usage_modes.allows(.copyable) and
                    offer.supported_response_uses.allows(.fresh) and
                    offer.supported_replay_policies.allows(.fresh) and
                    offer.supported_branch_policies.allows(.unrestricted);
                return offer.supported_usage_modes.allows(metadata.usage) and
                    offer.supported_response_uses.allows(.fresh) and
                    offer.supported_replay_policies.allows(metadata.replay_policy) and
                    offer.supported_branch_policies.allows(metadata.branch_policy);
            }

            fn offerResponseCompatible(offer: ProviderOffer, request: RequestEnvelope) bool {
                if (!requestAcceptsAnyResponseKind(request, offer.allowed_response_kinds)) return false;
                var refs: [3]lowering_api.ValueRef = undefined;
                const count = responseRefsForKinds(request, offer.allowed_response_kinds, &refs);
                if (offer.produced_response_refs.len == 0) return count != 0;
                for (refs[0..count]) |ref| {
                    if (listAllowsValueRef(offer.produced_response_refs, ref)) return true;
                }
                return false;
            }

            fn offerSourceSurfaceCompatible(offer: ProviderOffer, request: RequestEnvelope) bool {
                offer.validate() catch return false;
                request.validate() catch return false;
                if (offer.manifest_fingerprint != request.manifest_fingerprint) return false;
                if (request.bytes.len > offer.max_request_bytes) return false;
                if (request.capsule_image) |image| {
                    const has_capsule = true;
                    if (!offer.capsule_policy.allows(has_capsule) or image.len > offer.max_capsule_bytes) return false;
                } else {
                    const has_capsule = false;
                    if (!offer.capsule_policy.allows(has_capsule)) return false;
                }
                const requirement_label = requestRequirementLabel(request) orelse return false;
                if (!listAllowsString(offer.supported_protocol_labels, requirement_label)) return false;
                const protocol_op = requestProtocolOperationFingerprint(request) orelse return false;
                if (!listAllowsU64(offer.supported_protocol_op_fingerprints, protocol_op)) return false;
                const operation_sites_constrained = offer.supported_operation_sites.len != 0;
                const after_sites_constrained = offer.supported_after_sites.len != 0;
                return switch (request.kind) {
                    .operation => blk: {
                        if (!operation_sites_constrained and after_sites_constrained) break :blk false;
                        break :blk listAllowsValueRef(offer.accepted_payload_refs, request.value_ref) and listAllowsUsize(offer.supported_operation_sites, request.site_index);
                    },
                    .after => blk: {
                        if (!after_sites_constrained and operation_sites_constrained) break :blk false;
                        break :blk offerAllowsCurrentValueRef(offer.accepted_current_value_refs, request.value_ref) and listAllowsUsize(offer.supported_after_sites, request.site_index);
                    },
                };
            }

            fn treatyResponseUseAllowed(policy: Treaty.Policy, offer: ProviderOffer, response_use: ResponseUse) bool {
                return policy.allowed_response_uses.allows(response_use) and offer.supported_response_uses.allows(response_use);
            }

            fn treatyResponseUseForOffer(policy: Treaty.Policy, request_value: TreatyRequest, offer: ProviderOffer) ResponseUse {
                if (request_value.requested_response_use) |requested| return requested;
                if (policy.require_replay_only_response) {
                    if (treatyResponseUseAllowed(policy, offer, .replayed)) return .replayed;
                    if (treatyResponseUseAllowed(policy, offer, .deterministic_replay)) return .deterministic_replay;
                    return .replayed;
                }
                return .fresh;
            }

            fn treatyUsage(request: RequestEnvelope, request_value: TreatyRequest) Usage {
                return request_value.requested_usage_mode orelse if (request.usage_metadata) |metadata| metadata.usage else .copyable;
            }

            fn treatyReplayPolicy(request: RequestEnvelope, request_value: TreatyRequest) ResponseUse {
                return request_value.requested_replay_policy orelse if (request.usage_metadata) |metadata| metadata.replay_policy else .fresh;
            }

            fn treatyBranchPolicy(request: RequestEnvelope, request_value: TreatyRequest) BranchPolicy {
                return request_value.requested_branch_policy orelse if (request.usage_metadata) |metadata| metadata.branch_policy else .unrestricted;
            }

            fn offerUsageCompatibleForTreaty(offer: ProviderOffer, request: RequestEnvelope, request_value: TreatyRequest, policy: Treaty.Policy) bool {
                const usage = treatyUsage(request, request_value);
                const response_use = treatyResponseUseForOffer(policy, request_value, offer);
                const replay_policy = treatyReplayPolicy(request, request_value);
                const branch_policy = treatyBranchPolicy(request, request_value);
                return offer.supported_usage_modes.allows(usage) and
                    offer.supported_response_uses.allows(response_use) and
                    offer.supported_replay_policies.allows(replay_policy) and
                    offer.supported_branch_policies.allows(branch_policy);
            }

            fn offerResponseCompatibleForTreaty(offer: ProviderOffer, request: RequestEnvelope, request_value: TreatyRequest) bool {
                const kinds = responseKindSetIntersection(responseKindSetForRequest(request), responseKindSetIntersection(request_value.desired_response_kinds, offer.allowed_response_kinds));
                if (!requestAcceptsAnyResponseKind(request, kinds)) return false;
                var refs: [3]lowering_api.ValueRef = undefined;
                var refs_len = expectedResponseRefsForTreaty(request, request_value, kinds, &refs);
                refs_len = filterResponseRefsForOffer(offer, &refs, refs_len);
                if (refs_len == 0) return false;
                return true;
            }

            fn fingerprintMorphismOffer(offer: MorphismOffer) u64 {
                var hasher = std.hash.Wyhash.init(0);
                hashBytes(&hasher, "ability.exchange.morphism_offer");
                hashU32(&hasher, exchange_morphism_offer_fingerprint_version);
                hashBytes(&hasher, offer.label);
                hashOptionalExchangeU64(&hasher, offer.source_site_fingerprint);
                hashOptionalExchangeU64(&hasher, offer.source_protocol_op_fingerprint);
                hashU64(&hasher, offer.target_protocol_op_fingerprint);
                hashOptionalExchangeU64(&hasher, offer.dynamic_morphism_fingerprint);
                hashOptionalExchangeU64(&hasher, offer.residual_morphism_fingerprint);
                hashOptionalExchangeU64(&hasher, offer.pipeline_fingerprint);
                hashBytes(&hasher, @tagName(offer.source_usage));
                hashBytes(&hasher, @tagName(offer.target_usage));
                hashValueRefList(&hasher, offer.source_response_refs);
                hashValueRefList(&hasher, offer.target_response_refs);
                hashUsize(&hasher, offer.blockers.len);
                for (offer.blockers) |blocker| hashBytes(&hasher, @tagName(blocker.tag));
                return hasher.final();
            }

            fn fingerprintTreatyCertificate(certificate: Treaty.Certificate) u64 {
                var hasher = std.hash.Wyhash.init(0);
                hashBytes(&hasher, "ability.exchange.treaty.certificate");
                hashU32(&hasher, exchange_treaty_certificate_fingerprint_version);
                hashU64(&hasher, certificate.treaty_fingerprint);
                hashU64(&hasher, certificate.request_envelope_fingerprint);
                hashU32(&hasher, certificate.request_envelope_format_version);
                hashU64(&hasher, certificate.request_fingerprint);
                hashU64(&hasher, certificate.manifest_fingerprint);
                hashU64(&hasher, certificate.provider_fingerprint);
                hashU64(&hasher, certificate.provider_offer_fingerprint);
                hashStringList(&hasher, certificate.provider_offer_tags);
                hashU64(&hasher, certificate.capability_fingerprint);
                hashOptionalExchangeU64(&hasher, certificate.attenuated_capability_fingerprint);
                hashU64(&hasher, certificate.capability_path_fingerprint);
                hashOptionalExchangeU64(&hasher, certificate.capability_instance_fingerprint);
                hashOptionalExchangeU64(&hasher, certificate.obligation_fingerprint);
                hashOptionalExchangeU64(&hasher, certificate.effect_session_spec_fingerprint);
                hashU64(&hasher, certificate.route_fingerprint);
                hashU64List(&hasher, certificate.morphism_offer_fingerprints);
                hashU64List(&hasher, certificate.dynamic_morphism_fingerprints);
                hashU64List(&hasher, certificate.residualization_fingerprints);
                hashOptionalExchangeU64(&hasher, certificate.pipeline_fingerprint);
                hashOptionalExchangeU64(&hasher, certificate.source_protocol_op_fingerprint);
                hashOptionalExchangeU64(&hasher, certificate.target_protocol_op_fingerprint);
                hashBytes(&hasher, @tagName(certificate.handling));
                hashBytes(&hasher, @tagName(certificate.usage));
                hashBytes(&hasher, @tagName(certificate.provider_usage));
                hashBytes(&hasher, @tagName(certificate.response_use));
                hashBytes(&hasher, @tagName(certificate.replay_policy));
                hashBytes(&hasher, @tagName(certificate.branch_policy));
                hashBool(&hasher, certificate.expected_response_kinds.@"resume");
                hashBool(&hasher, certificate.expected_response_kinds.return_now);
                hashBool(&hasher, certificate.expected_response_kinds.resume_after);
                hashValueRefList(&hasher, certificate.expected_response_refs);
                hashValueRefList(&hasher, certificate.provider_response_refs);
                hashOptionalExchangeU64(&hasher, certificate.journal_policy_fingerprint);
                hashBool(&hasher, certificate.require_treaty_bound_response_authorization);
                for (certificate.blockers.blockers[0..certificate.blockers.count]) |blocker| hashBytes(&hasher, @tagName(blocker.tag));
                hashBool(&hasher, certificate.blockers.saturated);
                return hasher.final();
            }

